  onClose: () => void;
}

export const InvoiceModal: React.FC<InvoiceModalProps> = ({ items, onClose }) => {
  const [copied, setCopied] = React.useState(false);
  const totalRevenue = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const totalCount = items.reduce((sum, item) => sum + item.quantity, 0);
  const dateStr = new Date().toLocaleDateString('ar-SY');

  const handleCopy = () => {
    let text = `*تقرير مبيعات - مخبز كوكيز*\n`;
    text += `التاريخ: ${dateStr}\n`;
    text += `------------------\n`;

    items.forEach(item => {
      text += `- ${item.name}: ${item.quantity} عدد × ${item.price} = ${(item.price * item.quantity).toLocaleString()}\n`;
    });

    text += `------------------\n`;
    text += `*الإجمالي النهائي: ${totalRevenue.toLocaleString()} ل.س*\n`;
    text += `عدد القطع: ${totalCount}`;

    navigator.clipboard.writeText(text).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-white rounded-2xl w-full max-w-md shadow-2xl flex flex-col max-h-[90vh] animate-fade-up">

        {/* Header */}
        <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-gray-50 rounded-t-2xl">
          <h3 className="font-bold text-lg text-gray-800">معاينة الفاتورة</h3>
          <button onClick={onClose} className="p-2 hover:bg-gray-200 rounded-full transition-colors">
            <X size={20} className="text-gray-500" />
          </button>
        </div>

        {/* Content - Scrollable */}
        <div className="p-6 overflow-y-auto flex-1 font-mono text-sm leading-relaxed" id="invoice-content">
          <div className="text-center mb-6">
            <h2 className="text-xl font-bold mb-1">مخبز كوكيز</h2>
            <p className="text-gray-500 text-xs">تقرير مبيعات يومي</p>
            <p className="text-gray-500 text-xs">{dateStr}</p>
          </div>

          <div className="border-t border-b border-dashed border-gray-300 py-4 my-4">
            {items.map((item) => (
              <div key={item.id} className="flex justify-between mb-2">
                <span>{item.name} <span className="text-gray-400 text-xs">x{item.quantity}</span></span>
                <span className="font-bold">{(item.price * item.quantity).toLocaleString()}</span>
              </div>
            ))}
          </div>

          <div className="flex justify-between items-center text-lg font-bold mt-2">
            <span>الإجمالي:</span>
            <span>{totalRevenue.toLocaleString()} ل.س</span>
          </div>
          <div className="flex justify-between items-center text-gray-500 text-xs mt-1">
            <span>عدد المواد:</span>
            <span>{totalCount}</span>
          </div>
        </div>

        {/* Footer Actions */}
        <div className="p-4 border-t border-gray-100 grid grid-cols-2 gap-3 bg-gray-50 rounded-b-2xl">
          <button 
            onClick={handleCopy}
            className={`flex items-center justify-center gap-2 py-2 px-4 rounded-xl font-bold transition-all text-white shadow-md ${copied ? 'bg-green-600' : 'bg-gray-800 hover:bg-black'}`}
          >
            {copied ? <Check size={18} /> : <Copy size={18} />}
            <span>{copied ? 'تم النسخ!' : 'نسخ النص'}</span>
          </button>

          <button 
             onClick={onClose}
             className="bg-white border border-gray-300 text-gray-700 py-2 px-4 rounded-xl hover:bg-gray-100 font-bold transition-colors"
          >
            إغلاق
          </button>
        </div>
      </div>
    </div>
  );
};

