import React, { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { SalesForm } from './components/RecipeGenerator';
import { SalesTable } from './components/Menu';
import { Summary } from './components/InfoBox';
import { InvoiceModal } from './components/InvoiceModal';
import { SaleItem } from './types';

const App: React.FC = () => {
  // Initialize state from local storage if available
  const [sales, setSales] = useState<SaleItem[]>(() => {
    const saved = localStorage.getItem('dailySales');
    return saved ? JSON.parse(saved) : [];
  });

  const [showInvoice, setShowInvoice] = useState(false);

  // Save to local storage whenever sales change
  useEffect(() => {
    localStorage.setItem('dailySales', JSON.stringify(sales));
  }, [sales]);

  const handleAddItem = (newItem: Omit<SaleItem, 'id' | 'time'>) => {
    const item: SaleItem = {
      ...newItem,
      id: Date.now().toString(),
      time: new Date().toLocaleTimeString('ar-SY', { hour: '2-digit', minute: '2-digit' })
    };
    setSales(prev => [...prev, item]);
  };

  const handleDeleteItem = (id: string) => {
    if (confirm('هل أنت متأكد من حذف هذا العنصر؟')) {
      setSales(prev => prev.filter(item => item.id !== id));
    }
  };

  const handleClearAll = () => {
    if (confirm('هل أنت متأكد من بدء يوم جديد وحذف جميع البيانات؟')) {
        setSales([]);
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#F3F4F6]">
      <Header />

      <main className="flex-grow container mx-auto px-4 py-6 max-w-5xl">

        {/* Header for Print View Only */}
        <div className="hidden print:block text-center mb-8 border-b-2 border-black pb-4">
            <h1 className="text-3xl font-bold mb-2">تقرير المبيعات اليومي</h1>
            <p className="text-gray-600">التاريخ: {new Date().toLocaleDateString('ar-SY')}</p>
            <p className="text-gray-600">مخبز كوكيز</p>
        </div>

        {/* Top Summary Section */}
        <Summary items={sales} onPreview={() => setShowInvoice(true)} />

        {/* Input Form (Hidden on Print) */}
        <div className="mb-6">
            <SalesForm onAddItem={handleAddItem} />
        </div>

        {/* Sales List */}
        <div className="mb-20 print:mb-0">
            <div className="flex items-center justify-between mb-4 no-print">
                <h3 className="text-xl font-bold text-gray-800">قائمة المواد المباعة</h3>
                {sales.length > 0 && (
                    <button 
                        onClick={handleClearAll}
                        className="text-sm text-red-500 hover:text-red-700 underline font-medium"
                    >
                        بدء يوم جديد (مسح الكل)
                    </button>
                )}
            </div>
            <SalesTable items={sales} onDeleteItem={handleDeleteItem} />
        </div>
      </main>

      {/* Invoice Preview Modal */}
      {showInvoice && (
        <InvoiceModal items={sales} onClose={() => setShowInvoice(false)} />
      )}

      <footer className="text-center py-6 text-gray-400 text-sm no-print mt-auto">
        <p>نظام محاسبة مخبز كوكيز - نسخة الويب</p>
      </footer>
    </div>
  );
};

export default App;

