        {/* Content - Scrollable */}
        <div className="p-6 overflow-y-auto flex-1 font-mono text-sm leading-relaxed" id="invoice-content">
          <div className="text-center mb-6 border-b-2 border-black pb-4">
            <h2 className="text-2xl font-bold mb-1">مخبز كوكيز</h2>
            <p className="text-gray-600 font-bold">تقرير مبيعات يومي</p>
            <p className="text-gray-600">{dateStr}</p>
          </div>

          <table className="w-full mb-4 text-right">
             <thead>
                 <tr className="border-b border-black">
                     <th className="py-1">المادة</th>
                     <th className="py-1">الكمية</th>
                     <th className="py-1">الإجمالي</th>
                 </tr>
             </thead>
             <tbody className="divide-y divide-gray-200">
                {items.map((item) => (
                  <tr key={item.id}>
                    <td className="py-2">{item.name}</td>
                    <td className="py-2">{item.quantity}</td>
                    <td className="py-2 font-bold">{(item.price * item.quantity).toLocaleString()}</td>
                  </tr>
                ))}
             </tbody>
          </table>

          <div className="border-t-2 border-black pt-2 mt-4">
            <div className="flex justify-between items-center text-xl font-bold">
                <span>المجموع الكلي:</span>
                <span>{totalRevenue.toLocaleString()} ل.س</span>
            </div>
            <div className="flex justify-between items-center text-gray-600 text-sm mt-1">
                <span>عدد المواد المباعة:</span>
                <span>{totalCount}</span>
            </div>
          </div>

          <div className="mt-8 text-center text-xs text-gray-500 print:block hidden">
