import React, { useState } from 'react';
import { PlusCircle, Calculator } from 'lucide-react';
import { SaleItem } from '../types';

interface SalesFormProps {
  onAddItem: (item: Omit<SaleItem, 'id' | 'time'>) => void;
}

export const SalesForm: React.FC<SalesFormProps> = ({ onAddItem }) => {
  const [name, setName] = useState('');
  const [price, setPrice] = useState('');
  const [quantity, setQuantity] = useState('1');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !price || !quantity) return;

    onAddItem({
      name,
      price: parseFloat(price),
      quantity: parseInt(quantity)
    });

    // Reset form
    setName('');
    setPrice('');
    setQuantity('1');
  };

  return (
    <div className="bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-700 no-print">
      <div className="flex items-center gap-2 mb-4 border-b pb-3 border-gray-700">
        <Calculator className="text-[#FA8072]" size={20} />
        <h2 className="text-lg font-bold text-white">إضافة مبيعات جديدة</h2>
      </div>

      <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
        <div className="md:col-span-2">
          <label className="block text-sm font-medium text-gray-300 mb-1">اسم المنتج</label>
          <input
            type="text"
            value={name}
            onChange={(e) => setName(e.target.value)}
            placeholder="مثال: كوكيز شوكولا"
            className="w-full px-4 py-2 bg-gray-700 border border-gray-600 text-white placeholder-gray-400 rounded-xl focus:ring-2 focus:ring-[#FA8072] focus:border-transparent outline-none transition-all"
            required
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-300 mb-1">السعر (ل.س)</label>
          <input
            type="number"
            value={price}
            onChange={(e) => setPrice(e.target.value)}
            placeholder="0"
            min="0"
            className="w-full px-4 py-2 bg-gray-700 border border-gray-600 text-white placeholder-gray-400 rounded-xl focus:ring-2 focus:ring-[#FA8072] focus:border-transparent outline-none transition-all"
            required
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-300 mb-1">العدد</label>
          <div className="flex gap-2">
            <input
                type="number"
                value={quantity}
                onChange={(e) => setQuantity(e.target.value)}
                min="1"
                className="w-full px-4 py-2 bg-gray-700 border border-gray-600 text-white placeholder-gray-400 rounded-xl focus:ring-2 focus:ring-[#FA8072] focus:border-transparent outline-none transition-all"
                required
            />
            <button
                type="submit"
                className="bg-[#FA8072] hover:bg-[#e67365] text-white p-2 rounded-xl transition-colors shadow-md flex items-center justify-center min-w-[50px]"
                title="إضافة"
            >
                <PlusCircle size={24} />
            </button>
          </div>
        </div>
      </form>
    </div>
  );
};

