import React, { useEffect } from 'react';
import { X, Copy, Check, Printer } from 'lucide-react';
import { SaleItem } from '../types';

interface InvoiceModalProps {
  items: SaleItem[];
  onClose: () => void;
}

export const InvoiceModal: React.FC<InvoiceModalProps> = ({ items, onClose }) => {
  const [copied, setCopied] = React.useState(false);
  const totalRevenue = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const totalCount = items.reduce((sum, item) => sum + item.quantity, 0);
  const dateStr = new Date().toLocaleDateString('ar-SY');

  // Add a class to body when modal is open to help print styles target the modal content
  useEffect(() => {
    document.body.classList.add('print-mode');
    return () => {
      document.body.classList.remove('print-mode');
    };
  }, []);

  const handleCopy = () => {
    let text = `*تقرير مبيعات - مخبز كوكيز*\n`;
    text += `التاريخ: ${dateStr}\n`;
    text += `------------------\n`;

    items.forEach(item => {
      text += `- ${item.name}: ${item.quantity} عدد × ${item.price} = ${(item.price * item.quantity).toLocaleString()}\n`;
    });

    text += `------------------\n`;
    text += `*الإجمالي النهائي: ${totalRevenue.toLocaleString()} ل.س*\n`;
    text += `عدد القطع: ${totalCount}`;

    navigator.clipboard.writeText(text).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  const handlePrint = () => {
    window.print();
  };

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-2xl w-full max-w-md shadow-2xl flex flex-col max-h-[90vh] animate-fade-up border border-gray-700">

        {/* Header */}
        <div className="p-4 border-b border-gray-700 flex justify-between items-center bg-gray-900/50 rounded-t-2xl no-print">
          <h3 className="font-bold text-lg text-white">معاينة الفاتورة</h3>
          <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full transition-colors">
            <X size={20} className="text-gray-400" />
          </button>
        </div>

        {/* Content - Scrollable */}
        <div className="p-6 overflow-y-auto flex-1 font-mono text-sm leading-relaxed text-gray-300" id="invoice-content">
          <div className="text-center mb-6 border-b-2 border-gray-600 print:border-black pb-4">
            <h2 className="text-2xl font-bold mb-1 text-white print:text-black">مخبز كوكيز</h2>
            <p className="text-gray-400 font-bold print:text-gray-600">تقرير مبيعات يومي</p>
            <p className="text-gray-500 print:text-gray-600">{dateStr}</p>
          </div>

          <table className="w-full mb-4 text-right">
             <thead>
                 <tr className="border-b border-gray-600 print:border-black">
                     <th className="py-1 text-gray-300 print:text-black">المادة</th>
                     <th className="py-1 text-gray-300 print:text-black">الكمية</th>
                     <th className="py-1 text-gray-300 print:text-black">الإجمالي</th>
                 </tr>
             </thead>
             <tbody className="divide-y divide-gray-700 print:divide-gray-200">
                {items.map((item) => (
                  <tr key={item.id}>
                    <td className="py-2 text-gray-300 print:text-black">{item.name}</td>
                    <td className="py-2 text-gray-300 print:text-black">{item.quantity}</td>
                    <td className="py-2 font-bold text-white print:text-black">{(item.price * item.quantity).toLocaleString()}</td>
                  </tr>
                ))}
             </tbody>
          </table>

          <div className="border-t-2 border-gray-600 print:border-black pt-2 mt-4">
            <div className="flex justify-between items-center text-xl font-bold">
                <span className="text-white print:text-black">المجموع الكلي:</span>
                <span className="text-[#FA8072] print:text-black">{totalRevenue.toLocaleString()} ل.س</span>
            </div>
            <div className="flex justify-between items-center text-gray-500 text-sm mt-1 print:text-black">
                <span>عدد المواد المباعة:</span>
                <span>{totalCount}</span>
            </div>
          </div>

          <div className="mt-8 text-center text-xs text-gray-500 print:block hidden">
             تم استخراج هذا التقرير آلياً من نظام مبيعات مخبز كوكيز
          </div>
        </div>

        {/* Footer Actions */}
        <div className="p-4 border-t border-gray-700 grid grid-cols-2 gap-3 bg-gray-900/50 rounded-b-2xl no-print">
          <button 
            onClick={handlePrint}
            className="flex items-center justify-center gap-2 py-2 px-4 rounded-xl font-bold transition-all text-white shadow-md bg-[#FA8072] hover:bg-[#e67365]"
          >
            <Printer size={18} />
            <span>طباعة PDF</span>
          </button>

          <button 
            onClick={handleCopy}
            className={`flex items-center justify-center gap-2 py-2 px-4 rounded-xl font-bold transition-all text-white shadow-md ${copied ? 'bg-green-600' : 'bg-gray-700 hover:bg-gray-600'}`}
          >
            {copied ? <Check size={18} /> : <Copy size={18} />}
            <span>{copied ? 'تم النسخ' : 'نسخ النص'}</span>
          </button>
        </div>
      </div>
    </div>
  );
};

