import React, { useState } from 'react';
import { Plus, Trash2, Settings, X } from 'lucide-react';
import { Product } from '../types';

interface ProductManagerProps {
  products: Product[];
  onAddProduct: (product: Omit<Product, 'id'>) => void;
  onDeleteProduct: (id: string) => void;
  isOpen: boolean;
  onClose: () => void;
}

export const ProductManager: React.FC<ProductManagerProps> = ({ 
  products, 
  onAddProduct, 
  onDeleteProduct,
  isOpen,
  onClose
}) => {
  const [name, setName] = useState('');
  const [price, setPrice] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !price) return;

    onAddProduct({
      name,
      price: parseFloat(price)
    });

    setName('');
    setPrice('');
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-2xl w-full max-w-lg shadow-2xl border border-gray-700 animate-fade-up flex flex-col max-h-[85vh]">

        <div className="p-4 border-b border-gray-700 flex justify-between items-center bg-gray-900/50 rounded-t-2xl">
          <div className="flex items-center gap-2 text-white">
            <Settings size={20} className="text-[#FA8072]" />
            <h3 className="font-bold text-lg">إدارة المواد والأسعار</h3>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full transition-colors">
            <X size={20} className="text-gray-400" />
          </button>
        </div>

        <div className="p-6 overflow-y-auto">
          {/* Add New Product Form */}
          <form onSubmit={handleSubmit} className="mb-6 bg-gray-700/30 p-4 rounded-xl border border-gray-600">
            <h4 className="text-sm font-bold text-gray-300 mb-3">إضافة مادة جديدة للقائمة</h4>
            <div className="flex gap-2">
              <input
                type="text"
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder="اسم المادة (مثال: كوكيز فانيلا)"
                className="flex-grow px-3 py-2 bg-gray-900 border border-gray-600 text-white rounded-lg focus:ring-1 focus:ring-[#FA8072] outline-none text-sm"
                required
              />
              <input
                type="number"
                value={price}
                onChange={(e) => setPrice(e.target.value)}
                placeholder="السعر"
                className="w-24 px-3 py-2 bg-gray-900 border border-gray-600 text-white rounded-lg focus:ring-1 focus:ring-[#FA8072] outline-none text-sm"
                required
              />
              <button 
                type="submit"
                className="bg-[#FA8072] hover:bg-[#e67365] text-white p-2 rounded-lg transition-colors"
              >
                <Plus size={20} />
              </button>
            </div>
          </form>

          {/* Product List */}
          <div className="space-y-2">
            <h4 className="text-sm font-bold text-gray-400 mb-2">قائمة المواد الحالية ({products.length})</h4>
            {products.length === 0 ? (
              <p className="text-gray-500 text-center py-4 text-sm">لا توجد مواد مضافة بعد.</p>
            ) : (
              <div className="grid gap-2">
                {products.map(product => (
                  <div key={product.id} className="flex justify-between items-center bg-gray-700 p-3 rounded-lg border border-gray-600">
                    <div>
                      <span className="text-white font-medium block">{product.name}</span>
                      <span className="text-[#FA8072] text-sm font-bold">{product.price.toLocaleString()} ل.س</span>
                    </div>
                    <button 
                      onClick={() => onDeleteProduct(product.id)}
                      className="text-gray-400 hover:text-red-400 p-2 transition-colors"
                      title="حذف من القائمة"
                    >
                      <Trash2 size={18} />
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { PlusCircle, Calculator, Settings } from 'lucide-react';
import { SaleItem, Product } from '../types';

interface SalesFormProps {
  onAddItem: (item: Omit<SaleItem, 'id' | 'time'>) => void;
  products: Product[];
  onOpenProductManager: () => void;
}

export const SalesForm: React.FC<SalesFormProps> = ({ onAddItem, products, onOpenProductManager }) => {
  const [selectedProductId, setSelectedProductId] = useState('');
  const [customName, setCustomName] = useState(''); // Fallback if they want to type manually
  const [price, setPrice] = useState('');
  const [quantity, setQuantity] = useState('1');

  // Handle product selection
  const handleProductChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const pId = e.target.value;
    setSelectedProductId(pId);

    if (pId === 'custom') {
      setCustomName('');
      setPrice('');
    } else {
      const product = products.find(p => p.id === pId);
      if (product) {
        setPrice(product.price.toString());
      }
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    let finalName = customName;
    if (selectedProductId !== 'custom' && selectedProductId !== '') {
        const product = products.find(p => p.id === selectedProductId);
        if (product) finalName = product.name;
    }

    if (!finalName || !price || !quantity) return;

    onAddItem({
      name: finalName,
      price: parseFloat(price),
      quantity: parseInt(quantity)
    });

    // Reset form but keep last selected product if needed, or reset all? Let's reset quantity mostly.
    // Standard UX: Reset fields to allow new entry
    setQuantity('1');
    // We keep the product selected for faster entry of same item, or reset? 
    // Let's reset to allow choosing next item.
    // setSelectedProductId(''); 
    // setPrice('');
    // setCustomName('');
  };

  return (
    <div className="bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-700 no-print">
      <div className="flex items-center justify-between mb-4 border-b pb-3 border-gray-700">
        <div className="flex items-center gap-2">
            <Calculator className="text-[#FA8072]" size={20} />
            <h2 className="text-lg font-bold text-white">تسجيل مبيعات</h2>
        </div>
        <button 
            type="button"
            onClick={onOpenProductManager}
            className="text-xs flex items-center gap-1 text-gray-400 hover:text-white transition-colors bg-gray-700 px-3 py-1.5 rounded-lg"
        >
            <Settings size={14} />
            إدارة المواد والأسعار
        </button>
      </div>

      <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
        <div className="md:col-span-2">
          <label className="block text-sm font-medium text-gray-300 mb-1">المادة</label>
          {products.length > 0 ? (
             <div className="relative">
                 <select
                    value={selectedProductId}
                    onChange={handleProductChange}
                    className="w-full px-4 py-2 bg-gray-700 border border-gray-600 text-white rounded-xl focus:ring-2 focus:ring-[#FA8072] focus:border-transparent outline-none transition-all appearance-none"
                    required
                 >
                    <option value="" disabled>اختر المادة...</option>
                    {products.map(p => (
                        <option key={p.id} value={p.id}>{p.name}</option>
                    ))}
                    <option value="custom">-- مادة غير موجودة بالقائمة --</option>
                 </select>
                 {/* Custom name input if "custom" is selected */}
                 {selectedProductId === 'custom' && (
                     <input
                        type="text"
                        value={customName}
                        onChange={(e) => setCustomName(e.target.value)}
                        placeholder="اكتب اسم المادة يدوياً"
                        className="mt-2 w-full px-4 py-2 bg-gray-700 border border-gray-600 text-white rounded-xl focus:ring-2 focus:ring-[#FA8072] outline-none"
                        autoFocus
                        required
                     />
                 )}
             </div>
          ) : (
             <div className="text-gray-400 text-sm py-2 bg-gray-700/50 px-3 rounded-xl border border-dashed border-gray-600">
                 لا توجد مواد. اضغط "إدارة المواد" لإضافتها.
                 <input 
                    type="text" 
                    value={customName}
                    onChange={(e) => setCustomName(e.target.value)}
                    className="mt-2 w-full px-3 py-1 bg-gray-800 rounded border border-gray-600"
                    placeholder="أو اكتب الاسم هنا"
                    required
                 />
             </div>
          )}
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-300 mb-1">السعر (ل.س)</label>
          <input
            type="number"
            value={price}
            onChange={(e) => setPrice(e.target.value)}
            placeholder="0"
            min="0"
            className="w-full px-4 py-2 bg-gray-700 border border-gray-600 text-white placeholder-gray-400 rounded-xl focus:ring-2 focus:ring-[#FA8072] focus:border-transparent outline-none transition-all"
            required
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-300 mb-1">العدد</label>
          <div className="flex gap-2">
            <input
                type="number"
                value={quantity}
                onChange={(e) => setQuantity(e.target.value)}
                min="1"
                className="w-full px-4 py-2 bg-gray-700 border border-gray-600 text-white placeholder-gray-400 rounded-xl focus:ring-2 focus:ring-[#FA8072] focus:border-transparent outline-none transition-all"
                required
            />
            <button
                type="submit"
                className="bg-[#FA8072] hover:bg-[#e67365] text-white p-2 rounded-xl transition-colors shadow-md flex items-center justify-center min-w-[50px]"
                title="إضافة"
            >
                <PlusCircle size={24} />
            </button>
          </div>
        </div>
      </form>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { SalesForm } from './components/RecipeGenerator';
import { SalesTable } from './components/Menu';
import { Summary } from './components/InfoBox';
import { InvoiceModal } from './components/InvoiceModal';
import { ProductManager } from './components/ProductManager';
import { SaleItem, Product } from './types';

// Default initial products to help the user get started
const DEFAULT_PRODUCTS: Product[] = [
    { id: '1', name: 'كوكيز شوكولا', price: 5000 },
    { id: '2', name: 'كوكيز فانيلا', price: 4500 },
    { id: '3', name: 'براونيز', price: 7000 },
];

const App: React.FC = () => {
  // Sales State
  const [sales, setSales] = useState<SaleItem[]>(() => {
    const saved = localStorage.getItem('dailySales');
    return saved ? JSON.parse(saved) : [];
  });

  // Products State
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('products');
    return saved ? JSON.parse(saved) : DEFAULT_PRODUCTS;
  });

  const [showInvoice, setShowInvoice] = useState(false);
  const [showProductManager, setShowProductManager] = useState(false);

  // Persistence
  useEffect(() => {
    localStorage.setItem('dailySales', JSON.stringify(sales));
  }, [sales]);

  useEffect(() => {
    localStorage.setItem('products', JSON.stringify(products));
  }, [products]);

  // Handlers
  const handleAddItem = (newItem: Omit<SaleItem, 'id' | 'time'>) => {
    const item: SaleItem = {
      ...newItem,
      id: Date.now().toString(),
      time: new Date().toLocaleTimeString('ar-SY', { hour: '2-digit', minute: '2-digit' })
    };
    setSales(prev => [...prev, item]);
  };

  const handleDeleteItem = (id: string) => {
    if (confirm('هل أنت متأكد من حذف هذا العنصر؟')) {
      setSales(prev => prev.filter(item => item.id !== id));
    }
  };

  const handleClearAll = () => {
    if (confirm('هل أنت متأكد من بدء يوم جديد وحذف جميع البيانات؟')) {
        setSales([]);
    }
  };

  const handleAddProduct = (newProduct: Omit<Product, 'id'>) => {
    const product: Product = {
        ...newProduct,
        id: Date.now().toString()
    };
    setProducts(prev => [...prev, product]);
  };

  const handleDeleteProduct = (id: string) => {
    if (confirm('هل أنت متأكد من حذف هذه المادة من القائمة؟')) {
        setProducts(prev => prev.filter(p => p.id !== id));
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-gray-900 print:bg-white">
      <Header />

      <main className="flex-grow container mx-auto px-4 py-6 max-w-5xl">

        {/* Header for Print View Only */}
        <div className="hidden print:block text-center mb-8 border-b-2 border-black pb-4">
            <h1 className="text-3xl font-bold mb-2 text-black">تقرير المبيعات اليومي</h1>
            <p className="text-gray-600">التاريخ: {new Date().toLocaleDateString('ar-SY')}</p>
            <p className="text-gray-600">مخبز كوكيز</p>
        </div>

        {/* Top Summary Section */}
        <Summary items={sales} onPreview={() => setShowInvoice(true)} />

        {/* Input Form (Hidden on Print) */}
        <div className="mb-6">
            <SalesForm 
                onAddItem={handleAddItem} 
                products={products}
                onOpenProductManager={() => setShowProductManager(true)}
            />
        </div>

        {/* Sales List */}
        <div className="mb-20 print:mb-0">
            <div className="flex items-center justify-between mb-4 no-print">
                <h3 className="text-xl font-bold text-white">قائمة المواد المباعة</h3>
                {sales.length > 0 && (
                    <button 
                        onClick={handleClearAll}
                        className="text-sm text-red-400 hover:text-red-300 underline font-medium"
                    >
                        بدء يوم جديد (مسح الكل)
                    </button>
                )}
            </div>
            <SalesTable items={sales} onDeleteItem={handleDeleteItem} />
        </div>
      </main>

      {/* Modals */}
      {showInvoice && (
        <InvoiceModal items={sales} onClose={() => setShowInvoice(false)} />
      )}

      <ProductManager 
         isOpen={showProductManager}
         onClose={() => setShowProductManager(false)}
         products={products}
         onAddProduct={handleAddProduct}
         onDeleteProduct={handleDeleteProduct}
      />

      <footer className="text-center py-6 text-gray-500 text-sm no-print mt-auto">
        <p>نظام محاسبة مخبز كوكيز - نسخة الويب</p>
      </footer>
    </div>
  );
};

export default App;

