import React, { useState } from 'react';
import { PlusCircle, Calculator, Settings, Edit3 } from 'lucide-react';
import { SaleItem, Product } from '../types';

interface SalesFormProps {
  onAddItem: (item: Omit<SaleItem, 'id' | 'time'>) => void;
  products: Product[];
  onOpenProductManager: () => void;
}

export const SalesForm: React.FC<SalesFormProps> = ({ onAddItem, products, onOpenProductManager }) => {
  const [selectedProductId, setSelectedProductId] = useState('');
  const [customName, setCustomName] = useState('');
  const [price, setPrice] = useState('');
  const [quantity, setQuantity] = useState('1');

  // Handle product selection from grid
  const handleSelectProduct = (product: Product) => {
    setSelectedProductId(product.id);
    setPrice(product.price.toString());
    setCustomName(''); // Clear custom name if any
    setQuantity('1'); // Reset quantity to 1 for convenience
  };

  const handleSelectCustom = () => {
    setSelectedProductId('custom');
    setPrice('');
    setCustomName('');
    setQuantity('1');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    let finalName = customName;
    if (selectedProductId !== 'custom' && selectedProductId !== '') {
        const product = products.find(p => p.id === selectedProductId);
        if (product) finalName = product.name;
    }

    if (!finalName || !price || !quantity) return;

    onAddItem({
      name: finalName,
      price: parseFloat(price),
      quantity: parseInt(quantity)
    });

    // Reset logic: Keep the selection active to add more of the same, 
    // or reset? Typically for fast POS, keeping it selected is fine, 
    // but visually providing feedback is good.
    // Let's reset quantity to 1.
    setQuantity('1');
  };

  return (
    <div className="bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-700 no-print">
      <div className="flex items-center justify-between mb-4 border-b pb-3 border-gray-700">
        <div className="flex items-center gap-2">
            <Calculator className="text-[#FA8072]" size={20} />
            <h2 className="text-lg font-bold text-white">تسجيل مبيعات</h2>
        </div>
        <button 
            type="button"
            onClick={onOpenProductManager}
            className="text-xs flex items-center gap-1 text-gray-400 hover:text-white transition-colors bg-gray-700 px-3 py-1.5 rounded-lg"
        >
            <Settings size={14} />
            تعديل القائمة
        </button>
      </div>

      {/* Product Grid Selection */}
      <div className="mb-6">
        <label className="block text-sm font-medium text-gray-300 mb-2">اختر المنتج:</label>

        {products.length === 0 ? (
             <div className="text-center py-6 bg-gray-700/30 rounded-xl border border-dashed border-gray-600">
                 <p className="text-gray-400 mb-2">القائمة فارغة</p>
                 <button onClick={onOpenProductManager} className="text-[#FA8072] text-sm underline">إضافة منتجات</button>
             </div>
        ) : (
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3">
                {products.map(product => (
                    <button
                        key={product.id}
                        type="button"
                        onClick={() => handleSelectProduct(product)}
                        className={`
                            relative flex flex-col items-center justify-center p-3 rounded-xl transition-all border
                            ${selectedProductId === product.id 
                                ? 'bg-[#FA8072]/20 border-[#FA8072] text-white ring-1 ring-[#FA8072]' 
                                : 'bg-gray-700 border-gray-600 text-gray-300 hover:bg-gray-600 hover:border-gray-500'}
                        `}
                    >
                        <span className="font-bold text-sm text-center line-clamp-2">{product.name}</span>
                        <span className={`text-xs mt-1 ${selectedProductId === product.id ? 'text-[#FA8072] font-bold' : 'text-gray-400'}`}>
                            {product.price.toLocaleString()} ل.س
                        </span>
                    </button>
                ))}

                {/* Custom Item Button */}
                <button
                    type="button"
                    onClick={handleSelectCustom}
                    className={`
                        flex flex-col items-center justify-center p-3 rounded-xl transition-all border
                        ${selectedProductId === 'custom'
                            ? 'bg-blue-900/40 border-blue-400 text-white ring-1 ring-blue-400' 
                            : 'bg-gray-700 border-dashed border-gray-600 text-gray-400 hover:bg-gray-600'}
                    `}
                >
                    <Edit3 size={18} className="mb-1" />
                    <span className="text-xs">مادة أخرى</span>
                </button>
            </div>
        )}
      </div>

      {/* Action Area */}
      <form onSubmit={handleSubmit} className="bg-gray-900/50 p-4 rounded-xl border border-gray-700">
        <div className="grid grid-cols-1 md:grid-cols-12 gap-4 items-end">

            {/* Custom Name Input (Only shows if Custom is selected) */}
            {selectedProductId === 'custom' && (
                <div className="md:col-span-5 animate-fade-up">
                    <label className="block text-xs font-medium text-gray-400 mb-1">اسم المادة</label>
                    <input
                        type="text"
                        value={customName}
                        onChange={(e) => setCustomName(e.target.value)}
                        placeholder="أدخل اسم المادة"
                        className="w-full px-4 py-2 bg-gray-700 border border-gray-600 text-white rounded-xl focus:ring-2 focus:ring-[#FA8072] outline-none"
                        required
                        autoFocus
                    />
                </div>
            )}

            {/* Selected Item Display (if not custom) */}
            {selectedProductId !== 'custom' && (
                <div className="md:col-span-5">
                     <label className="block text-xs font-medium text-gray-400 mb-1">المادة المختارة</label>
                     <div className="w-full px-4 py-2 bg-gray-700/50 border border-gray-600 text-gray-300 rounded-xl">
                        {selectedProductId ? products.find(p => p.id === selectedProductId)?.name : 'يرجى اختيار مادة'}
                     </div>
                </div>
            )}

            <div className="md:col-span-3">
                <label className="block text-xs font-medium text-gray-400 mb-1">السعر</label>
                <input
                    type="number"
                    value={price}
                    onChange={(e) => setPrice(e.target.value)}
                    placeholder="0"
                    className="w-full px-4 py-2 bg-gray-700 border border-gray-600 text-white rounded-xl focus:ring-2 focus:ring-[#FA8072] outline-none"
                    required
                />
            </div>

            <div className="md:col-span-2">
                <label className="block text-xs font-medium text-gray-400 mb-1">العدد</label>
                <input
                    type="number"
                    value={quantity}
                    onChange={(e) => setQuantity(e.target.value)}
                    min="1"
                    className="w-full px-4 py-2 bg-gray-700 border border-gray-600 text-white rounded-xl focus:ring-2 focus:ring-[#FA8072] outline-none text-center"
                    required
                />
            </div>

            <div className="md:col-span-2">
                <button
                    type="submit"
                    disabled={!selectedProductId}
                    className={`w-full py-2 rounded-xl transition-all shadow-md flex items-center justify-center gap-2
                        ${selectedProductId 
                            ? 'bg-[#FA8072] hover:bg-[#e67365] text-white cursor-pointer transform active:scale-95' 
                            : 'bg-gray-700 text-gray-500 cursor-not-allowed'}
                    `}
                >
                    <PlusCircle size={20} />
                    <span>إضافة</span>
                </button>
            </div>
        </div>
      </form>
    </div>
  );
};

