import { SaleItem, Product } from '../types';

interface POSInterfaceProps {
  onCompleteOrder: (items: Omit<SaleItem, 'id' | 'time'>[]) => void;
  products: Product[];
  onOpenProductManager: () => void;
}

// Internal type for the local cart
interface CartItem {
    tempId: string;
    name: string;
    price: number;
    quantity: number;
    isCustom?: boolean;
}

export const POSInterface: React.FC<POSInterfaceProps> = ({ onCompleteOrder, products, onOpenProductManager }) => {
  const [cart, setCart] = useState<CartItem[]>([]);

  // Custom item modal/inline state
  const [showCustomInput, setShowCustomInput] = useState(false);
  const [customName, setCustomName] = useState('');
  const [customPrice, setCustomPrice] = useState('');

  // 1. Add Product to Cart Logic
  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.name === product.name && item.price === product.price && !item.isCustom);
      if (existing) {
        return prev.map(item => 
          (item.tempId === existing.tempId) ? { ...item, quantity: item.quantity + 1 } : item
        );
      }
      return [...prev, { tempId: Date.now().toString(), name: product.name, price: product.price, quantity: 1 }];
    });
  };

  // 2. Add Custom Item to Cart
  const addCustomToCart = () => {
    if (!customName || !customPrice) return;
    setCart(prev => [...prev, { 
        tempId: Date.now().toString(), 
        name: customName, 
        price: parseFloat(customPrice), 
        quantity: 1,
        isCustom: true
    }]);
    setCustomName('');
    setCustomPrice('');
    setShowCustomInput(false);
  };

  // 3. Cart Management
  const updateQuantity = (tempId: string, change: number) => {
    setCart(prev => prev.map(item => {
        if (item.tempId === tempId) {
            const newQty = Math.max(1, item.quantity + change);
            return { ...item, quantity: newQty };
        }
        return item;
    }));
  };

  const removeFromCart = (tempId: string) => {
    setCart(prev => prev.filter(item => item.tempId !== tempId));
  };

  const clearCart = () => {
      setCart([]);
  };

  // 4. Finalize Order
  const handleCheckout = () => {
      if (cart.length === 0) return;

      const salesItems = cart.map(({ name, price, quantity }) => ({
          name,
          price,
          quantity
      }));

      onCompleteOrder(salesItems);
      clearCart();
  };

  const cartTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 no-print">

