                                        <Minus size={14} />
                                    </button>
                                    <span className="text-white font-bold text-sm w-4 text-center">{item.quantity}</span>
                                    <button 
                                        onClick={() => updateQuantity(item.tempId, 1)}
                                        className="w-6 h-6 flex items-center justify-center bg-[#FA8072] text-white rounded hover:bg-[#e67365]"
                                    >
                                        <Plus size={14} />
                                    </button>
                                </div>
                            </div>

                            <button 
                                onClick={() => removeFromCart(item.tempId)}
                                className="absolute -left-2 -top-2 bg-red-500 text-white p-1 rounded-full opacity-0 group-hover:opacity-100 transition-opacity shadow-md"
                            >
                                <Trash2 size={12} />
                            </button>
