import React, { useState } from 'react';
import { PlusCircle, ShoppingCart, Settings, Edit3, Trash2, CheckCircle, Plus, Minus, Scale, Box } from 'lucide-react';
import { SaleItem, Product, UnitType } from '../types';

interface POSInterfaceProps {
  onCompleteOrder: (items: Omit<SaleItem, 'id' | 'time' | 'customerNumber' | 'orderId'>[]) => void;
  products: Product[];
  onOpenProductManager: () => void;
}

// Internal type for the local cart
interface CartItem {
    tempId: string;
    name: string;
    price: number; // This is now the "Sold Price" (editable)
    quantity: number;
    unitType: UnitType;
    isCustom?: boolean;
}

export const POSInterface: React.FC<POSInterfaceProps> = ({ onCompleteOrder, products, onOpenProductManager }) => {
  const [cart, setCart] = useState<CartItem[]>([]);

  // Custom item modal/inline state
  const [showCustomInput, setShowCustomInput] = useState(false);
  const [customName, setCustomName] = useState('');
  const [customPrice, setCustomPrice] = useState('');
  const [customUnit, setCustomUnit] = useState<UnitType>('piece');

  // 1. Add Product to Cart Logic
  const addToCart = (product: Product) => {
    setCart(prev => {
      // Find item with same name AND unit type. Price is ignored here because we want to allow re-adding same item even if we changed its price previously.
      // Actually, for simplicity, if item exists, just inc quantity. If they want different price, add separately? 
      // Better: Check if item exists with same Name.
      const existing = prev.find(item => item.name === product.name && item.unitType === product.unitType);

      if (existing) {
        return prev.map(item => 
          (item.tempId === existing.tempId) 
            ? { ...item, quantity: item.quantity + (item.unitType === 'kg' ? 1 : 1) } 
            : item
        );
      }
      return [...prev, { 
          tempId: Date.now().toString(), 
          name: product.name, 
          price: product.price, 
          quantity: 1, 
          unitType: product.unitType || 'piece' 
      }];
    });
  };

  // 2. Add Custom Item to Cart
  const addCustomToCart = () => {
    if (!customName || !customPrice) return;
    setCart(prev => [...prev, { 
        tempId: Date.now().toString(), 
        name: customName, 
        price: parseFloat(customPrice), 
        quantity: 1,
        unitType: customUnit,
        isCustom: true
    }]);
    setCustomName('');
    setCustomPrice('');
    setShowCustomInput(false);
  };

  // 3. Cart Management
  const updateQuantity = (tempId: string, change: number) => {
    setCart(prev => prev.map(item => {
        if (item.tempId === tempId) {
            const step = item.unitType === 'kg' ? 0.1 : 1;
            const newQty = Math.max(step, parseFloat((item.quantity + (change * step)).toFixed(2)));
            return { ...item, quantity: newQty };
        }
        return item;
    }));
  };

  const updateQuantityDirectly = (tempId: string, val: string) => {
      const num = parseFloat(val);
      if (isNaN(num) || num < 0) return;
      setCart(prev => prev.map(item => item.tempId === tempId ? { ...item, quantity: num } : item));
  };

  const updatePriceDirectly = (tempId: string, val: string) => {
      const num = parseFloat(val);
      if (isNaN(num) || num < 0) return;
      setCart(prev => prev.map(item => item.tempId === tempId ? { ...item, price: num } : item));
  };

  const removeFromCart = (tempId: string) => {
    setCart(prev => prev.filter(item => item.tempId !== tempId));
  };

  const clearCart = () => {
      setCart([]);
  };

  // 4. Finalize Order
  const handleCheckout = () => {
      if (cart.length === 0) return;

      const salesItems = cart.map(({ name, price, quantity, unitType }) => ({
          name,
          price,
          quantity,
          unitType
      }));

      onCompleteOrder(salesItems);
      clearCart();
  };

  const cartTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 no-print">

      {/* LEFT SECTION: Product Grid (Menu) */}
      <div className="lg:col-span-2 space-y-4">
        <div className="flex items-center justify-between bg-gray-800 p-4 rounded-xl border border-gray-700">
             <h2 className="font-bold text-white flex items-center gap-2">
                <Settings className="text-[#FA8072]" size={20} />
                قائمة المنتجات
             </h2>
             <button 
                onClick={onOpenProductManager}
                className="text-xs bg-gray-700 hover:bg-gray-600 text-gray-300 px-3 py-1.5 rounded-lg transition-colors"
             >
                تعديل القائمة
             </button>
        </div>

        {/* Grid */}
        <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
            {products.map(product => (
                <button
                    key={product.id}
                    onClick={() => addToCart(product)}
                    className="flex flex-col items-center justify-center p-4 bg-gray-800 border border-gray-700 hover:bg-gray-700 hover:border-[#FA8072] text-white rounded-2xl transition-all shadow-sm active:scale-95 group h-32 relative"
                >
                    <div className={`absolute top-2 right-2 px-1.5 py-0.5 rounded text-[10px] font-bold ${product.unitType === 'kg' ? 'bg-yellow-400 text-black' : 'bg-blue-300 text-black'}`}>
                        {product.unitType === 'kg' ? 'KG' : 'قطعة'}
                    </div>

                    <span className="font-bold text-sm text-center mb-1 line-clamp-2 group-hover:text-[#FA8072] transition-colors">{product.name}</span>
                    <span className="text-xs text-gray-400 bg-gray-900/50 px-2 py-1 rounded-md">{product.price.toLocaleString()} ل.س</span>
                </button>
            ))}

            {/* Custom Item Button */}
            <button
                onClick={() => setShowCustomInput(true)}
                className="flex flex-col items-center justify-center p-4 bg-gray-800 border border-dashed border-gray-600 hover:bg-gray-700 text-gray-400 rounded-2xl transition-all active:scale-95 h-32"
            >
                <Edit3 size={20} className="mb-2" />
                <span className="text-xs font-medium">مادة حرة</span>
            </button>
        </div>

        {/* Inline Custom Item Form */}
        {showCustomInput && (
            <div className="bg-gray-800 p-4 rounded-xl border border-[#FA8072] animate-fade-up">
                <h4 className="text-sm font-bold text-white mb-3">إضافة مادة غير مدرجة</h4>
                <div className="flex flex-col md:flex-row gap-2">
                    <input 
                        type="text" 
                        value={customName}
                        onChange={e => setCustomName(e.target.value)}
                        placeholder="اسم المادة"
                        className="flex-grow bg-gray-900 border border-gray-600 text-white px-3 py-2 rounded-lg text-sm outline-none focus:border-[#FA8072]"
                        autoFocus
                    />

                    <div className="flex bg-gray-900 rounded-lg p-1 border border-gray-600 w-fit">
                        <button
                            onClick={() => setCustomUnit('piece')}
                            className={`px-3 py-1 rounded text-xs ${customUnit === 'piece' ? 'bg-[#FA8072] text-white' : 'text-gray-400'}`}
                        >قطعة</button>
                        <button
                            onClick={() => setCustomUnit('kg')}
                            className={`px-3 py-1 rounded text-xs ${customUnit === 'kg' ? 'bg-[#FA8072] text-white' : 'text-gray-400'}`}
                        >كيلو</button>
                    </div>

                    <input 
                        type="number" 
                        value={customPrice}
                        onChange={e => setCustomPrice(e.target.value)}
                        placeholder="السعر"
                        className="w-24 bg-gray-900 border border-gray-600 text-white px-3 py-2 rounded-lg text-sm outline-none focus:border-[#FA8072]"
                    />
                    <button 
                        onClick={addCustomToCart}
                        className="bg-[#FA8072] text-white px-4 rounded-lg font-bold hover:bg-[#e67365] py-2"
                    >
                        إضافة
                    </button>
                    <button 
                        onClick={() => setShowCustomInput(false)}
                        className="bg-gray-700 text-gray-300 px-3 rounded-lg hover:bg-gray-600 py-2"
                    >
                        <Trash2 size={18} />
                    </button>
                </div>
            </div>
        )}
      </div>

      {/* RIGHT SECTION: Current Customer Bill (Cart) */}
      <div className="lg:col-span-1">
        <div className="bg-gray-800 rounded-2xl border border-gray-700 shadow-xl overflow-hidden flex flex-col h-full min-h-[500px]">
            {/* Cart Header */}
            <div className="bg-gray-900/80 p-4 border-b border-gray-700 flex justify-between items-center">
                <h3 className="font-bold text-white flex items-center gap-2">
                    <ShoppingCart size={20} className="text-[#FA8072]" />
                    زبون حالي
                </h3>
                {cart.length > 0 && (
                    <button onClick={clearCart} className="text-xs text-red-400 hover:text-red-300 underline">
                        إلغاء الطلب
                    </button>
                )}
            </div>

            {/* Cart Items */}
            <div className="flex-grow p-3 overflow-y-auto space-y-2">
                {cart.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center text-gray-500 opacity-50">
                        <ShoppingCart size={48} className="mb-2" />
                        <p>اضغط على المنتجات لإضافتها</p>
                    </div>
                ) : (
                    cart.map(item => (
                        <div key={item.tempId} className="bg-gray-700/50 p-3 rounded-xl flex flex-col gap-2 border border-gray-700 relative group">
                            <div className="flex justify-between items-start gap-2">
                                <div className="flex flex-col">
                                    <span className="text-white font-medium text-sm">{item.name}</span>
                                    <span className={`text-[10px] w-fit px-1.5 rounded-md ${item.unitType === 'kg' ? 'bg-yellow-500/20 text-yellow-500' : 'bg-blue-500/20 text-blue-400'}`}>
                                        {item.unitType === 'kg' ? 'وزن (كيلو)' : 'عدد (قطعة)'}
                                    </span>
                                </div>

                                {/* Total Item Price Display */}
                                <span className="text-[#FA8072] font-bold text-sm">
                                    {(item.price * item.quantity).toLocaleString()}
                                </span>
                            </div>

                            <div className="grid grid-cols-2 gap-2 mt-2 items-center bg-gray-800/50 p-2 rounded-lg">
                                {/* Price Editor */}
                                <div className="flex flex-col">
                                    <label className="text-[10px] text-gray-500 mb-0.5">سعر الإفرادي</label>
                                    <input 
                                        type="number"
                                        value={item.price}
                                        onChange={(e) => updatePriceDirectly(item.tempId, e.target.value)}
                                        className="w-full bg-gray-900 border border-gray-600 rounded px-2 py-1 text-xs text-white text-center focus:border-[#FA8072] outline-none"
                                    />
                                </div>

                                {/* Quantity Editor */}
                                <div className="flex flex-col">
                                    <label className="text-[10px] text-gray-500 mb-0.5">الكمية</label>
                                    <div className="flex items-center gap-1">
                                        <button 
                                            onClick={() => updateQuantity(item.tempId, -1)}
                                            className="w-6 h-6 flex items-center justify-center bg-gray-700 text-white rounded hover:bg-gray-600 text-xs"
                                        >
                                            <Minus size={12} />
                                        </button>
                                        <input 
                                            type="number"
                                            value={item.quantity}
                                            onChange={(e) => updateQuantityDirectly(item.tempId, e.target.value)}
                                            className="w-full bg-gray-900 border border-gray-600 rounded px-1 py-1 text-xs text-white text-center focus:border-[#FA8072] outline-none"
                                            step={item.unitType === 'kg' ? "0.1" : "1"}
                                        />
                                        <button 
                                            onClick={() => updateQuantity(item.tempId, 1)}
                                            className="w-6 h-6 flex items-center justify-center bg-[#FA8072] text-white rounded hover:bg-[#e67365] text-xs"
                                        >
                                            <Plus size={12} />
                                        </button>
                                    </div>
                                </div>
                            </div>

                            <button 
                                onClick={() => removeFromCart(item.tempId)}
                                className="absolute -left-2 -top-2 bg-red-500 text-white p-1 rounded-full opacity-0 group-hover:opacity-100 transition-opacity shadow-md z-10"
                            >
                                <Trash2 size={12} />
                            </button>
                        </div>
                    ))
                )}
            </div>

            {/* Cart Footer (Total & Checkout) */}
            <div className="p-4 bg-gray-900 border-t border-gray-700 mt-auto">
                <div className="flex justify-between items-center mb-4">
                    <span className="text-gray-400">الإجمالي المطلوب:</span>
                    <span className="text-2xl font-bold text-white">{cartTotal.toLocaleString()} <span className="text-sm font-normal text-gray-500">ل.س</span></span>
                </div>

                <button
                    onClick={handleCheckout}
                    disabled={cart.length === 0}
                    className={`
                        w-full py-3 rounded-xl font-bold text-lg flex items-center justify-center gap-2 transition-all shadow-lg
                        ${cart.length > 0 
                            ? 'bg-green-600 hover:bg-green-500 text-white transform active:scale-95' 
                            : 'bg-gray-700 text-gray-500 cursor-not-allowed'}
                    `}
                >
                    <CheckCircle size={24} />
                    <span>تأكيد البيع (موافق)</span>
                </button>
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { POSInterface } from './components/RecipeGenerator';
import { SalesTable } from './components/Menu';
import { Summary } from './components/InfoBox';
import { InvoiceModal } from './components/InvoiceModal';
import { ProductManager } from './components/ProductManager';
import { HistoryModal } from './components/HistoryModal';
import { SaleItem, Product, ArchivedDay } from './types';
import { Save } from 'lucide-react';

// Default initial products - Expanded list with Units
const DEFAULT_PRODUCTS: Product[] = [
    { id: '1', name: 'كوكيز كلاسيك (شوكولا)', price: 5000, unitType: 'piece' },
    { id: '2', name: 'كوكيز فانيلا', price: 4500, unitType: 'piece' },
    { id: '3', name: 'كوكيز دبل شوكليت', price: 5500, unitType: 'piece' },
    { id: '4', name: 'كوكيز فستق حلبي', price: 8000, unitType: 'piece' },
    { id: '5', name: 'كوكيز لوتس', price: 6000, unitType: 'piece' },
    { id: '6', name: 'براونيز (بالكيلو)', price: 70000, unitType: 'kg' },
    { id: '7', name: 'بيتيفور مشكل (بالكيلو)', price: 45000, unitType: 'kg' },
    { id: '8', name: 'ميني كوكيز (قطعة)', price: 2000, unitType: 'piece' },
];

const App: React.FC = () => {
  // Sales State (Current Day)
  const [sales, setSales] = useState<SaleItem[]>(() => {
    const saved = localStorage.getItem('dailySales');
    return saved ? JSON.parse(saved) : [];
  });

  // History State (Archived Days)
  const [history, setHistory] = useState<ArchivedDay[]>(() => {
    const saved = localStorage.getItem('salesHistory');
    return saved ? JSON.parse(saved) : [];
  });

  // Products State
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('products');
    return saved ? JSON.parse(saved) : DEFAULT_PRODUCTS;
  });

  const [showInvoice, setShowInvoice] = useState(false);
  const [showProductManager, setShowProductManager] = useState(false);
  const [showHistory, setShowHistory] = useState(false);

  // Persistence
  useEffect(() => {
    localStorage.setItem('dailySales', JSON.stringify(sales));
  }, [sales]);

  useEffect(() => {
    localStorage.setItem('salesHistory', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    localStorage.setItem('products', JSON.stringify(products));
  }, [products]);

  // Logic to calculate next customer number based on existing sales
  const getNextCustomerNumber = () => {
      if (sales.length === 0) return 1;
      const maxNum = Math.max(...sales.map(s => s.customerNumber || 0));
      return maxNum + 1;
  };

  // Handler for adding a complete order (Multiple items)
  const handleCompleteOrder = (newItems: Omit<SaleItem, 'id' | 'time' | 'customerNumber' | 'orderId'>[]) => {
    const currentTime = new Date().toLocaleTimeString('ar-SY', { hour: '2-digit', minute: '2-digit' });
    const orderId = Date.now().toString(); // Common ID for the whole order
    const customerNumber = getNextCustomerNumber(); // Incrementing customer number

    const itemsWithIds: SaleItem[] = newItems.map(item => ({
        ...item,
        id: Math.random().toString(36).substr(2, 9), // Unique ID for the item row
        orderId: orderId,
        customerNumber: customerNumber,
        time: currentTime
    }));

    setSales(prev => [...prev, ...itemsWithIds]);
  };

  const handleDeleteItem = (id: string) => {
    if (confirm('هل أنت متأكد من حذف هذا العنصر؟')) {
      setSales(prev => prev.filter(item => item.id !== id));
    }
  };

  // Delete entire order by customer number or order ID
  const handleDeleteOrder = (orderId: string) => {
      if(confirm('هل أنت متأكد من حذف طلب الزبون بالكامل؟')) {
          setSales(prev => prev.filter(item => item.orderId !== orderId));
      }
  };

  // SAFE CLOSE DAY (Archive then Clear)
  const handleEndDay = () => {
    if (sales.length === 0) {
        alert('لا توجد مبيعات لترحيلها.');
        return;
    }

    if (confirm('سيتم إغلاق اليوم الحالي وترحيل جميع المبيعات إلى الأرشيف. هل أنت متأكد؟')) {
        const totalRevenue = sales.reduce((sum, item) => sum + (item.price * item.quantity), 0);
        const totalItems = sales.reduce((sum, item) => sum + item.quantity, 0);

        const daySummary: ArchivedDay = {
            id: Date.now().toString(),
            date: new Date().toLocaleDateString('ar-SY'),
            timestamp: Date.now(),
            totalRevenue,
            totalItems,
            items: [...sales] // Keep a copy of items
        };

        setHistory(prev => [daySummary, ...prev]);
        setSales([]); // Safe to clear now
        alert('تم إغلاق اليوم وحفظ البيانات في الأرشيف بنجاح.');
    }
  };

  const handleAddProduct = (newProduct: Omit<Product, 'id'>) => {
    const product: Product = {
        ...newProduct,
        id: Date.now().toString()
    };
    setProducts(prev => [...prev, product]);
  };

  const handleDeleteProduct = (id: string) => {
    if (confirm('هل أنت متأكد من حذف هذه المادة من القائمة؟')) {
        setProducts(prev => prev.filter(p => p.id !== id));
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-gray-900 print:bg-white">
      <Header onOpenHistory={() => setShowHistory(true)} />

      <main className="flex-grow container mx-auto px-4 py-6 max-w-5xl">

        {/* Header for Print View Only */}
        <div className="hidden print:block text-center mb-8 border-b-2 border-black pb-4">
            <h1 className="text-3xl font-bold mb-2 text-black">تقرير المبيعات اليومي</h1>
            <p className="text-gray-600">التاريخ: {new Date().toLocaleDateString('ar-SY')}</p>
            <p className="text-gray-600">مخبز كوكيز</p>
        </div>

        {/* Top Summary Section */}
        <Summary items={sales} onPreview={() => setShowInvoice(true)} />

        {/* POS Interface (Input Form) */}
        <div className="mb-8">
            <POSInterface 
                onCompleteOrder={handleCompleteOrder} 
                products={products}
                onOpenProductManager={() => setShowProductManager(true)}
            />
        </div>

        {/* Daily Sales List */}
        <div className="mb-20 print:mb-0 border-t border-gray-700 pt-8">
            <div className="flex items-center justify-between mb-4 no-print">
                <h3 className="text-xl font-bold text-white">سجل الزبائن والمبيعات (اليوم الحالي)</h3>
                {sales.length > 0 && (
                    <button 
                        onClick={handleEndDay}
                        className="flex items-center gap-2 bg-green-900/40 hover:bg-green-900/60 text-green-400 px-4 py-2 rounded-xl transition-colors border border-green-800"
                    >
                        <Save size={18} />
                        <span className="font-bold">إغلاق اليوم (أرشفة وحفظ)</span>
                    </button>
                )}
            </div>

            <SalesTable 
                items={sales} 
                onDeleteItem={handleDeleteItem} 
                onDeleteOrder={handleDeleteOrder}
            />
        </div>
      </main>

      {/* Modals */}
      {showInvoice && (
        <InvoiceModal items={sales} onClose={() => setShowInvoice(false)} />
      )}

      {showHistory && (
        <HistoryModal 
            history={history} 
            onClose={() => setShowHistory(false)} 
            onClearHistory={() => setHistory([])}
        />
      )}

      <ProductManager 
         isOpen={showProductManager}
         onClose={() => setShowProductManager(false)}
         products={products}
         onAddProduct={handleAddProduct}
         onDeleteProduct={handleDeleteProduct}
      />

      <footer className="text-center py-6 text-gray-500 text-sm no-print mt-auto">
        <p>نظام محاسبة مخبز كوكيز - نسخة الويب</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Trash2, ShoppingBag, Search, User, ChevronDown, ChevronUp } from 'lucide-react';
import { SaleItem } from '../types';

interface SalesTableProps {
  items: SaleItem[];
  onDeleteItem: (id: string) => void;
  onDeleteOrder?: (orderId: string) => void;
}

export const SalesTable: React.FC<SalesTableProps> = ({ items, onDeleteItem, onDeleteOrder }) => {
  const [filterCustomer, setFilterCustomer] = useState<string>('');

  // Group items by orderId/customerNumber
  const groupedOrders = useMemo(() => {
    const groups: { [key: string]: SaleItem[] } = {};
    items.forEach(item => {
        // Fallback for old data without orderId
        const key = item.orderId || `legacy-${item.time}`;
        if (!groups[key]) {
            groups[key] = [];
        }
        groups[key].push(item);
    });

    // Convert to array and sort by time (newest first)
    return Object.values(groups).sort((a, b) => {
        // Try to sort by customer number descending
        const custA = a[0]?.customerNumber || 0;
        const custB = b[0]?.customerNumber || 0;
        return custB - custA;
    });
  }, [items]);

  // Filter logic
  const filteredOrders = useMemo(() => {
      if (!filterCustomer) return groupedOrders;
      return groupedOrders.filter(group => 
          group[0].customerNumber.toString() === filterCustomer
      );
  }, [groupedOrders, filterCustomer]);

  if (items.length === 0) {
    return (
      <div className="bg-gray-800 p-8 rounded-2xl shadow-sm border border-gray-700 text-center flex flex-col items-center justify-center min-h-[200px] print:hidden">
        <div className="bg-gray-700 p-4 rounded-full mb-3">
            <ShoppingBag className="text-gray-400 w-8 h-8" />
        </div>
        <p className="text-gray-400 font-medium">لا توجد مبيعات مسجلة اليوم حتى الآن.</p>
      </div>
    );
  }

  return (
    <div className="space-y-4">
        {/* Filter Bar */}
        <div className="bg-gray-800 p-4 rounded-xl border border-gray-700 flex items-center gap-4 no-print">
            <div className="flex items-center gap-2 text-gray-400">
                <Search size={20} />
                <span className="text-sm font-bold">فلترة حسب:</span>
            </div>
            <select 
                value={filterCustomer}
                onChange={(e) => setFilterCustomer(e.target.value)}
                className="bg-gray-900 text-white border border-gray-600 rounded-lg px-4 py-2 outline-none focus:ring-1 focus:ring-[#FA8072] flex-grow md:flex-grow-0 md:w-64"
            >
                <option value="">جميع الزبائن</option>
                {groupedOrders.map(group => (
                    <option key={group[0].orderId} value={group[0].customerNumber}>
                        الزبون رقم {group[0].customerNumber || 'غير محدد'}
                    </option>
                ))}
            </select>

            {filterCustomer && (
                <button 
                    onClick={() => setFilterCustomer('')}
                    className="text-sm text-[#FA8072] hover:underline"
                >
                    إلغاء الفلترة
                </button>
            )}
        </div>

        {/* Orders List */}
        <div className="space-y-4">
            {filteredOrders.map((group, index) => {
                const firstItem = group[0];
                const orderTotal = group.reduce((sum, item) => sum + (item.price * item.quantity), 0);

                return (
                    <div key={firstItem.orderId || index} className="bg-gray-800 rounded-2xl border border-gray-700 overflow-hidden animate-fade-up">
                        {/* Order Header */}
                        <div className="bg-gray-900/50 p-4 flex flex-wrap items-center justify-between border-b border-gray-700">
                            <div className="flex items-center gap-4">
                                <div className="bg-[#FA8072]/10 text-[#FA8072] px-3 py-1 rounded-lg font-bold border border-[#FA8072]/20 flex items-center gap-2">
                                    <User size={16} />
                                    <span>زبون رقم {firstItem.customerNumber || '?'}</span>
                                </div>
                                <span className="text-gray-400 text-sm font-mono">{firstItem.time}</span>
                            </div>

                            <div className="flex items-center gap-4 mt-2 md:mt-0">
                                <div className="text-white font-bold">
                                    <span className="text-gray-400 text-sm font-normal ml-2">إجمالي الفاتورة:</span>
                                    {orderTotal.toLocaleString()} ل.س
                                </div>
                                {onDeleteOrder && (
                                    <button 
                                        onClick={() => onDeleteOrder(firstItem.orderId)}
                                        className="text-red-400 hover:bg-red-400/10 p-2 rounded-lg transition-colors no-print"
                                        title="حذف الطلب بالكامل"
                                    >
                                        <Trash2 size={18} />
                                    </button>
                                )}
                            </div>
                        </div>

                        {/* Order Items Table */}
                        <div className="overflow-x-auto">
                            <table className="w-full text-right">
                                <thead className="bg-gray-700/20 text-xs text-gray-400">
                                    <tr>
                                        <th className="py-2 px-4">المادة</th>
                                        <th className="py-2 px-4 text-center">الكمية</th>
                                        <th className="py-2 px-4">سعر البيع</th>
                                        <th className="py-2 px-4">الإجمالي</th>
                                        <th className="py-2 px-4 w-10"></th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-gray-700/50 text-sm">
                                    {group.map(item => (
                                        <tr key={item.id} className="hover:bg-gray-700/20 transition-colors">
                                            <td className="py-2 px-4 font-medium text-gray-200">
                                                {item.name}
                                            </td>
                                            <td className="py-2 px-4 text-center">
                                                <span className="bg-gray-700 text-gray-300 px-2 py-0.5 rounded text-xs">
                                                    {item.quantity} {item.unitType === 'kg' ? 'كغ' : 'قطعة'}
                                                </span>
                                            </td>
                                            <td className="py-2 px-4 text-gray-400">{item.price.toLocaleString()}</td>
