                                                {(item.price * item.quantity).toLocaleString()}
                                            </td>
                                            <td className="py-2 px-4 text-left">
                                                <button
                                                    onClick={() => onDeleteItem(item.id)}
                                                    className="text-gray-600 hover:text-red-400 transition-colors"
                                                    title="حذف مادة"
                                                >
                                                    <Trash2 size={14} />
                                                </button>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                );
            })}
        </div>
    </div>
  );
};

import React, { useEffect } from 'react';
