    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Trash2, ShoppingBag, Search, User, ChevronDown, ChevronUp } from 'lucide-react';
import { SaleItem } from '../types';

interface SalesTableProps {
  items: SaleItem[];
  onDeleteItem: (id: string) => void;
  onDeleteOrder?: (orderId: string) => void;
}

export const SalesTable: React.FC<SalesTableProps> = ({ items, onDeleteItem, onDeleteOrder }) => {
  const [filterCustomer, setFilterCustomer] = useState<string>('');

  // Group items by orderId/customerNumber
  const groupedOrders = useMemo(() => {
    const groups: { [key: string]: SaleItem[] } = {};
    items.forEach(item => {
        // Fallback for old data without orderId
        const key = item.orderId || `legacy-${item.time}`;
        if (!groups[key]) {
            groups[key] = [];
        }
        groups[key].push(item);
    });

    // Convert to array and sort by time (newest first)
    return Object.values(groups).sort((a, b) => {
        // Try to sort by customer number descending
        const custA = a[0]?.customerNumber || 0;
        const custB = b[0]?.customerNumber || 0;
        return custB - custA;
    });
  }, [items]);

  // Filter logic
  const filteredOrders = useMemo(() => {
      if (!filterCustomer) return groupedOrders;
      return groupedOrders.filter(group => 
          group[0].customerNumber.toString() === filterCustomer
      );
  }, [groupedOrders, filterCustomer]);

  if (items.length === 0) {
    return (
      <div className="bg-gray-800 p-8 rounded-2xl shadow-sm border border-gray-700 text-center flex flex-col items-center justify-center min-h-[200px] print:hidden">
        <div className="bg-gray-700 p-4 rounded-full mb-3">
            <ShoppingBag className="text-gray-400 w-8 h-8" />
        </div>
        <p className="text-gray-400 font-medium">لا توجد مبيعات مسجلة اليوم حتى الآن.</p>
      </div>
    );
  }

  return (
    <div className="space-y-4">
        {/* Filter Bar */}
        <div className="bg-gray-800 p-4 rounded-xl border border-gray-700 flex items-center gap-4 no-print">
            <div className="flex items-center gap-2 text-gray-400">
                <Search size={20} />
                <span className="text-sm font-bold">فلترة حسب:</span>
            </div>
            <select 
                value={filterCustomer}
                onChange={(e) => setFilterCustomer(e.target.value)}
                className="bg-gray-900 text-white border border-gray-600 rounded-lg px-4 py-2 outline-none focus:ring-1 focus:ring-[#FA8072] flex-grow md:flex-grow-0 md:w-64"
            >
                <option value="">جميع الزبائن</option>
                {groupedOrders.map(group => (
                    <option key={group[0].orderId} value={group[0].customerNumber}>
                        الزبون رقم {group[0].customerNumber || 'غير محدد'}
                    </option>
                ))}
            </select>

            {filterCustomer && (
                <button 
                    onClick={() => setFilterCustomer('')}
                    className="text-sm text-[#FA8072] hover:underline"
                >
                    إلغاء الفلترة
                </button>
            )}
        </div>

        {/* Orders List */}
        <div className="space-y-4">
            {filteredOrders.map((group, index) => {
                const firstItem = group[0];
                const orderTotal = group.reduce((sum, item) => sum + (item.price * item.quantity), 0);

                return (
                    <div key={firstItem.orderId || index} className="bg-gray-800 rounded-2xl border border-gray-700 overflow-hidden animate-fade-up">
                        {/* Order Header */}
                        <div className="bg-gray-900/50 p-4 flex flex-wrap items-center justify-between border-b border-gray-700">
                            <div className="flex items-center gap-4">
                                <div className="bg-[#FA8072]/10 text-[#FA8072] px-3 py-1 rounded-lg font-bold border border-[#FA8072]/20 flex items-center gap-2">
                                    <User size={16} />
                                    <span>زبون رقم {firstItem.customerNumber || '?'}</span>
                                </div>
                                <span className="text-gray-400 text-sm font-mono">{firstItem.time}</span>
                            </div>

                            <div className="flex items-center gap-4 mt-2 md:mt-0">
                                <div className="text-white font-bold">
                                    <span className="text-gray-400 text-sm font-normal ml-2">إجمالي الفاتورة:</span>
                                    {orderTotal.toLocaleString()} ل.س
                                </div>
                                {onDeleteOrder && (
                                    <button 
                                        type="button"
                                        onClick={(e) => {
                                            e.stopPropagation();
                                            onDeleteOrder(firstItem.orderId);
                                        }}
                                        className="text-red-400 hover:bg-red-400/10 p-2 rounded-lg transition-colors no-print"
                                        title="حذف الطلب بالكامل"
                                    >
                                        <Trash2 size={18} />
                                    </button>
                                )}
                            </div>
                        </div>

                        {/* Order Items Table */}
                        <div className="overflow-x-auto">
                            <table className="w-full text-right">
                                <thead className="bg-gray-700/20 text-xs text-gray-400">
                                    <tr>
                                        <th className="py-2 px-4">المادة</th>
                                        <th className="py-2 px-4 text-center">الكمية</th>
                                        <th className="py-2 px-4">سعر البيع</th>
                                        <th className="py-2 px-4">الإجمالي</th>
                                        <th className="py-2 px-4 w-10"></th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-gray-700/50 text-sm">
                                    {group.map(item => (
                                        <tr key={item.id} className="hover:bg-gray-700/20 transition-colors">
                                            <td className="py-2 px-4 font-medium text-gray-200">
                                                {item.name}
                                            </td>
                                            <td className="py-2 px-4 text-center">
                                                <span className="bg-gray-700 text-gray-300 px-2 py-0.5 rounded text-xs">
                                                    {item.quantity} {item.unitType === 'kg' ? 'كغ' : 'قطعة'}
                                                </span>
                                            </td>
                                            <td className="py-2 px-4 text-gray-400">{item.price.toLocaleString()}</td>
                                            <td className="py-2 px-4 text-[#FA8072] font-medium">
                                                {(item.price * item.quantity).toLocaleString()}
                                            </td>
                                            <td className="py-2 px-4 text-left">
                                                <button
                                                    type="button"
                                                    onClick={(e) => {
                                                        e.stopPropagation();
                                                        onDeleteItem(item.id);
                                                    }}
                                                    className="text-gray-600 hover:text-red-400 transition-colors cursor-pointer"
                                                    title="حذف مادة"
                                                >
                                                    <Trash2 size={14} />
                                                </button>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                );
            })}
        </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { POSInterface } from './components/RecipeGenerator';
import { SalesTable } from './components/Menu';
import { Summary } from './components/InfoBox';
import { InvoiceModal } from './components/InvoiceModal';
import { ProductManager } from './components/ProductManager';
import { HistoryModal } from './components/HistoryModal';
import { SaleItem, Product, ArchivedDay } from './types';
import { Save } from 'lucide-react';

// Default initial products - Expanded list with Units
const DEFAULT_PRODUCTS: Product[] = [
    { id: '1', name: 'كوكيز كلاسيك (شوكولا)', price: 5000, unitType: 'piece' },
    { id: '2', name: 'كوكيز فانيلا', price: 4500, unitType: 'piece' },
    { id: '3', name: 'كوكيز دبل شوكليت', price: 5500, unitType: 'piece' },
    { id: '4', name: 'كوكيز فستق حلبي', price: 8000, unitType: 'piece' },
    { id: '5', name: 'كوكيز لوتس', price: 6000, unitType: 'piece' },
    { id: '6', name: 'براونيز (بالكيلو)', price: 70000, unitType: 'kg' },
    { id: '7', name: 'بيتيفور مشكل (بالكيلو)', price: 45000, unitType: 'kg' },
    { id: '8', name: 'ميني كوكيز (قطعة)', price: 2000, unitType: 'piece' },
];

const App: React.FC = () => {
  // Sales State (Current Day)
  const [sales, setSales] = useState<SaleItem[]>(() => {
    const saved = localStorage.getItem('dailySales');
    return saved ? JSON.parse(saved) : [];
  });

  // History State (Archived Days)
  const [history, setHistory] = useState<ArchivedDay[]>(() => {
    const saved = localStorage.getItem('salesHistory');
    return saved ? JSON.parse(saved) : [];
  });

  // Products State
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('products');
    return saved ? JSON.parse(saved) : DEFAULT_PRODUCTS;
  });

  const [showInvoice, setShowInvoice] = useState(false);
  const [showProductManager, setShowProductManager] = useState(false);
  const [showHistory, setShowHistory] = useState(false);

  // Persistence
  useEffect(() => {
    localStorage.setItem('dailySales', JSON.stringify(sales));
  }, [sales]);

  useEffect(() => {
    localStorage.setItem('salesHistory', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    localStorage.setItem('products', JSON.stringify(products));
  }, [products]);

  // Logic to calculate next customer number based on existing sales
  const getNextCustomerNumber = () => {
      if (sales.length === 0) return 1;
      const maxNum = Math.max(...sales.map(s => s.customerNumber || 0));
      return maxNum + 1;
  };

  // Handler for adding a complete order (Multiple items)
  const handleCompleteOrder = (newItems: Omit<SaleItem, 'id' | 'time' | 'customerNumber' | 'orderId'>[]) => {
    const currentTime = new Date().toLocaleTimeString('ar-SY', { hour: '2-digit', minute: '2-digit' });
    const orderId = Date.now().toString(); // Common ID for the whole order
    const customerNumber = getNextCustomerNumber(); // Incrementing customer number

    const itemsWithIds: SaleItem[] = newItems.map(item => ({
        ...item,
        id: Math.random().toString(36).substr(2, 9), // Unique ID for the item row
        orderId: orderId,
        customerNumber: customerNumber,
        time: currentTime
    }));

    setSales(prev => [...prev, ...itemsWithIds]);
  };

  const handleDeleteItem = (id: string) => {
    if (confirm('هل أنت متأكد من حذف هذا العنصر؟')) {
      // Convert both to string to ensure type safety
      setSales(prev => prev.filter(item => String(item.id) !== String(id)));
    }
  };

  // Delete entire order by customer number or order ID
  const handleDeleteOrder = (orderId: string) => {
      if(confirm('هل أنت متأكد من حذف طلب الزبون بالكامل؟')) {
          setSales(prev => prev.filter(item => String(item.orderId) !== String(orderId)));
      }
  };

  // SAFE CLOSE DAY (Archive then Clear)
  const handleEndDay = () => {
    if (sales.length === 0) {
        alert('لا توجد مبيعات لترحيلها.');
        return;
    }

    if (confirm('سيتم إغلاق اليوم الحالي وترحيل جميع المبيعات إلى الأرشيف. هل أنت متأكد؟')) {
        const totalRevenue = sales.reduce((sum, item) => sum + (item.price * item.quantity), 0);
        const totalItems = sales.reduce((sum, item) => sum + item.quantity, 0);

        const daySummary: ArchivedDay = {
            id: Date.now().toString(),
            date: new Date().toLocaleDateString('ar-SY'),
            timestamp: Date.now(),
            totalRevenue,
            totalItems,
            items: [...sales] // Keep a copy of items
        };

        setHistory(prev => [daySummary, ...prev]);
        setSales([]); // Safe to clear now
        alert('تم إغلاق اليوم وحفظ البيانات في الأرشيف بنجاح.');
    }
  };

  const handleAddProduct = (newProduct: Omit<Product, 'id'>) => {
    const product: Product = {
        ...newProduct,
        id: Date.now().toString()
    };
    setProducts(prev => [...prev, product]);
  };

  const handleDeleteProduct = (id: string) => {
    if (confirm('هل أنت متأكد من حذف هذه المادة من القائمة؟')) {
        // Convert both to string to ensure type safety
        setProducts(prev => prev.filter(p => String(p.id) !== String(id)));
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-gray-900 print:bg-white">
      <Header onOpenHistory={() => setShowHistory(true)} />

      <main className="flex-grow container mx-auto px-4 py-6 max-w-5xl">

        {/* Header for Print View Only */}
        <div className="hidden print:block text-center mb-8 border-b-2 border-black pb-4">
            <h1 className="text-3xl font-bold mb-2 text-black">تقرير المبيعات اليومي</h1>
            <p className="text-gray-600">التاريخ: {new Date().toLocaleDateString('ar-SY')}</p>
            <p className="text-gray-600">مخبز كوكيز</p>
        </div>

        {/* Top Summary Section */}
        <Summary items={sales} onPreview={() => setShowInvoice(true)} />

        {/* POS Interface (Input Form) */}
        <div className="mb-8">
            <POSInterface 
                onCompleteOrder={handleCompleteOrder} 
                products={products}
                onOpenProductManager={() => setShowProductManager(true)}
            />
        </div>

        {/* Daily Sales List */}
        <div className="mb-20 print:mb-0 border-t border-gray-700 pt-8">
            <div className="flex items-center justify-between mb-4 no-print">
                <h3 className="text-xl font-bold text-white">سجل الزبائن والمبيعات (اليوم الحالي)</h3>
                {sales.length > 0 && (
                    <button 
                        onClick={handleEndDay}
                        className="flex items-center gap-2 bg-green-900/40 hover:bg-green-900/60 text-green-400 px-4 py-2 rounded-xl transition-colors border border-green-800"
                    >
                        <Save size={18} />
                        <span className="font-bold">إغلاق اليوم (أرشفة وحفظ)</span>
                    </button>
                )}
            </div>

            <SalesTable 
                items={sales} 
                onDeleteItem={handleDeleteItem} 
                onDeleteOrder={handleDeleteOrder}
            />
        </div>
      </main>

      {/* Modals */}
      {showInvoice && (
        <InvoiceModal items={sales} onClose={() => setShowInvoice(false)} />
      )}

      {showHistory && (
        <HistoryModal 
            history={history} 
            onClose={() => setShowHistory(false)} 
            onClearHistory={() => setHistory([])}
        />
      )}

      <ProductManager 
         isOpen={showProductManager}
         onClose={() => setShowProductManager(false)}
         products={products}
         onAddProduct={handleAddProduct}
         onDeleteProduct={handleDeleteProduct}
      />

      <footer className="text-center py-6 text-gray-500 text-sm no-print mt-auto">
        <p>نظام محاسبة مخبز كوكيز - نسخة الويب</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Plus, Trash2, Settings, X, Scale, Box } from 'lucide-react';
import { Product, UnitType } from '../types';

interface ProductManagerProps {
  products: Product[];
  onAddProduct: (product: Omit<Product, 'id'>) => void;
  onDeleteProduct: (id: string) => void;
  isOpen: boolean;
  onClose: () => void;
}

