      text += `- ${item.name}: ${item.quantity} ${unit} × ${item.price} = ${(item.price * item.quantity).toLocaleString()}\n`;
    });

    text += `------------------\n`;
    text += `*الإجمالي النهائي: ${totalRevenue.toLocaleString()} ل.س*\n`;

    navigator.clipboard.writeText(text).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  const handlePrint = () => {
    window.print();
    setConfirmPrint(false);
  };

  const handleDownloadImage = async () => {
    const element = document.getElementById('invoice-content');
    if (!element) return;

    setIsGeneratingImg(true);

    try {
        // We capture exactly what is shown (Dark Mode Receipt) because it looks better on screen and is easier to share digitally
        const canvas = await html2canvas(element, {
            scale: 2, // Higher quality
            backgroundColor: '#1f2937', // Match the gray-800 background
            logging: false,
            useCORS: true
        });

        const image = canvas.toDataURL("image/png");
        const link = document.createElement('a');
        link.href = image;
        link.download = `فاتورة-كوكيز-${Date.now()}.png`;
        link.click();
    } catch (error) {
        console.error("Image generation failed", error);
        alert("عذراً، حدث خطأ أثناء إنشاء الصورة. يرجى المحاولة مرة أخرى.");
    } finally {
        setIsGeneratingImg(false);
    }
