          <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full transition-colors">
            <X size={20} className="text-gray-400" />
          </button>
        </div>

        {/* Content - Scrollable */}
        <div className="p-6 overflow-y-auto flex-1 font-mono text-sm leading-relaxed text-gray-300" id="invoice-content">
          <div className="text-center mb-6 border-b-2 border-gray-600 print:border-black pb-4">
            <h2 className="text-2xl font-bold mb-1 text-white print:text-black">مخبز كوكيز</h2>
            <p className="text-gray-400 font-bold print:text-gray-600">تقرير مبيعات يومي</p>
            <p className="text-gray-500 print:text-gray-600">{dateStr}</p>
          </div>

          <table className="w-full mb-4 text-right">
             <thead>
                 <tr className="border-b border-gray-600 print:border-black">
                     <th className="py-1 text-gray-300 print:text-black">المادة</th>
                     <th className="py-1 text-gray-300 print:text-black">الكمية</th>
                     <th className="py-1 text-gray-300 print:text-black">السعر</th>
                     <th className="py-1 text-gray-300 print:text-black">الإجمالي</th>
                 </tr>
             </thead>
             <tbody className="divide-y divide-gray-700 print:divide-gray-200">
                {items.map((item) => (
                  <tr key={item.id}>
                    <td className="py-2 text-gray-300 print:text-black">{item.name}</td>
                    <td className="py-2 text-gray-300 print:text-black">
                        {item.quantity} {item.unitType === 'kg' ? 'كغ' : ''}
                    </td>
                    <td className="py-2 text-gray-300 print:text-black">{item.price.toLocaleString()}</td>
                    <td className="py-2 font-bold text-white print:text-black">{(item.price * item.quantity).toLocaleString()}</td>
