const CACHE_NAME = 'cookies-bakery-v1';
const STATIC_URLS = [
  './',
  './index.html',
  './logo.png',
  './manifest.json'
];

// 1. Install Service Worker & Cache Static Assets
self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      // We try to cache core files. If one fails, it's okay, the dynamic fetch will catch them later.
      return cache.addAll(STATIC_URLS);
    })
  );
  self.skipWaiting();
});

// 2. Activate & Clean up old caches
self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((cacheNames) => {
      return Promise.all(
        cacheNames.map((cache) => {
          if (cache !== CACHE_NAME) {
            return caches.delete(cache);
          }
        })
      );
    })
  );
  self.clients.claim();
});

// 3. Fetch Strategy: Stale-While-Revalidate / Cache-First hybrid
// This ensures the app loads from cache instantly if offline.
self.addEventListener('fetch', (event) => {
  // Only handle GET requests
  if (event.request.method !== 'GET') return;

  event.respondWith(
    caches.match(event.request).then((cachedResponse) => {
      // Return cached response if found
      if (cachedResponse) {
        // Optional: Update cache in background for next time (Stale-While-Revalidate logic)
        // For strictly offline-first, returning the cache is enough.
        // But let's try to fetch new version in background if internet exists
        fetch(event.request).then(networkResponse => {
            if(networkResponse && networkResponse.status === 200) {
                 caches.open(CACHE_NAME).then(cache => {
                    cache.put(event.request, networkResponse.clone());
                 });
            }
        }).catch(() => {}); // Ignore errors in background fetch

        return cachedResponse;
      }

      // If not in cache, fetch from network
      return fetch(event.request).then((networkResponse) => {
        // Check if we received a valid response
        if (!networkResponse || networkResponse.status !== 200 || networkResponse.type !== 'basic' && networkResponse.type !== 'cors') {
          return networkResponse;
        }

        // Clone the response because it's a stream and can only be consumed once
        const responseToCache = networkResponse.clone();

        caches.open(CACHE_NAME).then((cache) => {
          cache.put(event.request, responseToCache);
        });

        return networkResponse;
      }).catch(() => {
        // Fallback for navigation requests (HTML)
        if (event.request.mode === 'navigate') {
          return caches.match('./index.html');
        }
      });
    })
  );
});

