    link.href = url;
    link.download = `cookies-bakery-backup-${dateStr}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleImportData = (file: File) => {
      const reader = new FileReader();
      reader.onload = (e) => {
          try {
              const content = e.target?.result as string;
              const data = JSON.parse(content);

              // Basic validation check
              if (!data || typeof data !== 'object') {
                  throw new Error('Invalid file format');
              }

              // Direct localStorage update to ensure data integrity during restore
              // Then reload page to reflect changes

              if (Array.isArray(data.sales)) {
                  localStorage.setItem('dailySales', JSON.stringify(data.sales));
              }
              if (Array.isArray(data.history)) {
                  localStorage.setItem('salesHistory', JSON.stringify(data.history));
              }
              if (Array.isArray(data.products)) {
                  localStorage.setItem('products', JSON.stringify(data.products));
              }

              alert('تم استعادة البيانات بنجاح! سيتم إعادة تحميل الصفحة الآن.');
              window.location.reload();

          } catch (error) {
              console.error('Import Error:', error);
              alert('حدث خطأ أثناء قراءة الملف. يرجى التأكد من أن الملف صالح.');
          }
      };
      reader.readAsText(file);
  };

  // RENDER LOGIN SCREEN IF NOT AUTHENTICATED
  if (!isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen flex flex-col bg-gray-900 print:bg-white">
