import React, { useState, useMemo } from 'react';
import { Trash2, ShoppingBag, Search, User, Download, Store } from 'lucide-react';
import { SaleItem } from '../types';

interface SalesTableProps {
  items: SaleItem[];
  onDeleteItem: (id: string) => void;
  onDeleteOrder?: (orderId: string) => void;
  onPreviewInvoice: (items: SaleItem[]) => void;
}

export const SalesTable: React.FC<SalesTableProps> = ({ items, onDeleteItem, onDeleteOrder, onPreviewInvoice }) => {
  const [searchTerm, setSearchTerm] = useState<string>('');

  // State for inline deletion confirmation
  const [confirmItemId, setConfirmItemId] = useState<string | null>(null);
  const [confirmOrderId, setConfirmOrderId] = useState<string | null>(null);

  // Group items by orderId
  const groupedOrders = useMemo(() => {
    const groups: { [key: string]: SaleItem[] } = {};
    items.forEach(item => {
        const key = item.orderId || `legacy-${item.time}`;
        if (!groups[key]) {
            groups[key] = [];
        }
        groups[key].push(item);
    });

    // Convert to array and sort by time (newest first)
    return Object.values(groups).sort((a, b) => {
        const timeA = a[0]?.id ? 1 : 0; // Simple check, ideally parse timestamp
        return 0; // Keeping original sort order (newest usually appended, so we might want to reverse in UI)
    }).reverse();
  }, [items]);

  // Filter logic for Search
  const filteredOrders = useMemo(() => {
      if (!searchTerm) return groupedOrders;
      const lowerTerm = searchTerm.toLowerCase();
      return groupedOrders.filter(group => {
          const first = group[0];
          const name = first.customerName?.toLowerCase() || '';
          const number = first.customerNumber.toString();
          return name.includes(lowerTerm) || number.includes(lowerTerm);
      });
  }, [groupedOrders, searchTerm]);

  if (items.length === 0) {
    return (
      <div className="bg-gray-800 p-8 rounded-2xl shadow-sm border border-gray-700 text-center flex flex-col items-center justify-center min-h-[200px] print:hidden">
        <div className="bg-gray-700 p-4 rounded-full mb-3">
            <ShoppingBag className="text-gray-400 w-8 h-8" />
        </div>
        <p className="text-gray-400 font-medium">لا توجد مبيعات مسجلة اليوم حتى الآن.</p>
      </div>
    );
  }

  return (
    <div className="space-y-4">
        {/* Search Bar */}
        <div className="bg-gray-800 p-4 rounded-xl border border-gray-700 flex flex-col md:flex-row items-center gap-4 no-print">
            <div className="relative w-full md:w-96">
                <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                <input 
                    type="text"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    placeholder="بحث عن فاتورة (اسم الزبون أو رقمه)..."
                    className="w-full bg-gray-900 border border-gray-600 text-white rounded-xl pr-10 pl-4 py-2 outline-none focus:border-[#FA8072]"
                />
            </div>

            <div className="text-gray-400 text-xs">
                عدد الفواتير المعروضة: {filteredOrders.length}
            </div>
        </div>

        {/* Orders List */}
        <div className="space-y-4">
            {filteredOrders.map((group, index) => {
                const firstItem = group[0];
                const orderTotal = group.reduce((sum, item) => sum + (item.price * item.quantity), 0);
                const orderId = firstItem.orderId;
                const displayName = firstItem.customerName ? `${firstItem.customerName}` : `زبون رقم ${firstItem.customerNumber || '?'}`;
                const isWholesale = firstItem.saleType === 'wholesale';

                return (
                    <div key={orderId || index} className="bg-gray-800 rounded-2xl border border-gray-700 overflow-hidden animate-fade-up">
                        {/* Order Header */}
                        <div className="bg-gray-900/50 p-4 flex flex-wrap items-center justify-between border-b border-gray-700">
                            <div className="flex items-center gap-4">
                                <div className={`px-3 py-1 rounded-lg font-bold border flex items-center gap-2 ${isWholesale ? 'bg-orange-900/20 text-orange-400 border-orange-500/20' : 'bg-blue-900/20 text-blue-400 border-blue-500/20'}`}>
                                    {isWholesale ? <Store size={16} /> : <User size={16} />}
                                    <span>
                                        {displayName}
                                        {/* If name exists, show number in small text */}
                                        {firstItem.customerName && <span className="text-xs opacity-70 mr-2">#{firstItem.customerNumber}</span>}
                                    </span>
                                </div>
                                <span className="text-gray-400 text-sm font-mono">{firstItem.time}</span>
                            </div>

                            <div className="flex items-center gap-4 mt-2 md:mt-0">
                                <div className="text-white font-bold">
                                    <span className="text-gray-400 text-sm font-normal ml-2">الإجمالي:</span>
                                    {orderTotal.toLocaleString()} ل.س
                                </div>

                                {/* Download Invoice Button */}
                                <button 
                                    onClick={() => onPreviewInvoice(group)}
                                    className="flex items-center gap-1 bg-green-600 hover:bg-green-500 text-white px-3 py-1.5 rounded-lg text-xs font-bold transition-colors no-print ml-2"
                                    title="تحميل الفاتورة PDF"
                                >
                                    <Download size={14} />
                                    تحميل PDF
                                </button>

                                {onDeleteOrder && (
                                    confirmOrderId === orderId ? (
                                        <div className="flex items-center gap-2 no-print">
                                            <span className="text-xs text-red-300 hidden md:inline">حذف؟</span>
                                            <button 
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    onDeleteOrder(orderId);
                                                    setConfirmOrderId(null);
                                                }}
                                                className="bg-red-500 text-white px-2 py-1 rounded text-xs hover:bg-red-600"
                                            >
                                                نعم
                                            </button>
                                            <button 
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    setConfirmOrderId(null);
                                                }}
                                                className="bg-gray-600 text-white px-2 py-1 rounded text-xs hover:bg-gray-500"
                                            >
                                                إلغاء
                                            </button>
                                        </div>
                                    ) : (
                                        <button 
                                            type="button"
                                            onClick={(e) => {
                                                e.stopPropagation();
                                                setConfirmOrderId(orderId);
                                            }}
                                            className="text-red-400 hover:bg-red-400/10 p-2 rounded-lg transition-colors no-print"
                                            title="حذف الطلب بالكامل"
                                        >
                                            <Trash2 size={18} />
                                        </button>
                                    )
                                )}
                            </div>
                        </div>

                        {/* Order Items Table */}
                        <div className="overflow-x-auto">
                            <table className="w-full text-right">
                                <thead className="bg-gray-700/20 text-xs text-gray-400">
                                    <tr>
                                        <th className="py-2 px-4">المادة</th>
                                        <th className="py-2 px-4 text-center">الكمية</th>
                                        <th className="py-2 px-4">السعر</th>
                                        <th className="py-2 px-4">الإجمالي</th>
                                        <th className="py-2 px-4 w-10"></th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-gray-700/50 text-sm">
                                    {group.map(item => (
                                        <tr key={item.id} className="hover:bg-gray-700/20 transition-colors">
                                            <td className="py-2 px-4 font-medium text-gray-200">
                                                {item.name}
                                            </td>
                                            <td className="py-2 px-4 text-center">
                                                <span className="bg-gray-700 text-gray-300 px-2 py-0.5 rounded text-xs">
                                                    {item.quantity} {item.unitType === 'kg' ? 'كغ' : 'قطعة'}
                                                </span>
                                            </td>
                                            <td className="py-2 px-4 text-gray-400">{item.price.toLocaleString()}</td>
                                            <td className="py-2 px-4 text-[#FA8072] font-medium">
                                                {(item.price * item.quantity).toLocaleString()}
                                            </td>
                                            <td className="py-2 px-4 text-left">
                                                {confirmItemId === item.id ? (
                                                    <div className="flex items-center gap-1">
                                                        <button
                                                            onClick={() => {
                                                                onDeleteItem(item.id);
                                                                setConfirmItemId(null);
                                                            }}
                                                            className="text-red-500 text-xs font-bold hover:underline"
                                                        >
                                                            تأكيد
                                                        </button>
                                                        <span className="text-gray-600">/</span>
                                                        <button
                                                            onClick={() => setConfirmItemId(null)}
                                                            className="text-gray-400 text-xs hover:text-white"
                                                        >
                                                            إلغاء
                                                        </button>
                                                    </div>
                                                ) : (
                                                    <button
                                                        type="button"
                                                        onClick={(e) => {
                                                            e.stopPropagation();
                                                            setConfirmItemId(item.id);
                                                        }}
                                                        className="text-gray-600 hover:text-red-400 transition-colors cursor-pointer"
                                                        title="حذف مادة"
                                                    >
                                                        <Trash2 size={14} />
                                                    </button>
                                                )}
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                );
            })}
        </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { X, Calendar, ChevronDown, ChevronUp, Download, Store, User, Search } from 'lucide-react';
import { ArchivedDay, SaleItem } from '../types';

interface HistoryModalProps {
  history: ArchivedDay[];
  onClose: () => void;
  onClearHistory: () => void;
  onPreviewInvoice: (items: SaleItem[]) => void;
}

export const HistoryModal: React.FC<HistoryModalProps> = ({ history, onClose, onClearHistory, onPreviewInvoice }) => {
  const [selectedYear, setSelectedYear] = useState<string>('all');
  const [selectedMonth, setSelectedMonth] = useState<string>('all');
  const [expandedDayId, setExpandedDayId] = useState<string | null>(null);

  // Helper to get years present in history
  const years = useMemo(() => {
    const uniqueYears = new Set<string>(history.map(day => new Date(day.timestamp).getFullYear().toString()));
    return Array.from(uniqueYears).sort((a: string, b: string) => b.localeCompare(a));
  }, [history]);

  // Helper to get months present in history (for selected year)
  const months = useMemo(() => {
    const uniqueMonths = new Set<number>(
      history
        .filter(day => selectedYear === 'all' || new Date(day.timestamp).getFullYear().toString() === selectedYear)
        .map(day => new Date(day.timestamp).getMonth())
    );
    return Array.from(uniqueMonths).sort((a: number, b: number) => b - a);
  }, [history, selectedYear]);

  // Filtered History
  const filteredHistory = useMemo(() => {
    return history.filter(day => {
      const date = new Date(day.timestamp);
      const yearMatch = selectedYear === 'all' || date.getFullYear().toString() === selectedYear;
      const monthMatch = selectedMonth === 'all' || date.getMonth().toString() === selectedMonth;
      return yearMatch && monthMatch;
    });
  }, [history, selectedYear, selectedMonth]);

  const getMonthName = (monthIndex: number) => {
    const date = new Date();
    date.setMonth(monthIndex);
    return date.toLocaleString('ar-SY', { month: 'long' });
  };

  const toggleDayDetails = (id: string) => {
    setExpandedDayId(prev => prev === id ? null : id);
  };

  // Helper to group items in a day by OrderID (Invoice)
  const getDayInvoices = (items: SaleItem[]) => {
      const groups: { [key: string]: SaleItem[] } = {};
      items.forEach(item => {
          const key = item.orderId || `legacy-${item.time}`;
          if (!groups[key]) groups[key] = [];
          groups[key].push(item);
      });
      return Object.values(groups).reverse(); // Show newest first within the day
  };

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-2xl w-full max-w-4xl shadow-2xl border border-gray-700 animate-fade-up flex flex-col max-h-[90vh]">

        {/* Header */}
        <div className="p-4 border-b border-gray-700 flex justify-between items-center bg-gray-900/50 rounded-t-2xl">
          <div className="flex items-center gap-2 text-white">
            <div className="bg-[#FA8072]/20 p-2 rounded-lg text-[#FA8072]">
                <Calendar size={22} />
            </div>
            <div>
                <h3 className="font-bold text-lg">سجل المبيعات (الأرشيف)</h3>
                <p className="text-xs text-gray-400">تصفح الفواتير السابقة حسب التاريخ</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full transition-colors">
            <X size={20} className="text-gray-400" />
          </button>
        </div>

        {/* Filters */}
        <div className="p-4 border-b border-gray-700 bg-gray-800/50 grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="relative">
                <select 
                    value={selectedYear}
                    onChange={(e) => { setSelectedYear(e.target.value); setSelectedMonth('all'); }}
                    className="w-full bg-gray-900 text-white text-sm border border-gray-600 rounded-lg px-3 py-2 appearance-none outline-none focus:border-[#FA8072]"
                >
                    <option value="all">كل السنوات</option>
                    {years.map(y => <option key={y} value={y}>{y}</option>)}
                </select>
                <ChevronDown size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
            </div>
            <div className="relative">
                <select 
                    value={selectedMonth}
                    onChange={(e) => setSelectedMonth(e.target.value)}
                    className="w-full bg-gray-900 text-white text-sm border border-gray-600 rounded-lg px-3 py-2 appearance-none outline-none focus:border-[#FA8072]"
                    disabled={selectedYear === 'all' && months.length > 12}
                >
                    <option value="all">كل الشهور</option>
                    {months.map(m => <option key={m} value={m}>{getMonthName(m)}</option>)}
                </select>
                <ChevronDown size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
            </div>
        </div>

        {/* Content List */}
        <div className="p-4 overflow-y-auto flex-1 bg-gray-900/20">
          {filteredHistory.length === 0 ? (
            <div className="text-center py-12 text-gray-500 flex flex-col items-center">
              <Search size={32} className="opacity-50 mb-2" />
              <p className="font-medium">لا توجد سجلات.</p>
            </div>
          ) : (
            <div className="space-y-3">
              {filteredHistory.map((day) => (
                <div key={day.id} className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden transition-all">
                    {/* Day Header */}
                    <div 
                        onClick={() => toggleDayDetails(day.id)}
                        className="p-4 flex items-center justify-between cursor-pointer hover:bg-gray-700/30"
                    >
                        <div className="flex items-center gap-3">
                             <div className={`p-2 rounded-lg ${expandedDayId === day.id ? 'bg-[#FA8072] text-white' : 'bg-gray-700 text-gray-300'}`}>
                                {expandedDayId === day.id ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                             </div>
                             <div>
                                <div className="text-white font-bold text-lg">{day.date}</div>
                                <div className="text-xs text-gray-400">{day.totalItems} قطعة مباعة</div>
                             </div>
                        </div>
                        <div className="text-right">
                             <span className="block text-xs text-gray-400">إجمالي اليوم</span>
                             <span className="block font-bold text-[#FA8072] text-lg">{day.totalRevenue.toLocaleString()} ل.س</span>
                        </div>
                    </div>

                    {/* Invoices List for the Day */}
                    {expandedDayId === day.id && (
                        <div className="bg-gray-900/50 border-t border-gray-700 p-3 space-y-3 animate-fade-up">
                            {getDayInvoices(day.items).map((invoice, idx) => {
                                const first = invoice[0];
                                const total = invoice.reduce((s, i) => s + (i.price * i.quantity), 0);
                                const isWholesale = first.saleType === 'wholesale';

                                return (
                                    <div key={idx} className="bg-gray-800 border border-gray-600 rounded-lg p-3">
                                        <div className="flex justify-between items-start mb-2">
                                            <div className="flex items-center gap-2">
                                                <div className={`p-1.5 rounded-md ${isWholesale ? 'bg-orange-500/20 text-orange-400' : 'bg-blue-500/20 text-blue-400'}`}>
                                                    {isWholesale ? <Store size={14} /> : <User size={14} />}
                                                </div>
                                                <div>
                                                    <span className="block text-sm font-bold text-white">
                                                        {first.customerName || `زبون #${first.customerNumber}`}
                                                    </span>
                                                    <span className="text-xs text-gray-500 font-mono">{first.time}</span>
                                                </div>
                                            </div>
                                            <div className="flex items-center gap-3">
                                                <span className="font-bold text-[#FA8072] text-sm">{total.toLocaleString()} ل.س</span>
                                                <button 
                                                    onClick={() => onPreviewInvoice(invoice)}
                                                    className="bg-gray-700 hover:bg-white hover:text-black text-white p-1.5 rounded-lg transition-colors"
                                                    title="تحميل PDF"
                                                >
                                                    <Download size={14} />
                                                </button>
                                            </div>
                                        </div>

                                        {/* Mini Items Table */}
                                        <table className="w-full text-xs text-right text-gray-400">
                                            <tbody>
                                                {invoice.map((item, i) => (
                                                    <tr key={i} className="border-t border-gray-700/50">
                                                        <td className="py-1">{item.name}</td>
                                                        <td className="py-1 text-center">{item.quantity} {item.unitType === 'kg' ? 'كغ' : ''}</td>
                                                        <td className="py-1 text-[#FA8072]">{item.price * item.quantity}</td>
                                                    </tr>
                                                ))}
                                            </tbody>
                                        </table>
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { X, Copy, Check, Download, FileSpreadsheet } from 'lucide-react';
import { SaleItem } from '../types';
import { utils, writeFile } from 'xlsx';

interface InvoiceModalProps {
  items: SaleItem[];
  onClose: () => void;
}

export const InvoiceModal: React.FC<InvoiceModalProps> = ({ items, onClose }) => {
  const [copied, setCopied] = useState(false);
  const [confirmPrint, setConfirmPrint] = useState(false);

  const totalRevenue = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const dateStr = new Date().toLocaleDateString('ar-SY');
  const firstItem = items[0];
  const uniqueCustomers = new Set(items.map(i => i.customerNumber));
  const isSingleCustomer = uniqueCustomers.size === 1;
  // Use explicit customer name if available, otherwise fallback to generic if single customer
  const customerName = firstItem?.customerName || (isSingleCustomer ? `زبون رقم ${firstItem.customerNumber}` : 'مبيعات مجمعة');
  const isWholesale = firstItem?.saleType === 'wholesale';

  useEffect(() => {
    document.body.classList.add('print-mode');
    return () => {
      document.body.classList.remove('print-mode');
    };
  }, []);

  const getInvoiceText = () => {
    let text = `*فاتورة - مخبز كوكيز*\n`;
    text += `التاريخ: ${dateStr}\n`;
    text += `العميل: ${customerName}\n`;
    text += `------------------\n`;
    items.forEach(item => {
      text += `- ${item.name}: ${item.quantity} × ${item.price} = ${(item.price * item.quantity).toLocaleString()}\n`;
    });
    text += `------------------\n`;
    text += `*الإجمالي: ${totalRevenue.toLocaleString()} ل.س*\n`;
    return text;
  };

  const handleCopy = () => {
    const text = getInvoiceText();
    navigator.clipboard.writeText(text).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  const handleDownloadExcel = () => {
    const rows = items.map(item => ({
        "المادة": item.name,
        "العميل": item.customerName || `زبون ${item.customerNumber}`,
        "الكمية": item.quantity,
        "السعر": item.price,
        "الإجمالي": item.price * item.quantity
    }));
    rows.push({
        "المادة": "المجموع الكلي",
        "العميل": "",
        "الكمية": 0,
        "السعر": 0,
        "الإجمالي": totalRevenue
    });
    const ws = utils.json_to_sheet(rows);
    const wb = utils.book_new();
    utils.book_append_sheet(wb, ws, "الفاتورة");
    writeFile(wb, `فاتورة-${Date.now()}.xlsx`);
  };

  const handlePrint = () => {
    window.print();
    setConfirmPrint(false);
  };

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-2xl w-full max-w-md shadow-2xl flex flex-col max-h-[90vh] animate-fade-up border border-gray-700">

        {/* Header */}
        <div className="p-4 border-b border-gray-700 flex justify-between items-center bg-gray-900/50 rounded-t-2xl no-print">
          <h3 className="font-bold text-lg text-white">معاينة الفاتورة</h3>
          <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full transition-colors">
            <X size={20} className="text-gray-400" />
          </button>
        </div>

        {/* Content */}
        <div className="p-6 overflow-y-auto flex-1 font-mono text-sm leading-relaxed text-gray-300 bg-white/5" id="invoice-content">
          <div className="text-center mb-6 border-b-2 border-gray-600 print:border-black pb-4">
            <h2 className="text-2xl font-bold mb-1 text-white print:text-black">مخبز كوكيز</h2>
            <p className="text-gray-400 font-bold print:text-gray-600">فاتورة مبيعات {isWholesale ? '(جملة)' : '(مفرق)'}</p>
            <p className="text-gray-500 print:text-gray-600 dir-ltr">{dateStr}</p>
            <div className="mt-2 border border-dashed border-gray-600 print:border-black p-2 rounded">
                <p className="text-white print:text-black font-bold text-lg">{customerName}</p>
            </div>
          </div>

          <table className="w-full mb-4 text-right">
             <thead>
                 <tr className="border-b border-gray-600 print:border-black">
                     <th className="py-2 text-gray-300 print:text-black">المادة</th>
                     <th className="py-2 text-center text-gray-300 print:text-black">الكمية</th>
                     <th className="py-2 text-gray-300 print:text-black">السعر</th>
                     <th className="py-2 text-gray-300 print:text-black">الإجمالي</th>
                 </tr>
             </thead>
             <tbody className="divide-y divide-gray-700 print:divide-gray-300">
                {items.map((item) => (
                  <tr key={item.id}>
                    <td className="py-2 text-gray-300 print:text-black font-medium">{item.name}</td>
                    <td className="py-2 text-center text-gray-300 print:text-black">
                        {item.quantity} {item.unitType === 'kg' ? 'كغ' : ''}
                    </td>
                    <td className="py-2 text-gray-300 print:text-black">{item.price.toLocaleString()}</td>
                    <td className="py-2 font-bold text-white print:text-black">{(item.price * item.quantity).toLocaleString()}</td>
                  </tr>
                ))}
             </tbody>
          </table>

          <div className="border-t-2 border-gray-600 print:border-black pt-4 mt-6">
            <div className="flex justify-between items-center text-xl font-bold">
                <span className="text-white print:text-black">المجموع الكلي:</span>
                <span className="text-[#FA8072] print:text-black">{totalRevenue.toLocaleString()} ل.س</span>
            </div>
          </div>

           <div className="mt-16 hidden print:flex justify-between items-end px-8">
               <div className="text-center">
                   <p className="mb-10 font-bold text-black text-base">المستلم</p>
                   <div className="w-40 border-b-2 border-black border-dotted"></div>
               </div>
               <div className="text-center">
                   <p className="mb-10 font-bold text-black text-base">الإدارة</p>
                   <div className="w-40 border-b-2 border-black border-dotted"></div>
               </div>
          </div>
        </div>

        {/* Footer Actions */}
        <div className="p-4 border-t border-gray-700 flex flex-col gap-3 bg-gray-900/50 rounded-b-2xl no-print">
            <div className="grid grid-cols-2 gap-3">
                {confirmPrint ? (
                    <div className="col-span-1 flex items-center gap-2">
                        <button onClick={handlePrint} className="flex-1 bg-green-600 text-white py-2 rounded-xl font-bold text-sm">تأكيد</button>
                        <button onClick={() => setConfirmPrint(false)} className="flex-1 bg-gray-600 text-white py-2 rounded-xl font-bold text-sm">إلغاء</button>
                    </div>
                ) : (
                    <button 
                    onClick={() => setConfirmPrint(true)}
                    className="col-span-1 flex items-center justify-center gap-2 py-2 px-4 rounded-xl font-bold transition-all text-white shadow-md bg-[#FA8072] hover:bg-[#e67365]"
                    >
                    <Download size={18} />
                    <span>تحميل PDF</span>
                    </button>
                )}

                <button 
                    onClick={handleDownloadExcel}
                    className="col-span-1 flex items-center justify-center gap-2 py-2 px-4 rounded-xl font-bold transition-all text-white shadow-md bg-green-700 hover:bg-green-600"
                >
                    <FileSpreadsheet size={18} />
                    <span>تصدير Excel</span>
                </button>
            </div>

            <button onClick={handleCopy} className={`w-full flex items-center justify-center gap-2 py-2 px-4 rounded-xl font-bold transition-all text-white shadow-md ${copied ? 'bg-green-600' : 'bg-gray-700 hover:bg-gray-600'}`}>
                {copied ? <Check size={18} /> : <Copy size={18} />}
                <span>{copied ? 'تم النسخ' : 'نسخ نصي'}</span>
            </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
