      });
    }
  }, []);

  useEffect(() => {
    const handleBeforeInstallPrompt = (e: any) => {
      e.preventDefault();
      setInstallPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    return () => window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
  }, []);

  const handleInstallClick = async () => {
    if (!installPrompt) return;
    installPrompt.prompt();
    const { outcome } = await installPrompt.userChoice;
    console.log(`User response: ${outcome}`);
    setInstallPrompt(null);
  };

  const updateLastSync = () => setLastSyncTime(new Date());

  useEffect(() => { localStorage.setItem('dailySales', JSON.stringify(sales)); updateLastSync(); }, [sales]);
  useEffect(() => { localStorage.setItem('salesHistory', JSON.stringify(history)); updateLastSync(); }, [history]);
  useEffect(() => { localStorage.setItem('products', JSON.stringify(products)); updateLastSync(); }, [products]);
  useEffect(() => { localStorage.setItem('customers', JSON.stringify(customers)); updateLastSync(); }, [customers]);

  const handleManualSync = () => {
    setIsSyncing(true);
    setTimeout(() => {
      localStorage.setItem('dailySales', JSON.stringify(sales));
      localStorage.setItem('salesHistory', JSON.stringify(history));
      localStorage.setItem('products', JSON.stringify(products));
      localStorage.setItem('customers', JSON.stringify(customers));
      setLastSyncTime(new Date());
      setIsSyncing(false);
    }, 800);
  };

  const handleLogin = () => { setIsAuthenticated(true); sessionStorage.setItem('isAuth', 'true'); };

  const getNextCustomerNumber = () => {
      if (sales.length === 0) return 1;
      const maxNum = Math.max(...sales.map(s => s.customerNumber || 0));
      return maxNum + 1;
  };

  // Enhanced Order Completion
  const handleCompleteOrder = (
      newItems: Omit<SaleItem, 'id' | 'time' | 'customerNumber' | 'orderId'>[], 
      customerName?: string, 
      customerId?: string,
      saleType: SaleType = 'retail'
    ) => {
    const currentTime = new Date().toLocaleTimeString('ar-SY', { hour: '2-digit', minute: '2-digit' });
    const orderId = Date.now().toString(); 
    const customerNumber = getNextCustomerNumber(); 

    const itemsWithIds: SaleItem[] = newItems.map(item => ({
        ...item,
        id: Math.random().toString(36).substr(2, 9), 
        orderId,
        customerNumber,
        customerName: customerName || undefined,
        customerId,
        saleType,
        time: currentTime
    }));

    setSales(prev => [...prev, ...itemsWithIds]);
  };

  const handleDeleteItem = (id: string) => {
    const itemToDelete = sales.find(item => String(item.id) === String(id));
    if (!itemToDelete) return;
    if (undoState?.timerId) clearTimeout(undoState.timerId);
    setSales(prev => prev.filter(item => String(item.id) !== String(id)));
    const timerId = setTimeout(() => setUndoState(null), 5000);
    setUndoState({ items: [itemToDelete], timerId });
  };

  const handleDeleteOrder = (orderId: string) => {
    const itemsToDelete = sales.filter(item => String(item.orderId) === String(orderId));
    if (itemsToDelete.length === 0) return;
    if (undoState?.timerId) clearTimeout(undoState.timerId);
    setSales(prev => prev.filter(item => String(item.orderId) !== String(orderId)));
    const timerId = setTimeout(() => setUndoState(null), 5000);
    setUndoState({ items: itemsToDelete, timerId });
  };

  const handleUndo = () => {
      if (!undoState) return;
      if (undoState.timerId) clearTimeout(undoState.timerId);
      setSales(prev => [...prev, ...undoState.items]);
      setUndoState(null);
  };

  const handleEndDay = () => {
    if (sales.length === 0) { alert('لا توجد مبيعات لترحيلها.'); return; }
    if (confirm('سيتم إغلاق اليوم وتفريغ المبيعات الحالية للأرشيف. هل أنت متأكد؟')) {
        const totalRevenue = sales.reduce((sum, item) => sum + (item.price * item.quantity), 0);
        const totalItems = sales.reduce((sum, item) => sum + item.quantity, 0);
        const daySummary: ArchivedDay = {
            id: Date.now().toString(),
            date: new Date().toLocaleDateString('ar-SY'),
            timestamp: Date.now(),
            totalRevenue,
            totalItems,
            items: [...sales]
        };
        setHistory(prev => [daySummary, ...prev]);
        setSales([]);
        setUndoState(null);
        alert('تم إغلاق اليوم بنجاح.');
    }
  };

  const handleAddProduct = (newProduct: Omit<Product, 'id'>) => {
    setProducts(prev => [...prev, { ...newProduct, id: Date.now().toString() }]);
  };
  const handleDeleteProduct = (id: string) => {
    setProducts(prev => prev.filter(p => String(p.id) !== String(id)));
  };

  const handleAddCustomer = (newCustomer: Omit<Customer, 'id'>) => {
      setCustomers(prev => [...prev, { ...newCustomer, id: Date.now().toString() }]);
  };
  const handleDeleteCustomer = (id: string) => {
      setCustomers(prev => prev.filter(c => c.id !== id));
  };

  const handleExportData = () => {
    const data = { appVersion: '1.1', timestamp: Date.now(), sales, history, products, customers };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `cookies-bakery-backup-${new Date().toLocaleDateString('ar-SY').replace(/\//g, '-')}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleImportData = (file: File) => {
      const reader = new FileReader();
      reader.onload = (e) => {
          try {
              const data = JSON.parse(e.target?.result as string);
              if (!data || typeof data !== 'object') throw new Error('Invalid file');
              if (Array.isArray(data.sales)) setSales(data.sales);
              if (Array.isArray(data.history)) setHistory(data.history);
              if (Array.isArray(data.products)) setProducts(data.products);
              if (Array.isArray(data.customers)) setCustomers(data.customers);
              alert('تم استعادة البيانات بنجاح!');
          } catch (error) { alert('خطأ في قراءة الملف.'); }
      };
      reader.readAsText(file);
  };

  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  return (
    <div className="min-h-screen flex flex-col bg-gray-900 print:bg-white">
      <Header 
        onOpenHistory={() => setShowHistory(true)} 
        onOpenDataManagement={() => setShowDataModal(true)}
        isOnline={isOnline}
        lastSyncTime={lastSyncTime}
        onManualSync={handleManualSync}
        isSyncing={isSyncing}
        installPrompt={installPrompt}
        onInstall={handleInstallClick}
      />

      <main className="flex-grow container mx-auto px-4 py-6 max-w-5xl">
        <div className="hidden print:block text-center mb-8 border-b-2 border-black pb-4">
            <h1 className="text-3xl font-bold mb-2 text-black">تقرير المبيعات اليومي</h1>
            <p className="text-gray-600">التاريخ: {new Date().toLocaleDateString('ar-SY')}</p>
        </div>

        {/* Summary shows total, onPreview loads ALL sales into modal */}
        <Summary items={sales} onPreview={() => setInvoiceItems(sales)} />

        <div className="mb-8">
            <POSInterface 
                onCompleteOrder={handleCompleteOrder} 
                products={products}
                customers={customers}
                onOpenProductManager={() => setShowProductManager(true)}
                onOpenCustomerManager={() => setShowCustomerManager(true)}
            />
        </div>

        <div className="mb-20 print:mb-0 border-t border-gray-700 pt-8">
            <div className="flex items-center justify-between mb-4 no-print">
                <h3 className="text-xl font-bold text-white">سجل الزبائن والمبيعات (اليوم الحالي)</h3>
                {sales.length > 0 && (
                    <button 
                        onClick={handleEndDay}
                        className="flex items-center gap-2 bg-green-900/40 hover:bg-green-900/60 text-green-400 px-4 py-2 rounded-xl transition-colors border border-green-800"
                    >
                        <Save size={18} />
                        <span className="font-bold">إغلاق اليوم (أرشفة)</span>
                    </button>
                )}
            </div>

            <SalesTable 
                items={sales} 
                onDeleteItem={handleDeleteItem} 
                onDeleteOrder={handleDeleteOrder}
                onPreviewInvoice={(items) => setInvoiceItems(items)}
            />
        </div>
      </main>

      {undoState && (
          <div className="fixed bottom-6 left-1/2 transform -translate-x-1/2 bg-gray-800 text-white px-6 py-3 rounded-xl shadow-2xl border border-gray-700 flex items-center gap-6 z-50 animate-fade-up min-w-[300px] justify-between">
              <span className="text-sm font-medium">تم حذف {undoState.items.length > 1 ? 'الطلب' : 'العنصر'}</span>
              <div className="flex items-center gap-4">
                  <button onClick={handleUndo} className="text-[#FA8072] font-bold text-sm flex items-center gap-1 hover:text-[#ff9a8d]"><RotateCcw size={16} /> تراجع</button>
                  <button onClick={() => { if (undoState.timerId) clearTimeout(undoState.timerId); setUndoState(null); }} className="text-gray-500 hover:text-white border-r border-gray-600 pr-4 mr-1"><X size={16} /></button>
              </div>
          </div>
      )}

      {invoiceItems && (
        <Suspense fallback={<ModalLoader />}>
            <InvoiceModal items={invoiceItems} onClose={() => setInvoiceItems(null)} />
        </Suspense>
      )}

      {showHistory && (
        <Suspense fallback={<ModalLoader />}>
            <HistoryModal 
                history={history} 
                onClose={() => setShowHistory(false)} 
                onClearHistory={() => setHistory([])}
                onPreviewInvoice={(items) => setInvoiceItems(items)}
            />
        </Suspense>
      )}

      {showProductManager && (
         <Suspense fallback={<ModalLoader />}>
            <ProductManager 
                isOpen={showProductManager}
                onClose={() => setShowProductManager(false)}
                products={products}
                onAddProduct={handleAddProduct}
                onDeleteProduct={handleDeleteProduct}
            />
         </Suspense>
      )}

      {showCustomerManager && (
         <Suspense fallback={<ModalLoader />}>
            <CustomerManager 
                isOpen={showCustomerManager}
                onClose={() => setShowCustomerManager(false)}
                customers={customers}
                onAddCustomer={handleAddCustomer}
                onDeleteCustomer={handleDeleteCustomer}
            />
         </Suspense>
      )}

      {showDataModal && (
        <Suspense fallback={<ModalLoader />}>
            <DataManagementModal 
                onClose={() => setShowDataModal(false)}
                onExport={handleExportData}
                onImport={handleImportData}
            />
        </Suspense>
      )}

      <footer className="text-center py-6 text-gray-500 text-sm no-print mt-auto">
        <p>نظام محاسبة مخبز كوكيز - v1.2</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { X, Calendar, ChevronDown, ChevronUp, Download, Store, User, Search, List, Receipt, Package } from 'lucide-react';
import { ArchivedDay, SaleItem } from '../types';

interface HistoryModalProps {
  history: ArchivedDay[];
  onClose: () => void;
  onClearHistory: () => void;
  onPreviewInvoice: (items: SaleItem[]) => void;
}

type ViewMode = 'invoices' | 'items';

export const HistoryModal: React.FC<HistoryModalProps> = ({ history, onClose, onClearHistory, onPreviewInvoice }) => {
  const [selectedYear, setSelectedYear] = useState<string>('all');
  const [selectedMonth, setSelectedMonth] = useState<string>('all');
  const [viewMode, setViewMode] = useState<ViewMode>('invoices');
  const [expandedDayId, setExpandedDayId] = useState<string | null>(null);

  // Helper to get years present in history
  const years = useMemo(() => {
    const uniqueYears = new Set<string>(history.map(day => new Date(day.timestamp).getFullYear().toString()));
    return Array.from(uniqueYears).sort((a: string, b: string) => b.localeCompare(a));
  }, [history]);

  // Helper to get months present in history (for selected year)
  const months = useMemo(() => {
    const uniqueMonths = new Set<number>(
      history
        .filter(day => selectedYear === 'all' || new Date(day.timestamp).getFullYear().toString() === selectedYear)
        .map(day => new Date(day.timestamp).getMonth())
    );
    return Array.from(uniqueMonths).sort((a: number, b: number) => b - a);
  }, [history, selectedYear]);

  // Filtered History
  const filteredHistory = useMemo(() => {
    return history.filter(day => {
      const date = new Date(day.timestamp);
      const yearMatch = selectedYear === 'all' || date.getFullYear().toString() === selectedYear;
      const monthMatch = selectedMonth === 'all' || date.getMonth().toString() === selectedMonth;
      return yearMatch && monthMatch;
    });
  }, [history, selectedYear, selectedMonth]);

  // Aggregated Items Logic (For Items View)
  const aggregatedItems = useMemo(() => {
      const itemMap = new Map<string, { name: string; quantity: number; revenue: number; unitType: string }>();

      filteredHistory.forEach(day => {
          day.items.forEach(item => {
              const key = `${item.name}-${item.unitType}`;
              const existing = itemMap.get(key);
              if (existing) {
                  existing.quantity += item.quantity;
                  existing.revenue += (item.price * item.quantity);
              } else {
                  itemMap.set(key, {
                      name: item.name,
                      quantity: item.quantity,
                      revenue: item.price * item.quantity,
                      unitType: item.unitType
                  });
              }
          });
      });

      return Array.from(itemMap.values()).sort((a, b) => b.revenue - a.revenue);
  }, [filteredHistory]);

  const totalFilteredRevenue = filteredHistory.reduce((sum, day) => sum + day.totalRevenue, 0);

  const getMonthName = (monthIndex: number) => {
    const date = new Date();
    date.setMonth(monthIndex);
    return date.toLocaleString('ar-SY', { month: 'long' });
  };

  const toggleDayDetails = (id: string) => {
    setExpandedDayId(prev => prev === id ? null : id);
  };

  // Helper to group items in a day by OrderID (Invoice)
  const getDayInvoices = (items: SaleItem[]) => {
      const groups: { [key: string]: SaleItem[] } = {};
      items.forEach(item => {
          const key = item.orderId || `legacy-${item.time}`;
          if (!groups[key]) groups[key] = [];
          groups[key].push(item);
      });
      return Object.values(groups).reverse(); // Show newest first within the day
  };

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-2xl w-full max-w-4xl shadow-2xl border border-gray-700 animate-fade-up flex flex-col max-h-[90vh]">

        {/* Header */}
        <div className="p-4 border-b border-gray-700 flex flex-col md:flex-row justify-between items-center gap-4 bg-gray-900/50 rounded-t-2xl">
          <div className="flex items-center gap-2 text-white w-full md:w-auto">
            <div className="bg-[#FA8072]/20 p-2 rounded-lg text-[#FA8072]">
                <Calendar size={22} />
            </div>
            <div>
                <h3 className="font-bold text-lg">سجل المبيعات (الأرشيف)</h3>
                <p className="text-xs text-gray-400">تصفح الفواتير والمواد المباعة</p>
            </div>
          </div>

           {/* View Mode Toggle */}
           <div className="flex bg-gray-700 p-1 rounded-lg w-full md:w-auto">
              <button 
                onClick={() => setViewMode('invoices')}
                className={`flex-1 flex items-center justify-center gap-2 px-4 py-2 rounded-md text-xs font-bold transition-all ${viewMode === 'invoices' ? 'bg-white text-black shadow' : 'text-gray-400 hover:text-white'}`}
              >
                  <Receipt size={14} />
                  الفواتير
              </button>
              <button 
                onClick={() => setViewMode('items')}
                className={`flex-1 flex items-center justify-center gap-2 px-4 py-2 rounded-md text-xs font-bold transition-all ${viewMode === 'items' ? 'bg-[#FA8072] text-white shadow' : 'text-gray-400 hover:text-white'}`}
              >
                  <Package size={14} />
                  تجميع المواد
              </button>
          </div>

          <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full transition-colors hidden md:block">
            <X size={20} className="text-gray-400" />
          </button>
        </div>

        {/* Filters */}
        <div className="p-4 border-b border-gray-700 bg-gray-800/50 grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="relative">
                <select 
                    value={selectedYear}
                    onChange={(e) => { setSelectedYear(e.target.value); setSelectedMonth('all'); }}
                    className="w-full bg-gray-900 text-white text-sm border border-gray-600 rounded-lg px-3 py-2 appearance-none outline-none focus:border-[#FA8072]"
                >
                    <option value="all">كل السنوات</option>
                    {years.map(y => <option key={y} value={y}>{y}</option>)}
                </select>
                <ChevronDown size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
            </div>
            <div className="relative">
                <select 
                    value={selectedMonth}
                    onChange={(e) => setSelectedMonth(e.target.value)}
                    className="w-full bg-gray-900 text-white text-sm border border-gray-600 rounded-lg px-3 py-2 appearance-none outline-none focus:border-[#FA8072]"
                    disabled={selectedYear === 'all' && months.length > 12}
                >
                    <option value="all">كل الشهور</option>
                    {months.map(m => <option key={m} value={m}>{getMonthName(m)}</option>)}
                </select>
                <ChevronDown size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
            </div>
        </div>

        {/* Content List */}
        <div className="p-4 overflow-y-auto flex-1 bg-gray-900/20">
          {filteredHistory.length === 0 ? (
            <div className="text-center py-12 text-gray-500 flex flex-col items-center">
              <Search size={32} className="opacity-50 mb-2" />
              <p className="font-medium">لا توجد سجلات في الفترة المحددة.</p>
            </div>
          ) : (
            <>
                {viewMode === 'invoices' ? (
                    // VIEW MODE 1: INVOICES LIST
                    <div className="space-y-3">
                    {filteredHistory.map((day) => (
                        <div key={day.id} className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden transition-all">
                            {/* Day Header */}
                            <div 
                                onClick={() => toggleDayDetails(day.id)}
                                className="p-4 flex items-center justify-between cursor-pointer hover:bg-gray-700/30"
                            >
                                <div className="flex items-center gap-3">
                                    <div className={`p-2 rounded-lg ${expandedDayId === day.id ? 'bg-[#FA8072] text-white' : 'bg-gray-700 text-gray-300'}`}>
                                        {expandedDayId === day.id ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                                    </div>
                                    <div>
                                        <div className="text-white font-bold text-lg">{day.date}</div>
                                        <div className="text-xs text-gray-400">{day.totalItems} قطعة مباعة</div>
                                    </div>
                                </div>
                                <div className="text-right">
                                    <span className="block text-xs text-gray-400">إجمالي اليوم</span>
                                    <span className="block font-bold text-[#FA8072] text-lg">{day.totalRevenue.toLocaleString()} ل.س</span>
                                </div>
                            </div>

                            {/* Invoices List for the Day */}
                            {expandedDayId === day.id && (
                                <div className="bg-gray-900/50 border-t border-gray-700 p-3 space-y-3 animate-fade-up">
                                    {getDayInvoices(day.items).map((invoice, idx) => {
                                        const first = invoice[0];
                                        const total = invoice.reduce((s, i) => s + (i.price * i.quantity), 0);
                                        const isWholesale = first.saleType === 'wholesale';

                                        return (
                                            <div key={idx} className="bg-gray-800 border border-gray-600 rounded-lg p-3">
                                                <div className="flex justify-between items-start mb-2">
                                                    <div className="flex items-center gap-2">
                                                        <div className={`p-1.5 rounded-md ${isWholesale ? 'bg-orange-500/20 text-orange-400' : 'bg-blue-500/20 text-blue-400'}`}>
                                                            {isWholesale ? <Store size={14} /> : <User size={14} />}
                                                        </div>
                                                        <div>
                                                            <span className="block text-sm font-bold text-white">
                                                                {first.customerName || `زبون #${first.customerNumber}`}
                                                            </span>
                                                            <span className="text-xs text-gray-500 font-mono">{first.time}</span>
                                                        </div>
                                                    </div>
                                                    <div className="flex items-center gap-3">
                                                        <span className="font-bold text-[#FA8072] text-sm">{total.toLocaleString()} ل.س</span>
                                                        <button 
                                                            onClick={() => onPreviewInvoice(invoice)}
                                                            className="bg-gray-700 hover:bg-white hover:text-black text-white p-1.5 rounded-lg transition-colors"
                                                            title="تحميل PDF"
                                                        >
                                                            <Download size={14} />
                                                        </button>
                                                    </div>
                                                </div>

                                                {/* Mini Items Table */}
                                                <table className="w-full text-xs text-right text-gray-400">
                                                    <tbody>
                                                        {invoice.map((item, i) => (
                                                            <tr key={i} className="border-t border-gray-700/50">
                                                                <td className="py-1">{item.name}</td>
                                                                <td className="py-1 text-center">{item.quantity} {item.unitType === 'kg' ? 'كغ' : ''}</td>
                                                                <td className="py-1 text-[#FA8072]">{item.price * item.quantity}</td>
                                                            </tr>
                                                        ))}
                                                    </tbody>
                                                </table>
                                            </div>
                                        );
                                    })}
                                </div>
                            )}
                        </div>
                    ))}
                    </div>
                ) : (
                    // VIEW MODE 2: AGGREGATED ITEMS LIST
                    <div className="animate-fade-up">
                        <div className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden">
                            <div className="p-4 border-b border-gray-700 bg-gray-700/30 flex justify-between items-center">
                                <h4 className="font-bold text-white">ملخص المواد المباعة ({selectedYear === 'all' ? 'الكل' : selectedYear})</h4>
                                <div className="text-[#FA8072] font-bold">{totalFilteredRevenue.toLocaleString()} ل.س</div>
                            </div>

                            <div className="overflow-x-auto">
                                <table className="w-full text-sm text-right">
                                    <thead className="bg-gray-900 text-gray-400 text-xs">
                                        <tr>
                                            <th className="p-3">المادة</th>
                                            <th className="p-3 text-center">الكمية الإجمالية</th>
                                            <th className="p-3">الإيراد الكلي</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-700">
                                        {aggregatedItems.map((item, idx) => (
                                            <tr key={idx} className="hover:bg-gray-700/50">
                                                <td className="p-3 font-medium text-white">{item.name}</td>
                                                <td className="p-3 text-center">
                                                    <span className={`px-2 py-1 rounded text-xs ${item.unitType === 'kg' ? 'bg-yellow-500/20 text-yellow-500' : 'bg-blue-500/20 text-blue-400'}`}>
                                                        {item.quantity.toLocaleString()} {item.unitType === 'kg' ? 'كغ' : 'قطعة'}
                                                    </span>
                                                </td>
                                                <td className="p-3 text-[#FA8072] font-bold">{item.revenue.toLocaleString()} ل.س</td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>

                            {aggregatedItems.length === 0 && (
                                <div className="p-8 text-center text-gray-500">لا توجد مواد مباعة.</div>
                            )}
                        </div>
                    </div>
                )}
            </>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useRef, useState } from 'react';
import { X, Download, Upload, Database, AlertTriangle, FileJson, Check, Trash2, Share2, Cloud } from 'lucide-react';

interface DataManagementModalProps {
  onExport: () => void;
  onImport: (file: File) => void;
  onClose: () => void;
}

export const DataManagementModal: React.FC<DataManagementModalProps> = ({ onExport, onImport, onClose }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setSelectedFile(file);
    }
    // Reset value to allow selecting the same file again if user cancels and retries
    if (e.target) e.target.value = '';
  };

  const handleConfirmImport = () => {
    if (!selectedFile) return;
    onImport(selectedFile);
    onClose();
  };

  const clearSelection = () => {
      setSelectedFile(null);
  };

  const handleShareToDrive = async () => {
      // 1. Create the data payload
      const sales = JSON.parse(localStorage.getItem('dailySales') || '[]');
      const history = JSON.parse(localStorage.getItem('salesHistory') || '[]');
      const products = JSON.parse(localStorage.getItem('products') || '[]');
      const customers = JSON.parse(localStorage.getItem('customers') || '[]');

      const data = { appVersion: '1.1', timestamp: Date.now(), sales, history, products, customers };
      const fileName = `cookies-bakery-backup-${new Date().toLocaleDateString('ar-SY').replace(/\//g, '-')}.json`;

      const file = new File([JSON.stringify(data, null, 2)], fileName, {
          type: 'application/json',
      });

      // 2. Use Web Share API
      if (navigator.canShare && navigator.canShare({ files: [file] })) {
          try {
              await navigator.share({
                  files: [file],
                  title: 'نسخة احتياطية - مخبز كوكيز',
                  text: 'ملف النسخة الاحتياطية لنظام المبيعات',
              });
              // Note: User should select "Drive" from the share sheet
          } catch (error) {
              console.log('Error sharing:', error);
          }
      } else {
          alert('المشاركة المباشرة غير مدعومة في هذا المتصفح. يرجى استخدام زر "تحميل ملف البيانات" ثم رفعه يدوياً.');
      }
  };

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-2xl w-full max-w-lg shadow-2xl border border-gray-700 animate-fade-up flex flex-col">

        {/* Header */}
        <div className="p-4 border-b border-gray-700 flex justify-between items-center bg-gray-900/50 rounded-t-2xl">
          <div className="flex items-center gap-2 text-white">
            <Database size={20} className="text-[#FA8072]" />
            <h3 className="font-bold text-lg">النسخ الاحتياطي والاستعادة</h3>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full transition-colors">
            <X size={20} className="text-gray-400" />
          </button>
        </div>

        {/* Content */}
        <div className="p-6 space-y-6">

            {/* Export Section */}
            <div className="bg-gray-700/30 p-4 rounded-xl border border-gray-600">
                <div className="flex items-start gap-3 mb-3">
                    <div className="bg-blue-500/20 p-2 rounded-lg text-blue-400">
                        <Download size={24} />
                    </div>
                    <div>
                        <h4 className="text-white font-bold text-sm">تصدير نسخة احتياطية</h4>
                        <p className="text-gray-400 text-xs mt-1">
                            حفظ البيانات على جهازك أو رفعها إلى السحابة.
                        </p>
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-3">
                    <button 
                        onClick={onExport}
                        className="bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-lg font-bold text-xs transition-colors flex items-center justify-center gap-2"
                    >
                        <Download size={16} />
                        تحميل (جهاز)
                    </button>

                    <button 
                        onClick={handleShareToDrive}
                        className="bg-green-600 hover:bg-green-500 text-white py-3 rounded-lg font-bold text-xs transition-colors flex items-center justify-center gap-2"
                    >
                        <Cloud size={16} />
                        Google Drive
                    </button>
                </div>
                 <p className="text-[10px] text-gray-500 mt-2 text-center">
                    * لمزامنة جوجل درايف: اضغط الزر الأخضر ثم اختر تطبيق "Drive" من القائمة.
                </p>
            </div>

            {/* Import Section */}
            <div className="bg-gray-700/30 p-4 rounded-xl border border-gray-600">
                <div className="flex items-start gap-3 mb-3">
                    <div className="bg-purple-500/20 p-2 rounded-lg text-purple-400">
                        <Upload size={24} />
