    setCart(prev => {
      // Find item with same name AND unit type.
      const existing = prev.find(item => item.name === product.name && item.unitType === product.unitType);

      if (existing) {
        return prev.map(item => 
          (item.tempId === existing.tempId) 
            ? { ...item, quantity: item.quantity + (item.unitType === 'kg' ? 1 : 1) } 
            : item
        );
      }
      return [...prev, { 
          tempId: Date.now().toString(), 
          name: product.name, 
          price: product.price, 
          quantity: 1, 
          unitType: product.unitType || 'piece' 
      }];
    });
  };

  // 2. Add Custom Item to Cart
  const addCustomToCart = () => {
    if (!customName || !customPrice) return;
    setCart(prev => [...prev, { 
        tempId: Date.now().toString(), 
        name: customName, 
        price: parseFloat(customPrice), 
        quantity: 1,
        unitType: customUnit,
        isCustom: true
    }]);
    setCustomName('');
    setCustomPrice('');
    setShowCustomInput(false);
  };

  // 3. Cart Management
  const updateQuantity = (tempId: string, change: number) => {
    setCart(prev => prev.map(item => {
        if (item.tempId === tempId) {
            const step = item.unitType === 'kg' ? 0.1 : 1;
            const newQty = Math.max(step, parseFloat((item.quantity + (change * step)).toFixed(2)));
            return { ...item, quantity: newQty };
        }
        return item;
    }));
  };

  const updateQuantityDirectly = (tempId: string, val: string) => {
      const num = parseFloat(val);
      if (isNaN(num) || num < 0) return;
      setCart(prev => prev.map(item => item.tempId === tempId ? { ...item, quantity: num } : item));
  };

  const updatePriceDirectly = (tempId: string, val: string) => {
      const num = parseFloat(val);
      if (isNaN(num) || num < 0) return;
      setCart(prev => prev.map(item => item.tempId === tempId ? { ...item, price: num } : item));
  };

  const updateTotalDirectly = (tempId: string, val: string) => {
      const newTotal = parseFloat(val);
      if (isNaN(newTotal) || newTotal < 0) return;

      setCart(prev => prev.map(item => {
          if (item.tempId === tempId) {
              if (item.price === 0) return item;
              const newQty = newTotal / item.price;
              return { ...item, quantity: parseFloat(newQty.toFixed(3)) };
          }
          return item;
      }));
  };

  const removeFromCart = (tempId: string) => {
    setCart(prev => prev.filter(item => item.tempId !== tempId));
  };

  const clearCart = () => {
      setCart([]);
      setManualCustomerName('');
      setSelectedCustomerId('');
      setSaleType('retail');
  };

  // 4. Finalize Order
  const handleCheckout = () => {
      if (cart.length === 0) return;

      // Validation for Wholesale
      if (saleType === 'wholesale' && !selectedCustomerId) {
          alert('يجب اختيار عميل عند البيع بالجملة');
          return;
      }

      const salesItems = cart.map(({ name, price, quantity, unitType }) => ({
          name,
          price,
          quantity,
          unitType,
          saleType // Include sale type in item
      }));

      // Determine final customer name
      let finalCustomerName = manualCustomerName;
      if (saleType === 'wholesale' && selectedCustomerId) {
          const cust = customers.find(c => c.id === selectedCustomerId);
          if (cust) finalCustomerName = cust.name;
      }

      onCompleteOrder(salesItems, finalCustomerName, selectedCustomerId || undefined, saleType);
      clearCart();
  };

  const cartTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 no-print">

      {/* LEFT SECTION: Product Grid (Menu) */}
      <div className="lg:col-span-2 space-y-4">
        <div className="flex items-center justify-between bg-gray-800 p-4 rounded-xl border border-gray-700">
             <h2 className="font-bold text-white flex items-center gap-2">
                <Settings className="text-[#FA8072]" size={20} />
                قائمة المنتجات
             </h2>
             <button 
                onClick={onOpenProductManager}
                className="text-xs bg-gray-700 hover:bg-gray-600 text-gray-300 px-3 py-1.5 rounded-lg transition-colors"
             >
                تعديل القائمة
             </button>
        </div>

        {/* Grid */}
        <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
            {products.map(product => (
                <button
                    key={product.id}
                    onClick={() => addToCart(product)}
                    className="flex flex-col items-center justify-center p-4 bg-gray-800 border border-gray-700 hover:bg-gray-700 hover:border-[#FA8072] text-white rounded-2xl transition-all shadow-sm active:scale-95 group h-32 relative"
                >
                    <div className={`absolute top-2 right-2 px-1.5 py-0.5 rounded text-[10px] font-bold ${product.unitType === 'kg' ? 'bg-yellow-400 text-black' : 'bg-blue-300 text-black'}`}>
                        {product.unitType === 'kg' ? 'KG' : 'قطعة'}
                    </div>

                    <span className="font-bold text-sm text-center mb-1 line-clamp-2 group-hover:text-[#FA8072] transition-colors">{product.name}</span>
                    <span className="text-xs text-gray-400 bg-gray-900/50 px-2 py-1 rounded-md">{product.price.toLocaleString('en-US')} ل.س</span>
                </button>
            ))}

            {/* Custom Item Button */}
            <button
                onClick={() => setShowCustomInput(true)}
                className="flex flex-col items-center justify-center p-4 bg-gray-800 border border-dashed border-gray-600 hover:bg-gray-700 text-gray-400 rounded-2xl transition-all active:scale-95 h-32"
            >
                <Edit3 size={20} className="mb-2" />
                <span className="text-xs font-medium">مادة حرة</span>
            </button>
        </div>

        {/* Inline Custom Item Form */}
        {showCustomInput && (
            <div className="bg-gray-800 p-4 rounded-xl border border-[#FA8072] animate-fade-up">
                <h4 className="text-sm font-bold text-white mb-3">إضافة مادة غير مدرجة</h4>
                <div className="flex flex-col md:flex-row gap-2">
                    <input 
                        type="text" 
                        value={customName}
                        onChange={e => setCustomName(e.target.value)}
                        placeholder="اسم المادة"
                        className="flex-grow bg-gray-900 border border-gray-600 text-white px-3 py-2 rounded-lg text-sm outline-none focus:border-[#FA8072]"
                        autoFocus
                    />

                    <div className="flex bg-gray-900 rounded-lg p-1 border border-gray-600 w-fit">
                        <button
                            onClick={() => setCustomUnit('piece')}
                            className={`px-3 py-1 rounded text-xs ${customUnit === 'piece' ? 'bg-[#FA8072] text-white' : 'text-gray-400'}`}
                        >قطعة</button>
                        <button
                            onClick={() => setCustomUnit('kg')}
                            className={`px-3 py-1 rounded text-xs ${customUnit === 'kg' ? 'bg-[#FA8072] text-white' : 'text-gray-400'}`}
                        >كيلو</button>
                    </div>

                    <input 
                        type="number" 
                        value={customPrice}
                        onChange={e => setCustomPrice(e.target.value)}
                        placeholder="السعر"
                        className="w-24 bg-gray-900 border border-gray-600 text-white px-3 py-2 rounded-lg text-sm outline-none focus:border-[#FA8072]"
                    />
                    <button 
                        onClick={addCustomToCart}
                        className="bg-[#FA8072] text-white px-4 rounded-lg font-bold hover:bg-[#e67365] py-2"
                    >
                        إضافة
                    </button>
                    <button 
                        onClick={() => setShowCustomInput(false)}
                        className="bg-gray-700 text-gray-300 px-3 rounded-lg hover:bg-gray-600 py-2"
                    >
                        <Trash2 size={18} />
                    </button>
                </div>
            </div>
        )}
      </div>

      {/* RIGHT SECTION: Current Customer Bill (Cart) */}
      <div className="lg:col-span-1">
        <div className="bg-gray-800 rounded-2xl border border-gray-700 shadow-xl overflow-hidden flex flex-col h-full min-h-[500px]">
            {/* Cart Header */}
            <div className="bg-gray-900/80 p-4 border-b border-gray-700 flex flex-col gap-3">
                <div className="flex justify-between items-center">
                    <h3 className="font-bold text-white flex items-center gap-2">
                        <ShoppingCart size={20} className="text-[#FA8072]" />
                        فاتورة البيع
                    </h3>
                    {cart.length > 0 && (
                        <button onClick={clearCart} className="text-xs text-red-400 hover:text-red-300 underline">
                            إلغاء الطلب
                        </button>
                    )}
                </div>

                {/* --- Wholesale vs Retail Toggle --- */}
                <div className="grid grid-cols-2 bg-gray-700 p-1 rounded-lg">
                    <button 
                        onClick={() => setSaleType('retail')}
                        className={`py-1.5 text-xs font-bold rounded-md flex items-center justify-center gap-2 transition-colors ${saleType === 'retail' ? 'bg-white text-black shadow' : 'text-gray-400 hover:text-white'}`}
                    >
                        <UserPen size={14} />
                        مفرق (عادي)
                    </button>
                    <button 
                        onClick={() => setSaleType('wholesale')}
                        className={`py-1.5 text-xs font-bold rounded-md flex items-center justify-center gap-2 transition-colors ${saleType === 'wholesale' ? 'bg-[#FA8072] text-white shadow' : 'text-gray-400 hover:text-white'}`}
                    >
                        <Store size={14} />
                        جملة
                    </button>
                </div>

                {/* Customer Selection */}
                {saleType === 'retail' ? (
                     <div className="relative">
                        <div className="absolute inset-y-0 right-0 flex items-center pr-3 pointer-events-none text-gray-500">
                            <UserPen size={14} />
                        </div>
                        <input 
                            type="text" 
                            value={manualCustomerName}
                            onChange={(e) => setManualCustomerName(e.target.value)}
                            placeholder="اسم الزبون (اختياري)..."
                            className="w-full bg-gray-800 border border-gray-600 text-white text-sm rounded-lg pr-9 pl-3 py-2 focus:border-[#FA8072] focus:ring-1 focus:ring-[#FA8072] outline-none transition-all placeholder:text-gray-600"
                        />
                    </div>
                ) : (
                    <div className="flex gap-2">
                        <div className="relative flex-grow">
                             <select
                                value={selectedCustomerId}
                                onChange={(e) => setSelectedCustomerId(e.target.value)}
                                className={`w-full bg-gray-800 border ${!selectedCustomerId ? 'border-red-500/50 animate-pulse' : 'border-gray-600'} text-white text-sm rounded-lg px-3 py-2 outline-none focus:border-[#FA8072]`}
                             >
                                 <option value="">اختر عميل الجملة...</option>
                                 {customers.map(c => (
                                     <option key={c.id} value={c.id}>{c.name}</option>
                                 ))}
                             </select>
                        </div>
                        <button 
                            onClick={onOpenCustomerManager}
                            className="bg-blue-600 hover:bg-blue-500 text-white px-3 rounded-lg"
                            title="إضافة عميل جديد"
                        >
                            <UserPlus size={18} />
                        </button>
                    </div>
                )}

            </div>

            {/* Cart Items */}
            <div className="flex-grow p-3 overflow-y-auto space-y-2">
                {cart.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center text-gray-500 opacity-50">
                        <ShoppingCart size={48} className="mb-2" />
                        <p>اضغط على المنتجات لإضافتها</p>
                    </div>
                ) : (
                    cart.map(item => (
                        <div key={item.tempId} className="bg-gray-700/50 p-3 rounded-xl flex flex-col gap-2 border border-gray-700 relative group">
                            <div className="flex justify-between items-start gap-2">
                                <div className="flex flex-col">
                                    <span className="text-white font-medium text-sm">{item.name}</span>
                                    <span className={`text-[10px] w-fit px-1.5 rounded-md ${item.unitType === 'kg' ? 'bg-yellow-500/20 text-yellow-500' : 'bg-blue-500/20 text-blue-400'}`}>
                                        {item.unitType === 'kg' ? 'وزن (كيلو)' : 'عدد (قطعة)'}
                                    </span>
                                </div>
                            </div>

                            {/* Inputs Container */}
                            <div className="flex flex-col gap-2 mt-1 bg-gray-800/50 p-2 rounded-lg">
                                {/* Price Editor */}
                                <div className="flex items-center justify-between gap-2">
                                    <label className="text-[10px] text-gray-500 w-16">سعر الإفرادي:</label>
                                    <input 
                                        type="number"
                                        value={item.price}
                                        onChange={(e) => updatePriceDirectly(item.tempId, e.target.value)}
                                        className="flex-1 bg-gray-900 border border-gray-600 rounded px-2 py-1 text-sm text-white text-center focus:border-[#FA8072] outline-none"
                                    />
                                </div>

                                {/* Quantity Editor */}
                                <div className="flex items-center justify-between gap-2">
                                    <label className="text-[10px] text-gray-500 w-16">الكمية:</label>
                                    <div className="flex items-center gap-1 flex-1">
                                        <button 
                                            onClick={() => updateQuantity(item.tempId, -1)}
                                            className="w-8 h-7 flex items-center justify-center bg-gray-700 text-white rounded hover:bg-gray-600"
                                        >
                                            <Minus size={14} />
                                        </button>
                                        <input 
                                            type="number"
                                            value={item.quantity}
                                            onChange={(e) => updateQuantityDirectly(item.tempId, e.target.value)}
                                            className="flex-1 bg-gray-900 border border-gray-600 rounded px-1 py-1 text-sm text-white text-center focus:border-[#FA8072] outline-none h-7"
                                            step={item.unitType === 'kg' ? "0.1" : "1"}
                                        />
                                        <button 
                                            onClick={() => updateQuantity(item.tempId, 1)}
                                            className="w-8 h-7 flex items-center justify-center bg-[#FA8072] text-white rounded hover:bg-[#e67365]"
                                        >
                                            <Plus size={14} />
                                        </button>
                                    </div>
                                </div>

                                {/* Total Price Editor */}
                                <div className="flex items-center justify-between gap-2 pt-2 border-t border-gray-700/50 mt-1">
                                    <div className="flex items-center gap-1 w-16">
                                        <Calculator size={10} className="text-[#FA8072]" />
                                        <label className="text-[10px] text-[#FA8072] font-bold">الإجمالي:</label>
                                    </div>
                                    <input 
                                        type="number"
                                        value={Math.round(item.price * item.quantity * 100) / 100}
                                        onChange={(e) => updateTotalDirectly(item.tempId, e.target.value)}
                                        className="flex-1 bg-gray-900 border border-[#FA8072]/50 rounded px-2 py-1 text-sm text-[#FA8072] font-bold text-center focus:border-[#FA8072] outline-none"
                                    />
                                </div>
                            </div>

                            <button 
                                onClick={() => removeFromCart(item.tempId)}
                                className="absolute -left-2 -top-2 bg-red-500 text-white p-1 rounded-full opacity-0 group-hover:opacity-100 transition-opacity shadow-md z-10"
                            >
                                <Trash2 size={12} />
                            </button>
                        </div>
                    ))
                )}
            </div>

            {/* Cart Footer (Total & Checkout) */}
            <div className="p-4 bg-gray-900 border-t border-gray-700 mt-auto">
                <div className="flex justify-between items-center mb-4">
                    <span className="text-gray-400">الإجمالي المطلوب:</span>
                    <span className="text-2xl font-bold text-white">{cartTotal.toLocaleString('en-US')} <span className="text-sm font-normal text-gray-500">ل.س</span></span>
                </div>

                <button
                    onClick={handleCheckout}
                    disabled={cart.length === 0}
                    className={`
                        w-full py-3 rounded-xl font-bold text-lg flex items-center justify-center gap-2 transition-all shadow-lg
                        ${cart.length > 0 
                            ? 'bg-green-600 hover:bg-green-500 text-white transform active:scale-95' 
                            : 'bg-gray-700 text-gray-500 cursor-not-allowed'}
                    `}
                >
                    <CheckCircle size={24} />
                    <span>تأكيد البيع (موافق)</span>
                </button>
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Trash2, ShoppingBag, Search, User, Download, Store } from 'lucide-react';
import { SaleItem } from '../types';

interface SalesTableProps {
  items: SaleItem[];
  onDeleteItem: (id: string) => void;
  onDeleteOrder?: (orderId: string) => void;
  onPreviewInvoice: (items: SaleItem[]) => void;
}

export const SalesTable: React.FC<SalesTableProps> = ({ items, onDeleteItem, onDeleteOrder, onPreviewInvoice }) => {
  const [searchTerm, setSearchTerm] = useState<string>('');

  // State for inline deletion confirmation
  const [confirmItemId, setConfirmItemId] = useState<string | null>(null);
  const [confirmOrderId, setConfirmOrderId] = useState<string | null>(null);

  // Group items by orderId
  const groupedOrders = useMemo(() => {
    const groups: { [key: string]: SaleItem[] } = {};
    items.forEach(item => {
        const key = item.orderId || `legacy-${item.time}`;
        if (!groups[key]) {
            groups[key] = [];
        }
        groups[key].push(item);
    });

    // Convert to array and sort by time (newest first)
    return Object.values(groups).sort((a, b) => {
        const timeA = a[0]?.id ? 1 : 0; // Simple check, ideally parse timestamp
        return 0; // Keeping original sort order (newest usually appended, so we might want to reverse in UI)
    }).reverse();
  }, [items]);

  // Filter logic for Search
  const filteredOrders = useMemo(() => {
      if (!searchTerm) return groupedOrders;
      const lowerTerm = searchTerm.toLowerCase();
      return groupedOrders.filter(group => {
          const first = group[0];
          const name = first.customerName?.toLowerCase() || '';
          const number = first.customerNumber.toString();
          return name.includes(lowerTerm) || number.includes(lowerTerm);
      });
  }, [groupedOrders, searchTerm]);

  if (items.length === 0) {
    return (
      <div className="bg-gray-800 p-8 rounded-2xl shadow-sm border border-gray-700 text-center flex flex-col items-center justify-center min-h-[200px] print:hidden">
        <div className="bg-gray-700 p-4 rounded-full mb-3">
            <ShoppingBag className="text-gray-400 w-8 h-8" />
        </div>
        <p className="text-gray-400 font-medium">لا توجد مبيعات مسجلة اليوم حتى الآن.</p>
      </div>
    );
  }

  return (
    <div className="space-y-4">
        {/* Search Bar */}
        <div className="bg-gray-800 p-4 rounded-xl border border-gray-700 flex flex-col md:flex-row items-center gap-4 no-print">
            <div className="relative w-full md:w-96">
                <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                <input 
                    type="text"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    placeholder="بحث عن فاتورة (اسم الزبون أو رقمه)..."
                    className="w-full bg-gray-900 border border-gray-600 text-white rounded-xl pr-10 pl-4 py-2 outline-none focus:border-[#FA8072]"
                />
            </div>

            <div className="text-gray-400 text-xs">
                عدد الفواتير المعروضة: {filteredOrders.length}
            </div>
        </div>

        {/* Orders List */}
        <div className="space-y-4">
            {filteredOrders.map((group, index) => {
                const firstItem = group[0];
                const orderTotal = group.reduce((sum, item) => sum + (item.price * item.quantity), 0);
                const orderId = firstItem.orderId;
                const displayName = firstItem.customerName ? `${firstItem.customerName}` : `زبون رقم ${firstItem.customerNumber || '?'}`;
                const isWholesale = firstItem.saleType === 'wholesale';

                return (
                    <div key={orderId || index} className="bg-gray-800 rounded-2xl border border-gray-700 overflow-hidden animate-fade-up">
                        {/* Order Header */}
                        <div className="bg-gray-900/50 p-4 flex flex-wrap items-center justify-between border-b border-gray-700">
                            <div className="flex items-center gap-4">
                                <div className={`px-3 py-1 rounded-lg font-bold border flex items-center gap-2 ${isWholesale ? 'bg-orange-900/20 text-orange-400 border-orange-500/20' : 'bg-blue-900/20 text-blue-400 border-blue-500/20'}`}>
                                    {isWholesale ? <Store size={16} /> : <User size={16} />}
                                    <span>
                                        {displayName}
                                        {/* If name exists, show number in small text */}
                                        {firstItem.customerName && <span className="text-xs opacity-70 mr-2">#{firstItem.customerNumber}</span>}
                                    </span>
                                </div>
                                <span className="text-gray-400 text-sm font-mono">{firstItem.time}</span>
                            </div>

                            <div className="flex items-center gap-4 mt-2 md:mt-0">
                                <div className="text-white font-bold">
                                    <span className="text-gray-400 text-sm font-normal ml-2">الإجمالي:</span>
                                    {orderTotal.toLocaleString('en-US')} ل.س
                                </div>

                                {/* Download Invoice Button */}
                                <button 
                                    onClick={() => onPreviewInvoice(group)}
                                    className="flex items-center gap-1 bg-green-600 hover:bg-green-500 text-white px-3 py-1.5 rounded-lg text-xs font-bold transition-colors no-print ml-2"
                                    title="تحميل الفاتورة PDF"
                                >
                                    <Download size={14} />
                                    تحميل PDF
                                </button>

                                {onDeleteOrder && (
                                    confirmOrderId === orderId ? (
                                        <div className="flex items-center gap-2 no-print">
                                            <span className="text-xs text-red-300 hidden md:inline">حذف؟</span>
                                            <button 
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    onDeleteOrder(orderId);
                                                    setConfirmOrderId(null);
                                                }}
                                                className="bg-red-500 text-white px-2 py-1 rounded text-xs hover:bg-red-600"
                                            >
                                                نعم
                                            </button>
                                            <button 
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    setConfirmOrderId(null);
                                                }}
                                                className="bg-gray-600 text-white px-2 py-1 rounded text-xs hover:bg-gray-500"
                                            >
                                                إلغاء
                                            </button>
                                        </div>
                                    ) : (
                                        <button 
                                            type="button"
                                            onClick={(e) => {
                                                e.stopPropagation();
                                                setConfirmOrderId(orderId);
                                            }}
                                            className="text-red-400 hover:bg-red-400/10 p-2 rounded-lg transition-colors no-print"
                                            title="حذف الطلب بالكامل"
                                        >
                                            <Trash2 size={18} />
                                        </button>
                                    )
                                )}
                            </div>
                        </div>

                        {/* Order Items Table */}
                        <div className="overflow-x-auto">
                            <table className="w-full text-right">
                                <thead className="bg-gray-700/20 text-xs text-gray-400">
                                    <tr>
                                        <th className="py-2 px-4">المادة</th>
                                        <th className="py-2 px-4 text-center">الكمية</th>
                                        <th className="py-2 px-4">السعر</th>
                                        <th className="py-2 px-4">الإجمالي</th>
                                        <th className="py-2 px-4 w-10"></th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-gray-700/50 text-sm">
                                    {group.map(item => (
                                        <tr key={item.id} className="hover:bg-gray-700/20 transition-colors">
                                            <td className="py-2 px-4 font-medium text-gray-200">
                                                {item.name}
                                            </td>
                                            <td className="py-2 px-4 text-center">
                                                <span className="bg-gray-700 text-gray-300 px-2 py-0.5 rounded text-xs">
                                                    {item.quantity} {item.unitType === 'kg' ? 'كغ' : 'قطعة'}
                                                </span>
                                            </td>
                                            <td className="py-2 px-4 text-gray-400">{item.price.toLocaleString('en-US')}</td>
                                            <td className="py-2 px-4 text-[#FA8072] font-medium">
                                                {(item.price * item.quantity).toLocaleString('en-US')}
                                            </td>
                                            <td className="py-2 px-4 text-left">
                                                {confirmItemId === item.id ? (
                                                    <div className="flex items-center gap-1">
                                                        <button
                                                            onClick={() => {
                                                                onDeleteItem(item.id);
                                                                setConfirmItemId(null);
                                                            }}
                                                            className="text-red-500 text-xs font-bold hover:underline"
                                                        >
                                                            تأكيد
                                                        </button>
                                                        <span className="text-gray-600">/</span>
                                                        <button
                                                            onClick={() => setConfirmItemId(null)}
                                                            className="text-gray-400 text-xs hover:text-white"
                                                        >
                                                            إلغاء
                                                        </button>
                                                    </div>
                                                ) : (
                                                    <button
                                                        type="button"
                                                        onClick={(e) => {
                                                            e.stopPropagation();
                                                            setConfirmItemId(item.id);
                                                        }}
                                                        className="text-gray-600 hover:text-red-400 transition-colors cursor-pointer"
                                                        title="حذف مادة"
                                                    >
                                                        <Trash2 size={14} />
                                                    </button>
                                                )}
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                );
            })}
        </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { X, Calendar, ChevronDown, ChevronUp, Download, Store, User, Search, Receipt, Package, ArrowRight, Folder, CalendarDays, Calculator } from 'lucide-react';
import { ArchivedDay, SaleItem } from '../types';

interface HistoryModalProps {
  history: ArchivedDay[];
  onClose: () => void;
  onClearHistory: () => void;
  onPreviewInvoice: (items: SaleItem[]) => void;
}

// Navigation Steps
type NavStep = 'years' | 'months' | 'days';
type ViewMode = 'invoices' | 'items';

export const HistoryModal: React.FC<HistoryModalProps> = ({ history, onClose, onClearHistory, onPreviewInvoice }) => {
  // Navigation State
  const [step, setStep] = useState<NavStep>('years');
  const [selectedYear, setSelectedYear] = useState<string>('');
  const [selectedMonth, setSelectedMonth] = useState<number>(-1);
  const [searchTerm, setSearchTerm] = useState('');

  // View Details State
  const [viewMode, setViewMode] = useState<ViewMode>('invoices');
  const [expandedDayId, setExpandedDayId] = useState<string | null>(null);

  // --- SEARCH LOGIC (GLOBAL) ---
  const searchResults = useMemo(() => {
      if (!searchTerm) return null;
      const lowerTerm = searchTerm.toLowerCase();

      // Flatten everything into invoices
      const allInvoices: { date: string; items: SaleItem[]; total: number; customerName: string; saleType: string }[] = [];

      history.forEach(day => {
          const dayGroups: { [key: string]: SaleItem[] } = {};
          day.items.forEach(item => {
              const key = item.orderId || `legacy-${item.time}`;
              if (!dayGroups[key]) dayGroups[key] = [];
              dayGroups[key].push(item);
          });

          Object.values(dayGroups).forEach(group => {
              const first = group[0];
              const name = first.customerName || `زبون ${first.customerNumber}`;
              // Search by Name or ID
              if (name.toLowerCase().includes(lowerTerm) || first.customerNumber.toString().includes(lowerTerm)) {
                  allInvoices.push({
                      date: day.date,
                      items: group,
                      total: group.reduce((sum, i) => sum + i.price * i.quantity, 0),
                      customerName: name,
                      saleType: first.saleType
                  });
              }
          });
      });

      return allInvoices;
  }, [history, searchTerm]);

  // --- DATA HELPERS (Navigation) ---

  // 1. Get Available Years
  const years = useMemo(() => {
    const uniqueYears = new Set<string>(history.map(day => new Date(day.timestamp).getFullYear().toString()));
    return Array.from(uniqueYears).sort((a, b) => b.localeCompare(a));
  }, [history]);

  // 2. Get Available Months for Selected Year
  const months = useMemo(() => {
    if (!selectedYear) return [];
    const uniqueMonths = new Set<number>(
      history
        .filter(day => new Date(day.timestamp).getFullYear().toString() === selectedYear)
        .map(day => new Date(day.timestamp).getMonth())
    );
    return Array.from(uniqueMonths).sort((a, b) => b - a);
  }, [history, selectedYear]);

  // 3. Get Days for Selected Year & Month
  const currentDaysData = useMemo(() => {
    if (!selectedYear || selectedMonth === -1) return [];
    return history.filter(day => {
      const d = new Date(day.timestamp);
      return d.getFullYear().toString() === selectedYear && d.getMonth() === selectedMonth;
    });
  }, [history, selectedYear, selectedMonth]);

  // 4. Aggregated Items Logic (For Items View in Step 3)
  const aggregatedItems = useMemo(() => {
      const itemMap = new Map<string, { name: string; quantity: number; revenue: number; unitType: string }>();

      currentDaysData.forEach(day => {
          day.items.forEach(item => {
              const key = `${item.name}-${item.unitType}`;
              const existing = itemMap.get(key);
              if (existing) {
                  existing.quantity += item.quantity;
                  existing.revenue += (item.price * item.quantity);
              } else {
                  itemMap.set(key, {
                      name: item.name,
                      quantity: item.quantity,
                      revenue: item.price * item.quantity,
                      unitType: item.unitType
                  });
              }
          });
      });

      return Array.from(itemMap.values()).sort((a, b) => b.revenue - a.revenue);
  }, [currentDaysData]);

  const totalRevenueForPeriod = currentDaysData.reduce((sum, day) => sum + day.totalRevenue, 0);

  // --- HANDLERS ---

  const handleYearSelect = (year: string) => {
    setSelectedYear(year);
    setStep('months');
  };

  const handleMonthSelect = (monthIndex: number) => {
    setSelectedMonth(monthIndex);
    setStep('days');
  };

  const handleBack = () => {
    if (step === 'days') {
        setStep('months');
        setSelectedMonth(-1);
    } else if (step === 'months') {
        setStep('years');
        setSelectedYear('');
    }
  };

  const getMonthName = (monthIndex: number) => {
    const date = new Date();
    date.setMonth(monthIndex);
    return date.toLocaleString('ar-SY', { month: 'long' });
  };

  // Helper to group items in a day by OrderID (Invoice)
  const getDayInvoices = (items: SaleItem[]) => {
      const groups: { [key: string]: SaleItem[] } = {};
      items.forEach(item => {
          const key = item.orderId || `legacy-${item.time}`;
          if (!groups[key]) groups[key] = [];
          groups[key].push(item);
      });
      return Object.values(groups).reverse(); 
  };

  // --- RENDER CONTENT BASED ON STEP ---

  const renderContent = () => {
    // 0. SEARCH RESULTS MODE
    if (searchTerm) {
        if (!searchResults || searchResults.length === 0) {
            return (
                <div className="flex flex-col items-center justify-center h-full text-gray-500">
                    <Search size={48} className="mb-4 opacity-50" />
                    <p>لا توجد نتائج مطابقة لـ "{searchTerm}"</p>
                </div>
            );
        }

        const totalSearchRevenue = searchResults.reduce((acc, curr) => acc + curr.total, 0);

        return (
            <div className="animate-fade-up space-y-4">
                 {/* Summary Card for Search */}
                 <div className="bg-gray-700/50 p-4 rounded-xl border border-gray-600 flex justify-between items-center">
                    <div>
                        <h4 className="text-white font-bold text-sm">نتائج البحث عن: "{searchTerm}"</h4>
                        <p className="text-gray-400 text-xs mt-1">تم العثور على {searchResults.length} فاتورة</p>
                    </div>
                    <div className="text-right">
                        <span className="block text-xs text-gray-400">إجمالي المبلغ</span>
                        <span className="block font-bold text-[#FA8072] text-xl">{totalSearchRevenue.toLocaleString('en-US')} ل.س</span>
                    </div>
                 </div>

                 {/* Results List */}
                 <div className="space-y-3">
                    {searchResults.map((inv, idx) => (
                         <div key={idx} className="bg-gray-800 border border-gray-700 rounded-xl p-4">
                             <div className="flex justify-between items-start mb-3 border-b border-gray-700 pb-2">
                                 <div>
                                     <div className="flex items-center gap-2 mb-1">
                                        <div className={`p-1 rounded-md ${inv.saleType === 'wholesale' ? 'bg-orange-500/20 text-orange-400' : 'bg-blue-500/20 text-blue-400'}`}>
                                            {inv.saleType === 'wholesale' ? <Store size={14} /> : <User size={14} />}
                                        </div>
                                        <span className="font-bold text-white">{inv.customerName}</span>
                                     </div>
                                     <span className="text-xs text-gray-500">{inv.date} - {inv.items[0].time}</span>
                                 </div>
                                 <div className="flex items-center gap-3">
                                     <span className="font-bold text-[#FA8072]">{inv.total.toLocaleString('en-US')} ل.س</span>
                                     <button 
                                        onClick={() => onPreviewInvoice(inv.items)}
                                        className="bg-gray-700 hover:bg-white hover:text-black text-white p-1.5 rounded-lg transition-colors"
                                    >
                                        <Download size={16} />
                                    </button>
                                 </div>
                             </div>

                             {/* Items Preview */}
                             <div className="text-xs text-gray-400">
                                 {inv.items.map((i, k) => (
                                     <span key={k} className="inline-block bg-gray-900 px-2 py-1 rounded mr-1 mb-1 border border-gray-700">
                                         {i.name} ({i.quantity})
                                     </span>
                                 ))}
                             </div>
                         </div>
                    ))}
                 </div>
            </div>
        );
    }

    // STEP 1: YEARS
    if (step === 'years') {
        if (years.length === 0) {
            return (
                <div className="flex flex-col items-center justify-center h-64 text-gray-500">
                    <Search size={48} className="mb-4 opacity-50" />
                    <p>لا توجد سجلات محفوظة.</p>
                </div>
            );
        }
        return (
            <div className="grid grid-cols-2 md:grid-cols-3 gap-4 animate-fade-up">
                {years.map(year => (
                    <button 
                        key={year}
                        onClick={() => handleYearSelect(year)}
                        className="bg-gray-700 hover:bg-gray-600 border border-gray-600 hover:border-[#FA8072] text-white p-6 rounded-2xl flex flex-col items-center justify-center gap-3 transition-all group"
                    >
                        <Folder size={40} className="text-[#FA8072] group-hover:scale-110 transition-transform" />
                        <span className="text-xl font-bold">{year}</span>
                        <span className="text-xs text-gray-400">سنة مالية</span>
                    </button>
                ))}
            </div>
        );
    }

    // STEP 2: MONTHS
    if (step === 'months') {
        return (
            <div className="grid grid-cols-2 md:grid-cols-3 gap-4 animate-fade-up">
                {months.map(monthIdx => (
                    <button 
                        key={monthIdx}
                        onClick={() => handleMonthSelect(monthIdx)}
                        className="bg-gray-700 hover:bg-gray-600 border border-gray-600 hover:border-[#FA8072] text-white p-6 rounded-2xl flex flex-col items-center justify-center gap-3 transition-all group"
                    >
                        <CalendarDays size={40} className="text-blue-400 group-hover:scale-110 transition-transform" />
                        <span className="text-xl font-bold">{getMonthName(monthIdx)}</span>
                        <span className="text-xs text-gray-400">{selectedYear}</span>
                    </button>
                ))}
            </div>
        );
    }

    // STEP 3: DAYS (DETAILS)
    if (step === 'days') {
        return (
            <div className="flex flex-col gap-4 animate-fade-up h-full">
                {/* Toggle View Mode */}
                 <div className="flex bg-gray-700 p-1 rounded-xl shrink-0">
                    <button 
                        onClick={() => setViewMode('invoices')}
                        className={`flex-1 flex items-center justify-center gap-2 px-4 py-2.5 rounded-lg text-sm font-bold transition-all ${viewMode === 'invoices' ? 'bg-white text-black shadow' : 'text-gray-400 hover:text-white'}`}
                    >
                        <Receipt size={16} />
                        عرض الفواتير (يومي)
                    </button>
                    <button 
                        onClick={() => setViewMode('items')}
                        className={`flex-1 flex items-center justify-center gap-2 px-4 py-2.5 rounded-lg text-sm font-bold transition-all ${viewMode === 'items' ? 'bg-[#FA8072] text-white shadow' : 'text-gray-400 hover:text-white'}`}
                    >
                        <Package size={16} />
                        تجميع المواد (شهري)
                    </button>
                </div>

                <div className="flex-1 overflow-y-auto min-h-0 bg-gray-900/30 rounded-xl border border-gray-700/50 p-2">
                     {currentDaysData.length === 0 ? (
                        <div className="text-center py-12 text-gray-500">لا توجد بيانات لهذا الشهر.</div>
                     ) : (
                        <>
                            {viewMode === 'invoices' ? (
                                // MODE A: LIST OF DAYS WITH INVOICES
                                <div className="space-y-3">
                                    {currentDaysData.map((day) => (
                                        <div key={day.id} className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden transition-all">
                                            <div 
                                                onClick={() => setExpandedDayId(expandedDayId === day.id ? null : day.id)}
                                                className="p-4 flex items-center justify-between cursor-pointer hover:bg-gray-700/30"
                                            >
                                                <div className="flex items-center gap-3">
                                                    <div className={`p-2 rounded-lg ${expandedDayId === day.id ? 'bg-[#FA8072] text-white' : 'bg-gray-700 text-gray-300'}`}>
                                                        {expandedDayId === day.id ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                                                    </div>
                                                    <div>
                                                        <div className="text-white font-bold text-lg">{day.date}</div>
                                                        <div className="text-xs text-gray-400">{day.totalItems} قطعة مباعة</div>
                                                    </div>
                                                </div>
                                                <div className="text-right">
                                                    <span className="font-bold text-[#FA8072] text-lg">{day.totalRevenue.toLocaleString('en-US')} ل.س</span>
                                                </div>
                                            </div>

                                            {expandedDayId === day.id && (
                                                <div className="bg-gray-900/50 border-t border-gray-700 p-3 space-y-3 animate-fade-up">
                                                    {getDayInvoices(day.items).map((invoice, idx) => {
                                                        const first = invoice[0];
                                                        const total = invoice.reduce((s, i) => s + (i.price * i.quantity), 0);
                                                        const isWholesale = first.saleType === 'wholesale';
                                                        return (
                                                            <div key={idx} className="bg-gray-800 border border-gray-600 rounded-lg p-3">
                                                                <div className="flex justify-between items-start mb-2">
                                                                    <div className="flex items-center gap-2">
                                                                        <div className={`p-1.5 rounded-md ${isWholesale ? 'bg-orange-500/20 text-orange-400' : 'bg-blue-500/20 text-blue-400'}`}>
                                                                            {isWholesale ? <Store size={14} /> : <User size={14} />}
                                                                        </div>
                                                                        <div>
                                                                            <span className="block text-sm font-bold text-white">
                                                                                {first.customerName || `زبون #${first.customerNumber}`}
                                                                            </span>
                                                                            <span className="text-xs text-gray-500 font-mono">{first.time}</span>
                                                                        </div>
                                                                    </div>
                                                                    <div className="flex items-center gap-3">
                                                                        <span className="font-bold text-[#FA8072] text-sm">{total.toLocaleString('en-US')} ل.س</span>
                                                                        <button 
                                                                            onClick={() => onPreviewInvoice(invoice)}
                                                                            className="bg-gray-700 hover:bg-white hover:text-black text-white p-1.5 rounded-lg transition-colors"
                                                                            title="تحميل PDF"
                                                                        >
                                                                            <Download size={14} />
                                                                        </button>
                                                                    </div>
                                                                </div>
                                                                <table className="w-full text-xs text-right text-gray-400">
                                                                    <tbody>
                                                                        {invoice.map((item, i) => (
                                                                            <tr key={i} className="border-t border-gray-700/50">
                                                                                <td className="py-1">{item.name}</td>
                                                                                <td className="py-1 text-center">{item.quantity}</td>
                                                                                <td className="py-1 text-[#FA8072]">{item.price * item.quantity}</td>
                                                                            </tr>
                                                                        ))}
                                                                    </tbody>
                                                                </table>
                                                            </div>
                                                        );
                                                    })}
                                                </div>
                                            )}
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                // MODE B: AGGREGATED ITEMS
                                <div className="animate-fade-up">
                                    <div className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden">
                                        <div className="p-4 border-b border-gray-700 bg-gray-700/30 flex justify-between items-center">
                                            <div>
                                                <h4 className="font-bold text-white">إجمالي شهر {getMonthName(selectedMonth)}</h4>
                                                <p className="text-xs text-gray-400">{selectedYear}</p>
                                            </div>
                                            <div className="text-[#FA8072] font-bold text-xl">{totalRevenueForPeriod.toLocaleString('en-US')} ل.س</div>
                                        </div>
                                        <div className="overflow-x-auto">
                                            <table className="w-full text-sm text-right">
                                                <thead className="bg-gray-900 text-gray-400 text-xs">
                                                    <tr>
                                                        <th className="p-3">المادة</th>
                                                        <th className="p-3 text-center">الكمية</th>
                                                        <th className="p-3">الإيراد</th>
                                                    </tr>
                                                </thead>
                                                <tbody className="divide-y divide-gray-700">
                                                    {aggregatedItems.map((item, idx) => (
                                                        <tr key={idx} className="hover:bg-gray-700/50">
                                                            <td className="p-3 font-medium text-white">{item.name}</td>
                                                            <td className="p-3 text-center">
                                                                <span className={`px-2 py-1 rounded text-xs ${item.unitType === 'kg' ? 'bg-yellow-500/20 text-yellow-500' : 'bg-blue-500/20 text-blue-400'}`}>
                                                                    {item.quantity.toLocaleString('en-US')} {item.unitType === 'kg' ? 'كغ' : 'قطعة'}
                                                                </span>
                                                            </td>
                                                            <td className="p-3 text-[#FA8072] font-bold">{item.revenue.toLocaleString('en-US')} ل.س</td>
                                                        </tr>
                                                    ))}
                                                </tbody>
                                            </table>
                                        </div>
                                    </div>
                                </div>
                            )}
                        </>
                     )}
                </div>
            </div>
        );
    }
  };

  // --- HEADER TEXT HELPER ---
  const getHeaderText = () => {
    if (searchTerm) return 'نتائج البحث';
    if (step === 'years') return 'اختيار السنة';
    if (step === 'months') return `سنة ${selectedYear} - اختيار الشهر`;
    if (step === 'days') return `${getMonthName(selectedMonth)} ${selectedYear}`;
    return '';
  };

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-2xl w-full max-w-4xl shadow-2xl border border-gray-700 animate-fade-up flex flex-col h-[85vh]">

        {/* Header */}
        <div className="p-4 border-b border-gray-700 bg-gray-900/50 rounded-t-2xl shrink-0 space-y-3">
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-3 text-white">
                    {/* BACK BUTTON LOGIC */}
                    {!searchTerm && step !== 'years' ? (
                        <button 
                            onClick={handleBack}
                            className="bg-gray-700 hover:bg-[#FA8072] text-white p-2 rounded-full transition-colors"
                            title="رجوع للخلف"
                        >
                            <ArrowRight size={20} />
                        </button>
                    ) : (
                        <div className="bg-[#FA8072]/20 p-2 rounded-lg text-[#FA8072]">
                            {searchTerm ? <Search size={22} /> : <Calendar size={22} />}
                        </div>
                    )}

                    <div>
                        <h3 className="font-bold text-lg">{getHeaderText()}</h3>
                        {!searchTerm && step === 'years' && <p className="text-xs text-gray-400">سجل المبيعات (الأرشيف)</p>}
                    </div>
                </div>

                <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full transition-colors text-gray-400 hover:text-white">
                    <X size={24} />
                </button>
            </div>

            {/* Search Bar */}
            <div className="relative">
                <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                <input 
                    type="text" 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    placeholder="بحث عن زبون في الأرشيف لمعرفة مجموع حساباته..."
                    className="w-full bg-gray-900 border border-gray-600 text-white rounded-xl pr-10 pl-4 py-2.5 outline-none focus:border-[#FA8072] focus:ring-1 focus:ring-[#FA8072] placeholder:text-gray-600 transition-all text-sm"
                />
            </div>
        </div>

        {/* Dynamic Content */}
        <div className="p-4 flex-1 overflow-hidden flex flex-col bg-gray-900/20">
            {renderContent()}
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { X, Copy, Check, Download, FileSpreadsheet } from 'lucide-react';
import { SaleItem } from '../types';
import { utils, writeFile } from 'xlsx';

interface InvoiceModalProps {
  items: SaleItem[];
  onClose: () => void;
}

export const InvoiceModal: React.FC<InvoiceModalProps> = ({ items, onClose }) => {
  const [copied, setCopied] = useState(false);
  const [confirmPrint, setConfirmPrint] = useState(false);

  const totalRevenue = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const dateStr = new Date().toLocaleDateString('en-GB'); // DD/MM/YYYY with English digits
  const firstItem = items[0];
  const uniqueCustomers = new Set(items.map(i => i.customerNumber));
  const isSingleCustomer = uniqueCustomers.size === 1;
  // Use explicit customer name if available, otherwise fallback to generic if single customer
  const customerName = firstItem?.customerName || (isSingleCustomer ? `زبون رقم ${firstItem.customerNumber}` : 'مبيعات مجمعة');
  const isWholesale = firstItem?.saleType === 'wholesale';

  useEffect(() => {
    document.body.classList.add('print-mode');
    return () => {
      document.body.classList.remove('print-mode');
    };
  }, []);

  const getInvoiceText = () => {
    let text = `*فاتورة - مخبز كوكيز*\n`;
    text += `التاريخ: ${dateStr}\n`;
    text += `العميل: ${customerName}\n`;
    text += `------------------\n`;
    items.forEach(item => {
      text += `- ${item.name}: ${item.quantity} × ${item.price} = ${(item.price * item.quantity).toLocaleString('en-US')}\n`;
    });
    text += `------------------\n`;
    text += `*الإجمالي: ${totalRevenue.toLocaleString('en-US')} ل.س*\n`;
    return text;
  };

  const handleCopy = () => {
    const text = getInvoiceText();
    navigator.clipboard.writeText(text).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  const handleDownloadExcel = () => {
    const rows = items.map(item => ({
        "المادة": item.name,
        "العميل": item.customerName || `زبون ${item.customerNumber}`,
        "الكمية": item.quantity,
        "السعر": item.price,
        "الإجمالي": item.price * item.quantity
    }));
    rows.push({
        "المادة": "المجموع الكلي",
        "العميل": "",
        "الكمية": 0,
        "السعر": 0,
        "الإجمالي": totalRevenue
    });
    const ws = utils.json_to_sheet(rows);
    const wb = utils.book_new();
