import React, { useState } from 'react';
import { Plus, Trash2, Settings, X, Scale, Box } from 'lucide-react';
import { Product, UnitType } from '../types';

interface ProductManagerProps {
  products: Product[];
  onAddProduct: (product: Omit<Product, 'id'>) => void;
  onDeleteProduct: (id: string) => void;
  isOpen: boolean;
  onClose: () => void;
}

export const ProductManager: React.FC<ProductManagerProps> = ({ 
  products, 
  onAddProduct, 
  onDeleteProduct,
  isOpen,
  onClose
}) => {
  const [name, setName] = useState('');
  const [price, setPrice] = useState('');
  const [unitType, setUnitType] = useState<UnitType>('piece');

  // State to track which product is being deleted
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !price) return;

    onAddProduct({
      name,
      price: parseFloat(price),
      unitType
    });

    setName('');
    setPrice('');
    setUnitType('piece'); // Reset to default
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-2xl w-full max-w-lg shadow-2xl border border-gray-700 animate-fade-up flex flex-col max-h-[85vh]">

        <div className="p-4 border-b border-gray-700 flex justify-between items-center bg-gray-900/50 rounded-t-2xl">
          <div className="flex items-center gap-2 text-white">
            <Settings size={20} className="text-[#FA8072]" />
            <h3 className="font-bold text-lg">إدارة المواد والأسعار</h3>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full transition-colors">
            <X size={20} className="text-gray-400" />
          </button>
        </div>

        <div className="p-6 overflow-y-auto">
          {/* Add New Product Form */}
          <form onSubmit={handleSubmit} className="mb-6 bg-gray-700/30 p-4 rounded-xl border border-gray-600">
            <h4 className="text-sm font-bold text-gray-300 mb-3">إضافة مادة جديدة للقائمة</h4>
            <div className="flex flex-col gap-3">
                <input
                    type="text"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    placeholder="اسم المادة (مثال: كوكيز فانيلا)"
                    className="w-full px-3 py-2 bg-gray-900 border border-gray-600 text-white rounded-lg focus:ring-1 focus:ring-[#FA8072] outline-none text-sm"
                    required
                />

                <div className="flex gap-2">
                    <input
                        type="number"
                        value={price}
                        onChange={(e) => setPrice(e.target.value)}
                        placeholder="السعر"
                        className="flex-grow px-3 py-2 bg-gray-900 border border-gray-600 text-white rounded-lg focus:ring-1 focus:ring-[#FA8072] outline-none text-sm"
                        required
                    />

                     {/* Unit Type Selector */}
                    <div className="flex bg-gray-900 rounded-lg p-1 border border-gray-600 shrink-0">
                        <button
                            type="button"
                            onClick={() => setUnitType('piece')}
                            className={`flex items-center gap-1 px-3 py-1.5 rounded-md text-xs transition-colors ${unitType === 'piece' ? 'bg-[#FA8072] text-white font-bold' : 'text-gray-400 hover:text-white'}`}
                        >
                            <Box size={14} />
                            قطعة
                        </button>
                        <button
                            type="button"
                            onClick={() => setUnitType('kg')}
                            className={`flex items-center gap-1 px-3 py-1.5 rounded-md text-xs transition-colors ${unitType === 'kg' ? 'bg-[#FA8072] text-white font-bold' : 'text-gray-400 hover:text-white'}`}
                        >
                            <Scale size={14} />
                            كيلو
                        </button>
                    </div>
                </div>

                <button 
                    type="submit"
                    className="w-full bg-[#FA8072] hover:bg-[#e67365] text-white py-2.5 rounded-lg transition-colors flex items-center justify-center gap-2 font-bold mt-1 shadow-lg shadow-[#FA8072]/20"
                >
                    <Plus size={18} />
                    <span>إضافة المادة</span>
                </button>
            </div>
          </form>

          {/* Product List */}
          <div className="space-y-2">
            <h4 className="text-sm font-bold text-gray-400 mb-2">قائمة المواد الحالية ({products.length})</h4>
            {products.length === 0 ? (
              <p className="text-gray-500 text-center py-4 text-sm">لا توجد مواد مضافة بعد.</p>
            ) : (
              <div className="grid gap-2">
                {products.map(product => (
                  <div key={product.id} className="flex justify-between items-center bg-gray-700 p-3 rounded-lg border border-gray-600">
                    <div>
                      <div className="flex items-center gap-2">
                          <span className="text-white font-medium">{product.name}</span>
                          <span className={`text-[10px] px-1.5 py-0.5 rounded text-black font-bold ${product.unitType === 'kg' ? 'bg-yellow-400' : 'bg-blue-300'}`}>
                              {product.unitType === 'kg' ? 'كيلو' : 'قطعة'}
                          </span>
                      </div>
                      <span className="text-[#FA8072] text-sm font-bold">{product.price.toLocaleString('en-US')} ل.س</span>
                    </div>

                    {/* Delete Action with Confirmation */}
                    {confirmDeleteId === product.id ? (
                        <div className="flex items-center gap-2 animate-fade-up">
                            <span className="text-xs text-red-300">حذف؟</span>
                            <button
                                type="button"
                                onClick={(e) => {
                                    e.stopPropagation();
                                    onDeleteProduct(product.id);
                                    setConfirmDeleteId(null);
                                }}
                                className="bg-red-500 hover:bg-red-600 text-white px-3 py-1 rounded text-xs font-bold transition-colors"
                            >
                                نعم
                            </button>
                            <button
                                type="button"
                                onClick={(e) => {
                                    e.stopPropagation();
                                    setConfirmDeleteId(null);
                                }}
                                className="bg-gray-600 hover:bg-gray-500 text-white px-2 py-1 rounded text-xs transition-colors"
                            >
                                لا
                            </button>
                        </div>
                    ) : (
                        <button 
                          type="button"
                          onClick={(e) => {
                            e.preventDefault();
                            e.stopPropagation();
                            setConfirmDeleteId(product.id);
                          }}
                          className="text-gray-400 hover:text-red-400 p-2 transition-colors cursor-pointer"
                          title="حذف من القائمة"
                        >
                          <Trash2 size={18} />
                        </button>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, Suspense } from 'react';
import { Header } from './components/Header';
import { POSInterface } from './components/RecipeGenerator';
import { SalesTable } from './components/Menu';
import { Summary } from './components/InfoBox';
import { Login } from './components/Login';
import { SaleItem, Product, ArchivedDay, SaleType, Customer } from './types';
import { Save, RotateCcw, X, Loader2 } from 'lucide-react';

const InvoiceModal = React.lazy(() => import('./components/InvoiceModal').then(module => ({ default: module.InvoiceModal })));
const ProductManager = React.lazy(() => import('./components/ProductManager').then(module => ({ default: module.ProductManager })));
const HistoryModal = React.lazy(() => import('./components/HistoryModal').then(module => ({ default: module.HistoryModal })));
const DataManagementModal = React.lazy(() => import('./components/DataManagementModal').then(module => ({ default: module.DataManagementModal })));
const CustomerManager = React.lazy(() => import('./components/CustomerManager').then(module => ({ default: module.CustomerManager })));

const DEFAULT_PRODUCTS: Product[] = [];

const useOnlineStatus = () => {
  const [isOnline, setIsOnline] = useState(() => navigator.onLine);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    const intervalId = setInterval(() => {
      if (navigator.onLine !== isOnline) setIsOnline(navigator.onLine);
    }, 2000);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
      clearInterval(intervalId);
    };
  }, [isOnline]);
  return isOnline;
};

const ModalLoader = () => (
    <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center backdrop-blur-sm">
        <div className="bg-gray-800 p-4 rounded-full shadow-xl border border-gray-700">
            <Loader2 className="animate-spin text-[#FA8072]" size={32} />
        </div>
    </div>
);

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => sessionStorage.getItem('isAuth') === 'true');
  const isOnline = useOnlineStatus();
  const [lastSyncTime, setLastSyncTime] = useState<Date>(new Date());
  const [isSyncing, setIsSyncing] = useState(false);
  const [installPrompt, setInstallPrompt] = useState<any>(null);

  // Core Data State
  const [sales, setSales] = useState<SaleItem[]>(() => {
    const saved = localStorage.getItem('dailySales');
    return saved ? JSON.parse(saved) : [];
  });
  const [history, setHistory] = useState<ArchivedDay[]>(() => {
    const saved = localStorage.getItem('salesHistory');
    return saved ? JSON.parse(saved) : [];
  });
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('products');
    return saved ? JSON.parse(saved) : DEFAULT_PRODUCTS;
  });
  const [customers, setCustomers] = useState<Customer[]>(() => {
      const saved = localStorage.getItem('customers');
      return saved ? JSON.parse(saved) : [];
  });

  // UI State
  const [invoiceItems, setInvoiceItems] = useState<SaleItem[] | null>(null); // For Invoice Modal
  const [showProductManager, setShowProductManager] = useState(false);
  const [showCustomerManager, setShowCustomerManager] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [showDataModal, setShowDataModal] = useState(false);

  const [undoState, setUndoState] = useState<{ items: SaleItem[], timerId: ReturnType<typeof setTimeout> } | null>(null);

  useEffect(() => {
    if (navigator.storage && navigator.storage.persist) {
      navigator.storage.persist().then(granted => {
        if (granted) console.log("Storage persistence granted");
      });
    }
  }, []);

  useEffect(() => {
    const handleBeforeInstallPrompt = (e: any) => {
      e.preventDefault();
      setInstallPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    return () => window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
  }, []);

  const handleInstallClick = async () => {
    if (!installPrompt) return;
    installPrompt.prompt();
    const { outcome } = await installPrompt.userChoice;
    console.log(`User response: ${outcome}`);
    setInstallPrompt(null);
  };

  const updateLastSync = () => setLastSyncTime(new Date());

  useEffect(() => { localStorage.setItem('dailySales', JSON.stringify(sales)); updateLastSync(); }, [sales]);
  useEffect(() => { localStorage.setItem('salesHistory', JSON.stringify(history)); updateLastSync(); }, [history]);
  useEffect(() => { localStorage.setItem('products', JSON.stringify(products)); updateLastSync(); }, [products]);
  useEffect(() => { localStorage.setItem('customers', JSON.stringify(customers)); updateLastSync(); }, [customers]);

  const handleManualSync = () => {
    setIsSyncing(true);
    setTimeout(() => {
      localStorage.setItem('dailySales', JSON.stringify(sales));
      localStorage.setItem('salesHistory', JSON.stringify(history));
      localStorage.setItem('products', JSON.stringify(products));
      localStorage.setItem('customers', JSON.stringify(customers));
      setLastSyncTime(new Date());
      setIsSyncing(false);
    }, 800);
  };

  const handleLogin = () => { setIsAuthenticated(true); sessionStorage.setItem('isAuth', 'true'); };

  const getNextCustomerNumber = () => {
      if (sales.length === 0) return 1;
      const maxNum = Math.max(...sales.map(s => s.customerNumber || 0));
      return maxNum + 1;
  };

  // Enhanced Order Completion
  const handleCompleteOrder = (
      newItems: Omit<SaleItem, 'id' | 'time' | 'customerNumber' | 'orderId'>[], 
      customerName?: string, 
      customerId?: string,
      saleType: SaleType = 'retail'
    ) => {
    // Force English numerals for time
    const currentTime = new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
    const orderId = Date.now().toString(); 
    const customerNumber = getNextCustomerNumber(); 

    const itemsWithIds: SaleItem[] = newItems.map(item => ({
        ...item,
        id: Math.random().toString(36).substr(2, 9), 
        orderId,
        customerNumber,
        customerName: customerName || undefined,
        customerId,
        saleType,
        time: currentTime
    }));

    setSales(prev => [...prev, ...itemsWithIds]);
  };

  const handleDeleteItem = (id: string) => {
    const itemToDelete = sales.find(item => String(item.id) === String(id));
    if (!itemToDelete) return;
    if (undoState?.timerId) clearTimeout(undoState.timerId);
    setSales(prev => prev.filter(item => String(item.id) !== String(id)));
    const timerId = setTimeout(() => setUndoState(null), 5000);
    setUndoState({ items: [itemToDelete], timerId });
  };

  const handleDeleteOrder = (orderId: string) => {
    const itemsToDelete = sales.filter(item => String(item.orderId) === String(orderId));
    if (itemsToDelete.length === 0) return;
    if (undoState?.timerId) clearTimeout(undoState.timerId);
    setSales(prev => prev.filter(item => String(item.orderId) !== String(orderId)));
    const timerId = setTimeout(() => setUndoState(null), 5000);
    setUndoState({ items: itemsToDelete, timerId });
  };

  const handleUndo = () => {
      if (!undoState) return;
      if (undoState.timerId) clearTimeout(undoState.timerId);
      setSales(prev => [...prev, ...undoState.items]);
      setUndoState(null);
  };

  const handleEndDay = () => {
    if (sales.length === 0) { alert('لا توجد مبيعات لترحيلها.'); return; }
    if (confirm('سيتم إغلاق اليوم وتفريغ المبيعات الحالية للأرشيف. هل أنت متأكد؟')) {
        const totalRevenue = sales.reduce((sum, item) => sum + (item.price * item.quantity), 0);
        const totalItems = sales.reduce((sum, item) => sum + item.quantity, 0);
        const daySummary: ArchivedDay = {
            id: Date.now().toString(),
            // Force English numerals for date
            date: new Date().toLocaleDateString('en-GB'),
            timestamp: Date.now(),
            totalRevenue,
            totalItems,
            items: [...sales]
        };
        setHistory(prev => [daySummary, ...prev]);
        setSales([]);
        setUndoState(null);
        alert('تم إغلاق اليوم بنجاح.');
    }
  };

  const handleAddProduct = (newProduct: Omit<Product, 'id'>) => {
    setProducts(prev => [...prev, { ...newProduct, id: Date.now().toString() }]);
  };
  const handleDeleteProduct = (id: string) => {
    setProducts(prev => prev.filter(p => String(p.id) !== String(id)));
  };

  const handleAddCustomer = (newCustomer: Omit<Customer, 'id'>) => {
      setCustomers(prev => [...prev, { ...newCustomer, id: Date.now().toString() }]);
  };
  const handleDeleteCustomer = (id: string) => {
      setCustomers(prev => prev.filter(c => c.id !== id));
  };

  const handleExportData = () => {
    const data = { appVersion: '1.1', timestamp: Date.now(), sales, history, products, customers };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    // Filename with English numerals
    link.download = `cookies-bakery-backup-${new Date().toLocaleDateString('en-GB').replace(/\//g, '-')}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleImportData = (file: File) => {
      const reader = new FileReader();
      reader.onload = (e) => {
          try {
              const data = JSON.parse(e.target?.result as string);
              if (!data || typeof data !== 'object') throw new Error('Invalid file');
              if (Array.isArray(data.sales)) setSales(data.sales);
              if (Array.isArray(data.history)) setHistory(data.history);
              if (Array.isArray(data.products)) setProducts(data.products);
              if (Array.isArray(data.customers)) setCustomers(data.customers);
              alert('تم استعادة البيانات بنجاح!');
          } catch (error) { alert('خطأ في قراءة الملف.'); }
      };
      reader.readAsText(file);
  };

  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  return (
    <div className="min-h-screen flex flex-col bg-gray-900 print:bg-white">
      <Header 
        onOpenHistory={() => setShowHistory(true)} 
        onOpenDataManagement={() => setShowDataModal(true)}
        isOnline={isOnline}
        lastSyncTime={lastSyncTime}
        onManualSync={handleManualSync}
        isSyncing={isSyncing}
        installPrompt={installPrompt}
        onInstall={handleInstallClick}
      />

      <main className="flex-grow container mx-auto px-4 py-6 max-w-5xl">
        <div className="hidden print:block text-center mb-8 border-b-2 border-black pb-4">
            <h1 className="text-3xl font-bold mb-2 text-black">تقرير المبيعات اليومي</h1>
            <p className="text-gray-600">التاريخ: {new Date().toLocaleDateString('en-GB')}</p>
        </div>

        {/* Summary shows total, onPreview loads ALL sales into modal */}
        <Summary items={sales} onPreview={() => setInvoiceItems(sales)} />

        <div className="mb-8">
            <POSInterface 
                onCompleteOrder={handleCompleteOrder} 
                products={products}
                customers={customers}
                onOpenProductManager={() => setShowProductManager(true)}
                onOpenCustomerManager={() => setShowCustomerManager(true)}
            />
        </div>

        <div className="mb-20 print:mb-0 border-t border-gray-700 pt-8">
            <div className="flex items-center justify-between mb-4 no-print">
                <h3 className="text-xl font-bold text-white">سجل الزبائن والمبيعات (اليوم الحالي)</h3>
                {sales.length > 0 && (
                    <button 
                        onClick={handleEndDay}
                        className="flex items-center gap-2 bg-green-900/40 hover:bg-green-900/60 text-green-400 px-4 py-2 rounded-xl transition-colors border border-green-800"
                    >
                        <Save size={18} />
