import React, { useState, useMemo } from 'react';
import { Plus, Trash2, X, Wallet, ShoppingCart, Calendar, ChevronDown, ChevronUp, FileText, Folder } from 'lucide-react';
import { PurchaseInvoice, PurchaseItem, ArchivedDay } from '../types';

interface ExpensesModalProps {
  currentPurchases: PurchaseInvoice[];
  archivedHistory: ArchivedDay[]; // To show past invoices
  onAddInvoice: (invoice: PurchaseInvoice) => void;
  onDeleteInvoice: (id: string) => void;
  isOpen: boolean;
  onClose: () => void;
}

type Tab = 'new' | 'history';

export const ExpensesModal: React.FC<ExpensesModalProps> = ({ 
  currentPurchases, 
  archivedHistory,
  onAddInvoice, 
  onDeleteInvoice,
  isOpen,
  onClose
}) => {
  const [activeTab, setActiveTab] = useState<Tab>('new');

  // -- New Invoice State --
  const [supplierName, setSupplierName] = useState('');
  const [itemInputs, setItemInputs] = useState({ name: '', quantity: '', cost: '' });
  const [currentInvoiceItems, setCurrentInvoiceItems] = useState<PurchaseItem[]>([]);

  // -- History View State --
  const [selectedYear, setSelectedYear] = useState<string>('All');
  const [selectedMonth, setSelectedMonth] = useState<string>('All');

  // --- Logic: Add Item to temporary list ---
  const addItemToInvoice = () => {
      if (!itemInputs.name || !itemInputs.quantity || !itemInputs.cost) return;
      const qty = parseFloat(itemInputs.quantity);
      const cost = parseFloat(itemInputs.cost);

      const newItem: PurchaseItem = {
          id: Date.now().toString(),
          name: itemInputs.name,
          quantity: qty,
          cost: cost,
          total: qty * cost
      };

      setCurrentInvoiceItems(prev => [...prev, newItem]);
      setItemInputs({ name: '', quantity: '', cost: '' }); // Reset inputs
      // Keep focus logic if needed, but simple reset is fine
  };

  const removeItemFromInvoice = (itemId: string) => {
      setCurrentInvoiceItems(prev => prev.filter(i => i.id !== itemId));
  };

  // --- Logic: Save Invoice ---
  const handleSaveInvoice = () => {
      if (!supplierName || currentInvoiceItems.length === 0) {
          alert('يرجى إدخال اسم المورد وإضافة مادة واحدة على الأقل.');
          return;
      }

      const totalAmount = currentInvoiceItems.reduce((sum, item) => sum + item.total, 0);
      const newInvoice: PurchaseInvoice = {
          id: Date.now().toString(),
          supplierName,
          date: new Date().toLocaleDateString('en-GB'),
          timestamp: Date.now(),
          items: currentInvoiceItems,
          totalAmount
      };

      onAddInvoice(newInvoice);

      // Reset Form
      setSupplierName('');
      setCurrentInvoiceItems([]);
      alert('تم حفظ فاتورة المشتريات بنجاح');
  };

  // --- Logic: Grouping History Data ---
  const allInvoices = useMemo(() => {
      // Combine today's purchases with archived purchases
      let all: PurchaseInvoice[] = [...currentPurchases];
      archivedHistory.forEach(day => {
          if (day.purchaseInvoices) {
              all = [...all, ...day.purchaseInvoices];
          }
      });
      return all.sort((a, b) => b.timestamp - a.timestamp); // Newest first
  }, [currentPurchases, archivedHistory]);

  const years = useMemo(() => Array.from(new Set(allInvoices.map(inv => new Date(inv.timestamp).getFullYear().toString()))), [allInvoices]);

  const filteredInvoices = useMemo(() => {
      return allInvoices.filter(inv => {
          const d = new Date(inv.timestamp);
          const y = d.getFullYear().toString();
          const m = (d.getMonth() + 1).toString();

          if (selectedYear !== 'All' && y !== selectedYear) return false;
          if (selectedMonth !== 'All' && m !== selectedMonth) return false;
          return true;
      });
  }, [allInvoices, selectedYear, selectedMonth]);

  const getMonthName = (m: number) => new Date(2000, m - 1).toLocaleString('ar-SY', { month: 'long' });

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-2xl w-full max-w-2xl shadow-2xl border border-gray-700 animate-fade-up flex flex-col h-[85vh]">

        {/* Header */}
        <div className="p-4 border-b border-gray-700 flex justify-between items-center bg-gray-900/50 rounded-t-2xl shrink-0">
          <div className="flex items-center gap-2 text-white">
            <ShoppingCart size={20} className="text-red-400" />
            <h3 className="font-bold text-lg">إدارة المشتريات والموردين</h3>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full transition-colors">
            <X size={20} className="text-gray-400" />
          </button>
        </div>

        {/* Tabs */}
        <div className="flex border-b border-gray-700 bg-gray-700/20">
            <button 
                onClick={() => setActiveTab('new')}
                className={`flex-1 py-3 text-sm font-bold transition-colors flex items-center justify-center gap-2 ${activeTab === 'new' ? 'bg-[#FA8072] text-white' : 'text-gray-400 hover:text-white hover:bg-gray-700'}`}
            >
                <Plus size={16} />
                فاتورة شراء جديدة
            </button>
            <button 
                onClick={() => setActiveTab('history')}
                className={`flex-1 py-3 text-sm font-bold transition-colors flex items-center justify-center gap-2 ${activeTab === 'history' ? 'bg-[#FA8072] text-white' : 'text-gray-400 hover:text-white hover:bg-gray-700'}`}
            >
                <Folder size={16} />
                أرشيف الفواتير
            </button>
        </div>

        {/* Content */}
        <div className="p-6 overflow-y-auto flex-1 bg-gray-900/30">

          {/* === TAB 1: NEW INVOICE === */}
          {activeTab === 'new' && (
              <div className="space-y-6 animate-fade-up">
                  {/* Supplier Info */}
                  <div className="bg-gray-800 p-4 rounded-xl border border-gray-700">
                      <label className="text-xs text-gray-400 mb-1 block">اسم المورد / المصدر</label>
                      <input 
                          type="text" 
                          value={supplierName}
                          onChange={e => setSupplierName(e.target.value)}
                          className="w-full bg-gray-900 border border-gray-600 rounded-lg px-3 py-2 text-white outline-none focus:border-red-400"
                          placeholder="مثال: شركة النور، أبو محمد للخضار..."
                      />
                  </div>

                  {/* Item Entry */}
                  <div className="bg-gray-800 p-4 rounded-xl border border-gray-700">
                      <h4 className="text-sm font-bold text-white mb-3 flex items-center gap-2">
                          <Plus size={16} className="text-red-400" />
                          إضافة أصناف للفاتورة
                      </h4>
                      <div className="grid grid-cols-12 gap-2">
                          <div className="col-span-5">
                              <input 
                                  type="text" 
                                  value={itemInputs.name}
                                  onChange={e => setItemInputs({...itemInputs, name: e.target.value})}
                                  placeholder="اسم الصنف (طحين، سكر...)"
                                  className="w-full bg-gray-900 border border-gray-600 rounded-lg px-2 py-2 text-white text-sm outline-none focus:border-red-400"
                              />
                          </div>
                          <div className="col-span-3">
                              <input 
                                  type="number" 
                                  value={itemInputs.quantity}
                                  onChange={e => setItemInputs({...itemInputs, quantity: e.target.value})}
                                  placeholder="الكمية"
                                  className="w-full bg-gray-900 border border-gray-600 rounded-lg px-2 py-2 text-white text-sm outline-none focus:border-red-400 text-center"
                              />
                          </div>
                          <div className="col-span-3">
                               <input 
                                  type="number" 
                                  value={itemInputs.cost}
                                  onChange={e => setItemInputs({...itemInputs, cost: e.target.value})}
                                  placeholder="السعر"
                                  className="w-full bg-gray-900 border border-gray-600 rounded-lg px-2 py-2 text-white text-sm outline-none focus:border-red-400 text-center"
                              />
                          </div>
                          <div className="col-span-1">
                              <button 
                                  onClick={addItemToInvoice}
                                  className="w-full h-full bg-red-600 hover:bg-red-500 text-white rounded-lg flex items-center justify-center transition-colors"
                              >
                                  <Plus size={18} />
                              </button>
                          </div>
                      </div>
                  </div>

                  {/* Items List Table */}
                  <div className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden min-h-[150px]">
                      <table className="w-full text-sm text-right">
                          <thead className="bg-gray-900 text-gray-400 text-xs">
                              <tr>
                                  <th className="p-3">المادة</th>
                                  <th className="p-3 text-center">الكمية</th>
                                  <th className="p-3">السعر</th>
                                  <th className="p-3">الإجمالي</th>
                                  <th className="p-3 w-10"></th>
                              </tr>
                          </thead>
                          <tbody className="divide-y divide-gray-700">
                              {currentInvoiceItems.length === 0 ? (
                                  <tr>
                                      <td colSpan={5} className="text-center py-8 text-gray-500">لم يتم إضافة أصناف بعد</td>
                                  </tr>
                              ) : (
                                  currentInvoiceItems.map(item => (
                                      <tr key={item.id} className="hover:bg-gray-700/50">
                                          <td className="p-3 text-white">{item.name}</td>
                                          <td className="p-3 text-center text-gray-300">{item.quantity}</td>
                                          <td className="p-3 text-gray-300">{item.cost.toLocaleString('en-US')}</td>
                                          <td className="p-3 font-bold text-red-400">{item.total.toLocaleString('en-US')}</td>
                                          <td className="p-3">
                                              <button onClick={() => removeItemFromInvoice(item.id)} className="text-gray-500 hover:text-red-500">
                                                  <Trash2 size={14} />
                                              </button>
                                          </td>
                                      </tr>
                                  ))
                              )}
                          </tbody>
                      </table>
                  </div>

                  {/* Footer Total */}
                  <div className="flex items-center justify-between bg-gray-800 p-4 rounded-xl border border-gray-700">
                      <div>
                          <p className="text-gray-400 text-xs">إجمالي الفاتورة</p>
                          <h3 className="text-2xl font-bold text-red-400">
                              {currentInvoiceItems.reduce((sum, i) => sum + i.total, 0).toLocaleString('en-US')} <span className="text-sm">ل.س</span>
                          </h3>
                      </div>
                      <button 
                          onClick={handleSaveInvoice}
                          className="bg-green-600 hover:bg-green-500 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2 shadow-lg"
                      >
                          <FileText size={18} />
                          حفظ الفاتورة
                      </button>
                  </div>
              </div>
          )}

          {/* === TAB 2: HISTORY === */}
          {activeTab === 'history' && (
              <div className="space-y-4 animate-fade-up">

                  {/* Filters */}
                  <div className="flex gap-2 bg-gray-800 p-3 rounded-xl border border-gray-700">
                      <div className="flex-1">
                          <select 
                              value={selectedYear} 
                              onChange={(e) => setSelectedYear(e.target.value)}
                              className="w-full bg-gray-900 border border-gray-600 text-white rounded-lg px-3 py-2 text-sm outline-none"
                          >
                              <option value="All">كل السنوات</option>
                              {years.map(y => <option key={y} value={y}>{y}</option>)}
                          </select>
                      </div>
                      <div className="flex-1">
                          <select 
                              value={selectedMonth} 
                              onChange={(e) => setSelectedMonth(e.target.value)}
                              className="w-full bg-gray-900 border border-gray-600 text-white rounded-lg px-3 py-2 text-sm outline-none"
                          >
                              <option value="All">كل الأشهر</option>
                              {Array.from({length: 12}, (_, i) => i + 1).map(m => (
                                  <option key={m} value={m}>{m} - {getMonthName(m)}</option>
                              ))}
                          </select>
                      </div>
                  </div>

                  {/* List */}
                  <div className="space-y-3">
                      {filteredInvoices.length === 0 ? (
                          <div className="text-center py-10 text-gray-500">لا توجد فواتير مطابقة للتصفية.</div>
                      ) : (
                          filteredInvoices.map(invoice => (
                              <div key={invoice.id} className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden group">
                                  <div className="p-4 flex items-center justify-between bg-gray-800 hover:bg-gray-700/50 transition-colors">
                                      <div>
                                          <div className="flex items-center gap-2 mb-1">
                                              <span className="font-bold text-white text-lg">{invoice.supplierName}</span>
                                              <span className="text-xs bg-gray-700 text-gray-300 px-2 py-0.5 rounded-md border border-gray-600">{invoice.date}</span>
                                          </div>
                                          <p className="text-xs text-gray-500">{invoice.items.length} صنف</p>
                                      </div>
                                      <div className="text-left">
                                           <div className="font-bold text-red-400 text-lg">{invoice.totalAmount.toLocaleString('en-US')} ل.س</div>
                                           {/* Only allow deleting if it's in the current active session (optional logic, simplified here to always allow delete if needed, or pass logic) */}
                                           {currentPurchases.find(p => p.id === invoice.id) && (
                                                <button 
                                                    onClick={(e) => { e.stopPropagation(); onDeleteInvoice(invoice.id); }}
                                                    className="text-gray-600 hover:text-red-500 text-xs mt-1 underline"
                                                >
                                                    حذف الفاتورة
                                                </button>
                                           )}
                                      </div>
                                  </div>

                                  {/* Expanded details (simple view) */}
                                  <div className="bg-gray-900/50 p-3 border-t border-gray-700">
                                      <table className="w-full text-xs text-right text-gray-400">
                                          <thead>
                                              <tr className="border-b border-gray-700/50">
                                                  <th className="pb-1">المادة</th>
                                                  <th className="pb-1">الكمية</th>
                                                  <th className="pb-1">السعر</th>
                                                  <th className="pb-1">الإجمالي</th>
                                              </tr>
                                          </thead>
                                          <tbody className="divide-y divide-gray-800">
                                              {invoice.items.map(item => (
                                                  <tr key={item.id}>
                                                      <td className="py-1 text-gray-300">{item.name}</td>
                                                      <td className="py-1">{item.quantity}</td>
                                                      <td className="py-1">{item.cost.toLocaleString('en-US')}</td>
                                                      <td className="py-1 text-red-400">{item.total.toLocaleString('en-US')}</td>
                                                  </tr>
                                              ))}
                                          </tbody>
                                      </table>
                                  </div>
                              </div>
                          ))
                      )}
                  </div>
              </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, Suspense } from 'react';
import { Header } from './components/Header';
import { POSInterface } from './components/RecipeGenerator';
import { SalesTable } from './components/Menu';
import { Summary } from './components/InfoBox';
import { Login } from './components/Login';
import { SaleItem, Product, ArchivedDay, SaleType, Customer, PurchaseInvoice } from './types';
import { Save, RotateCcw, X, Loader2 } from 'lucide-react';

const InvoiceModal = React.lazy(() => import('./components/InvoiceModal').then(module => ({ default: module.InvoiceModal })));
const ProductManager = React.lazy(() => import('./components/ProductManager').then(module => ({ default: module.ProductManager })));
const HistoryModal = React.lazy(() => import('./components/HistoryModal').then(module => ({ default: module.HistoryModal })));
const DataManagementModal = React.lazy(() => import('./components/DataManagementModal').then(module => ({ default: module.DataManagementModal })));
const CustomerManager = React.lazy(() => import('./components/CustomerManager').then(module => ({ default: module.CustomerManager })));
const ExpensesModal = React.lazy(() => import('./components/ExpensesModal').then(module => ({ default: module.ExpensesModal })));

const DEFAULT_PRODUCTS: Product[] = [];

const useOnlineStatus = () => {
  const [isOnline, setIsOnline] = useState(() => navigator.onLine);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    const intervalId = setInterval(() => {
      if (navigator.onLine !== isOnline) setIsOnline(navigator.onLine);
    }, 2000);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
      clearInterval(intervalId);
    };
  }, [isOnline]);
  return isOnline;
};

const ModalLoader = () => (
    <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center backdrop-blur-sm">
        <div className="bg-gray-800 p-4 rounded-full shadow-xl border border-gray-700">
            <Loader2 className="animate-spin text-[#FA8072]" size={32} />
        </div>
    </div>
);

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => sessionStorage.getItem('isAuth') === 'true');
  const isOnline = useOnlineStatus();
  const [lastSyncTime, setLastSyncTime] = useState<Date>(new Date());
  const [isSyncing, setIsSyncing] = useState(false);
  const [installPrompt, setInstallPrompt] = useState<any>(null);

  // Core Data State
  const [sales, setSales] = useState<SaleItem[]>(() => {
    const saved = localStorage.getItem('dailySales');
    return saved ? JSON.parse(saved) : [];
  });
  // Changed from expenses to purchaseInvoices
  const [purchaseInvoices, setPurchaseInvoices] = useState<PurchaseInvoice[]>(() => {
      const saved = localStorage.getItem('dailyPurchaseInvoices');
      return saved ? JSON.parse(saved) : [];
  });
  const [history, setHistory] = useState<ArchivedDay[]>(() => {
    const saved = localStorage.getItem('salesHistory');
    return saved ? JSON.parse(saved) : [];
  });
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('products');
    return saved ? JSON.parse(saved) : DEFAULT_PRODUCTS;
  });
  const [customers, setCustomers] = useState<Customer[]>(() => {
      const saved = localStorage.getItem('customers');
      return saved ? JSON.parse(saved) : [];
  });

  // UI State
  const [invoiceItems, setInvoiceItems] = useState<SaleItem[] | null>(null); // For Invoice Modal
  const [showProductManager, setShowProductManager] = useState(false);
  const [showCustomerManager, setShowCustomerManager] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [showDataModal, setShowDataModal] = useState(false);
  const [showExpensesModal, setShowExpensesModal] = useState(false);

  const [undoState, setUndoState] = useState<{ items: SaleItem[], timerId: ReturnType<typeof setTimeout> } | null>(null);

  useEffect(() => {
    if (navigator.storage && navigator.storage.persist) {
      navigator.storage.persist().then(granted => {
        if (granted) console.log("Storage persistence granted");
      });
    }
  }, []);

  useEffect(() => {
    const handleBeforeInstallPrompt = (e: any) => {
      e.preventDefault();
      setInstallPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    return () => window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
  }, []);

  const handleInstallClick = async () => {
    if (!installPrompt) return;
    installPrompt.prompt();
    const { outcome } = await installPrompt.userChoice;
    console.log(`User response: ${outcome}`);
    setInstallPrompt(null);
  };

  const updateLastSync = () => setLastSyncTime(new Date());

  useEffect(() => { localStorage.setItem('dailySales', JSON.stringify(sales)); updateLastSync(); }, [sales]);
  // Update storage key for purchaseInvoices
  useEffect(() => { localStorage.setItem('dailyPurchaseInvoices', JSON.stringify(purchaseInvoices)); updateLastSync(); }, [purchaseInvoices]);
  useEffect(() => { localStorage.setItem('salesHistory', JSON.stringify(history)); updateLastSync(); }, [history]);
  useEffect(() => { localStorage.setItem('products', JSON.stringify(products)); updateLastSync(); }, [products]);
  useEffect(() => { localStorage.setItem('customers', JSON.stringify(customers)); updateLastSync(); }, [customers]);

  const handleManualSync = () => {
    setIsSyncing(true);
    setTimeout(() => {
      localStorage.setItem('dailySales', JSON.stringify(sales));
      localStorage.setItem('dailyPurchaseInvoices', JSON.stringify(purchaseInvoices));
      localStorage.setItem('salesHistory', JSON.stringify(history));
      localStorage.setItem('products', JSON.stringify(products));
      localStorage.setItem('customers', JSON.stringify(customers));
      setLastSyncTime(new Date());
      setIsSyncing(false);
    }, 800);
  };

  const handleLogin = () => { setIsAuthenticated(true); sessionStorage.setItem('isAuth', 'true'); };

  const getNextCustomerNumber = () => {
      if (sales.length === 0) return 1;
      const maxNum = Math.max(...sales.map(s => s.customerNumber || 0));
      return maxNum + 1;
  };

  // Enhanced Order Completion
  const handleCompleteOrder = (
      newItems: Omit<SaleItem, 'id' | 'time' | 'customerNumber' | 'orderId'>[], 
      customerName?: string, 
      customerId?: string,
      saleType: SaleType = 'retail'
    ) => {
    // Force English numerals for time
    const currentTime = new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
    const orderId = Date.now().toString(); 
    const customerNumber = getNextCustomerNumber(); 

    const itemsWithIds: SaleItem[] = newItems.map(item => ({
        ...item,
        id: Math.random().toString(36).substr(2, 9), 
        orderId,
        customerNumber,
        customerName: customerName || undefined,
        customerId,
        saleType,
        time: currentTime
    }));

    setSales(prev => [...prev, ...itemsWithIds]);
  };

  const handleDeleteItem = (id: string) => {
    const itemToDelete = sales.find(item => String(item.id) === String(id));
    if (!itemToDelete) return;
    if (undoState?.timerId) clearTimeout(undoState.timerId);
    setSales(prev => prev.filter(item => String(item.id) !== String(id)));
    const timerId = setTimeout(() => setUndoState(null), 5000);
    setUndoState({ items: [itemToDelete], timerId });
  };

  const handleDeleteOrder = (orderId: string) => {
    const itemsToDelete = sales.filter(item => String(item.orderId) === String(orderId));
    if (itemsToDelete.length === 0) return;
    if (undoState?.timerId) clearTimeout(undoState.timerId);
    setSales(prev => prev.filter(item => String(item.orderId) !== String(orderId)));
    const timerId = setTimeout(() => setUndoState(null), 5000);
    setUndoState({ items: itemsToDelete, timerId });
  };

  const handleUndo = () => {
      if (!undoState) return;
      if (undoState.timerId) clearTimeout(undoState.timerId);
      setSales(prev => [...prev, ...undoState.items]);
      setUndoState(null);
  };

  // Purchase Invoices Logic
  const handleAddPurchaseInvoice = (newInvoice: PurchaseInvoice) => {
      setPurchaseInvoices(prev => [...prev, newInvoice]);
  };

  const handleDeletePurchaseInvoice = (id: string) => {
      setPurchaseInvoices(prev => prev.filter(inv => inv.id !== id));
  };

  const handleEndDay = () => {
    if (sales.length === 0 && purchaseInvoices.length === 0) { alert('لا توجد بيانات لترحيلها.'); return; }
    if (confirm('سيتم إغلاق اليوم وتفريغ المبيعات والمشتريات الحالية للأرشيف. هل أنت متأكد؟')) {
        const totalRevenue = sales.reduce((sum, item) => sum + (item.price * item.quantity), 0);
        const totalExpenses = purchaseInvoices.reduce((sum, inv) => sum + inv.totalAmount, 0);
        const totalItems = sales.reduce((sum, item) => sum + item.quantity, 0);

        const daySummary: ArchivedDay = {
            id: Date.now().toString(),
            // Force English numerals for date
            date: new Date().toLocaleDateString('en-GB'),
            timestamp: Date.now(),
            totalRevenue,
            totalExpenses,
            totalItems,
            items: [...sales],
            purchaseInvoices: [...purchaseInvoices] // Store invoices in archive
        };
        setHistory(prev => [daySummary, ...prev]);
        setSales([]);
        setPurchaseInvoices([]);
        setUndoState(null);
        alert('تم إغلاق اليوم بنجاح.');
    }
  };

  const handleAddProduct = (newProduct: Omit<Product, 'id'>) => {
    setProducts(prev => [...prev, { ...newProduct, id: Date.now().toString() }]);
  };
  const handleDeleteProduct = (id: string) => {
    setProducts(prev => prev.filter(p => String(p.id) !== String(id)));
  };

  const handleAddCustomer = (newCustomer: Omit<Customer, 'id'>) => {
      setCustomers(prev => [...prev, { ...newCustomer, id: Date.now().toString() }]);
  };
  const handleDeleteCustomer = (id: string) => {
      setCustomers(prev => prev.filter(c => c.id !== id));
  };

  const handleExportData = () => {
    const data = { appVersion: '1.3', timestamp: Date.now(), sales, purchaseInvoices, history, products, customers };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    // Filename with English numerals
    link.download = `cookies-bakery-backup-${new Date().toLocaleDateString('en-GB').replace(/\//g, '-')}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleImportData = (file: File) => {
      const reader = new FileReader();
      reader.onload = (e) => {
          try {
              const data = JSON.parse(e.target?.result as string);
              if (!data || typeof data !== 'object') throw new Error('Invalid file');
              if (Array.isArray(data.sales)) setSales(data.sales);
              // Handle new Purchase Invoices array or legacy expenses if needed
              if (Array.isArray(data.purchaseInvoices)) setPurchaseInvoices(data.purchaseInvoices);
              else setPurchaseInvoices([]); 

              if (Array.isArray(data.history)) setHistory(data.history);
              if (Array.isArray(data.products)) setProducts(data.products);
              if (Array.isArray(data.customers)) setCustomers(data.customers);
              alert('تم استعادة البيانات بنجاح!');
          } catch (error) { alert('خطأ في قراءة الملف.'); }
      };
      reader.readAsText(file);
  };

  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  return (
    <div className="min-h-screen flex flex-col bg-gray-900 print:bg-white">
      <Header 
        onOpenHistory={() => setShowHistory(true)} 
        onOpenDataManagement={() => setShowDataModal(true)}
        onOpenExpenses={() => setShowExpensesModal(true)}
        isOnline={isOnline}
        lastSyncTime={lastSyncTime}
        onManualSync={handleManualSync}
        isSyncing={isSyncing}
        installPrompt={installPrompt}
        onInstall={handleInstallClick}
      />

      <main className="flex-grow container mx-auto px-4 py-6 max-w-5xl">
        <div className="hidden print:block text-center mb-8 border-b-2 border-black pb-4">
            <h1 className="text-3xl font-bold mb-2 text-black">تقرير المبيعات اليومي</h1>
            <p className="text-gray-600">التاريخ: {new Date().toLocaleDateString('en-GB')}</p>
        </div>

        {/* Summary shows total sales only */}
        <Summary items={sales} onPreview={() => setInvoiceItems(sales)} />

        <div className="mb-8">
            <POSInterface 
                onCompleteOrder={handleCompleteOrder} 
                products={products}
                customers={customers}
                onOpenProductManager={() => setShowProductManager(true)}
                onOpenCustomerManager={() => setShowCustomerManager(true)}
            />
        </div>

        <div className="mb-20 print:mb-0 border-t border-gray-700 pt-8">
            <div className="flex items-center justify-between mb-4 no-print">
                <h3 className="text-xl font-bold text-white">سجل الزبائن والمبيعات (اليوم الحالي)</h3>
                {sales.length > 0 && (
                    <button 
                        onClick={handleEndDay}
                        className="flex items-center gap-2 bg-green-900/40 hover:bg-green-900/60 text-green-400 px-4 py-2 rounded-xl transition-colors border border-green-800"
                    >
                        <Save size={18} />
                        <span className="font-bold">إغلاق اليوم (أرشفة)</span>
                    </button>
                )}
            </div>

            <SalesTable 
                items={sales} 
                onDeleteItem={handleDeleteItem} 
                onDeleteOrder={handleDeleteOrder}
                onPreviewInvoice={(items) => setInvoiceItems(items)}
            />
        </div>
      </main>

      {undoState && (
          <div className="fixed bottom-6 left-1/2 transform -translate-x-1/2 bg-gray-800 text-white px-6 py-3 rounded-xl shadow-2xl border border-gray-700 flex items-center gap-6 z-50 animate-fade-up min-w-[300px] justify-between">
              <span className="text-sm font-medium">تم حذف {undoState.items.length > 1 ? 'الطلب' : 'العنصر'}</span>
              <div className="flex items-center gap-4">
                  <button onClick={handleUndo} className="text-[#FA8072] font-bold text-sm flex items-center gap-1 hover:text-[#ff9a8d]"><RotateCcw size={16} /> تراجع</button>
                  <button onClick={() => { if (undoState.timerId) clearTimeout(undoState.timerId); setUndoState(null); }} className="text-gray-500 hover:text-white border-r border-gray-600 pr-4 mr-1"><X size={16} /></button>
              </div>
          </div>
      )}

      {invoiceItems && (
        <Suspense fallback={<ModalLoader />}>
            <InvoiceModal items={invoiceItems} onClose={() => setInvoiceItems(null)} />
        </Suspense>
      )}

      {showHistory && (
        <Suspense fallback={<ModalLoader />}>
            <HistoryModal 
                history={history} 
                onClose={() => setShowHistory(false)} 
                onClearHistory={() => setHistory([])}
                onPreviewInvoice={(items) => setInvoiceItems(items)}
            />
        </Suspense>
      )}

      {showProductManager && (
         <Suspense fallback={<ModalLoader />}>
            <ProductManager 
                isOpen={showProductManager}
                onClose={() => setShowProductManager(false)}
                products={products}
                onAddProduct={handleAddProduct}
                onDeleteProduct={handleDeleteProduct}
            />
         </Suspense>
      )}

      {showCustomerManager && (
         <Suspense fallback={<ModalLoader />}>
            <CustomerManager 
                isOpen={showCustomerManager}
                onClose={() => setShowCustomerManager(false)}
                customers={customers}
                onAddCustomer={handleAddCustomer}
                onDeleteCustomer={handleDeleteCustomer}
            />
         </Suspense>
      )}

      {showDataModal && (
        <Suspense fallback={<ModalLoader />}>
            <DataManagementModal 
                onClose={() => setShowDataModal(false)}
                onExport={handleExportData}
                onImport={handleImportData}
            />
        </Suspense>
      )}

      {showExpensesModal && (
          <Suspense fallback={<ModalLoader />}>
              <ExpensesModal
                isOpen={showExpensesModal}
                onClose={() => setShowExpensesModal(false)}
                currentPurchases={purchaseInvoices}
                archivedHistory={history}
                onAddInvoice={handleAddPurchaseInvoice}
                onDeleteInvoice={handleDeletePurchaseInvoice}
              />
          </Suspense>
      )}

