  const updateLastSync = () => setLastSyncTime(new Date());

  useEffect(() => { localStorage.setItem('dailySales', JSON.stringify(sales)); updateLastSync(); }, [sales]);
  useEffect(() => { localStorage.setItem('dailyPurchaseInvoices', JSON.stringify(purchaseInvoices)); updateLastSync(); }, [purchaseInvoices]);
  useEffect(() => { localStorage.setItem('salesHistory', JSON.stringify(history)); updateLastSync(); }, [history]);
  useEffect(() => { localStorage.setItem('products', JSON.stringify(products)); updateLastSync(); }, [products]);
  useEffect(() => { localStorage.setItem('customers', JSON.stringify(customers)); updateLastSync(); }, [customers]);
  useEffect(() => { localStorage.setItem('suppliers', JSON.stringify(suppliers)); updateLastSync(); }, [suppliers]);

  const handleManualSync = () => {
    setIsSyncing(true);
    setTimeout(() => {
      localStorage.setItem('dailySales', JSON.stringify(sales));
      localStorage.setItem('dailyPurchaseInvoices', JSON.stringify(purchaseInvoices));
      localStorage.setItem('salesHistory', JSON.stringify(history));
      localStorage.setItem('products', JSON.stringify(products));
      localStorage.setItem('customers', JSON.stringify(customers));
      localStorage.setItem('suppliers', JSON.stringify(suppliers));
      setLastSyncTime(new Date());
      setIsSyncing(false);
    }, 800);
  };

  const handleLogin = () => { setIsAuthenticated(true); sessionStorage.setItem('isAuth', 'true'); };

  const getNextCustomerNumber = () => {
      if (sales.length === 0) return 1;
      const maxNum = Math.max(...sales.map(s => s.customerNumber || 0));
      return maxNum + 1;
  };

  // Enhanced Order Completion
  const handleCompleteOrder = (
      newItems: Omit<SaleItem, 'id' | 'time' | 'customerNumber' | 'orderId'>[], 
      customerName?: string, 
      customerId?: string,
      saleType: SaleType = 'retail'
    ) => {
    // Force English numerals for time
    const currentTime = new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
    const orderId = Date.now().toString(); 
    const customerNumber = getNextCustomerNumber(); 

    const itemsWithIds: SaleItem[] = newItems.map(item => ({
        ...item,
        id: Math.random().toString(36).substr(2, 9), 
        orderId,
        customerNumber,
        customerName: customerName || undefined,
        customerId,
        saleType,
        time: currentTime
    }));

    setSales(prev => [...prev, ...itemsWithIds]);
  };

  const handleDeleteItem = (id: string) => {
    const itemToDelete = sales.find(item => String(item.id) === String(id));
    if (!itemToDelete) return;
    if (undoState?.timerId) clearTimeout(undoState.timerId);
    setSales(prev => prev.filter(item => String(item.id) !== String(id)));
    const timerId = setTimeout(() => setUndoState(null), 5000);
    setUndoState({ items: [itemToDelete], timerId });
  };

  const handleDeleteOrder = (orderId: string) => {
    const itemsToDelete = sales.filter(item => String(item.orderId) === String(orderId));
    if (itemsToDelete.length === 0) return;
    if (undoState?.timerId) clearTimeout(undoState.timerId);
    setSales(prev => prev.filter(item => String(item.orderId) !== String(orderId)));
    const timerId = setTimeout(() => setUndoState(null), 5000);
    setUndoState({ items: itemsToDelete, timerId });
  };

  const handleUndo = () => {
      if (!undoState) return;
      if (undoState.timerId) clearTimeout(undoState.timerId);
      setSales(prev => [...prev, ...undoState.items]);
      setUndoState(null);
  };

  // Purchase Invoices Logic
  const handleAddPurchaseInvoice = (newInvoice: PurchaseInvoice) => {
      setPurchaseInvoices(prev => [...prev, newInvoice]);
  };

  const handleDeletePurchaseInvoice = (id: string) => {
      setPurchaseInvoices(prev => prev.filter(inv => inv.id !== id));
  };

  const handleEndDay = () => {
    if (sales.length === 0 && purchaseInvoices.length === 0) { alert('لا توجد بيانات لترحيلها.'); return; }
    if (confirm('سيتم إغلاق اليوم وتفريغ المبيعات والمشتريات الحالية للأرشيف. هل أنت متأكد؟')) {
        const totalRevenue = sales.reduce((sum, item) => sum + (item.price * item.quantity), 0);
        const totalExpenses = purchaseInvoices.reduce((sum, inv) => sum + inv.totalAmount, 0);
        const totalItems = sales.reduce((sum, item) => sum + item.quantity, 0);

        const daySummary: ArchivedDay = {
            id: Date.now().toString(),
            // Force English numerals for date
            date: new Date().toLocaleDateString('en-GB'),
            timestamp: Date.now(),
            totalRevenue,
            totalExpenses,
            totalItems,
            items: [...sales],
            purchaseInvoices: [...purchaseInvoices] // Store invoices in archive
        };
        setHistory(prev => [daySummary, ...prev]);
        setSales([]);
        setPurchaseInvoices([]);
        setUndoState(null);
        alert('تم إغلاق اليوم بنجاح.');
    }
  };

  // Product Handlers
  const handleAddProduct = (newProduct: Omit<Product, 'id'>) => {
    setProducts(prev => [...prev, { ...newProduct, id: Date.now().toString() }]);
  };
  const handleDeleteProduct = (id: string) => {
    setProducts(prev => prev.filter(p => String(p.id) !== String(id)));
  };

  // Customer Handlers
  const handleAddCustomer = (newCustomer: Omit<Customer, 'id'>) => {
      setCustomers(prev => [...prev, { ...newCustomer, id: Date.now().toString() }]);
  };
  const handleDeleteCustomer = (id: string) => {
      setCustomers(prev => prev.filter(c => c.id !== id));
  };

  // Supplier Handlers
  const handleAddSupplier = (newSupplier: Omit<Supplier, 'id'>) => {
      setSuppliers(prev => [...prev, { ...newSupplier, id: Date.now().toString() }]);
  };
  const handleDeleteSupplier = (id: string) => {
      setSuppliers(prev => prev.filter(s => s.id !== id));
  };

  const handleExportData = () => {
    const data = { appVersion: '1.3', timestamp: Date.now(), sales, purchaseInvoices, history, products, customers, suppliers };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    // Filename with English numerals
    link.download = `cookies-bakery-backup-${new Date().toLocaleDateString('en-GB').replace(/\//g, '-')}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleImportData = (file: File) => {
      const reader = new FileReader();
      reader.onload = (e) => {
          try {
              const data = JSON.parse(e.target?.result as string);
              if (!data || typeof data !== 'object') throw new Error('Invalid file');
              if (Array.isArray(data.sales)) setSales(data.sales);
              if (Array.isArray(data.purchaseInvoices)) setPurchaseInvoices(data.purchaseInvoices);
              else setPurchaseInvoices([]); 

              if (Array.isArray(data.history)) setHistory(data.history);
              if (Array.isArray(data.products)) setProducts(data.products);
              if (Array.isArray(data.customers)) setCustomers(data.customers);
              if (Array.isArray(data.suppliers)) setSuppliers(data.suppliers);
              alert('تم استعادة البيانات بنجاح!');
          } catch (error) { alert('خطأ في قراءة الملف.'); }
      };
      reader.readAsText(file);
  };

  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  return (
    <div className="min-h-screen flex flex-col bg-gray-900 print:bg-white">
      <Header 
        onOpenHistory={() => setShowHistory(true)} 
        onOpenDataManagement={() => setShowDataModal(true)}
        onOpenExpenses={() => setShowExpensesModal(true)}
        isOnline={isOnline}
        lastSyncTime={lastSyncTime}
        onManualSync={handleManualSync}
        isSyncing={isSyncing}
        installPrompt={installPrompt}
        onInstall={handleInstallClick}
      />

      <main className="flex-grow container mx-auto px-4 py-6 max-w-5xl">
        <div className="hidden print:block text-center mb-8 border-b-2 border-black pb-4">
            <h1 className="text-3xl font-bold mb-2 text-black">تقرير المبيعات اليومي</h1>
            <p className="text-gray-600">التاريخ: {new Date().toLocaleDateString('en-GB')}</p>
        </div>

        {/* Summary shows total sales only */}
        <Summary items={sales} onPreview={() => setInvoiceItems(sales)} />

        <div className="mb-8">
            <POSInterface 
                onCompleteOrder={handleCompleteOrder} 
                products={products}
                customers={customers}
                onOpenProductManager={() => setShowProductManager(true)}
                onOpenCustomerManager={() => setShowCustomerManager(true)}
            />
        </div>

        <div className="mb-20 print:mb-0 border-t border-gray-700 pt-8">
            <div className="flex items-center justify-between mb-4 no-print">
                <h3 className="text-xl font-bold text-white">سجل الزبائن والمبيعات (اليوم الحالي)</h3>
                {sales.length > 0 && (
                    <button 
                        onClick={handleEndDay}
                        className="flex items-center gap-2 bg-green-900/40 hover:bg-green-900/60 text-green-400 px-4 py-2 rounded-xl transition-colors border border-green-800"
                    >
                        <Save size={18} />
                        <span className="font-bold">إغلاق اليوم (أرشفة)</span>
                    </button>
                )}
            </div>

            <SalesTable 
                items={sales} 
                onDeleteItem={handleDeleteItem} 
                onDeleteOrder={handleDeleteOrder}
                onPreviewInvoice={(items) => setInvoiceItems(items)}
            />
        </div>
      </main>

      {undoState && (
          <div className="fixed bottom-6 left-1/2 transform -translate-x-1/2 bg-gray-800 text-white px-6 py-3 rounded-xl shadow-2xl border border-gray-700 flex items-center gap-6 z-50 animate-fade-up min-w-[300px] justify-between">
              <span className="text-sm font-medium">تم حذف {undoState.items.length > 1 ? 'الطلب' : 'العنصر'}</span>
              <div className="flex items-center gap-4">
                  <button onClick={handleUndo} className="text-[#FA8072] font-bold text-sm flex items-center gap-1 hover:text-[#ff9a8d]"><RotateCcw size={16} /> تراجع</button>
                  <button onClick={() => { if (undoState.timerId) clearTimeout(undoState.timerId); setUndoState(null); }} className="text-gray-500 hover:text-white border-r border-gray-600 pr-4 mr-1"><X size={16} /></button>
              </div>
          </div>
      )}

      {invoiceItems && (
        <Suspense fallback={<ModalLoader />}>
            <InvoiceModal items={invoiceItems} onClose={() => setInvoiceItems(null)} />
        </Suspense>
      )}

      {showHistory && (
        <Suspense fallback={<ModalLoader />}>
            <HistoryModal 
                history={history} 
                onClose={() => setShowHistory(false)} 
                onClearHistory={() => setHistory([])}
                onPreviewInvoice={(items) => setInvoiceItems(items)}
            />
        </Suspense>
      )}

      {showProductManager && (
         <Suspense fallback={<ModalLoader />}>
            <ProductManager 
                isOpen={showProductManager}
                onClose={() => setShowProductManager(false)}
                products={products}
                onAddProduct={handleAddProduct}
                onDeleteProduct={handleDeleteProduct}
            />
         </Suspense>
      )}

      {showCustomerManager && (
         <Suspense fallback={<ModalLoader />}>
            <CustomerManager 
                isOpen={showCustomerManager}
                onClose={() => setShowCustomerManager(false)}
                customers={customers}
                onAddCustomer={handleAddCustomer}
                onDeleteCustomer={handleDeleteCustomer}
            />
         </Suspense>
      )}

      {showDataModal && (
        <Suspense fallback={<ModalLoader />}>
            <DataManagementModal 
                onClose={() => setShowDataModal(false)}
                onExport={handleExportData}
                onImport={handleImportData}
            />
        </Suspense>
      )}

      {showExpensesModal && (
          <Suspense fallback={<ModalLoader />}>
              <ExpensesModal
                isOpen={showExpensesModal}
                onClose={() => setShowExpensesModal(false)}
                currentPurchases={purchaseInvoices}
                archivedHistory={history}
                onAddInvoice={handleAddPurchaseInvoice}
                onDeleteInvoice={handleDeletePurchaseInvoice}
                suppliers={suppliers}
                onAddSupplier={handleAddSupplier}
                onDeleteSupplier={handleDeleteSupplier}
              />
          </Suspense>
      )}

      <footer className="text-center py-6 text-gray-500 text-sm no-print mt-auto">
        <p>نظام محاسبة مخبز كوكيز - v1.3</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo, Suspense } from 'react';
import { Plus, Trash2, X, ShoppingCart, Folder, FileText, CheckCircle, Clock, Download, Printer, UserPlus } from 'lucide-react';
import { PurchaseInvoice, PurchaseItem, ArchivedDay, PaymentStatus, Supplier } from '../types';

const PurchasePrintModal = React.lazy(() => import('./PurchasePrintModal').then(module => ({ default: module.PurchasePrintModal })));

interface ExpensesModalProps {
  currentPurchases: PurchaseInvoice[];
  archivedHistory: ArchivedDay[]; 
  onAddInvoice: (invoice: PurchaseInvoice) => void;
  onDeleteInvoice: (id: string) => void;
  isOpen: boolean;
  onClose: () => void;
  // Suppliers Props
  suppliers?: Supplier[];
  onAddSupplier?: (supplier: Omit<Supplier, 'id'>) => void;
  onDeleteSupplier?: (id: string) => void;
}

type Tab = 'new' | 'history';

export const ExpensesModal: React.FC<ExpensesModalProps> = ({ 
  currentPurchases, 
  archivedHistory,
  onAddInvoice, 
  onDeleteInvoice,
  isOpen,
  onClose,
  suppliers = [],
  onAddSupplier,
  onDeleteSupplier
}) => {
  const [activeTab, setActiveTab] = useState<Tab>('new');

  // -- New Invoice State --
  const [supplierName, setSupplierName] = useState('');
  const [paymentStatus, setPaymentStatus] = useState<PaymentStatus>('paid'); 
  const [itemInputs, setItemInputs] = useState({ name: '', quantity: '', cost: '' });
  const [currentInvoiceItems, setCurrentInvoiceItems] = useState<PurchaseItem[]>([]);

  // -- Printing State --
  const [invoiceToPrint, setInvoiceToPrint] = useState<PurchaseInvoice | null>(null);

  // -- History View State --
  const [selectedYear, setSelectedYear] = useState<string>('All');
  const [selectedMonth, setSelectedMonth] = useState<string>('All');

  const addItemToInvoice = () => {
      if (!itemInputs.name || !itemInputs.quantity || !itemInputs.cost) return;
      const qty = parseFloat(itemInputs.quantity);
      const cost = parseFloat(itemInputs.cost);

      const newItem: PurchaseItem = {
          id: Date.now().toString(),
          name: itemInputs.name,
          quantity: qty,
          cost: cost,
          total: qty * cost
      };

      setCurrentInvoiceItems(prev => [...prev, newItem]);
      setItemInputs({ name: '', quantity: '', cost: '' }); 
  };

  const removeItemFromInvoice = (itemId: string) => {
      setCurrentInvoiceItems(prev => prev.filter(i => i.id !== itemId));
  };

  const handleSaveInvoice = () => {
      if (!supplierName || currentInvoiceItems.length === 0) {
          alert('يرجى إدخال اسم المورد وإضافة مادة واحدة على الأقل.');
          return;
      }

      const totalAmount = currentInvoiceItems.reduce((sum, item) => sum + item.total, 0);
      const newInvoice: PurchaseInvoice = {
          id: Date.now().toString(),
          supplierName,
          date: new Date().toLocaleDateString('en-GB'),
          timestamp: Date.now(),
          items: currentInvoiceItems,
          totalAmount,
          paymentStatus
      };

      onAddInvoice(newInvoice);

      setSupplierName('');
      setCurrentInvoiceItems([]);
      setPaymentStatus('paid');
      alert('تم حفظ فاتورة المشتريات بنجاح');
  };

  const handleSaveSupplier = () => {
      if (!supplierName || !onAddSupplier) return;
      // Check if exists
      if (suppliers.some(s => s.name === supplierName)) {
          alert('هذا المورد موجود بالفعل');
          return;
      }
      onAddSupplier({ name: supplierName });
      alert('تم حفظ المورد في القائمة');
  };

  // --- Logic: Grouping History Data ---
  const allInvoices = useMemo(() => {
      let all: PurchaseInvoice[] = [...currentPurchases];
      archivedHistory.forEach(day => {
          if (day.purchaseInvoices) {
              all = [...all, ...day.purchaseInvoices];
          }
      });
      return all.sort((a, b) => b.timestamp - a.timestamp); 
  }, [currentPurchases, archivedHistory]);

  const years = useMemo(() => Array.from(new Set(allInvoices.map(inv => new Date(inv.timestamp).getFullYear().toString()))), [allInvoices]);

  const filteredInvoices = useMemo(() => {
      return allInvoices.filter(inv => {
          const d = new Date(inv.timestamp);
          const y = d.getFullYear().toString();
          const m = (d.getMonth() + 1).toString();

          if (selectedYear !== 'All' && y !== selectedYear) return false;
          if (selectedMonth !== 'All' && m !== selectedMonth) return false;
          return true;
      });
  }, [allInvoices, selectedYear, selectedMonth]);

  const getMonthName = (m: number) => new Date(2000, m - 1).toLocaleString('ar-SY', { month: 'long' });

  if (!isOpen) return null;

  return (
    <>
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-2xl w-full max-w-2xl shadow-2xl border border-gray-700 animate-fade-up flex flex-col h-[85vh]">

        {/* Header */}
        <div className="p-4 border-b border-gray-700 flex justify-between items-center bg-gray-900/50 rounded-t-2xl shrink-0">
          <div className="flex items-center gap-2 text-white">
            <ShoppingCart size={20} className="text-red-400" />
            <h3 className="font-bold text-lg">إدارة المشتريات والموردين</h3>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full transition-colors">
            <X size={20} className="text-gray-400" />
          </button>
        </div>

        {/* Tabs */}
        <div className="flex border-b border-gray-700 bg-gray-700/20">
            <button 
                onClick={() => setActiveTab('new')}
                className={`flex-1 py-3 text-sm font-bold transition-colors flex items-center justify-center gap-2 ${activeTab === 'new' ? 'bg-[#FA8072] text-white' : 'text-gray-400 hover:text-white hover:bg-gray-700'}`}
            >
                <Plus size={16} />
                فاتورة شراء جديدة
            </button>
            <button 
                onClick={() => setActiveTab('history')}
                className={`flex-1 py-3 text-sm font-bold transition-colors flex items-center justify-center gap-2 ${activeTab === 'history' ? 'bg-[#FA8072] text-white' : 'text-gray-400 hover:text-white hover:bg-gray-700'}`}
            >
                <Folder size={16} />
                أرشيف الفواتير
            </button>
        </div>

        {/* Content */}
        <div className="p-6 overflow-y-auto flex-1 bg-gray-900/30">

          {/* === TAB 1: NEW INVOICE === */}
          {activeTab === 'new' && (
              <div className="space-y-6 animate-fade-up">
                  {/* Supplier Info & Payment Status */}
                  <div className="flex flex-col md:flex-row gap-4">
                      <div className="bg-gray-800 p-4 rounded-xl border border-gray-700 flex-grow">
                          <div className="flex justify-between items-center mb-1">
                             <label className="text-xs text-gray-400 block">اسم المورد / المصدر</label>
                             {onAddSupplier && (
                                 <button onClick={handleSaveSupplier} className="text-[10px] text-[#FA8072] hover:underline flex items-center gap-1">
                                     <UserPlus size={10} />
                                     حفظ المورد في القائمة
                                 </button>
                             )}
                          </div>

                          <div className="flex gap-2">
                             <div className="relative flex-grow">
                                <input 
                                    list="suppliers-list"
                                    type="text" 
                                    value={supplierName}
                                    onChange={e => setSupplierName(e.target.value)}
                                    className="w-full bg-gray-900 border border-gray-600 rounded-lg px-3 py-2 text-white outline-none focus:border-red-400"
                                    placeholder="اختر او اكتب اسم المورد..."
                                />
                                <datalist id="suppliers-list">
                                    {suppliers.map(s => (
                                        <option key={s.id} value={s.name} />
                                    ))}
                                </datalist>
                             </div>
                          </div>
                      </div>

                      <div className="bg-gray-800 p-4 rounded-xl border border-gray-700 min-w-[200px]">
                          <label className="text-xs text-gray-400 mb-2 block">حالة الدفع</label>
                          <div className="flex bg-gray-900 p-1 rounded-lg">
                              <button 
                                onClick={() => setPaymentStatus('paid')}
                                className={`flex-1 py-1.5 text-xs font-bold rounded-md transition-colors flex items-center justify-center gap-1 ${paymentStatus === 'paid' ? 'bg-green-600 text-white' : 'text-gray-400 hover:text-white'}`}
                              >
                                  <CheckCircle size={12} />
                                  مدفوع (نقدي)
                              </button>
                              <button 
                                onClick={() => setPaymentStatus('credit')}
                                className={`flex-1 py-1.5 text-xs font-bold rounded-md transition-colors flex items-center justify-center gap-1 ${paymentStatus === 'credit' ? 'bg-orange-600 text-white' : 'text-gray-400 hover:text-white'}`}
                              >
                                  <Clock size={12} />
                                  آجل (ذمم)
                              </button>
                          </div>
                      </div>
                  </div>

                  {/* Item Entry */}
                  <div className="bg-gray-800 p-4 rounded-xl border border-gray-700">
                      <h4 className="text-sm font-bold text-white mb-3 flex items-center gap-2">
                          <Plus size={16} className="text-red-400" />
                          إضافة أصناف للفاتورة
                      </h4>
                      <div className="grid grid-cols-12 gap-2">
                          <div className="col-span-5">
                              <input 
                                  type="text" 
                                  value={itemInputs.name}
                                  onChange={e => setItemInputs({...itemInputs, name: e.target.value})}
                                  placeholder="اسم الصنف (طحين، سكر...)"
                                  className="w-full bg-gray-900 border border-gray-600 rounded-lg px-2 py-2 text-white text-sm outline-none focus:border-red-400"
                              />
                          </div>
                          <div className="col-span-3">
                              <input 
                                  type="number" 
                                  value={itemInputs.quantity}
                                  onChange={e => setItemInputs({...itemInputs, quantity: e.target.value})}
                                  placeholder="الكمية"
                                  className="w-full bg-gray-900 border border-gray-600 rounded-lg px-2 py-2 text-white text-sm outline-none focus:border-red-400 text-center"
                              />
                          </div>
                          <div className="col-span-3">
                               <input 
                                  type="number" 
                                  value={itemInputs.cost}
                                  onChange={e => setItemInputs({...itemInputs, cost: e.target.value})}
                                  placeholder="السعر"
                                  className="w-full bg-gray-900 border border-gray-600 rounded-lg px-2 py-2 text-white text-sm outline-none focus:border-red-400 text-center"
                              />
                          </div>
                          <div className="col-span-1">
                              <button 
                                  onClick={addItemToInvoice}
                                  className="w-full h-full bg-red-600 hover:bg-red-500 text-white rounded-lg flex items-center justify-center transition-colors"
                              >
                                  <Plus size={18} />
                              </button>
                          </div>
                      </div>
                  </div>

                  {/* Items List Table */}
                  <div className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden min-h-[150px]">
                      <table className="w-full text-sm text-right">
                          <thead className="bg-gray-900 text-gray-400 text-xs">
                              <tr>
                                  <th className="p-3">المادة</th>
                                  <th className="p-3 text-center">الكمية</th>
                                  <th className="p-3">السعر</th>
                                  <th className="p-3">الإجمالي</th>
                                  <th className="p-3 w-10"></th>
                              </tr>
                          </thead>
                          <tbody className="divide-y divide-gray-700">
                              {currentInvoiceItems.length === 0 ? (
                                  <tr>
                                      <td colSpan={5} className="text-center py-8 text-gray-500">لم يتم إضافة أصناف بعد</td>
                                  </tr>
                              ) : (
                                  currentInvoiceItems.map(item => (
                                      <tr key={item.id} className="hover:bg-gray-700/50">
                                          <td className="p-3 text-white">{item.name}</td>
                                          <td className="p-3 text-center text-gray-300">{item.quantity}</td>
                                          <td className="p-3 text-gray-300">{item.cost.toLocaleString('en-US')}</td>
                                          <td className="p-3 font-bold text-red-400">{item.total.toLocaleString('en-US')}</td>
                                          <td className="p-3">
                                              <button onClick={() => removeItemFromInvoice(item.id)} className="text-gray-500 hover:text-red-500">
                                                  <Trash2 size={14} />
                                              </button>
                                          </td>
                                      </tr>
                                  ))
                              )}
                          </tbody>
                      </table>
                  </div>

                  {/* Footer Total */}
                  <div className="flex items-center justify-between bg-gray-800 p-4 rounded-xl border border-gray-700">
                      <div>
                          <p className="text-gray-400 text-xs">إجمالي الفاتورة</p>
                          <h3 className="text-2xl font-bold text-red-400">
                              {currentInvoiceItems.reduce((sum, i) => sum + i.total, 0).toLocaleString('en-US')} <span className="text-sm">ل.س</span>
                          </h3>
                      </div>
                      <button 
                          onClick={handleSaveInvoice}
                          className="bg-green-600 hover:bg-green-500 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2 shadow-lg"
                      >
                          <FileText size={18} />
                          حفظ الفاتورة
                      </button>
                  </div>
              </div>
          )}

          {/* === TAB 2: HISTORY === */}
          {activeTab === 'history' && (
              <div className="space-y-4 animate-fade-up">

                  {/* Filters */}
                  <div className="flex gap-2 bg-gray-800 p-3 rounded-xl border border-gray-700">
                      <div className="flex-1">
                          <select 
                              value={selectedYear} 
                              onChange={(e) => setSelectedYear(e.target.value)}
                              className="w-full bg-gray-900 border border-gray-600 text-white rounded-lg px-3 py-2 text-sm outline-none"
                          >
                              <option value="All">كل السنوات</option>
                              {years.map(y => <option key={y} value={y}>{y}</option>)}
                          </select>
                      </div>
                      <div className="flex-1">
                          <select 
                              value={selectedMonth} 
                              onChange={(e) => setSelectedMonth(e.target.value)}
                              className="w-full bg-gray-900 border border-gray-600 text-white rounded-lg px-3 py-2 text-sm outline-none"
                          >
                              <option value="All">كل الأشهر</option>
                              {Array.from({length: 12}, (_, i) => i + 1).map(m => (
                                  <option key={m} value={m}>{m} - {getMonthName(m)}</option>
                              ))}
                          </select>
                      </div>
                  </div>

                  {/* List */}
                  <div className="space-y-3">
                      {filteredInvoices.length === 0 ? (
                          <div className="text-center py-10 text-gray-500">لا توجد فواتير مطابقة للتصفية.</div>
                      ) : (
                          filteredInvoices.map(invoice => (
                              <div key={invoice.id} className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden group">
                                  <div className="p-4 flex items-center justify-between bg-gray-800 hover:bg-gray-700/50 transition-colors">
                                      <div>
                                          <div className="flex items-center gap-2 mb-1">
                                              <span className="font-bold text-white text-lg">{invoice.supplierName}</span>
                                              <span className="text-xs bg-gray-700 text-gray-300 px-2 py-0.5 rounded-md border border-gray-600">{invoice.date}</span>

                                              {/* Payment Status Badge */}
                                              {invoice.paymentStatus === 'credit' ? (
                                                <span className="text-[10px] bg-orange-900/30 text-orange-400 px-2 py-0.5 rounded-md border border-orange-700/50 flex items-center gap-1 font-bold">
                                                    <Clock size={10} />
                                                    آجل (ذمم)
                                                </span>
                                              ) : (
                                                <span className="text-[10px] bg-green-900/30 text-green-400 px-2 py-0.5 rounded-md border border-green-700/50 flex items-center gap-1 font-bold">
                                                    <CheckCircle size={10} />
                                                    مدفوع
                                                </span>
                                              )}
                                          </div>
                                          <p className="text-xs text-gray-500">{invoice.items.length} صنف</p>
                                      </div>
                                      <div className="text-left flex items-center gap-3">
                                           <div className="font-bold text-red-400 text-lg">{invoice.totalAmount.toLocaleString('en-US')} ل.س</div>
                                           <button 
                                                onClick={(e) => { e.stopPropagation(); setInvoiceToPrint(invoice); }}
                                                className="bg-gray-700 hover:bg-[#FA8072] text-white p-2 rounded-lg transition-colors shadow-sm"
                                                title="طباعة PDF"
                                            >
                                                <Printer size={16} />
                                            </button>
                                           {currentPurchases.find(p => p.id === invoice.id) && (
                                                <button 
                                                    onClick={(e) => { e.stopPropagation(); onDeleteInvoice(invoice.id); }}
                                                    className="text-gray-600 hover:text-red-500 p-2"
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                           )}
                                      </div>
                                  </div>

                                  {/* Expanded details (simple view) */}
                                  <div className="bg-gray-900/50 p-3 border-t border-gray-700">
                                      <table className="w-full text-xs text-right text-gray-400">
                                          <thead>
                                              <tr className="border-b border-gray-700/50">
                                                  <th className="pb-1">المادة</th>
                                                  <th className="pb-1">الكمية</th>
                                                  <th className="pb-1">السعر</th>
                                                  <th className="pb-1">الإجمالي</th>
                                              </tr>
                                          </thead>
                                          <tbody className="divide-y divide-gray-800">
                                              {invoice.items.map(item => (
                                                  <tr key={item.id}>
                                                      <td className="py-1 text-gray-300">{item.name}</td>
                                                      <td className="py-1">{item.quantity}</td>
                                                      <td className="py-1">{item.cost.toLocaleString('en-US')}</td>
                                                      <td className="py-1 text-red-400">{item.total.toLocaleString('en-US')}</td>
                                                  </tr>
                                              ))}
                                          </tbody>
                                      </table>
                                  </div>
                              </div>
                          ))
                      )}
                  </div>
              </div>
          )}
        </div>
      </div>
    </div>

    {/* Print Modal */}
    {invoiceToPrint && (
        <Suspense fallback={null}>
            <PurchasePrintModal 
                invoice={invoiceToPrint} 
                onClose={() => setInvoiceToPrint(null)} 
            />
        </Suspense>
    )}
    </>
  );
};

import React, { useState } from 'react';
import { ShoppingCart, Settings, Edit3, Trash2, CheckCircle, Plus, Minus, Calculator, UserPen, Users, Store, UserPlus } from 'lucide-react';
import { SaleItem, Product, UnitType, SaleType, Customer } from '../types';

interface POSInterfaceProps {
  onCompleteOrder: (items: Omit<SaleItem, 'id' | 'time' | 'customerNumber' | 'orderId'>[], customerName?: string, customerId?: string, saleType?: SaleType) => void;
  products: Product[];
  customers: Customer[];
  onOpenProductManager: () => void;
  onOpenCustomerManager: () => void;
}

// Internal type for the local cart
interface CartItem {
    tempId: string;
    name: string;
    price: number;
    quantity: number;
    unitType: UnitType;
    isCustom?: boolean;
}

export const POSInterface: React.FC<POSInterfaceProps> = ({ 
    onCompleteOrder, 
    products, 
    customers, 
    onOpenProductManager, 
    onOpenCustomerManager 
}) => {
  const [cart, setCart] = useState<CartItem[]>([]);

  // Sale Context State
  const [saleType, setSaleType] = useState<SaleType>('retail');
  const [selectedCustomerId, setSelectedCustomerId] = useState<string>('');
  const [manualCustomerName, setManualCustomerName] = useState(''); // For retail optional name

  // Custom item modal/inline state
  const [showCustomInput, setShowCustomInput] = useState(false);
  const [customName, setCustomName] = useState('');
  const [customPrice, setCustomPrice] = useState('');
  const [customUnit, setCustomUnit] = useState<UnitType>('piece');

  // 1. Add Product to Cart Logic
  const addToCart = (product: Product) => {
    setCart(prev => {
      // Find item with same name AND unit type.
      const existing = prev.find(item => item.name === product.name && item.unitType === product.unitType);

      if (existing) {
        return prev.map(item => 
          (item.tempId === existing.tempId) 
            ? { ...item, quantity: item.quantity + (item.unitType === 'kg' ? 1 : 1) } 
            : item
        );
      }
      return [...prev, { 
          tempId: Date.now().toString(), 
          name: product.name, 
          price: product.price, 
          quantity: 1, 
          unitType: product.unitType || 'piece' 
      }];
    });
  };

  // 2. Add Custom Item to Cart
  const addCustomToCart = () => {
    if (!customName || !customPrice) return;
    setCart(prev => [...prev, { 
        tempId: Date.now().toString(), 
        name: customName, 
        price: parseFloat(customPrice), 
        quantity: 1,
        unitType: customUnit,
        isCustom: true
    }]);
    setCustomName('');
    setCustomPrice('');
    setShowCustomInput(false);
  };

  // 3. Cart Management
  const updateQuantity = (tempId: string, change: number) => {
    setCart(prev => prev.map(item => {
        if (item.tempId === tempId) {
            const step = item.unitType === 'kg' ? 0.1 : 1;
            const newQty = Math.max(step, parseFloat((item.quantity + (change * step)).toFixed(2)));
            return { ...item, quantity: newQty };
        }
        return item;
    }));
  };

  const updateQuantityDirectly = (tempId: string, val: string) => {
      // Allow empty string (clearing the input) to act as 0 temporarily
      if (val === '') {
          setCart(prev => prev.map(item => item.tempId === tempId ? { ...item, quantity: 0 } : item));
          return;
      }
      const num = parseFloat(val);
      if (isNaN(num) || num < 0) return;
      setCart(prev => prev.map(item => item.tempId === tempId ? { ...item, quantity: num } : item));
  };

  const updatePriceDirectly = (tempId: string, val: string) => {
      if (val === '') {
          setCart(prev => prev.map(item => item.tempId === tempId ? { ...item, price: 0 } : item));
          return;
      }
      const num = parseFloat(val);
      if (isNaN(num) || num < 0) return;
      setCart(prev => prev.map(item => item.tempId === tempId ? { ...item, price: num } : item));
  };

  const updateTotalDirectly = (tempId: string, val: string) => {
      if (val === '') return; // Don't update on empty string for total
      const newTotal = parseFloat(val);
      if (isNaN(newTotal) || newTotal < 0) return;

      setCart(prev => prev.map(item => {
          if (item.tempId === tempId) {
              if (item.price === 0) return item;
              const newQty = newTotal / item.price;
              return { ...item, quantity: parseFloat(newQty.toFixed(3)) };
          }
          return item;
      }));
  };

  const removeFromCart = (tempId: string) => {
    setCart(prev => prev.filter(item => item.tempId !== tempId));
  };

  const clearCart = () => {
      setCart([]);
      setManualCustomerName('');
      setSelectedCustomerId('');
      setSaleType('retail');
  };

  // 4. Finalize Order
  const handleCheckout = () => {
      if (cart.length === 0) return;

      // Validation for Wholesale
      if (saleType === 'wholesale' && !selectedCustomerId) {
          alert('يجب اختيار عميل عند البيع بالجملة');
          return;
      }

      const salesItems = cart.map(({ name, price, quantity, unitType }) => ({
          name,
          price,
          quantity,
          unitType,
          saleType // Include sale type in item
      }));

      // Determine final customer name
      let finalCustomerName = manualCustomerName;
      if (saleType === 'wholesale' && selectedCustomerId) {
          const cust = customers.find(c => c.id === selectedCustomerId);
          if (cust) finalCustomerName = cust.name;
      }

      onCompleteOrder(salesItems, finalCustomerName, selectedCustomerId || undefined, saleType);
      clearCart();
  };

  const cartTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 no-print">

      {/* LEFT SECTION: Product Grid (Menu) */}
      <div className="lg:col-span-2 space-y-4">
        <div className="flex items-center justify-between bg-gray-800 p-4 rounded-xl border border-gray-700">
             <h2 className="font-bold text-white flex items-center gap-2">
                <Settings className="text-[#FA8072]" size={20} />
                قائمة المنتجات
             </h2>
             <button 
                onClick={onOpenProductManager}
                className="text-xs bg-gray-700 hover:bg-gray-600 text-gray-300 px-3 py-1.5 rounded-lg transition-colors"
             >
                تعديل القائمة
             </button>
        </div>

        {/* Grid */}
        <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
            {products.map(product => (
                <button
                    key={product.id}
                    onClick={() => addToCart(product)}
                    className="flex flex-col items-center justify-center p-4 bg-gray-800 border border-gray-700 hover:bg-gray-700 hover:border-[#FA8072] text-white rounded-2xl transition-all shadow-sm active:scale-95 group h-32 relative"
                >
                    <div className={`absolute top-2 right-2 px-1.5 py-0.5 rounded text-[10px] font-bold ${product.unitType === 'kg' ? 'bg-yellow-400 text-black' : 'bg-blue-300 text-black'}`}>
                        {product.unitType === 'kg' ? 'KG' : 'قطعة'}
                    </div>

                    <span className="font-bold text-sm text-center mb-1 line-clamp-2 group-hover:text-[#FA8072] transition-colors">{product.name}</span>
                    <span className="text-xs text-gray-400 bg-gray-900/50 px-2 py-1 rounded-md">{product.price.toLocaleString('en-US')} ل.س</span>
                </button>
            ))}

            {/* Custom Item Button */}
            <button
                onClick={() => setShowCustomInput(true)}
                className="flex flex-col items-center justify-center p-4 bg-gray-800 border border-dashed border-gray-600 hover:bg-gray-700 text-gray-400 rounded-2xl transition-all active:scale-95 h-32"
            >
                <Edit3 size={20} className="mb-2" />
                <span className="text-xs font-medium">مادة حرة</span>
            </button>
        </div>

        {/* Inline Custom Item Form */}
        {showCustomInput && (
            <div className="bg-gray-800 p-4 rounded-xl border border-[#FA8072] animate-fade-up">
                <h4 className="text-sm font-bold text-white mb-3">إضافة مادة غير مدرجة</h4>
                <div className="flex flex-col md:flex-row gap-2">
                    <input 
                        type="text" 
                        value={customName}
                        onChange={e => setCustomName(e.target.value)}
                        placeholder="اسم المادة"
                        className="flex-grow bg-gray-900 border border-gray-600 text-white px-3 py-2 rounded-lg text-sm outline-none focus:border-[#FA8072]"
                        autoFocus
                    />

                    <div className="flex bg-gray-900 rounded-lg p-1 border border-gray-600 w-fit">
                        <button
                            onClick={() => setCustomUnit('piece')}
                            className={`px-3 py-1 rounded text-xs ${customUnit === 'piece' ? 'bg-[#FA8072] text-white' : 'text-gray-400'}`}
                        >قطعة</button>
                        <button
                            onClick={() => setCustomUnit('kg')}
                            className={`px-3 py-1 rounded text-xs ${customUnit === 'kg' ? 'bg-[#FA8072] text-white' : 'text-gray-400'}`}
                        >كيلو</button>
                    </div>

                    <input 
                        type="number" 
                        value={customPrice}
                        onChange={e => setCustomPrice(e.target.value)}
                        placeholder="السعر"
                        className="w-24 bg-gray-900 border border-gray-600 text-white px-3 py-2 rounded-lg text-sm outline-none focus:border-[#FA8072]"
                    />
                    <button 
                        onClick={addCustomToCart}
                        className="bg-[#FA8072] text-white px-4 rounded-lg font-bold hover:bg-[#e67365] py-2"
                    >
                        إضافة
                    </button>
                    <button 
                        onClick={() => setShowCustomInput(false)}
                        className="bg-gray-700 text-gray-300 px-3 rounded-lg hover:bg-gray-600 py-2"
                    >
                        <Trash2 size={18} />
                    </button>
                </div>
            </div>
        )}
      </div>

      {/* RIGHT SECTION: Current Customer Bill (Cart) */}
      <div className="lg:col-span-1">
        <div className="bg-gray-800 rounded-2xl border border-gray-700 shadow-xl overflow-hidden flex flex-col h-full min-h-[500px]">
            {/* Cart Header */}
            <div className="bg-gray-900/80 p-4 border-b border-gray-700 flex flex-col gap-3">
                <div className="flex justify-between items-center">
                    <h3 className="font-bold text-white flex items-center gap-2">
                        <ShoppingCart size={20} className="text-[#FA8072]" />
                        فاتورة البيع
                    </h3>
                    {cart.length > 0 && (
                        <button onClick={clearCart} className="text-xs text-red-400 hover:text-red-300 underline">
                            إلغاء الطلب
                        </button>
                    )}
                </div>

                {/* --- Wholesale vs Retail Toggle --- */}
                <div className="grid grid-cols-2 bg-gray-700 p-1 rounded-lg">
                    <button 
                        onClick={() => setSaleType('retail')}
                        className={`py-1.5 text-xs font-bold rounded-md flex items-center justify-center gap-2 transition-colors ${saleType === 'retail' ? 'bg-white text-black shadow' : 'text-gray-400 hover:text-white'}`}
                    >
                        <UserPen size={14} />
                        مفرق (عادي)
                    </button>
                    <button 
                        onClick={() => setSaleType('wholesale')}
                        className={`py-1.5 text-xs font-bold rounded-md flex items-center justify-center gap-2 transition-colors ${saleType === 'wholesale' ? 'bg-[#FA8072] text-white shadow' : 'text-gray-400 hover:text-white'}`}
                    >
                        <Store size={14} />
                        جملة
                    </button>
                </div>

                {/* Customer Selection */}
                {saleType === 'retail' ? (
                     <div className="relative">
                        <div className="absolute inset-y-0 right-0 flex items-center pr-3 pointer-events-none text-gray-500">
                            <UserPen size={14} />
                        </div>
                        <input 
                            type="text" 
                            value={manualCustomerName}
                            onChange={(e) => setManualCustomerName(e.target.value)}
                            placeholder="اسم الزبون (اختياري)..."
                            className="w-full bg-gray-800 border border-gray-600 text-white text-sm rounded-lg pr-9 pl-3 py-2 focus:border-[#FA8072] focus:ring-1 focus:ring-[#FA8072] outline-none transition-all placeholder:text-gray-600"
                        />
                    </div>
                ) : (
                    <div className="flex gap-2">
                        <div className="relative flex-grow">
                             <select
                                value={selectedCustomerId}
                                onChange={(e) => setSelectedCustomerId(e.target.value)}
                                className={`w-full bg-gray-800 border ${!selectedCustomerId ? 'border-red-500/50 animate-pulse' : 'border-gray-600'} text-white text-sm rounded-lg px-3 py-2 outline-none focus:border-[#FA8072]`}
                             >
                                 <option value="">اختر عميل الجملة...</option>
                                 {customers.map(c => (
                                     <option key={c.id} value={c.id}>{c.name}</option>
                                 ))}
                             </select>
                        </div>
                        <button 
                            onClick={onOpenCustomerManager}
                            className="bg-blue-600 hover:bg-blue-500 text-white px-3 rounded-lg"
                            title="إضافة عميل جديد"
                        >
                            <UserPlus size={18} />
                        </button>
                    </div>
                )}

            </div>

            {/* Cart Items */}
            <div className="flex-grow p-3 overflow-y-auto space-y-2">
                {cart.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center text-gray-500 opacity-50">
                        <ShoppingCart size={48} className="mb-2" />
                        <p>اضغط على المنتجات لإضافتها</p>
                    </div>
                ) : (
                    cart.map(item => (
                        <div key={item.tempId} className="bg-gray-700/50 p-3 rounded-xl flex flex-col gap-2 border border-gray-700 relative group">
                            <div className="flex justify-between items-start gap-2">
                                <div className="flex flex-col">
                                    <span className="text-white font-medium text-sm">{item.name}</span>
                                    <span className={`text-[10px] w-fit px-1.5 rounded-md ${item.unitType === 'kg' ? 'bg-yellow-500/20 text-yellow-500' : 'bg-blue-500/20 text-blue-400'}`}>
                                        {item.unitType === 'kg' ? 'وزن (كيلو)' : 'عدد (قطعة)'}
                                    </span>
                                </div>
                            </div>

                            {/* Inputs Container */}
                            <div className="flex flex-col gap-2 mt-1 bg-gray-800/50 p-2 rounded-lg">
                                {/* Price Editor */}
                                <div className="flex items-center justify-between gap-2">
                                    <label className="text-[10px] text-gray-500 w-16">سعر الإفرادي:</label>
                                    <input 
                                        type="number"
                                        value={item.price === 0 ? '' : item.price}
                                        onFocus={(e) => e.target.select()} // Auto-select on focus
                                        onChange={(e) => updatePriceDirectly(item.tempId, e.target.value)}
                                        className="flex-1 bg-gray-900 border border-gray-600 rounded px-2 py-1 text-sm text-white text-center focus:border-[#FA8072] outline-none"
                                    />
                                </div>

                                {/* Quantity Editor */}
                                <div className="flex items-center justify-between gap-2">
                                    <label className="text-[10px] text-gray-500 w-16">الكمية:</label>
                                    <div className="flex items-center gap-1 flex-1">
                                        <button 
                                            onClick={() => updateQuantity(item.tempId, -1)}
                                            className="w-8 h-7 flex items-center justify-center bg-gray-700 text-white rounded hover:bg-gray-600"
                                        >
                                            <Minus size={14} />
                                        </button>
                                        <input 
                                            type="number"
                                            value={item.quantity === 0 ? '' : item.quantity}
                                            onFocus={(e) => e.target.select()} // Auto-select on focus
                                            onChange={(e) => updateQuantityDirectly(item.tempId, e.target.value)}
                                            className="flex-1 bg-gray-900 border border-gray-600 rounded px-1 py-1 text-sm text-white text-center focus:border-[#FA8072] outline-none h-7"
                                            step={item.unitType === 'kg' ? "0.1" : "1"}
                                        />
                                        <button 
                                            onClick={() => updateQuantity(item.tempId, 1)}
                                            className="w-8 h-7 flex items-center justify-center bg-[#FA8072] text-white rounded hover:bg-[#e67365]"
                                        >
                                            <Plus size={14} />
                                        </button>
                                    </div>
                                </div>

                                {/* Total Price Editor */}
                                <div className="flex items-center justify-between gap-2 pt-2 border-t border-gray-700/50 mt-1">
                                    <div className="flex items-center gap-1 w-16">
                                        <Calculator size={10} className="text-[#FA8072]" />
                                        <label className="text-[10px] text-[#FA8072] font-bold">الإجمالي:</label>
                                    </div>
                                    <input 
                                        type="number"
                                        value={Math.round(item.price * item.quantity * 100) / 100}
                                        onFocus={(e) => e.target.select()}
                                        onChange={(e) => updateTotalDirectly(item.tempId, e.target.value)}
                                        className="flex-1 bg-gray-900 border border-[#FA8072]/50 rounded px-2 py-1 text-sm text-[#FA8072] font-bold text-center focus:border-[#FA8072] outline-none"
                                    />
                                </div>
                            </div>

                            <button 
                                onClick={() => removeFromCart(item.tempId)}
                                className="absolute -left-2 -top-2 bg-red-500 text-white p-1 rounded-full opacity-0 group-hover:opacity-100 transition-opacity shadow-md z-10"
                            >
                                <Trash2 size={12} />
                            </button>
                        </div>
                    ))
                )}
            </div>

            {/* Cart Footer (Total & Checkout) */}
            <div className="p-4 bg-gray-900 border-t border-gray-700 mt-auto">
                <div className="flex justify-between items-center mb-4">
                    <span className="text-gray-400">الإجمالي المطلوب:</span>
                    <span className="text-2xl font-bold text-white">{cartTotal.toLocaleString('en-US')} <span className="text-sm font-normal text-gray-500">ل.س</span></span>
                </div>

                <button
                    onClick={handleCheckout}
                    disabled={cart.length === 0}
                    className={`
                        w-full py-3 rounded-xl font-bold text-lg flex items-center justify-center gap-2 transition-all shadow-lg
                        ${cart.length > 0 
                            ? 'bg-green-600 hover:bg-green-500 text-white transform active:scale-95' 
                            : 'bg-gray-700 text-gray-500 cursor-not-allowed'}
                    `}
                >
                    <CheckCircle size={24} />
                    <span>تأكيد البيع (موافق)</span>
                </button>
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, Suspense } from 'react';
import { Header } from './components/Header';
import { POSInterface } from './components/RecipeGenerator';
import { SalesTable } from './components/Menu';
import { Summary } from './components/InfoBox';
import { Login } from './components/Login';
import { SaleItem, Product, ArchivedDay, SaleType, Customer, PurchaseInvoice, Supplier } from './types';
import { Save, RotateCcw, X, Loader2 } from 'lucide-react';

const InvoiceModal = React.lazy(() => import('./components/InvoiceModal').then(module => ({ default: module.InvoiceModal })));
const ProductManager = React.lazy(() => import('./components/ProductManager').then(module => ({ default: module.ProductManager })));
const HistoryModal = React.lazy(() => import('./components/HistoryModal').then(module => ({ default: module.HistoryModal })));
const DataManagementModal = React.lazy(() => import('./components/DataManagementModal').then(module => ({ default: module.DataManagementModal })));
const CustomerManager = React.lazy(() => import('./components/CustomerManager').then(module => ({ default: module.CustomerManager })));
const ExpensesModal = React.lazy(() => import('./components/ExpensesModal').then(module => ({ default: module.ExpensesModal })));

const DEFAULT_PRODUCTS: Product[] = [];

const useOnlineStatus = () => {
  const [isOnline, setIsOnline] = useState(() => navigator.onLine);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    const intervalId = setInterval(() => {
      if (navigator.onLine !== isOnline) setIsOnline(navigator.onLine);
    }, 2000);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
      clearInterval(intervalId);
    };
  }, [isOnline]);
  return isOnline;
};

const ModalLoader = () => (
    <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center backdrop-blur-sm">
        <div className="bg-gray-800 p-4 rounded-full shadow-xl border border-gray-700">
            <Loader2 className="animate-spin text-[#FA8072]" size={32} />
        </div>
    </div>
);

// New Component: Circular Percentage Loader
const LoadingScreen = ({ progress }: { progress: number }) => {
    const radius = 60;
    const stroke = 8;
    const normalizedRadius = radius - stroke * 2;
    const circumference = normalizedRadius * 2 * Math.PI;
    const strokeDashoffset = circumference - (progress / 100) * circumference;

    return (
      <div className="fixed inset-0 bg-[#111827] z-[100] flex flex-col items-center justify-center">
        <div className="relative flex items-center justify-center">
            {/* Background Circle */}
            <svg height={radius * 2} width={radius * 2} className="rotate-[-90deg]">
                <circle
                    stroke="#1F2937"
                    strokeWidth={stroke}
                    r={normalizedRadius}
                    cx={radius}
                    cy={radius}
                    fill="transparent"
                />
                {/* Progress Circle */}
                <circle
                    stroke="#FA8072"
                    strokeWidth={stroke}
                    strokeDasharray={circumference + ' ' + circumference}
                    style={{ strokeDashoffset, transition: 'stroke-dashoffset 0.1s linear' }}
                    strokeLinecap="round"
                    r={normalizedRadius}
                    cx={radius}
                    cy={radius}
                    fill="transparent"
                />
            </svg>
            <div className="absolute inset-0 flex items-center justify-center text-white font-bold text-xl">
                {progress}%
            </div>
        </div>
        <div className="mt-8 text-center animate-pulse">
            <img src="/logo.png" className="w-16 h-16 object-contain mx-auto mb-4" onError={(e) => (e.target as HTMLImageElement).style.display='none'} />
            <h2 className="text-xl font-bold text-white mb-1">مخبز كوكيز</h2>
            <p className="text-gray-400 text-sm">جاري تحميل النظام...</p>
        </div>
      </div>
    );
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => sessionStorage.getItem('isAuth') === 'true');
  const [isAppLoading, setIsAppLoading] = useState(false);
  const [loadingProgress, setLoadingProgress] = useState(0);

  const isOnline = useOnlineStatus();
  const [lastSyncTime, setLastSyncTime] = useState<Date>(new Date());
  const [isSyncing, setIsSyncing] = useState(false);
  const [installPrompt, setInstallPrompt] = useState<any>(null);

  // Core Data State
  const [sales, setSales] = useState<SaleItem[]>(() => {
    const saved = localStorage.getItem('dailySales');
    return saved ? JSON.parse(saved) : [];
  });

  const [purchaseInvoices, setPurchaseInvoices] = useState<PurchaseInvoice[]>(() => {
      const saved = localStorage.getItem('dailyPurchaseInvoices');
      return saved ? JSON.parse(saved) : [];
  });
  const [history, setHistory] = useState<ArchivedDay[]>(() => {
    const saved = localStorage.getItem('salesHistory');
    return saved ? JSON.parse(saved) : [];
  });
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('products');
    return saved ? JSON.parse(saved) : DEFAULT_PRODUCTS;
  });
  const [customers, setCustomers] = useState<Customer[]>(() => {
      const saved = localStorage.getItem('customers');
      return saved ? JSON.parse(saved) : [];
  });
  const [suppliers, setSuppliers] = useState<Supplier[]>(() => {
      const saved = localStorage.getItem('suppliers');
      return saved ? JSON.parse(saved) : [];
  });

  // UI State
  const [invoiceItems, setInvoiceItems] = useState<SaleItem[] | null>(null); // For Invoice Modal
  const [showProductManager, setShowProductManager] = useState(false);
  const [showCustomerManager, setShowCustomerManager] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [showDataModal, setShowDataModal] = useState(false);
  const [showExpensesModal, setShowExpensesModal] = useState(false);

  const [undoState, setUndoState] = useState<{ items: SaleItem[], timerId: ReturnType<typeof setTimeout> } | null>(null);

  useEffect(() => {
    if (navigator.storage && navigator.storage.persist) {
      navigator.storage.persist().then(granted => {
        if (granted) console.log("Storage persistence granted");
      });
    }
  }, []);

  useEffect(() => {
    const handleBeforeInstallPrompt = (e: any) => {
      e.preventDefault();
      setInstallPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    return () => window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
  }, []);

  const handleInstallClick = async () => {
    if (!installPrompt) return;
    installPrompt.prompt();
    const { outcome } = await installPrompt.userChoice;
    console.log(`User response: ${outcome}`);
    setInstallPrompt(null);
  };

  const updateLastSync = () => setLastSyncTime(new Date());

  useEffect(() => { localStorage.setItem('dailySales', JSON.stringify(sales)); updateLastSync(); }, [sales]);
  useEffect(() => { localStorage.setItem('dailyPurchaseInvoices', JSON.stringify(purchaseInvoices)); updateLastSync(); }, [purchaseInvoices]);
  useEffect(() => { localStorage.setItem('salesHistory', JSON.stringify(history)); updateLastSync(); }, [history]);
  useEffect(() => { localStorage.setItem('products', JSON.stringify(products)); updateLastSync(); }, [products]);
  useEffect(() => { localStorage.setItem('customers', JSON.stringify(customers)); updateLastSync(); }, [customers]);
  useEffect(() => { localStorage.setItem('suppliers', JSON.stringify(suppliers)); updateLastSync(); }, [suppliers]);

  const handleManualSync = () => {
    setIsSyncing(true);
    setTimeout(() => {
      localStorage.setItem('dailySales', JSON.stringify(sales));
      localStorage.setItem('dailyPurchaseInvoices', JSON.stringify(purchaseInvoices));
      localStorage.setItem('salesHistory', JSON.stringify(history));
      localStorage.setItem('products', JSON.stringify(products));
      localStorage.setItem('customers', JSON.stringify(customers));
      localStorage.setItem('suppliers', JSON.stringify(suppliers));
      setLastSyncTime(new Date());
      setIsSyncing(false);
    }, 800);
  };

  const handleLogin = () => {
      // 1. Show Loader
      setIsAppLoading(true);
      setLoadingProgress(0);

      // 2. Simulate Loading Progress
      let currentProgress = 0;
      const interval = setInterval(() => {
          // Non-linear increment to make it feel natural
          const increment = Math.random() * 15;
          currentProgress += increment;

          if (currentProgress >= 100) {
              currentProgress = 100;
              clearInterval(interval);
              setLoadingProgress(100);

              // 3. Finish Loading
              setTimeout(() => {
                  sessionStorage.setItem('isAuth', 'true');
                  setIsAuthenticated(true);
                  setIsAppLoading(false);
              }, 600); // Small delay at 100%
          } else {
              setLoadingProgress(Math.floor(currentProgress));
          }
      }, 150);
  };

  const getNextCustomerNumber = () => {
      if (sales.length === 0) return 1;
      const maxNum = Math.max(...sales.map(s => s.customerNumber || 0));
      return maxNum + 1;
  };

  // Enhanced Order Completion
  const handleCompleteOrder = (
      newItems: Omit<SaleItem, 'id' | 'time' | 'customerNumber' | 'orderId'>[], 
      customerName?: string, 
      customerId?: string,
      saleType: SaleType = 'retail'
    ) => {
    // Force English numerals for time
    const currentTime = new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
    const orderId = Date.now().toString(); 
    const customerNumber = getNextCustomerNumber(); 

    const itemsWithIds: SaleItem[] = newItems.map(item => ({
        ...item,
        id: Math.random().toString(36).substr(2, 9), 
        orderId,
        customerNumber,
        customerName: customerName || undefined,
        customerId,
        saleType,
        time: currentTime
    }));

    setSales(prev => [...prev, ...itemsWithIds]);
  };

  const handleDeleteItem = (id: string) => {
    const itemToDelete = sales.find(item => String(item.id) === String(id));
    if (!itemToDelete) return;
    if (undoState?.timerId) clearTimeout(undoState.timerId);
    setSales(prev => prev.filter(item => String(item.id) !== String(id)));
    const timerId = setTimeout(() => setUndoState(null), 5000);
    setUndoState({ items: [itemToDelete], timerId });
  };

  const handleDeleteOrder = (orderId: string) => {
    const itemsToDelete = sales.filter(item => String(item.orderId) === String(orderId));
    if (itemsToDelete.length === 0) return;
    if (undoState?.timerId) clearTimeout(undoState.timerId);
    setSales(prev => prev.filter(item => String(item.orderId) !== String(orderId)));
    const timerId = setTimeout(() => setUndoState(null), 5000);
    setUndoState({ items: itemsToDelete, timerId });
  };

  const handleUndo = () => {
      if (!undoState) return;
      if (undoState.timerId) clearTimeout(undoState.timerId);
      setSales(prev => [...prev, ...undoState.items]);
      setUndoState(null);
  };

  // Purchase Invoices Logic
  const handleAddPurchaseInvoice = (newInvoice: PurchaseInvoice) => {
      setPurchaseInvoices(prev => [...prev, newInvoice]);
  };

  const handleDeletePurchaseInvoice = (id: string) => {
      setPurchaseInvoices(prev => prev.filter(inv => inv.id !== id));
  };

  const handleEndDay = () => {
    if (sales.length === 0 && purchaseInvoices.length === 0) { alert('لا توجد بيانات لترحيلها.'); return; }
    if (confirm('سيتم إغلاق اليوم وتفريغ المبيعات والمشتريات الحالية للأرشيف. هل أنت متأكد؟')) {
        const totalRevenue = sales.reduce((sum, item) => sum + (item.price * item.quantity), 0);
        const totalExpenses = purchaseInvoices.reduce((sum, inv) => sum + inv.totalAmount, 0);
        const totalItems = sales.reduce((sum, item) => sum + item.quantity, 0);

        const daySummary: ArchivedDay = {
            id: Date.now().toString(),
            // Force English numerals for date
            date: new Date().toLocaleDateString('en-GB'),
            timestamp: Date.now(),
            totalRevenue,
            totalExpenses,
            totalItems,
            items: [...sales],
            purchaseInvoices: [...purchaseInvoices] // Store invoices in archive
        };
        setHistory(prev => [daySummary, ...prev]);
        setSales([]);
        setPurchaseInvoices([]);
        setUndoState(null);
        alert('تم إغلاق اليوم بنجاح.');
    }
  };

  // Product Handlers
  const handleAddProduct = (newProduct: Omit<Product, 'id'>) => {
    setProducts(prev => [...prev, { ...newProduct, id: Date.now().toString() }]);
  };
  const handleDeleteProduct = (id: string) => {
    setProducts(prev => prev.filter(p => String(p.id) !== String(id)));
  };

  // Customer Handlers
  const handleAddCustomer = (newCustomer: Omit<Customer, 'id'>) => {
      setCustomers(prev => [...prev, { ...newCustomer, id: Date.now().toString() }]);
  };
  const handleDeleteCustomer = (id: string) => {
      setCustomers(prev => prev.filter(c => c.id !== id));
  };

  // Supplier Handlers
  const handleAddSupplier = (newSupplier: Omit<Supplier, 'id'>) => {
      setSuppliers(prev => [...prev, { ...newSupplier, id: Date.now().toString() }]);
  };
  const handleDeleteSupplier = (id: string) => {
      setSuppliers(prev => prev.filter(s => s.id !== id));
  };

  const handleExportData = () => {
    const data = { appVersion: '1.3', timestamp: Date.now(), sales, purchaseInvoices, history, products, customers, suppliers };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    // Filename with English numerals
    link.download = `cookies-bakery-backup-${new Date().toLocaleDateString('en-GB').replace(/\//g, '-')}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleImportData = (file: File) => {
      const reader = new FileReader();
      reader.onload = (e) => {
          try {
              const data = JSON.parse(e.target?.result as string);
              if (!data || typeof data !== 'object') throw new Error('Invalid file');
              if (Array.isArray(data.sales)) setSales(data.sales);
              if (Array.isArray(data.purchaseInvoices)) setPurchaseInvoices(data.purchaseInvoices);
              else setPurchaseInvoices([]); 

              if (Array.isArray(data.history)) setHistory(data.history);
              if (Array.isArray(data.products)) setProducts(data.products);
              if (Array.isArray(data.customers)) setCustomers(data.customers);
              if (Array.isArray(data.suppliers)) setSuppliers(data.suppliers);
              alert('تم استعادة البيانات بنجاح!');
          } catch (error) { alert('خطأ في قراءة الملف.'); }
      };
      reader.readAsText(file);
  };

  // Authentication & Loading Check
  if (isAppLoading) {
      return <LoadingScreen progress={loadingProgress} />;
  }

  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  return (
    <div className="min-h-screen flex flex-col bg-gray-900 print:bg-white">
      <Header 
        onOpenHistory={() => setShowHistory(true)} 
        onOpenDataManagement={() => setShowDataModal(true)}
        onOpenExpenses={() => setShowExpensesModal(true)}
        isOnline={isOnline}
        lastSyncTime={lastSyncTime}
        onManualSync={handleManualSync}
        isSyncing={isSyncing}
        installPrompt={installPrompt}
        onInstall={handleInstallClick}
      />

      <main className="flex-grow container mx-auto px-4 py-6 max-w-5xl">
        <div className="hidden print:block text-center mb-8 border-b-2 border-black pb-4">
            <h1 className="text-3xl font-bold mb-2 text-black">تقرير المبيعات اليومي</h1>
            <p className="text-gray-600">التاريخ: {new Date().toLocaleDateString('en-GB')}</p>
        </div>

        {/* Summary shows total sales only */}
        <Summary items={sales} onPreview={() => setInvoiceItems(sales)} />

        <div className="mb-8">
            <POSInterface 
                onCompleteOrder={handleCompleteOrder} 
                products={products}
                customers={customers}
                onOpenProductManager={() => setShowProductManager(true)}
                onOpenCustomerManager={() => setShowCustomerManager(true)}
            />
        </div>

        <div className="mb-20 print:mb-0 border-t border-gray-700 pt-8">
            <div className="flex items-center justify-between mb-4 no-print">
                <h3 className="text-xl font-bold text-white">سجل الزبائن والمبيعات (اليوم الحالي)</h3>
                {sales.length > 0 && (
                    <button 
                        onClick={handleEndDay}
                        className="flex items-center gap-2 bg-green-900/40 hover:bg-green-900/60 text-green-400 px-4 py-2 rounded-xl transition-colors border border-green-800"
                    >
                        <Save size={18} />
                        <span className="font-bold">إغلاق اليوم (أرشفة)</span>
                    </button>
                )}
            </div>

            <SalesTable 
                items={sales} 
                onDeleteItem={handleDeleteItem} 
                onDeleteOrder={handleDeleteOrder}
                onPreviewInvoice={(items) => setInvoiceItems(items)}
            />
        </div>
      </main>

      {undoState && (
          <div className="fixed bottom-6 left-1/2 transform -translate-x-1/2 bg-gray-800 text-white px-6 py-3 rounded-xl shadow-2xl border border-gray-700 flex items-center gap-6 z-50 animate-fade-up min-w-[300px] justify-between">
              <span className="text-sm font-medium">تم حذف {undoState.items.length > 1 ? 'الطلب' : 'العنصر'}</span>
              <div className="flex items-center gap-4">
                  <button onClick={handleUndo} className="text-[#FA8072] font-bold text-sm flex items-center gap-1 hover:text-[#ff9a8d]"><RotateCcw size={16} /> تراجع</button>
                  <button onClick={() => { if (undoState.timerId) clearTimeout(undoState.timerId); setUndoState(null); }} className="text-gray-500 hover:text-white border-r border-gray-600 pr-4 mr-1"><X size={16} /></button>
              </div>
          </div>
      )}

      {invoiceItems && (
        <Suspense fallback={<ModalLoader />}>
            <InvoiceModal items={invoiceItems} onClose={() => setInvoiceItems(null)} />
        </Suspense>
      )}

      {showHistory && (
        <Suspense fallback={<ModalLoader />}>
            <HistoryModal 
                history={history} 
                onClose={() => setShowHistory(false)} 
                onClearHistory={() => setHistory([])}
                onPreviewInvoice={(items) => setInvoiceItems(items)}
            />
        </Suspense>
      )}

      {showProductManager && (
         <Suspense fallback={<ModalLoader />}>
            <ProductManager 
                isOpen={showProductManager}
                onClose={() => setShowProductManager(false)}
                products={products}
                onAddProduct={handleAddProduct}
                onDeleteProduct={handleDeleteProduct}
            />
         </Suspense>
      )}

      {showCustomerManager && (
         <Suspense fallback={<ModalLoader />}>
            <CustomerManager 
                isOpen={showCustomerManager}
                onClose={() => setShowCustomerManager(false)}
                customers={customers}
                onAddCustomer={handleAddCustomer}
                onDeleteCustomer={handleDeleteCustomer}
            />
         </Suspense>
      )}

      {showDataModal && (
        <Suspense fallback={<ModalLoader />}>
            <DataManagementModal 
                onClose={() => setShowDataModal(false)}
                onExport={handleExportData}
                onImport={handleImportData}
            />
        </Suspense>
      )}

      {showExpensesModal && (
          <Suspense fallback={<ModalLoader />}>
              <ExpensesModal
                isOpen={showExpensesModal}
                onClose={() => setShowExpensesModal(false)}
                currentPurchases={purchaseInvoices}
                archivedHistory={history}
                onAddInvoice={handleAddPurchaseInvoice}
                onDeleteInvoice={handleDeletePurchaseInvoice}
                suppliers={suppliers}
                onAddSupplier={handleAddSupplier}
                onDeleteSupplier={handleDeleteSupplier}
              />
          </Suspense>
      )}

      <footer className="text-center py-6 text-gray-500 text-sm no-print mt-auto">
        <p>نظام محاسبة مخبز كوكيز - v1.3</p>
      </footer>
    </div>
  );
};

