import React, { useRef, useState } from 'react';
import { X, Download, Upload, Database, AlertTriangle, FileJson, Check, Trash2, Share2, Cloud } from 'lucide-react';

interface DataManagementModalProps {
  onExport: () => void;
  onImport: (file: File) => void;
  onClose: () => void;
}

export const DataManagementModal: React.FC<DataManagementModalProps> = ({ onExport, onImport, onClose }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setSelectedFile(file);
    }
    if (e.target) e.target.value = '';
  };

  const handleConfirmImport = () => {
    if (!selectedFile) return;
    onImport(selectedFile);
    onClose();
  };

  const clearSelection = () => {
      setSelectedFile(null);
  };

  const handleShareToDrive = async () => {
      try {
          // 1. Get current data from localStorage
          const sales = JSON.parse(localStorage.getItem('dailySales') || '[]');
          const invoices = JSON.parse(localStorage.getItem('dailyPurchaseInvoices') || '[]');
          const history = JSON.parse(localStorage.getItem('salesHistory') || '[]');
          const products = JSON.parse(localStorage.getItem('products') || '[]');
          const customers = JSON.parse(localStorage.getItem('customers') || '[]');
          const suppliers = JSON.parse(localStorage.getItem('suppliers') || '[]');

          const data = { 
              appVersion: '1.3', 
              timestamp: Date.now(), 
              sales, 
              purchaseInvoices: invoices, 
              history, 
              products, 
              customers, 
              suppliers 
          };

          const dateStr = new Date().toLocaleDateString('en-GB').replace(/\//g, '-');
          const fileName = `cookies-bakery-backup-${dateStr}.json`;

          const jsonString = JSON.stringify(data, null, 2);
          const file = new File([jsonString], fileName, { type: 'application/json' });

          // 2. Check if Web Share API with Files is supported
          if (navigator.canShare && navigator.canShare({ files: [file] })) {
              await navigator.share({
                  files: [file],
                  title: 'نسخة احتياطية - مخبز كوكيز',
                  text: `نسخة بتاريخ ${dateStr}`,
              });
              alert('اختر تطبيق Google Drive من قائمة المشاركة لحفظ الملف سحابياً.');
          } else {
              // Fallback to direct download if sharing is not available
              alert('متصفحك لا يدعم المشاركة المباشرة. سيتم تحميل الملف لجهازك، يرجى رفعه يدوياً إلى Google Drive.');
              onExport();
          }
      } catch (error) {
          console.error('Error sharing:', error);
          if (error instanceof Error && error.name !== 'AbortError') {
              alert('حدث خطأ أثناء محاولة المشاركة. سيتم تحميل الملف محلياً بدلاً من ذلك.');
              onExport();
          }
      }
  };

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-2xl w-full max-w-lg shadow-2xl border border-gray-700 animate-fade-up flex flex-col">

        {/* Header */}
        <div className="p-4 border-b border-gray-700 flex justify-between items-center bg-gray-900/50 rounded-t-2xl">
          <div className="flex items-center gap-2 text-white">
            <Database size={20} className="text-[#FA8072]" />
            <h3 className="font-bold text-lg">النسخ الاحتياطي والاستعادة</h3>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full transition-colors">
            <X size={20} className="text-gray-400" />
          </button>
        </div>

        {/* Content */}
        <div className="p-6 space-y-6">

            {/* Export Section */}
            <div className="bg-gray-700/30 p-4 rounded-xl border border-gray-600">
                <div className="flex items-start gap-3 mb-3">
                    <div className="bg-blue-500/20 p-2 rounded-lg text-blue-400">
                        <Download size={24} />
                    </div>
                    <div>
                        <h4 className="text-white font-bold text-sm">تصدير نسخة احتياطية</h4>
                        <p className="text-gray-400 text-xs mt-1">حفظ البيانات على جهازك أو رفعها إلى السحابة.</p>
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-3">
                    <button 
                        onClick={onExport}
                        className="bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-lg font-bold text-xs transition-colors flex items-center justify-center gap-2"
                    >
                        <Download size={16} />
                        تحميل (جهاز)
                    </button>

                    <button 
                        onClick={handleShareToDrive}
                        className="bg-green-600 hover:bg-green-500 text-white py-3 rounded-lg font-bold text-xs transition-colors flex items-center justify-center gap-2"
                    >
                        <Cloud size={16} />
                        Google Drive
                    </button>
                </div>
                 <p className="text-[10px] text-gray-500 mt-2 text-center font-bold">
                    * لمزامنة Drive: اضغط الزر الأخضر واختر تطبيق Drive من القائمة الظاهرة.
                </p>
            </div>

            {/* Import Section */}
            <div className="bg-gray-700/30 p-4 rounded-xl border border-gray-600">
                <div className="flex items-start gap-3 mb-3">
                    <div className="bg-purple-500/20 p-2 rounded-lg text-purple-400">
                        <Upload size={24} />
                    </div>
                    <div>
                        <h4 className="text-white font-bold text-sm">استيراد بيانات (Restore)</h4>
                        <p className="text-gray-400 text-xs mt-1">استرجاع البيانات من ملف محفوظ مسبقاً.</p>
                    </div>
                </div>

                <div className="bg-yellow-500/10 border border-yellow-500/20 rounded-lg p-3 mb-4 flex items-start gap-2">
                    <AlertTriangle size={16} className="text-yellow-500 shrink-0 mt-0.5" />
                    <p className="text-[10px] text-yellow-200 leading-relaxed font-bold">
                        تحذير: هذه العملية ستقوم باستبدال جميع البيانات الحالية ببيانات الملف المختار.
                    </p>
                </div>

                <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".json" className="hidden" />

                {!selectedFile ? (
                    <button 
                        onClick={() => fileInputRef.current?.click()}
                        className="w-full bg-gray-600 hover:bg-gray-500 text-white py-3 rounded-lg font-bold text-sm transition-colors flex items-center justify-center gap-2 border border-gray-500 border-dashed"
                    >
                        <Upload size={18} />
                        اختيار ملف النسخة الاحتياطية
                    </button>
                ) : (
                    <div className="space-y-3 animate-fade-up">
                        <div className="bg-gray-800 p-3 rounded-lg border border-gray-600 flex items-center justify-between">
                            <div className="flex items-center gap-3 overflow-hidden">
                                <div className="bg-green-900/50 p-2 rounded"><FileJson className="text-green-400" size={24} /></div>
                                <div className="flex flex-col overflow-hidden text-right">
                                    <span className="text-sm text-white font-medium truncate">{selectedFile.name}</span>
                                    <span className="text-[10px] text-gray-400">{(selectedFile.size / 1024).toFixed(2)} KB</span>
                                </div>
                            </div>
                            <button onClick={clearSelection} className="p-2 hover:bg-red-500/20 text-red-400 rounded-lg"><Trash2 size={18} /></button>
                        </div>
                        <button onClick={handleConfirmImport} className="w-full bg-green-600 hover:bg-green-500 text-white py-3 rounded-lg font-bold text-sm flex items-center justify-center gap-2 shadow-lg"><Check size={18} /> تأكيد واستعادة البيانات</button>
                    </div>
                )}
            </div>

        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, Suspense } from 'react';
import { Plus, Trash2, X, ShoppingCart, Folder, FileText, CheckCircle, Clock, Download, Printer, UserPlus, ArrowRight, CalendarDays, TrendingDown, Search } from 'lucide-react';
import { PurchaseInvoice, PurchaseItem, ArchivedDay, PaymentStatus, Supplier } from '../types';

const PurchasePrintModal = React.lazy(() => import('./PurchasePrintModal').then(module => ({ default: module.PurchasePrintModal })));

interface ExpensesModalProps {
  currentPurchases: PurchaseInvoice[];
  archivedHistory: ArchivedDay[]; 
  onAddInvoice: (invoice: PurchaseInvoice) => void;
  onDeleteInvoice: (id: string) => void;
  isOpen: boolean;
  onClose: () => void;
  suppliers?: Supplier[];
  onAddSupplier?: (supplier: Omit<Supplier, 'id'>) => void;
  onDeleteSupplier?: (id: string) => void;
}

type Tab = 'new' | 'history' | 'suppliers';
type NavStep = 'years' | 'months' | 'days';

export const ExpensesModal: React.FC<ExpensesModalProps> = ({ 
  currentPurchases, 
  archivedHistory,
  onAddInvoice, 
  onDeleteInvoice,
  isOpen,
  onClose,
  suppliers = [],
  onAddSupplier,
  onDeleteSupplier
}) => {
  const [activeTab, setActiveTab] = useState<Tab>('new');

  // -- New Invoice State --
  const [supplierName, setSupplierName] = useState('');
  const [paymentStatus, setPaymentStatus] = useState<PaymentStatus>('paid'); 
  const [itemInputs, setItemInputs] = useState({ name: '', quantity: '', cost: '' });
  const [currentInvoiceItems, setCurrentInvoiceItems] = useState<PurchaseItem[]>([]);

  // -- Archive & Search State --
  const [navStep, setNavStep] = useState<NavStep>('years');
  const [selectedYear, setSelectedYear] = useState<string>('');
  const [selectedMonth, setSelectedMonth] = useState<number>(-1);
  const [searchTerm, setSearchTerm] = useState('');

  // -- Printing State --
  const [invoiceToPrint, setInvoiceToPrint] = useState<PurchaseInvoice | null>(null);

  // --- Supplier Logic ---
  const handleSaveSupplier = () => {
    const trimmedName = supplierName.trim();
    if (!trimmedName) {
        alert('يرجى إدخال اسم المورد أولاً');
        return;
    }
    if (suppliers.some(s => s.name === trimmedName)) {
        alert('هذا المورد موجود مسبقاً في القائمة');
        return;
    }
    if (onAddSupplier) {
        onAddSupplier({ name: trimmedName });
        alert(`تم حفظ المورد "${trimmedName}" في القائمة بنجاح`);
    }
  };

  // --- Archive Logic ---
  const allInvoices = useMemo(() => {
    let all: PurchaseInvoice[] = [...currentPurchases];
    archivedHistory.forEach(day => {
        if (day.purchaseInvoices) {
            all = [...all, ...day.purchaseInvoices];
        }
    });
    return all.sort((a, b) => b.timestamp - a.timestamp); 
  }, [currentPurchases, archivedHistory]);

  // Search Filter
  const searchResults = useMemo(() => {
      if (!searchTerm) return null;
      const lower = searchTerm.toLowerCase();
      return allInvoices.filter(inv => 
          inv.supplierName.toLowerCase().includes(lower) || 
          inv.items.some(item => item.name.toLowerCase().includes(lower))
      );
  }, [allInvoices, searchTerm]);

  const years = useMemo(() => {
    const uniqueYears = new Set<string>(allInvoices.map(inv => new Date(inv.timestamp).getFullYear().toString()));
    return Array.from(uniqueYears).sort((a, b) => b.localeCompare(a));
  }, [allInvoices]);

  const months = useMemo(() => {
    if (!selectedYear) return [];
    const uniqueMonths = new Set<number>(
        allInvoices
        .filter(inv => new Date(inv.timestamp).getFullYear().toString() === selectedYear)
        .map(inv => new Date(inv.timestamp).getMonth())
    );
    return Array.from(uniqueMonths).sort((a, b) => b - a);
  }, [allInvoices, selectedYear]);

  const filteredInvoices = useMemo(() => {
    if (!selectedYear || selectedMonth === -1) return [];
    return allInvoices.filter(inv => {
        const d = new Date(inv.timestamp);
        return d.getFullYear().toString() === selectedYear && d.getMonth() === selectedMonth;
    });
  }, [allInvoices, selectedYear, selectedMonth]);

  const getMonthName = (m: number) => new Date(2000, m).toLocaleString('ar-SY', { month: 'long' });

  // --- Handlers ---
  const addItemToInvoice = () => {
      if (!itemInputs.name || !itemInputs.quantity || !itemInputs.cost) return;
      const qty = parseFloat(itemInputs.quantity);
      const cost = parseFloat(itemInputs.cost);
      const newItem: PurchaseItem = {
          id: Date.now().toString(),
          name: itemInputs.name,
          quantity: qty,
          cost: cost,
          total: qty * cost
      };
      setCurrentInvoiceItems(prev => [...prev, newItem]);
      setItemInputs({ name: '', quantity: '', cost: '' }); 
  };

  const handleSaveInvoice = () => {
      if (!supplierName || currentInvoiceItems.length === 0) {
          alert('يرجى إدخال اسم المورد وإضافة مادة واحدة على الأقل.');
          return;
      }
      const totalAmount = currentInvoiceItems.reduce((sum, item) => sum + item.total, 0);
      onAddInvoice({
          id: Date.now().toString(),
          supplierName,
          date: new Date().toLocaleDateString('en-GB'),
          timestamp: Date.now(),
          items: currentInvoiceItems,
          totalAmount,
          paymentStatus
      });
      setSupplierName('');
      setCurrentInvoiceItems([]);
      setPaymentStatus('paid');
      alert('تم حفظ فاتورة المشتريات بنجاح');
  };

  if (!isOpen) return null;

  return (
    <>
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-2xl w-full max-w-2xl shadow-2xl border border-gray-700 animate-fade-up flex flex-col h-[85vh]">

        {/* Header */}
        <div className="p-4 border-b border-gray-700 flex justify-between items-center bg-gray-900/50 rounded-t-2xl shrink-0">
          <div className="flex items-center gap-2 text-white">
            <ShoppingCart size={20} className="text-red-400" />
            <h3 className="font-bold text-lg">إدارة المشتريات والموردين</h3>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full transition-colors">
            <X size={20} className="text-gray-400" />
          </button>
        </div>

        {/* Tabs Navigation */}
        <div className="flex border-b border-gray-700 bg-gray-700/20">
            <button 
                onClick={() => { setActiveTab('new'); setSearchTerm(''); }}
                className={`flex-1 py-3 text-sm font-bold transition-colors flex items-center justify-center gap-2 ${activeTab === 'new' ? 'bg-[#FA8072] text-white' : 'text-gray-400 hover:text-white hover:bg-gray-700'}`}
            >
                <Plus size={16} />
                فاتورة جديدة
            </button>
            <button 
                onClick={() => setActiveTab('history')}
                className={`flex-1 py-3 text-sm font-bold transition-colors flex items-center justify-center gap-2 ${activeTab === 'history' ? 'bg-[#FA8072] text-white' : 'text-gray-400 hover:text-white hover:bg-gray-700'}`}
            >
                <Folder size={16} />
                أرشيف المشتريات
            </button>
            <button 
                onClick={() => { setActiveTab('suppliers'); setSearchTerm(''); }}
                className={`flex-1 py-3 text-sm font-bold transition-colors flex items-center justify-center gap-2 ${activeTab === 'suppliers' ? 'bg-[#FA8072] text-white' : 'text-gray-400 hover:text-white hover:bg-gray-700'}`}
            >
                <UserPlus size={16} />
                الموردين
            </button>
        </div>

        {/* Content Area */}
        <div className="p-4 md:p-6 overflow-y-auto flex-1 bg-gray-900/30">

          {/* === TAB 1: NEW INVOICE === */}
          {activeTab === 'new' && (
              <div className="space-y-6 animate-fade-up">
                  <div className="flex flex-col md:flex-row gap-4">
                      <div className="bg-gray-800 p-4 rounded-xl border border-gray-700 flex-grow">
                          <div className="flex justify-between items-center mb-1">
                             <label className="text-xs text-gray-400 block font-bold">اسم المورد</label>
                             <button onClick={handleSaveSupplier} className="text-[10px] text-[#FA8072] hover:underline flex items-center gap-1 font-bold">
                                 <UserPlus size={10} />
                                 حفظ المورد في القائمة
                             </button>
                          </div>
                          <input 
                              list="suppliers-list-data"
                              type="text" 
                              value={supplierName}
                              onChange={e => setSupplierName(e.target.value)}
                              className="w-full bg-gray-900 border border-gray-600 rounded-lg px-3 py-2 text-white outline-none focus:border-red-400"
                              placeholder="اختر او اكتب اسم المورد..."
                          />
                          <datalist id="suppliers-list-data">
                              {suppliers.map(s => <option key={s.id} value={s.name} />)}
                          </datalist>
                      </div>

                      <div className="bg-gray-800 p-4 rounded-xl border border-gray-700 min-w-[200px]">
                          <label className="text-xs text-gray-400 mb-2 block font-bold">طريقة الدفع</label>
                          <div className="flex bg-gray-900 p-1 rounded-lg">
                              <button 
                                onClick={() => setPaymentStatus('paid')}
                                className={`flex-1 py-1.5 text-xs font-bold rounded-md transition-colors ${paymentStatus === 'paid' ? 'bg-green-600 text-white' : 'text-gray-400'}`}
                              >نقدية</button>
                              <button 
                                onClick={() => setPaymentStatus('credit')}
                                className={`flex-1 py-1.5 text-xs font-bold rounded-md transition-colors ${paymentStatus === 'credit' ? 'bg-orange-600 text-white' : 'text-gray-400'}`}
                              >آجل</button>
                          </div>
                      </div>
                  </div>

                  <div className="bg-gray-800 p-4 rounded-xl border border-gray-700">
                      <div className="grid grid-cols-12 gap-2">
                          <input type="text" value={itemInputs.name} onChange={e => setItemInputs({...itemInputs, name: e.target.value})} placeholder="المادة" className="col-span-5 bg-gray-900 border border-gray-600 rounded-lg px-2 py-2 text-white text-sm" />
                          <input type="number" value={itemInputs.quantity} onChange={e => setItemInputs({...itemInputs, quantity: e.target.value})} placeholder="الكمية" className="col-span-3 bg-gray-900 border border-gray-600 rounded-lg px-2 py-2 text-white text-sm text-center" />
                          <input type="number" value={itemInputs.cost} onChange={e => setItemInputs({...itemInputs, cost: e.target.value})} placeholder="السعر" className="col-span-3 bg-gray-900 border border-gray-600 rounded-lg px-2 py-2 text-white text-sm text-center" />
                          <button onClick={addItemToInvoice} className="col-span-1 bg-red-600 text-white rounded-lg flex items-center justify-center"><Plus size={18} /></button>
                      </div>
                  </div>

                  <div className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden min-h-[100px]">
                      <table className="w-full text-sm text-right">
                          <thead className="bg-gray-900 text-gray-400 text-xs font-bold">
                              <tr><th className="p-3">المادة</th><th className="p-3 text-center">الكمية</th><th className="p-3">السعر</th><th className="p-3">الإجمالي</th><th className="p-3 w-10"></th></tr>
                          </thead>
                          <tbody className="divide-y divide-gray-700">
                              {currentInvoiceItems.map(item => (
                                  <tr key={item.id}>
                                      <td className="p-3 text-white">{item.name}</td>
                                      <td className="p-3 text-center text-gray-300">{item.quantity}</td>
                                      <td className="p-3 text-gray-300">{item.cost.toLocaleString()}</td>
                                      <td className="p-3 font-bold text-red-400">{item.total.toLocaleString()}</td>
                                      <td className="p-3"><button onClick={() => setCurrentInvoiceItems(prev => prev.filter(i => i.id !== item.id))} className="text-gray-500 hover:text-red-500"><Trash2 size={14} /></button></td>
                                  </tr>
                              ))}
                          </tbody>
                      </table>
                  </div>

                  <div className="flex items-center justify-between bg-gray-800 p-4 rounded-xl border border-gray-700">
                      <h3 className="text-2xl font-bold text-red-400">{currentInvoiceItems.reduce((s, i) => s + i.total, 0).toLocaleString()} <span className="text-sm">ل.س</span></h3>
                      <button onClick={handleSaveInvoice} className="bg-green-600 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2 shadow-lg"><FileText size={18} /> حفظ الفاتورة</button>
                  </div>
              </div>
          )}

          {/* === TAB 2: HISTORY (NEW STEP-BASED UI WITH SEARCH) === */}
          {activeTab === 'history' && (
              <div className="space-y-4 animate-fade-up">
                  {/* Search Bar */}
                  <div className="relative">
                      <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                      <input 
                        type="text" 
                        value={searchTerm}
                        onChange={e => setSearchTerm(e.target.value)}
                        placeholder="بحث في المشتريات (اسم مورد أو مادة)..."
                        className="w-full bg-gray-800 border border-gray-700 rounded-xl pr-10 pl-4 py-2.5 text-sm text-white outline-none focus:border-red-400 transition-all"
                      />
                  </div>

                  {searchTerm ? (
                      // Search Results View
                      <div className="space-y-3">
                          {searchResults && searchResults.length > 0 ? (
                              searchResults.map(invoice => (
                                  <div key={invoice.id} className="bg-gray-800 rounded-xl border border-gray-700 p-4">
                                      <div className="flex justify-between items-start mb-2">
                                          <div>
                                              <span className="font-bold text-white block">{invoice.supplierName}</span>
                                              <span className="text-xs text-gray-500">{invoice.date}</span>
                                          </div>
                                          <div className="text-left flex items-center gap-2">
                                              <span className="font-bold text-red-400">{invoice.totalAmount.toLocaleString()}</span>
                                              <button onClick={() => setInvoiceToPrint(invoice)} className="text-gray-400 hover:text-white p-1"><Printer size={16} /></button>
                                          </div>
                                      </div>
                                      <div className="text-[10px] text-gray-400 truncate">
                                          {invoice.items.map(i => i.name).join(' ، ')}
                                      </div>
                                  </div>
                              ))
                          ) : (
                              <div className="text-center py-10 text-gray-500">لا توجد نتائج مطابقة لبحثك</div>
                          )}
                      </div>
                  ) : (
                      // Stepped Navigation View
                      <>
                          <div className="flex items-center gap-2 mb-2">
                              {navStep !== 'years' && (
                                  <button onClick={() => setNavStep(navStep === 'days' ? 'months' : 'years')} className="p-1.5 bg-gray-700 rounded-lg text-white hover:bg-[#FA8072] transition-colors">
                                      <ArrowRight size={18} />
                                  </button>
                              )}
                              <h4 className="text-white font-bold text-sm">
                                  {navStep === 'years' && 'اختر السنة'}
                                  {navStep === 'months' && `سنة ${selectedYear} - اختر الشهر`}
                                  {navStep === 'days' && `${getMonthName(selectedMonth)} ${selectedYear}`}
                              </h4>
                          </div>

                          {navStep === 'years' && (
                              <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                                  {years.length === 0 ? <p className="col-span-full text-center py-10 text-gray-500">لا توجد بيانات مؤرشفة</p> : 
                                    years.map(y => (
                                      <button key={y} onClick={() => { setSelectedYear(y); setNavStep('months'); }} className="bg-gray-800 p-6 rounded-2xl border border-gray-700 hover:border-[#FA8072] flex flex-col items-center gap-2 transition-all group">
                                          <Folder size={32} className="text-[#FA8072] group-hover:scale-110 transition-transform" />
                                          <span className="font-bold text-lg text-white">{y}</span>
                                      </button>
                                  ))}
                              </div>
                          )}

                          {navStep === 'months' && (
                              <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                                  {months.map(m => (
                                      <button key={m} onClick={() => { setSelectedMonth(m); setNavStep('days'); }} className="bg-gray-800 p-6 rounded-2xl border border-gray-700 hover:border-[#FA8072] flex flex-col items-center gap-2 transition-all group">
                                          <CalendarDays size={32} className="text-blue-400 group-hover:scale-110 transition-transform" />
                                          <span className="font-bold text-lg text-white">{getMonthName(m)}</span>
                                      </button>
                                  ))}
                              </div>
                          )}

                          {navStep === 'days' && (
                              <div className="space-y-3">
                                  {filteredInvoices.map(invoice => (
                                      <div key={invoice.id} className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden group">
                                          <div className="p-4 flex items-center justify-between">
                                              <div>
                                                  <div className="flex items-center gap-2 mb-1">
                                                      <span className="font-bold text-white">{invoice.supplierName}</span>
                                                      <span className="text-[10px] bg-gray-700 text-gray-400 px-2 py-0.5 rounded-md">{invoice.date}</span>
                                                      <span className={`text-[10px] font-bold px-2 py-0.5 rounded-md ${invoice.paymentStatus === 'paid' ? 'bg-green-900/30 text-green-400' : 'bg-orange-900/30 text-orange-400'}`}>
                                                          {invoice.paymentStatus === 'paid' ? 'مدفوعة' : 'آجل'}
                                                      </span>
                                                  </div>
                                                  <p className="text-xs text-gray-500">{invoice.items.length} مواد</p>
                                              </div>
                                              <div className="text-left flex items-center gap-2">
                                                   <div className="font-bold text-red-400 text-lg">{invoice.totalAmount.toLocaleString()} <span className="text-xs font-normal">ل.س</span></div>
                                                   <button onClick={() => setInvoiceToPrint(invoice)} className="bg-gray-700 hover:bg-[#FA8072] text-white p-2 rounded-lg transition-all"><Printer size={16} /></button>
                                                   {currentPurchases.some(p => p.id === invoice.id) && (
                                                        <button onClick={() => onDeleteInvoice(invoice.id)} className="text-gray-600 hover:text-red-500 p-2"><Trash2 size={16} /></button>
                                                   )}
                                              </div>
                                          </div>
                                      </div>
                                  ))}
                              </div>
                          )}
                      </>
                  )}
              </div>
          )}

          {/* === TAB 3: SUPPLIERS LIST === */}
          {activeTab === 'suppliers' && (
              <div className="space-y-4 animate-fade-up">
                  <div className="bg-gray-800 p-4 rounded-xl border border-gray-700 flex flex-col gap-3">
                      <label className="text-sm font-bold text-white">إضافة مورد جديد للقائمة</label>
                      <div className="flex gap-2">
                          <input type="text" value={supplierName} onChange={e => setSupplierName(e.target.value)} placeholder="اسم المورد..." className="flex-grow bg-gray-900 border border-gray-600 rounded-lg px-3 py-2 text-white" />
                          <button onClick={handleSaveSupplier} className="bg-[#FA8072] text-white px-6 rounded-lg font-bold">إضافة</button>
                      </div>
                  </div>
                  <div className="space-y-2">
                      <h4 className="text-xs text-gray-500 font-bold mb-2">الموردين المسجلين ({suppliers.length})</h4>
                      {suppliers.length === 0 ? <p className="text-center py-10 text-gray-500">لا يوجد موردين في القائمة</p> : 
                        suppliers.map(s => (
                          <div key={s.id} className="bg-gray-800 p-3 rounded-xl border border-gray-700 flex justify-between items-center">
                              <span className="text-white font-bold">{s.name}</span>
                              <button onClick={() => onDeleteSupplier?.(s.id)} className="text-gray-500 hover:text-red-500 p-2 transition-colors"><Trash2 size={16} /></button>
                          </div>
                      ))}
                  </div>
              </div>
          )}
        </div>
      </div>
    </div>

    {invoiceToPrint && (
        <Suspense fallback={null}>
            <PurchasePrintModal invoice={invoiceToPrint} onClose={() => setInvoiceToPrint(null)} />
        </Suspense>
    )}
    </>
  );
};

import React, { useRef, useState } from 'react';
import { X, Download, Upload, Database, AlertTriangle, FileJson, Check, Trash2, Share2, Cloud, ExternalLink } from 'lucide-react';

interface DataManagementModalProps {
  onExport: () => void;
  onImport: (file: File) => void;
  onClose: () => void;
}

export const DataManagementModal: React.FC<DataManagementModalProps> = ({ onExport, onImport, onClose }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [isSharing, setIsSharing] = useState(false);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setSelectedFile(file);
    }
    if (e.target) e.target.value = '';
  };

  const handleConfirmImport = () => {
    if (!selectedFile) return;
    onImport(selectedFile);
    onClose();
  };

  const clearSelection = () => {
      setSelectedFile(null);
  };

  const handleShareToDrive = async () => {
      setIsSharing(true);
      try {
          const sales = JSON.parse(localStorage.getItem('dailySales') || '[]');
          const invoices = JSON.parse(localStorage.getItem('dailyPurchaseInvoices') || '[]');
          const history = JSON.parse(localStorage.getItem('salesHistory') || '[]');
          const products = JSON.parse(localStorage.getItem('products') || '[]');
          const customers = JSON.parse(localStorage.getItem('customers') || '[]');
          const suppliers = JSON.parse(localStorage.getItem('suppliers') || '[]');

          const data = { 
              appVersion: '1.3', 
              timestamp: Date.now(), 
              sales, 
              purchaseInvoices: invoices, 
              history, 
              products, 
              customers, 
              suppliers 
          };

          const dateStr = new Date().toLocaleDateString('en-GB').replace(/\//g, '-');
          const fileName = `cookies-bakery-backup-${dateStr}.json`;

          const jsonString = JSON.stringify(data, null, 2);
          const file = new File([jsonString], fileName, { type: 'application/json' });

          // Check for Share API
          if (navigator.canShare && navigator.canShare({ files: [file] })) {
              await navigator.share({
                  files: [file],
                  title: 'نسخة احتياطية - مخبز كوكيز',
                  text: `نسخة بتاريخ ${dateStr}`,
              });
              alert('تم فتح قائمة المشاركة. اختر تطبيق Drive لحفظ النسخة سحابياً.');
          } else {
              // Fallback to instructions + download
              if (confirm('متصفحك لا يدعم المشاركة المباشرة. سيتم تحميل الملف لجهازك أولاً، هل تريد فتحه في صفحة Google Drive لرفعه يدوياً؟')) {
                  onExport();
                  window.open('https://drive.google.com/drive/u/0/my-drive', '_blank');
              }
          }
      } catch (error) {
          console.error('Error sharing:', error);
          if (error instanceof Error && error.name !== 'AbortError') {
              alert('عذراً، حدث خطأ أثناء المزامنة. يمكنك تحميل الملف يدوياً ورفعه للدرايف.');
              onExport();
          }
      } finally {
          setIsSharing(false);
      }
  };

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-2xl w-full max-w-lg shadow-2xl border border-gray-700 animate-fade-up flex flex-col">

        {/* Header */}
        <div className="p-4 border-b border-gray-700 flex justify-between items-center bg-gray-900/50 rounded-t-2xl">
          <div className="flex items-center gap-2 text-white">
            <Database size={20} className="text-[#FA8072]" />
            <h3 className="font-bold text-lg">النسخ الاحتياطي والاستعادة</h3>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full transition-colors">
            <X size={20} className="text-gray-400" />
          </button>
        </div>

        {/* Content */}
        <div className="p-6 space-y-6">

            {/* Export Section */}
            <div className="bg-gray-700/30 p-4 rounded-xl border border-gray-600">
                <div className="flex items-start gap-3 mb-3">
                    <div className="bg-blue-500/20 p-2 rounded-lg text-blue-400">
                        <Download size={24} />
                    </div>
                    <div>
                        <h4 className="text-white font-bold text-sm">تصدير نسخة احتياطية</h4>
                        <p className="text-gray-400 text-xs mt-1">حفظ البيانات على جهازك أو رفعها إلى السحابة.</p>
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-3">
                    <button 
                        onClick={onExport}
                        className="bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-lg font-bold text-xs transition-colors flex items-center justify-center gap-2"
                    >
                        <Download size={16} />
                        تحميل (جهاز)
                    </button>

                    <button 
                        onClick={handleShareToDrive}
                        disabled={isSharing}
                        className="bg-green-600 hover:bg-green-500 text-white py-3 rounded-lg font-bold text-xs transition-colors flex items-center justify-center gap-2 disabled:opacity-50"
                    >
                        {isSharing ? <Check size={16} className="animate-pulse" /> : <Cloud size={16} />}
                        {isSharing ? 'جاري الفتح...' : 'Google Drive'}
                    </button>
                </div>
                 <div className="mt-3 p-2 bg-gray-900/50 rounded-lg flex items-start gap-2 border border-gray-700">
                    <ExternalLink size={12} className="text-gray-500 shrink-0 mt-0.5" />
                    <p className="text-[10px] text-gray-500 font-bold leading-relaxed">
                        ملاحظة: زر Google Drive يقوم بفتح قائمة المشاركة في هاتفك؛ اختر "Drive" وسيتم رفع الملف تلقائياً إلى حسابك.
                    </p>
                 </div>
            </div>

            {/* Import Section */}
            <div className="bg-gray-700/30 p-4 rounded-xl border border-gray-600">
                <div className="flex items-start gap-3 mb-3">
                    <div className="bg-purple-500/20 p-2 rounded-lg text-purple-400">
                        <Upload size={24} />
                    </div>
                    <div>
                        <h4 className="text-white font-bold text-sm">استيراد بيانات (Restore)</h4>
                        <p className="text-gray-400 text-xs mt-1">استرجاع البيانات من ملف محفوظ مسبقاً.</p>
                    </div>
                </div>

                <div className="bg-yellow-500/10 border border-yellow-500/20 rounded-lg p-3 mb-4 flex items-start gap-2">
                    <AlertTriangle size={16} className="text-yellow-500 shrink-0 mt-0.5" />
                    <p className="text-[10px] text-yellow-200 leading-relaxed font-bold">
                        تحذير: هذه العملية ستقوم باستبدال جميع البيانات الحالية ببيانات الملف المختار.
                    </p>
                </div>

                <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".json" className="hidden" />

                {!selectedFile ? (
                    <button 
                        onClick={() => fileInputRef.current?.click()}
                        className="w-full bg-gray-600 hover:bg-gray-500 text-white py-3 rounded-lg font-bold text-sm transition-colors flex items-center justify-center gap-2 border border-gray-500 border-dashed"
                    >
                        <Upload size={18} />
                        اختيار ملف النسخة الاحتياطية
                    </button>
                ) : (
                    <div className="space-y-3 animate-fade-up">
                        <div className="bg-gray-800 p-3 rounded-lg border border-gray-600 flex items-center justify-between">
                            <div className="flex items-center gap-3 overflow-hidden">
                                <div className="bg-green-900/50 p-2 rounded"><FileJson className="text-green-400" size={24} /></div>
                                <div className="flex flex-col overflow-hidden text-right">
                                    <span className="text-sm text-white font-medium truncate">{selectedFile.name}</span>
                                    <span className="text-[10px] text-gray-400">{(selectedFile.size / 1024).toFixed(2)} KB</span>
                                </div>
                            </div>
                            <button onClick={clearSelection} className="p-2 hover:bg-red-500/20 text-red-400 rounded-lg"><Trash2 size={18} /></button>
                        </div>
                        <button onClick={handleConfirmImport} className="w-full bg-green-600 hover:bg-green-500 text-white py-3 rounded-lg font-bold text-sm flex items-center justify-center gap-2 shadow-lg"><Check size={18} /> تأكيد واستعادة البيانات</button>
                    </div>
                )}
            </div>

        </div>
      </div>
    </div>
  );
};

