    </div>
);

// Improved Loading Screen with Circular Progress and Detailed Status
const LoadingScreen = ({ progress, message }: { progress: number, message: string }) => {
    const radius = 70;
    const stroke = 10;
    const normalizedRadius = radius - stroke * 2;
    const circumference = normalizedRadius * 2 * Math.PI;
    const strokeDashoffset = circumference - (progress / 100) * circumference;

    return (
      <div className="fixed inset-0 bg-[#0f172a] z-[100] flex flex-col items-center justify-center p-6 text-center">
        <div className="mb-12">
            <h1 className="text-3xl font-black text-[#FA8072] tracking-tighter mb-1">مخبز كوكيز</h1>
            <p className="text-gray-500 text-sm font-bold">Cookies Bakery POS System</p>
        </div>

        <div className="relative flex items-center justify-center mb-10">
            <svg height={radius * 2} width={radius * 2} className="transform rotate-[-90deg]">
                <circle
                    stroke="#1e293b"
                    strokeWidth={stroke}
                    r={normalizedRadius}
                    cx={radius}
                    cy={radius}
                    fill="transparent"
                />
                <circle
                    stroke="#FA8072"
                    strokeWidth={stroke}
                    strokeDasharray={circumference + ' ' + circumference}
                    style={{ strokeDashoffset, transition: 'stroke-dashoffset 0.3s ease-in-out' }}
                    strokeLinecap="round"
                    r={normalizedRadius}
                    cx={radius}
                    cy={radius}
                    fill="transparent"
                />
            </svg>
            <div className="absolute flex flex-col items-center justify-center">
                <span className="text-white font-black text-2xl">{progress}%</span>
            </div>
        </div>

        <div className="max-w-xs w-full bg-gray-800/50 p-4 rounded-2xl border border-gray-700/50 backdrop-blur-md">
            <div className="flex items-center justify-center gap-3 text-[#FA8072] mb-1">
                <Loader2 size={16} className="animate-spin" />
                <span className="text-xs font-bold uppercase tracking-widest">Processing</span>
            </div>
            <p className="text-gray-300 font-bold text-sm leading-relaxed">{message}</p>
        </div>

        <div className="mt-12 text-gray-600 text-[10px] font-mono">
            ESTABLISHING SECURE CONNECTION...
        </div>
      </div>
    );
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => sessionStorage.getItem('isAuth') === 'true');
  const [isAppLoading, setIsAppLoading] = useState(false);
  const [loadingProgress, setLoadingProgress] = useState(0);
  const [loadingMessage, setLoadingMessage] = useState('');

  const isOnline = useOnlineStatus();
  const [lastSyncTime, setLastSyncTime] = useState<Date>(new Date());
  const [isSyncing, setIsSyncing] = useState(false);
  const [installPrompt, setInstallPrompt] = useState<any>(null);

  // Core Data State
  const [sales, setSales] = useState<SaleItem[]>(() => {
    const saved = localStorage.getItem('dailySales');
    return saved ? JSON.parse(saved) : [];
  });

  const [purchaseInvoices, setPurchaseInvoices] = useState<PurchaseInvoice[]>(() => {
      const saved = localStorage.getItem('dailyPurchaseInvoices');
      return saved ? JSON.parse(saved) : [];
  });
  const [history, setHistory] = useState<ArchivedDay[]>(() => {
    const saved = localStorage.getItem('salesHistory');
    return saved ? JSON.parse(saved) : [];
  });
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('products');
    return saved ? JSON.parse(saved) : DEFAULT_PRODUCTS;
  });
  const [customers, setCustomers] = useState<Customer[]>(() => {
      const saved = localStorage.getItem('customers');
      return saved ? JSON.parse(saved) : [];
  });
  const [suppliers, setSuppliers] = useState<Supplier[]>(() => {
      const saved = localStorage.getItem('suppliers');
      return saved ? JSON.parse(saved) : [];
  });

  // UI State
  const [invoiceItems, setInvoiceItems] = useState<SaleItem[] | null>(null);
  const [showProductManager, setShowProductManager] = useState(false);
  const [showCustomerManager, setShowCustomerManager] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [showDataModal, setShowDataModal] = useState(false);
  const [showExpensesModal, setShowExpensesModal] = useState(false);

  const [undoState, setUndoState] = useState<{ items: SaleItem[], timerId: ReturnType<typeof setTimeout> } | null>(null);

  const handleLogin = () => {
      setIsAppLoading(true);
      setLoadingProgress(0);
      setLoadingMessage('بدء تهيئة النظام وتأمين الاتصال...');

      const steps = [
        { progress: 15, message: 'جاري فحص حالة التخزين المحلي والذاكرة المؤقتة...' },
        { progress: 30, message: 'استرجاع قائمة المنتجات والأسعار المحدثة...' },
        { progress: 50, message: 'تحميل أرشيف المبيعات والتقارير السنوية...' },
        { progress: 70, message: 'مزامنة بيانات الموردين والمشتريات الجارية...' },
        { progress: 85, message: 'تجهيز واجهة المستخدم وتطبيق التخصيصات...' },
        { progress: 95, message: 'اللمسات الأخيرة لتشغيل التطبيق...' },
        { progress: 100, message: 'جاهز للعمل! يتم توجيهك الآن...' }
      ];

      let currentStep = 0;
      const interval = setInterval(() => {
          if (currentStep < steps.length) {
              setLoadingProgress(steps[currentStep].progress);
              setLoadingMessage(steps[currentStep].message);
              currentStep++;
          } else {
              clearInterval(interval);
              setTimeout(() => {
                  sessionStorage.setItem('isAuth', 'true');
                  setIsAuthenticated(true);
                  setIsAppLoading(false);
              }, 400);
          }
      }, 500);
  };

  useEffect(() => { localStorage.setItem('dailySales', JSON.stringify(sales)); }, [sales]);
  useEffect(() => { localStorage.setItem('dailyPurchaseInvoices', JSON.stringify(purchaseInvoices)); }, [purchaseInvoices]);
  useEffect(() => { localStorage.setItem('salesHistory', JSON.stringify(history)); }, [history]);
  useEffect(() => { localStorage.setItem('products', JSON.stringify(products)); }, [products]);
  useEffect(() => { localStorage.setItem('customers', JSON.stringify(customers)); }, [customers]);
  useEffect(() => { localStorage.setItem('suppliers', JSON.stringify(suppliers)); }, [suppliers]);

  const handleManualSync = () => {
    setIsSyncing(true);
    setTimeout(() => {
      setLastSyncTime(new Date());
      setIsSyncing(false);
    }, 800);
  };

  const handleCompleteOrder = (items: any, name?: string, id?: string, type: SaleType = 'retail') => {
    const orderId = Date.now().toString(); 
    const time = new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
    const customerNumber = sales.length > 0 ? Math.max(...sales.map(s => s.customerNumber)) + 1 : 1;
    const itemsWithIds = items.map((i: any) => ({ ...i, id: Math.random().toString(36).substr(2,9), orderId, customerNumber, customerName: name, customerId: id, saleType: type, time }));
    setSales(prev => [...prev, ...itemsWithIds]);
  };

  const handleAddPurchaseInvoice = (newInvoice: PurchaseInvoice) => setPurchaseInvoices(prev => [...prev, newInvoice]);
  const handleDeletePurchaseInvoice = (id: string) => setPurchaseInvoices(prev => prev.filter(inv => inv.id !== id));
  const handleAddSupplier = (newSupplier: Omit<Supplier, 'id'>) => setSuppliers(prev => [...prev, { ...newSupplier, id: Date.now().toString() }]);
  const handleDeleteSupplier = (id: string) => setSuppliers(prev => prev.filter(s => s.id !== id));

  if (isAppLoading) return <LoadingScreen progress={loadingProgress} message={loadingMessage} />;
  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  return (
    <div className="min-h-screen flex flex-col bg-gray-900 print:bg-white">
      <Header 
        onOpenHistory={() => setShowHistory(true)} 
        onOpenDataManagement={() => setShowDataModal(true)}
        onOpenExpenses={() => setShowExpensesModal(true)}
        isOnline={isOnline}
        lastSyncTime={lastSyncTime}
        onManualSync={handleManualSync}
        isSyncing={isSyncing}
        installPrompt={installPrompt}
      />

      <main className="flex-grow container mx-auto px-4 py-6 max-w-5xl">
        <Summary items={sales} onPreview={() => setInvoiceItems(sales)} />
        <POSInterface 
            onCompleteOrder={handleCompleteOrder} 
            products={products}
            customers={customers}
            onOpenProductManager={() => setShowProductManager(true)}
            onOpenCustomerManager={() => setShowCustomerManager(true)}
        />
        <div className="mt-8">
            <SalesTable items={sales} onDeleteItem={(id) => setSales(s => s.filter(i => i.id !== id))} onDeleteOrder={(oid) => setSales(s => s.filter(i => i.orderId !== oid))} onPreviewInvoice={setInvoiceItems} />
        </div>
      </main>

      {showExpensesModal && (
          <Suspense fallback={<ModalLoader />}>
              <ExpensesModal
                isOpen={showExpensesModal}
                onClose={() => setShowExpensesModal(false)}
                currentPurchases={purchaseInvoices}
                archivedHistory={history}
                onAddInvoice={handleAddPurchaseInvoice}
                onDeleteInvoice={handleDeletePurchaseInvoice}
                suppliers={suppliers}
                onAddSupplier={handleAddSupplier}
                onDeleteSupplier={handleDeleteSupplier}
              />
          </Suspense>
      )}

      {/* Other Modals (History, ProductManager, etc) omitted for brevity - Assume they remain same */}
      {showHistory && <Suspense fallback={<ModalLoader />}><HistoryModal history={history} onClose={() => setShowHistory(false)} onClearHistory={() => setHistory([])} onPreviewInvoice={setInvoiceItems} /></Suspense>}
      {showProductManager && <Suspense fallback={<ModalLoader />}><ProductManager isOpen={showProductManager} onClose={() => setShowProductManager(false)} products={products} onAddProduct={(p) => setProducts(s => [...s, {...p, id: Date.now().toString()}])} onDeleteProduct={(id) => setProducts(s => s.filter(p => p.id !== id))} /></Suspense>}
      {showCustomerManager && <Suspense fallback={<ModalLoader />}><CustomerManager isOpen={showCustomerManager} onClose={() => setShowCustomerManager(false)} customers={customers} onAddCustomer={(c) => setCustomers(s => [...s, {...c, id: Date.now().toString()}])} onDeleteCustomer={(id) => setCustomers(s => s.filter(c => c.id !== id))} /></Suspense>}
      {showDataModal && <Suspense fallback={<ModalLoader />}><DataManagementModal onClose={() => setShowDataModal(false)} onExport={() => {}} onImport={() => {}} /></Suspense>}
      {invoiceItems && <Suspense fallback={<ModalLoader />}><InvoiceModal items={invoiceItems} onClose={() => setInvoiceItems(null)} /></Suspense>}

      <footer className="text-center py-6 text-gray-500 text-sm no-print">
        <p>نظام محاسبة مخبز كوكيز - v1.3</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo, Suspense } from 'react';
import { Plus, Trash2, X, ShoppingCart, Folder, FileText, CheckCircle, Clock, Download, Printer, UserPlus, ArrowRight, CalendarDays, TrendingDown, Search, Phone, FileSignature } from 'lucide-react';
import { PurchaseInvoice, PurchaseItem, ArchivedDay, PaymentStatus, Supplier } from '../types';

const PurchasePrintModal = React.lazy(() => import('./PurchasePrintModal').then(module => ({ default: module.PurchasePrintModal })));

interface ExpensesModalProps {
  currentPurchases: PurchaseInvoice[];
  archivedHistory: ArchivedDay[]; 
  onAddInvoice: (invoice: PurchaseInvoice) => void;
  onDeleteInvoice: (id: string) => void;
  isOpen: boolean;
  onClose: () => void;
  suppliers: Supplier[];
  onAddSupplier?: (supplier: Omit<Supplier, 'id'>) => void;
  onDeleteSupplier?: (id: string) => void;
}

type Tab = 'new' | 'history' | 'suppliers';
type NavStep = 'years' | 'months' | 'days';

export const ExpensesModal: React.FC<ExpensesModalProps> = ({ 
  currentPurchases, 
  archivedHistory,
  onAddInvoice, 
  onDeleteInvoice,
  isOpen,
  onClose,
  suppliers = [],
  onAddSupplier,
  onDeleteSupplier
}) => {
  const [activeTab, setActiveTab] = useState<Tab>('new');

  // -- New Invoice State --
  const [supplierName, setSupplierName] = useState('');
  const [paymentStatus, setPaymentStatus] = useState<PaymentStatus>('paid'); 
  const [itemInputs, setItemInputs] = useState({ name: '', quantity: '', cost: '' });
  const [currentInvoiceItems, setCurrentInvoiceItems] = useState<PurchaseItem[]>([]);

  // -- Supplier Management Form (Localized to Suppliers Tab) --
  const [newSupName, setNewSupName] = useState('');
  const [newSupPhone, setNewSupPhone] = useState('');
  const [newSupNotes, setNewSupNotes] = useState('');

  // -- Archive Navigation --
  const [navStep, setNavStep] = useState<NavStep>('years');
  const [selectedYear, setSelectedYear] = useState<string>('');
  const [selectedMonth, setSelectedMonth] = useState<number>(-1);
  const [searchTerm, setSearchTerm] = useState('');

  const [invoiceToPrint, setInvoiceToPrint] = useState<PurchaseInvoice | null>(null);

  // --- Handlers ---
  const handleCreateSupplier = () => {
    if (!newSupName.trim()) { alert('يرجى إدخال اسم المورد'); return; }
    if (onAddSupplier) {
        onAddSupplier({
            name: newSupName.trim(),
            phone: newSupPhone.trim(),
            notes: newSupNotes.trim()
        });
        setNewSupName('');
        setNewSupPhone('');
        setNewSupNotes('');
        alert('تم حفظ المورد بنجاح في القائمة.');
    }
  };

  const handleSaveInvoice = () => {
      if (!supplierName || currentInvoiceItems.length === 0) {
          alert('يرجى اختيار مورد وإضافة مادة واحدة على الأقل.');
          return;
      }
      const totalAmount = currentInvoiceItems.reduce((sum, item) => sum + item.total, 0);
      onAddInvoice({
          id: Date.now().toString(),
          supplierName,
          date: new Date().toLocaleDateString('en-GB'),
          timestamp: Date.now(),
          items: currentInvoiceItems,
          totalAmount,
          paymentStatus
      });
      setSupplierName('');
      setCurrentInvoiceItems([]);
      alert('تم حفظ الفاتورة بنجاح.');
  };

  const addItem = () => {
      if (!itemInputs.name || !itemInputs.quantity || !itemInputs.cost) return;
      const q = parseFloat(itemInputs.quantity);
      const c = parseFloat(itemInputs.cost);
      setCurrentInvoiceItems(prev => [...prev, { id: Date.now().toString(), name: itemInputs.name, quantity: q, cost: c, total: q * c }]);
      setItemInputs({ name: '', quantity: '', cost: '' });
  };

  // --- Archive Logic ---
  const allInvoices = useMemo(() => {
    let all = [...currentPurchases];
    archivedHistory.forEach(day => { if (day.purchaseInvoices) all = [...all, ...day.purchaseInvoices]; });
    return all.sort((a, b) => b.timestamp - a.timestamp);
  }, [currentPurchases, archivedHistory]);

  const searchResults = useMemo(() => {
    if (!searchTerm) return null;
    return allInvoices.filter(i => i.supplierName.includes(searchTerm) || i.items.some(it => it.name.includes(searchTerm)));
  }, [allInvoices, searchTerm]);

  if (!isOpen) return null;

  return (
    <>
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-2xl w-full max-w-2xl shadow-2xl border border-gray-700 animate-fade-up flex flex-col h-[85vh]">

        <div className="p-4 border-b border-gray-700 flex justify-between items-center bg-gray-900/50 rounded-t-2xl shrink-0">
          <div className="flex items-center gap-2 text-white">
            <ShoppingCart size={20} className="text-[#FA8072]" />
            <h3 className="font-bold text-lg">إدارة المشتريات والموردين</h3>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full transition-colors"><X size={20} className="text-gray-400" /></button>
        </div>

        <div className="flex border-b border-gray-700 bg-gray-700/20">
            <button onClick={() => setActiveTab('new')} className={`flex-1 py-3 text-sm font-bold flex items-center justify-center gap-2 ${activeTab === 'new' ? 'bg-[#FA8072] text-white' : 'text-gray-400 hover:bg-gray-700'}`}><Plus size={16} /> فاتورة شراء</button>
            <button onClick={() => setActiveTab('history')} className={`flex-1 py-3 text-sm font-bold flex items-center justify-center gap-2 ${activeTab === 'history' ? 'bg-[#FA8072] text-white' : 'text-gray-400 hover:bg-gray-700'}`}><Folder size={16} /> الأرشيف</button>
            <button onClick={() => setActiveTab('suppliers')} className={`flex-1 py-3 text-sm font-bold flex items-center justify-center gap-2 ${activeTab === 'suppliers' ? 'bg-[#FA8072] text-white' : 'text-gray-400 hover:bg-gray-700'}`}><UserPlus size={16} /> الموردين</button>
        </div>

        <div className="p-4 md:p-6 overflow-y-auto flex-1 bg-gray-900/30">

          {/* TAB 1: NEW INVOICE */}
          {activeTab === 'new' && (
              <div className="space-y-4 animate-fade-up">
                  <div className="bg-gray-800 p-4 rounded-xl border border-gray-700">
                      <label className="text-xs text-gray-500 font-bold mb-2 block text-right">اختر المورد من القائمة المسجلة</label>
                      <div className="flex gap-2">
                        <select 
                            value={supplierName} 
                            onChange={e => setSupplierName(e.target.value)}
                            className="flex-grow bg-gray-900 border border-gray-600 rounded-lg px-3 py-2 text-white text-sm outline-none focus:border-[#FA8072]"
                        >
                            <option value="">-- اختر مورد من القائمة --</option>
                            {suppliers.map(s => <option key={s.id} value={s.name}>{s.name} {s.phone ? `(${s.phone})` : ''}</option>)}
                        </select>
                        <button onClick={() => setActiveTab('suppliers')} className="bg-gray-700 p-2 rounded-lg text-[#FA8072] border border-gray-600" title="إضافة مورد جديد"><UserPlus size={20} /></button>
                      </div>
                  </div>

                  <div className="bg-gray-800 p-4 rounded-xl border border-gray-700 flex flex-col md:flex-row gap-2">
                      <input type="text" value={itemInputs.name} onChange={e => setItemInputs({...itemInputs, name: e.target.value})} placeholder="اسم المادة..." className="flex-grow bg-gray-900 border border-gray-600 rounded-lg px-3 py-2 text-white text-sm" />
                      <input type="number" value={itemInputs.quantity} onChange={e => setItemInputs({...itemInputs, quantity: e.target.value})} placeholder="الكمية" className="w-24 bg-gray-900 border border-gray-600 rounded-lg px-2 text-center text-white text-sm" />
                      <input type="number" value={itemInputs.cost} onChange={e => setItemInputs({...itemInputs, cost: e.target.value})} placeholder="السعر" className="w-24 bg-gray-900 border border-gray-600 rounded-lg px-2 text-center text-white text-sm" />
                      <button onClick={addItem} className="bg-red-600 text-white p-2 rounded-lg"><Plus size={20} /></button>
                  </div>

                  <div className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden">
                      <table className="w-full text-sm text-right">
                          <thead className="bg-gray-900 text-gray-400 text-xs"><tr><th className="p-3">المادة</th><th className="p-3 text-center">الكمية</th><th className="p-3 text-center">السعر</th><th className="p-3">الإجمالي</th><th className="p-3"></th></tr></thead>
                          <tbody className="divide-y divide-gray-700">
                              {currentInvoiceItems.map(item => (
                                  <tr key={item.id}><td className="p-3 text-white">{item.name}</td><td className="p-3 text-center">{item.quantity}</td><td className="p-3 text-center">{item.cost.toLocaleString()}</td><td className="p-3 font-bold text-red-400">{item.total.toLocaleString()}</td><td className="p-3 text-left"><button onClick={() => setCurrentInvoiceItems(s => s.filter(i => i.id !== item.id))} className="text-gray-500 hover:text-red-500"><Trash2 size={14} /></button></td></tr>
                              ))}
                          </tbody>
                      </table>
                  </div>

                  <div className="flex items-center justify-between bg-gray-800 p-4 rounded-xl border border-gray-700">
                      <div className="text-xl font-bold text-red-400">{currentInvoiceItems.reduce((s,i) => s+i.total, 0).toLocaleString()} <span className="text-xs text-gray-500">ل.س</span></div>
                      <button onClick={handleSaveInvoice} className="bg-green-600 text-white px-6 py-2.5 rounded-xl font-bold flex items-center gap-2 shadow-lg"><FileText size={18} /> حفظ الفاتورة</button>
                  </div>
              </div>
          )}

          {/* TAB 3: SUPPLIER MANAGEMENT (CONSOLIDATED) */}
          {activeTab === 'suppliers' && (
              <div className="space-y-6 animate-fade-up">
                  <div className="bg-gray-800 p-5 rounded-xl border border-gray-700 space-y-4">
                      <h4 className="text-[#FA8072] font-bold text-sm flex items-center gap-2"><UserPlus size={18} /> إضافة مورد جديد للقاعدة</h4>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                          <div className="space-y-1"><label className="text-[10px] text-gray-500 font-bold pr-1">اسم المورد</label><input type="text" value={newSupName} onChange={e => setNewSupName(e.target.value)} placeholder="اسم المورد..." className="w-full bg-gray-900 border border-gray-600 rounded-lg px-3 py-2 text-white text-sm" /></div>
                          <div className="space-y-1"><label className="text-[10px] text-gray-500 font-bold pr-1">رقم الهاتف (اختياري)</label><input type="text" value={newSupPhone} onChange={e => setNewSupPhone(e.target.value)} placeholder="رقم الهاتف..." className="w-full bg-gray-900 border border-gray-600 rounded-lg px-3 py-2 text-white text-sm dir-ltr text-right" /></div>
                      </div>
                      <div className="space-y-1"><label className="text-[10px] text-gray-500 font-bold pr-1">ملاحظات إضافية (اختياري)</label><textarea value={newSupNotes} onChange={e => setNewSupNotes(e.target.value)} placeholder="العنوان أو شروط التعامل..." rows={2} className="w-full bg-gray-900 border border-gray-600 rounded-lg px-3 py-2 text-white text-sm"></textarea></div>
                      <button onClick={handleCreateSupplier} className="w-full bg-[#FA8072] text-white py-3 rounded-xl font-bold flex items-center justify-center gap-2 shadow-lg"><CheckCircle size={18} /> إضافة المورد</button>
                  </div>

                  <div className="space-y-2">
                      <h4 className="text-xs text-gray-500 font-bold px-1">الموردين المسجلين ({suppliers.length})</h4>
                      <div className="grid gap-2">
                          {suppliers.map(s => (
                              <div key={s.id} className="bg-gray-800 p-4 rounded-xl border border-gray-700 flex justify-between items-start">
                                  <div>
                                      <span className="text-white font-bold block">{s.name}</span>
                                      {s.phone && <span className="text-xs text-gray-400 flex items-center gap-1 mt-1 font-mono"><Phone size={10} /> {s.phone}</span>}
