                      </div>
                  </div>
              </div>
          )}

          {/* TAB 2: ARCHIVE (Simplified navigation) */}
          {activeTab === 'history' && (
              <div className="space-y-4 animate-fade-up">
                  <div className="relative"><Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} /><input type="text" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} placeholder="بحث في المشتريات (اسم مورد أو مادة)..." className="w-full bg-gray-800 border border-gray-700 rounded-xl pr-10 pl-4 py-2.5 text-sm text-white outline-none" /></div>
                  <div className="space-y-3">
                      {(searchTerm ? searchResults : allInvoices)?.map(inv => (
                          <div key={inv.id} className="bg-gray-800 rounded-xl border border-gray-700 p-4 flex items-center justify-between">
                              <div><span className="font-bold text-white block">{inv.supplierName}</span><span className="text-[10px] text-gray-500">{inv.date}</span></div>
                              <div className="flex items-center gap-2"><span className="font-bold text-red-400">{inv.totalAmount.toLocaleString()}</span><button onClick={() => setInvoiceToPrint(inv)} className="bg-gray-700 text-white p-2 rounded-lg hover:bg-[#FA8072] transition-colors"><Printer size={16} /></button></div>
                          </div>
                      ))}
                  </div>
              </div>
          )}
        </div>
      </div>
    </div>
    {invoiceToPrint && <Suspense fallback={null}><PurchasePrintModal invoice={invoiceToPrint} onClose={() => setInvoiceToPrint(null)} /></Suspense>}
    </>
  );
};

import React, { useState, useEffect, Suspense } from 'react';
