const LoadingScreen = ({ progress, message }: { progress: number, message: string }) => {
    const radius = 70;
    const stroke = 8;
    const normalizedRadius = radius - stroke * 2;
    const circumference = normalizedRadius * 2 * Math.PI;
    const strokeDashoffset = circumference - (progress / 100) * circumference;

    return (
      <div className="fixed inset-0 bg-[#0f172a] z-[100] flex flex-col items-center justify-center p-6 text-center">
        <div className="mb-12">
            <h1 className="text-3xl font-black text-[#FA8072] tracking-tighter mb-1">مخبز كوكيز</h1>
            <p className="text-gray-500 text-sm font-bold">Cookies Bakery POS System</p>
        </div>
        <div className="relative flex items-center justify-center mb-10">
            <svg height={radius * 2} width={radius * 2} className="transform rotate-[-90deg]">
                <circle stroke="#1e293b" strokeWidth={stroke} r={normalizedRadius} cx={radius} cy={radius} fill="transparent" />
                <circle stroke="#FA8072" strokeWidth={stroke} strokeDasharray={circumference + ' ' + circumference} style={{ strokeDashoffset, transition: 'stroke-dashoffset 0.3s ease-in-out' }} strokeLinecap="round" r={normalizedRadius} cx={radius} cy={radius} fill="transparent" />
            </svg>
            <div className="absolute flex flex-col items-center justify-center">
                <span className="text-white font-black text-2xl">{progress}%</span>
            </div>
        </div>
        <div className="max-w-xs w-full bg-gray-800/50 p-4 rounded-2xl border border-gray-700/50 backdrop-blur-md">
            <div className="flex items-center justify-center gap-3 text-[#FA8072] mb-1"><Loader2 size={16} className="animate-spin" /><span className="text-xs font-bold uppercase tracking-widest">Processing Data</span></div>
            <p className="text-gray-300 font-bold text-sm leading-relaxed">{message}</p>
        </div>
      </div>
    );
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => sessionStorage.getItem('isAuth') === 'true');
  const [isAppLoading, setIsAppLoading] = useState(false);
  const [loadingProgress, setLoadingProgress] = useState(0);
  const [loadingMessage, setLoadingMessage] = useState('');

  const isOnline = useOnlineStatus();
  const [lastSyncTime, setLastSyncTime] = useState<Date>(new Date());
  const [isSyncing, setIsSyncing] = useState(false);

  const [sales, setSales] = useState<SaleItem[]>(() => JSON.parse(localStorage.getItem('dailySales') || '[]'));
  const [purchaseInvoices, setPurchaseInvoices] = useState<PurchaseInvoice[]>(() => JSON.parse(localStorage.getItem('dailyPurchaseInvoices') || '[]'));
  const [history, setHistory] = useState<ArchivedDay[]>(() => JSON.parse(localStorage.getItem('salesHistory') || '[]'));
  const [products, setProducts] = useState<Product[]>(() => JSON.parse(localStorage.getItem('products') || '[]'));
  const [customers, setCustomers] = useState<Customer[]>(() => JSON.parse(localStorage.getItem('customers') || '[]'));
  const [suppliers, setSuppliers] = useState<Supplier[]>(() => JSON.parse(localStorage.getItem('suppliers') || '[]'));

  const [invoiceItems, setInvoiceItems] = useState<SaleItem[] | null>(null);
  const [showProductManager, setShowProductManager] = useState(false);
  const [showCustomerManager, setShowCustomerManager] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [showDataModal, setShowDataModal] = useState(false);
  const [showExpensesModal, setShowExpensesModal] = useState(false);

  const handleLogin = () => {
      setIsAppLoading(true);
      setLoadingProgress(0);
      setLoadingMessage('بدء تهيئة النظام وتأمين الاتصال...');
      const steps = [
        { progress: 15, message: 'فحص حالة التخزين المحلي والذاكرة...' },
        { progress: 30, message: 'تحميل قائمة المنتجات وأحدث الأسعار...' },
        { progress: 50, message: 'مزامنة أرشيف المبيعات والتقارير المالية...' },
        { progress: 70, message: 'تجهيز سجل المشتريات وقاعدة بيانات الموردين...' },
        { progress: 85, message: 'تطبيق إعدادات واجهة المستخدم المخصصة...' },
        { progress: 95, message: 'اللمسات النهائية لتشغيل التطبيق...' },
        { progress: 100, message: 'اكتمل التحميل! يتم توجيهك الآن...' }
      ];
      let currentStep = 0;
      const interval = setInterval(() => {
          if (currentStep < steps.length) {
              setLoadingProgress(steps[currentStep].progress);
              setLoadingMessage(steps[currentStep].message);
              currentStep++;
          } else {
              clearInterval(interval);
              setTimeout(() => {
                  sessionStorage.setItem('isAuth', 'true');
                  setIsAuthenticated(true);
                  setIsAppLoading(false);
              }, 400);
          }
      }, 400);
  };

  useEffect(() => { localStorage.setItem('dailySales', JSON.stringify(sales)); }, [sales]);
  useEffect(() => { localStorage.setItem('dailyPurchaseInvoices', JSON.stringify(purchaseInvoices)); }, [purchaseInvoices]);
  useEffect(() => { localStorage.setItem('salesHistory', JSON.stringify(history)); }, [history]);
  useEffect(() => { localStorage.setItem('products', JSON.stringify(products)); }, [products]);
  useEffect(() => { localStorage.setItem('customers', JSON.stringify(customers)); }, [customers]);
  useEffect(() => { localStorage.setItem('suppliers', JSON.stringify(suppliers)); }, [suppliers]);

  const handleAddSupplier = (newSup: Omit<Supplier, 'id'>) => setSuppliers(prev => [...prev, { ...newSup, id: Date.now().toString() }]);
  const handleDeleteSupplier = (id: string) => setSuppliers(prev => prev.filter(s => s.id !== id));

  const handleCompleteOrder = (items: any[], name?: string, id?: string, type: SaleType = 'retail') => {
      const orderId = Date.now().toString(); 
      const time = new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
      const customerNumber = sales.length > 0 ? Math.max(...sales.map(s => s.customerNumber)) + 1 : 1;

      const itemsWithIds = items.map((i: any) => ({ 
          ...i, 
          id: Math.random().toString(36).substr(2,9), 
          orderId, 
          customerNumber, 
          customerName: name, 
          customerId: id, 
          saleType: type, 
          time 
      }));
      setSales(prev => [...prev, ...itemsWithIds]);
  };

  if (isAppLoading) return <LoadingScreen progress={loadingProgress} message={loadingMessage} />;
  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  return (
    <div className="min-h-screen flex flex-col bg-gray-900 print:bg-white">
      <Header 
        onOpenHistory={() => setShowHistory(true)} 
        onOpenDataManagement={() => setShowDataModal(true)}
        onOpenExpenses={() => setShowExpensesModal(true)}
        isOnline={isOnline}
        lastSyncTime={lastSyncTime}
        onManualSync={() => { setIsSyncing(true); setTimeout(() => { setLastSyncTime(new Date()); setIsSyncing(false); }, 800); }}
        isSyncing={isSyncing}
      />
      <main className="flex-grow container mx-auto px-4 py-6 max-w-5xl">
        <Summary items={sales} onPreview={() => setInvoiceItems(sales)} />
        <POSInterface 
            onCompleteOrder={handleCompleteOrder} 
            products={products}
            customers={customers}
            onOpenProductManager={() => setShowProductManager(true)}
            onOpenCustomerManager={() => setShowCustomerManager(true)}
        />
        <div className="mt-8">
            <SalesTable items={sales} onDeleteItem={(id) => setSales(s => s.filter(i => i.id !== id))} onDeleteOrder={(oid) => setSales(s => s.filter(i => i.orderId !== oid))} onPreviewInvoice={setInvoiceItems} />
        </div>
      </main>

      {showExpensesModal && (
          <Suspense fallback={<ModalLoader />}>
              <ExpensesModal isOpen={showExpensesModal} onClose={() => setShowExpensesModal(false)} currentPurchases={purchaseInvoices} archivedHistory={history} onAddInvoice={(inv) => setPurchaseInvoices(prev => [...prev, inv])} onDeleteInvoice={(id) => setPurchaseInvoices(prev => prev.filter(inv => inv.id !== id))} suppliers={suppliers} onAddSupplier={handleAddSupplier} onDeleteSupplier={handleDeleteSupplier} />
          </Suspense>
      )}
      {showHistory && <Suspense fallback={<ModalLoader />}><HistoryModal history={history} onClose={() => setShowHistory(false)} onClearHistory={() => setHistory([])} onPreviewInvoice={setInvoiceItems} /></Suspense>}
      {showProductManager && <Suspense fallback={<ModalLoader />}><ProductManager isOpen={showProductManager} onClose={() => setShowProductManager(false)} products={products} onAddProduct={(p) => setProducts(s => [...s, {...p, id: Date.now().toString()}])} onDeleteProduct={(id) => setProducts(s => s.filter(p => p.id !== id))} /></Suspense>}
      {showCustomerManager && <Suspense fallback={<ModalLoader />}><CustomerManager isOpen={showCustomerManager} onClose={() => setShowCustomerManager(false)} customers={customers} onAddCustomer={(c) => setCustomers(s => [...s, {...c, id: Date.now().toString()}])} onDeleteCustomer={(id) => setCustomers(s => s.filter(c => c.id !== id))} /></Suspense>}
      {showDataModal && <Suspense fallback={<ModalLoader />}><DataManagementModal onClose={() => setShowDataModal(false)} onExport={() => {}} onImport={() => {}} /></Suspense>}
      {invoiceItems && <Suspense fallback={<ModalLoader />}><InvoiceModal items={invoiceItems} onClose={() => setInvoiceItems(null)} /></Suspense>}
      <footer className="text-center py-6 text-gray-500 text-sm no-print"><p>نظام محاسبة مخبز كوكيز - v1.3</p></footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Plus, Trash2, Settings, X, Scale, Box, Edit2, Check, RotateCcw } from 'lucide-react';
import { Product, UnitType } from '../types';

interface ProductManagerProps {
  products: Product[];
  onAddProduct: (product: Omit<Product, 'id'>) => void;
  onUpdateProduct: (id: string, product: Partial<Product>) => void;
  onDeleteProduct: (id: string) => void;
  isOpen: boolean;
  onClose: () => void;
}

export const ProductManager: React.FC<ProductManagerProps> = ({ 
  products, 
  onAddProduct, 
  onUpdateProduct,
  onDeleteProduct,
  isOpen,
  onClose
}) => {
  const [name, setName] = useState('');
  const [price, setPrice] = useState('');
  const [costPrice, setCostPrice] = useState('');
  const [unitType, setUnitType] = useState<UnitType>('piece');

  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState({ name: '', price: '', costPrice: '', unitType: 'piece' as UnitType });

  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !price || !costPrice) return;

    onAddProduct({
      name,
      price: parseFloat(price),
      costPrice: parseFloat(costPrice),
      unitType
    });

    setName('');
    setPrice('');
    setCostPrice('');
    setUnitType('piece');
  };

  const startEdit = (p: Product) => {
    setEditingId(p.id);
    setEditForm({ name: p.name, price: p.price.toString(), costPrice: p.costPrice.toString(), unitType: p.unitType });
  };

  const handleUpdate = () => {
    if (!editingId) return;
    onUpdateProduct(editingId, {
      name: editForm.name,
      price: parseFloat(editForm.price),
      costPrice: parseFloat(editForm.costPrice),
      unitType: editForm.unitType
    });
    setEditingId(null);
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-2xl w-full max-w-xl shadow-2xl border border-gray-700 animate-fade-up flex flex-col max-h-[85vh]">

        <div className="p-4 border-b border-gray-700 flex justify-between items-center bg-gray-900/50 rounded-t-2xl">
          <div className="flex items-center gap-2 text-white">
            <Settings size={20} className="text-[#FA8072]" />
            <h3 className="font-bold text-lg">إدارة المواد (التسعير والتكلفة)</h3>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full transition-colors">
            <X size={20} className="text-gray-400" />
          </button>
        </div>

        <div className="p-6 overflow-y-auto">
          {!editingId && (
              <form onSubmit={handleSubmit} className="mb-6 bg-gray-700/30 p-4 rounded-xl border border-gray-600">
                <h4 className="text-sm font-bold text-gray-300 mb-3">إضافة مادة جديدة</h4>
                <div className="flex flex-col gap-3">
                    <input
                        type="text"
                        value={name}
                        onChange={(e) => setName(e.target.value)}
                        placeholder="اسم المادة..."
                        className="w-full px-3 py-2 bg-gray-900 border border-gray-600 text-white rounded-lg outline-none text-sm"
                        required
                    />

                    <div className="grid grid-cols-2 gap-2">
                        <div className="space-y-1">
                            <label className="text-[10px] text-gray-500 font-bold pr-1">رأس المال (التكلفة)</label>
                            <input
                                type="number"
                                value={costPrice}
                                onChange={(e) => setCostPrice(e.target.value)}
                                placeholder="التكلفة"
                                className="w-full px-3 py-2 bg-gray-900 border border-gray-600 text-[#FA8072] rounded-lg outline-none text-sm font-bold"
                                required
                            />
                        </div>
                        <div className="space-y-1">
                            <label className="text-[10px] text-gray-500 font-bold pr-1">سعر البيع</label>
                            <input
                                type="number"
                                value={price}
                                onChange={(e) => setPrice(e.target.value)}
                                placeholder="سعر البيع"
                                className="w-full px-3 py-2 bg-gray-900 border border-gray-600 text-green-400 rounded-lg outline-none text-sm font-bold"
                                required
                            />
                        </div>
                    </div>

                    <div className="flex items-center justify-between gap-4">
                        <div className="flex bg-gray-900 rounded-lg p-1 border border-gray-600 shrink-0">
                            <button type="button" onClick={() => setUnitType('piece')} className={`px-3 py-1.5 rounded-md text-xs transition-colors ${unitType === 'piece' ? 'bg-[#FA8072] text-white font-bold' : 'text-gray-400'}`}>قطعة</button>
                            <button type="button" onClick={() => setUnitType('kg')} className={`px-3 py-1.5 rounded-md text-xs transition-colors ${unitType === 'kg' ? 'bg-[#FA8072] text-white font-bold' : 'text-gray-400'}`}>كيلو</button>
                        </div>
                        <button type="submit" className="flex-grow bg-[#FA8072] text-white py-2.5 rounded-lg font-bold flex items-center justify-center gap-2 shadow-lg"><Plus size={18} /> إضافة</button>
                    </div>
                </div>
              </form>
          )}

          {editingId && (
              <div className="mb-6 bg-blue-900/20 p-4 rounded-xl border border-blue-500/30 animate-fade-up">
                  <h4 className="text-sm font-bold text-blue-400 mb-3 flex items-center gap-2"><Edit2 size={16} /> تعديل بيانات: {editForm.name}</h4>
                  <div className="space-y-3">
                      <input type="text" value={editForm.name} onChange={e => setEditForm({...editForm, name: e.target.value})} className="w-full bg-gray-900 border border-gray-600 text-white p-2 rounded-lg text-sm" />
                      <div className="grid grid-cols-2 gap-2">
                          <div className="space-y-1">
                              <label className="text-[10px] text-gray-400">رأس المال الجديد</label>
                              <input type="number" value={editForm.costPrice} onChange={e => setEditForm({...editForm, costPrice: e.target.value})} className="w-full bg-gray-900 border border-gray-600 text-[#FA8072] p-2 rounded-lg font-bold" />
                          </div>
                          <div className="space-y-1">
                              <label className="text-[10px] text-gray-400">سعر البيع الجديد</label>
                              <input type="number" value={editForm.price} onChange={e => setEditForm({...editForm, price: e.target.value})} className="w-full bg-gray-900 border border-gray-600 text-green-400 p-2 rounded-lg font-bold" />
                          </div>
                      </div>
                      <div className="flex gap-2">
                          <button onClick={handleUpdate} className="flex-1 bg-green-600 text-white py-2 rounded-lg font-bold flex items-center justify-center gap-2"><Check size={18} /> حفظ التغييرات</button>
                          <button onClick={() => setEditingId(null)} className="px-4 bg-gray-700 text-gray-300 py-2 rounded-lg"><RotateCcw size={18} /></button>
                      </div>
                      <p className="text-[10px] text-gray-500 text-center font-bold">* التغيير سيطبق على المبيعات المستقبلية فقط ولا يؤثر على الأرشيف.</p>
                  </div>
              </div>
          )}

          <div className="space-y-2">
            <h4 className="text-sm font-bold text-gray-400 mb-2">قائمة المنتجات ({products.length})</h4>
            <div className="grid gap-2">
                {products.map(product => (
                  <div key={product.id} className="flex justify-between items-center bg-gray-700 p-3 rounded-xl border border-gray-600 group">
                    <div className="flex-grow">
                      <div className="flex items-center gap-2">
                          <span className="text-white font-bold">{product.name}</span>
                          <span className={`text-[9px] px-1.5 py-0.5 rounded text-black font-bold ${product.unitType === 'kg' ? 'bg-yellow-400' : 'bg-blue-300'}`}>{product.unitType === 'kg' ? 'كغ' : 'قطعة'}</span>
                      </div>
                      <div className="flex items-center gap-3 mt-1.5">
                          <div className="flex flex-col"><span className="text-[9px] text-gray-500 uppercase">التكلفة:</span><span className="text-red-400 text-xs font-bold">{product.costPrice.toLocaleString()}</span></div>
                          <div className="flex flex-col"><span className="text-[9px] text-gray-500 uppercase">البيع:</span><span className="text-green-400 text-xs font-bold">{product.price.toLocaleString()}</span></div>
                      </div>
                    </div>

                    <div className="flex items-center gap-1">
                        <button onClick={() => startEdit(product)} className="text-gray-400 hover:text-blue-400 p-2"><Edit2 size={18} /></button>
                        {confirmDeleteId === product.id ? (
                            <div className="flex items-center gap-1">
                                <button onClick={() => { onDeleteProduct(product.id); setConfirmDeleteId(null); }} className="bg-red-500 text-white px-2 py-1 rounded text-xs">تأكيد</button>
                                <button onClick={() => setConfirmDeleteId(null)} className="text-gray-400 text-xs">إلغاء</button>
                            </div>
                        ) : (
                            <button onClick={() => setConfirmDeleteId(product.id)} className="text-gray-500 hover:text-red-400 p-2"><Trash2 size={18} /></button>
                        )}
                    </div>
                  </div>
                ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

