const ExpensesModal = React.lazy(() => import('./components/ExpensesModal').then(module => ({ default: module.ExpensesModal })));

const useOnlineStatus = () => {
  const [isOnline, setIsOnline] = useState(() => navigator.onLine);
  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, [isOnline]);
  return isOnline;
};

const ModalLoader = () => (
    <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center backdrop-blur-sm">
        <div className="bg-gray-800 p-4 rounded-full shadow-xl border border-gray-700">
            <Loader2 className="animate-spin text-[#FA8072]" size={32} />
        </div>
    </div>
);

const LoadingScreen = ({ progress, message }: { progress: number, message: string }) => {
    const radius = 70;
    const stroke = 8;
    const normalizedRadius = radius - stroke * 2;
    const circumference = normalizedRadius * 2 * Math.PI;
    const strokeDashoffset = circumference - (progress / 100) * circumference;

    return (
      <div className="fixed inset-0 bg-[#0f172a] z-[100] flex flex-col items-center justify-center p-6 text-center">
        <div className="mb-12">
            <h1 className="text-3xl font-black text-[#FA8072] tracking-tighter mb-1">مخبز كوكيز</h1>
            <p className="text-gray-500 text-sm font-bold">Cookies Bakery POS System</p>
        </div>
        <div className="relative flex items-center justify-center mb-10">
            <svg height={radius * 2} width={radius * 2} className="transform rotate-[-90deg]">
                <circle stroke="#1e293b" strokeWidth={stroke} r={normalizedRadius} cx={radius} cy={radius} fill="transparent" />
                <circle stroke="#FA8072" strokeWidth={stroke} strokeDasharray={circumference + ' ' + circumference} style={{ strokeDashoffset, transition: 'stroke-dashoffset 0.3s ease-in-out' }} strokeLinecap="round" r={normalizedRadius} cx={radius} cy={radius} fill="transparent" />
            </svg>
            <div className="absolute flex flex-col items-center justify-center">
                <span className="text-white font-black text-2xl">{progress}%</span>
            </div>
        </div>
        <div className="max-w-xs w-full bg-gray-800/50 p-4 rounded-2xl border border-gray-700/50 backdrop-blur-md">
            <div className="flex items-center justify-center gap-3 text-[#FA8072] mb-1"><Loader2 size={16} className="animate-spin" /><span className="text-xs font-bold uppercase tracking-widest">Processing Data</span></div>
            <p className="text-gray-300 font-bold text-sm leading-relaxed">{message}</p>
        </div>
      </div>
    );
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => sessionStorage.getItem('isAuth') === 'true');
  const [isAppLoading, setIsAppLoading] = useState(false);
  const [loadingProgress, setLoadingProgress] = useState(0);
  const [loadingMessage, setLoadingMessage] = useState('');

  const isOnline = useOnlineStatus();
  const [lastSyncTime, setLastSyncTime] = useState<Date>(new Date());
  const [isSyncing, setIsSyncing] = useState(false);

  const [sales, setSales] = useState<SaleItem[]>(() => JSON.parse(localStorage.getItem('dailySales') || '[]'));
  const [purchaseInvoices, setPurchaseInvoices] = useState<PurchaseInvoice[]>(() => JSON.parse(localStorage.getItem('dailyPurchaseInvoices') || '[]'));
  const [history, setHistory] = useState<ArchivedDay[]>(() => JSON.parse(localStorage.getItem('salesHistory') || '[]'));
  const [products, setProducts] = useState<Product[]>(() => JSON.parse(localStorage.getItem('products') || '[]'));
  const [customers, setCustomers] = useState<Customer[]>(() => JSON.parse(localStorage.getItem('customers') || '[]'));
  const [suppliers, setSuppliers] = useState<Supplier[]>(() => JSON.parse(localStorage.getItem('suppliers') || '[]'));

  const [invoiceItems, setInvoiceItems] = useState<SaleItem[] | null>(null);
  const [showProductManager, setShowProductManager] = useState(false);
  const [showCustomerManager, setShowCustomerManager] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [showDataModal, setShowDataModal] = useState(false);
  const [showExpensesModal, setShowExpensesModal] = useState(false);

  const handleLogin = () => {
      setIsAppLoading(true);
      setLoadingProgress(0);
      setLoadingMessage('بدء تهيئة النظام وتأمين الاتصال...');
      const steps = [
        { progress: 15, message: 'فحص حالة التخزين المحلي والذاكرة...' },
        { progress: 30, message: 'تحميل قائمة المنتجات وأحدث الأسعار...' },
        { progress: 50, message: 'مزامنة أرشيف المبيعات والتقارير المالية...' },
        { progress: 70, message: 'تجهيز سجل المشتريات وقاعدة بيانات الموردين...' },
        { progress: 85, message: 'تطبيق إعدادات واجهة المستخدم المخصصة...' },
        { progress: 95, message: 'اللمسات النهائية لتشغيل التطبيق...' },
        { progress: 100, message: 'اكتمل التحميل! يتم توجيهك الآن...' }
      ];
      let currentStep = 0;
      const interval = setInterval(() => {
          if (currentStep < steps.length) {
              setLoadingProgress(steps[currentStep].progress);
              setLoadingMessage(steps[currentStep].message);
              currentStep++;
          } else {
              clearInterval(interval);
              setTimeout(() => {
                  sessionStorage.setItem('isAuth', 'true');
                  setIsAuthenticated(true);
                  setIsAppLoading(false);
              }, 400);
          }
      }, 400);
  };

  useEffect(() => { localStorage.setItem('dailySales', JSON.stringify(sales)); }, [sales]);
  useEffect(() => { localStorage.setItem('dailyPurchaseInvoices', JSON.stringify(purchaseInvoices)); }, [purchaseInvoices]);
  useEffect(() => { localStorage.setItem('salesHistory', JSON.stringify(history)); }, [history]);
  useEffect(() => { localStorage.setItem('products', JSON.stringify(products)); }, [products]);
  useEffect(() => { localStorage.setItem('customers', JSON.stringify(customers)); }, [customers]);
  useEffect(() => { localStorage.setItem('suppliers', JSON.stringify(suppliers)); }, [suppliers]);

  // Real-time Sync Effect: Keep History Archive always updated with today's activity
  useEffect(() => {
    const todayStr = new Date().toLocaleDateString('en-GB');
    const totalRevenue = sales.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    const totalExpenses = purchaseInvoices.reduce((sum, inv) => sum + inv.totalAmount, 0);
    const totalItems = sales.reduce((sum, item) => sum + item.quantity, 0);

    setHistory(prevHistory => {
      const existingDayIdx = prevHistory.findIndex(day => day.date === todayStr);

      const todayData: ArchivedDay = {
        id: existingDayIdx !== -1 ? prevHistory[existingDayIdx].id : Date.now().toString(),
        date: todayStr,
        timestamp: existingDayIdx !== -1 ? prevHistory[existingDayIdx].timestamp : Date.now(),
        totalRevenue,
        totalExpenses,
        totalItems,
        items: sales,
        purchaseInvoices: purchaseInvoices
      };

      if (existingDayIdx !== -1) {
        const newHistory = [...prevHistory];
        newHistory[existingDayIdx] = todayData;
        return newHistory;
      } else {
        return [todayData, ...prevHistory];
      }
    });
  }, [sales, purchaseInvoices]);

  const handleAddSupplier = (newSup: Omit<Supplier, 'id'>) => setSuppliers(prev => [...prev, { ...newSup, id: Date.now().toString() }]);
  const handleDeleteSupplier = (id: string) => setSuppliers(prev => prev.filter(s => s.id !== id));

  const handleCompleteOrder = (items: any[], name?: string, id?: string, type: SaleType = 'retail') => {
      const orderId = Date.now().toString(); 
      const time = new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
      const customerNumber = sales.length > 0 ? Math.max(...sales.map(s => s.customerNumber)) + 1 : 1;

      const itemsWithIds = items.map((i: any) => ({ 
          ...i, 
          id: Math.random().toString(36).substr(2,9), 
          orderId, 
          customerNumber, 
          customerName: name, 
          customerId: id, 
          saleType: type, 
          time 
      }));
      setSales(prev => [...prev, ...itemsWithIds]);
  };

  const updateProduct = (id: string, updates: Partial<Product>) => {
    setProducts(prev => prev.map(p => p.id === id ? { ...p, ...updates } : p));
  };

  if (isAppLoading) return <LoadingScreen progress={loadingProgress} message={loadingMessage} />;
  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  return (
    <div className="min-h-screen flex flex-col bg-gray-900 print:bg-white">
      <Header 
        onOpenHistory={() => setShowHistory(true)} 
        onOpenDataManagement={() => setShowDataModal(true)}
        onOpenExpenses={() => setShowExpensesModal(true)}
        isOnline={isOnline}
        lastSyncTime={lastSyncTime}
        onManualSync={() => { setIsSyncing(true); setTimeout(() => { setLastSyncTime(new Date()); setIsSyncing(false); }, 800); }}
        isSyncing={isSyncing}
      />
      <main className="flex-grow container mx-auto px-4 py-6 max-w-5xl">
        <Summary items={sales} onPreview={() => setInvoiceItems(sales)} />
        <POSInterface 
            onCompleteOrder={handleCompleteOrder} 
            products={products}
            customers={customers}
            onOpenProductManager={() => setShowProductManager(true)}
            onOpenCustomerManager={() => setShowCustomerManager(true)}
        />
        <div className="mt-8">
            <SalesTable items={sales} onDeleteItem={(id) => setSales(s => s.filter(i => i.id !== id))} onDeleteOrder={(oid) => setSales(s => s.filter(i => i.orderId !== oid))} onPreviewInvoice={setInvoiceItems} />
        </div>
      </main>

      {showExpensesModal && (
          <Suspense fallback={<ModalLoader />}>
              <ExpensesModal isOpen={showExpensesModal} onClose={() => setShowExpensesModal(false)} currentPurchases={purchaseInvoices} archivedHistory={history} onAddInvoice={(inv) => setPurchaseInvoices(prev => [...prev, inv])} onDeleteInvoice={(id) => setPurchaseInvoices(prev => prev.filter(inv => inv.id !== id))} suppliers={suppliers} onAddSupplier={handleAddSupplier} onDeleteSupplier={handleDeleteSupplier} />
          </Suspense>
