};

import React, { useRef, useState } from 'react';
import { X, Download, Upload, Database, AlertTriangle, FileJson, Check, Trash2, Cloud, ExternalLink } from 'lucide-react';

interface DataManagementModalProps {
  onExport: () => void;
  onImport: (file: File) => void;
  onClose: () => void;
}

export const DataManagementModal: React.FC<DataManagementModalProps> = ({ onExport, onImport, onClose }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [isSharing, setIsSharing] = useState(false);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) setSelectedFile(file);
    if (e.target) e.target.value = '';
  };

  const handleConfirmImport = () => {
    if (!selectedFile) return;
    onImport(selectedFile);
    onClose();
  };

  const handleShareToDrive = async () => {
      setIsSharing(true);
      try {
          // Re-gathering data locally to ensure a fresh file for sharing
          const backup = {
              version: '1.4',
              timestamp: Date.now(),
              sales: JSON.parse(localStorage.getItem('dailySales') || '[]'),
              purchaseInvoices: JSON.parse(localStorage.getItem('dailyPurchaseInvoices') || '[]'),
              history: JSON.parse(localStorage.getItem('salesHistory') || '[]'),
              products: JSON.parse(localStorage.getItem('products') || '[]'),
              customers: JSON.parse(localStorage.getItem('customers') || '[]'),
              suppliers: JSON.parse(localStorage.getItem('suppliers') || '[]')
          };

          const fileName = `cookies-bakery-backup-${new Date().toLocaleDateString('en-GB').replace(/\//g, '-')}.json`;
          const file = new File([JSON.stringify(backup, null, 2)], fileName, { type: 'application/json' });

          if (navigator.share && navigator.canShare && navigator.canShare({ files: [file] })) {
              await navigator.share({
                  files: [file],
                  title: 'نسخة احتياطية - مخبز كوكيز',
                  text: 'ملف البيانات المحفوظ',
              });
          } else {
              onExport(); // Fallback to normal download
              alert('المشاركة غير مدعومة في متصفحك. تم تحميل الملف يدوياً.');
          }
      } catch (error) {
          console.error('Error sharing:', error);
          onExport(); // Final fallback
      } finally {
          setIsSharing(false);
      }
  };

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-2xl w-full max-w-lg shadow-2xl border border-gray-700 animate-fade-up flex flex-col overflow-hidden">

        <div className="p-4 border-b border-gray-700 flex justify-between items-center bg-gray-900/50">
          <div className="flex items-center gap-2 text-white">
            <Database size={20} className="text-[#FA8072]" />
            <h3 className="font-bold text-lg">النسخ الاحتياطي</h3>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full transition-colors"><X size={20} className="text-gray-400" /></button>
        </div>

        <div className="p-6 space-y-6 overflow-y-auto">
            <div className="bg-gray-700/30 p-4 rounded-xl border border-gray-600">
                <div className="flex items-start gap-3 mb-4">
                    <div className="bg-blue-500/20 p-2 rounded-lg text-blue-400"><Download size={24} /></div>
                    <div><h4 className="text-white font-bold text-sm">تصدير البيانات</h4><p className="text-gray-400 text-[10px]">حفظ نسخة احتياطية من كافة مبيعاتك ومنتجاتك.</p></div>
                </div>
                <div className="grid grid-cols-2 gap-3">
                    <button onClick={onExport} className="bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-lg font-bold text-xs flex items-center justify-center gap-2 transition-all"><Download size={16} /> تحميل (جهاز)</button>
                    <button onClick={handleShareToDrive} disabled={isSharing} className="bg-green-600 hover:bg-green-500 text-white py-3 rounded-lg font-bold text-xs flex items-center justify-center gap-2 transition-all disabled:opacity-50">{isSharing ? <Check size={16} className="animate-pulse" /> : <Cloud size={16} />} مشاركة (Drive)</button>
                </div>
            </div>

            <div className="bg-gray-700/30 p-4 rounded-xl border border-gray-600">
                <div className="flex items-start gap-3 mb-4">
                    <div className="bg-purple-500/20 p-2 rounded-lg text-purple-400"><Upload size={24} /></div>
                    <div><h4 className="text-white font-bold text-sm">استيراد البيانات</h4><p className="text-gray-400 text-[10px]">استرجاع بياناتك من ملف JSON محفوظ.</p></div>
                </div>
                <div className="bg-yellow-500/10 border border-yellow-500/20 rounded-lg p-3 mb-4 flex items-start gap-2">
                    <AlertTriangle size={16} className="text-yellow-500 shrink-0 mt-0.5" />
                    <p className="text-[10px] text-yellow-200 font-bold leading-relaxed">تحذير: هذه العملية ستقوم باستبدال البيانات الحالية تماماً بالبيانات المستوردة.</p>
                </div>
                <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".json" className="hidden" />
                {!selectedFile ? (
                    <button onClick={() => fileInputRef.current?.click()} className="w-full bg-gray-600 hover:bg-gray-500 text-white py-3 rounded-lg font-bold text-sm border border-gray-500 border-dashed flex items-center justify-center gap-2"><Upload size={18} /> اختيار الملف</button>
                ) : (
                    <div className="space-y-3 animate-fade-up">
                        <div className="bg-gray-800 p-3 rounded-lg border border-gray-600 flex items-center justify-between">
                            <div className="flex items-center gap-3"><div className="bg-green-900/50 p-2 rounded"><FileJson className="text-green-400" size={20} /></div><span className="text-xs text-white font-medium truncate max-w-[150px]">{selectedFile.name}</span></div>
                            <button onClick={() => setSelectedFile(null)} className="text-red-400"><Trash2 size={16} /></button>
                        </div>
                        <button onClick={handleConfirmImport} className="w-full bg-green-600 hover:bg-green-500 text-white py-3 rounded-lg font-bold text-sm flex items-center justify-center gap-2"><Check size={18} /> تأكيد الاستعادة</button>
                    </div>
                )}
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, Suspense, useCallback } from 'react';
