import React, { useState } from 'react';
import { ShoppingCart, Settings, Edit3, Trash2, CheckCircle, Plus, Minus, UserPen, Store, UserPlus, X, BadgeDollarSign } from 'lucide-react';
import { SaleItem, Product, UnitType, SaleType, Customer } from '../types';

interface POSInterfaceProps {
  onCompleteOrder: (items: any[], customerName?: string, customerId?: string, saleType?: SaleType) => void;
  products: Product[];
  customers: Customer[];
  onOpenProductManager: () => void;
  onOpenCustomerManager: () => void;
}

export const POSInterface: React.FC<POSInterfaceProps> = ({ 
    onCompleteOrder, products, customers, onOpenProductManager, onOpenCustomerManager 
}) => {
  const [cart, setCart] = useState<any[]>([]);
  const [saleType, setSaleType] = useState<SaleType>('retail');
  const [selectedCustomerId, setSelectedCustomerId] = useState('');
  const [manualCustomerName, setManualCustomerName] = useState(''); 
  const [showCustomInput, setShowCustomInput] = useState(false);
  const [customForm, setCustomForm] = useState({ name: '', price: '', cost: '', unit: 'piece' as UnitType });

  const addToCart = (p: Product) => {
    setCart(prev => {
      const idx = prev.findIndex(i => i.name === p.name && i.unitType === p.unitType);
      if (idx > -1) {
        const next = [...prev];
        next[idx] = { ...next[idx], quantity: next[idx].quantity + 1 };
        return next;
      }
      return [...prev, { 
        tempId: Math.random().toString(36).substr(2,9), 
        name: p.name, 
        price: p.price, 
        costPrice: p.costPrice || 0, 
        quantity: 1, 
        unitType: p.unitType 
      }];
    });
  };

  const addCustomToCart = () => {
    if (!customForm.name || !customForm.price) return;
    setCart(prev => [...prev, { 
        tempId: Math.random().toString(36).substr(2,9), 
        name: customForm.name, 
        price: parseFloat(customForm.price) || 0, 
        costPrice: parseFloat(customForm.cost) || 0,
        quantity: 1,
        unitType: customForm.unit
    }]);
    setCustomForm({ name: '', price: '', cost: '', unit: 'piece' });
    setShowCustomInput(false);
  };

  const updateQty = (id: string, delta: number) => {
    setCart(prev => prev.map(i => i.tempId === id ? { ...i, quantity: Math.max(0.1, parseFloat((i.quantity + delta * (i.unitType === 'kg' ? 0.1 : 1)).toFixed(2))) } : i));
  };

  // NEW FEATURE: Calculate quantity based on total price for KG products
  const updateByPrice = (id: string, totalAmount: string) => {
    const amount = parseFloat(totalAmount);
    if (isNaN(amount) || amount <= 0) return;

    setCart(prev => prev.map(i => {
      if (i.tempId === id && i.unitType === 'kg') {
        // newQty = total / unitPrice
        const newQty = parseFloat((amount / i.price).toFixed(3));
        return { ...i, quantity: newQty };
      }
      return i;
    }));
  };

  const isCheckoutDisabled = cart.length === 0 || (saleType === 'wholesale' && !selectedCustomerId);

  const handleCheckout = () => {
    if (isCheckoutDisabled) return;

    const items = cart.map(({ name, price, costPrice, quantity, unitType }) => ({ name, price, costPrice, quantity, unitType }));
    const name = saleType === 'wholesale' ? customers.find(c => c.id === selectedCustomerId)?.name : manualCustomerName;

    onCompleteOrder(items, name, selectedCustomerId || undefined, saleType);

    // Reset state after order
    setCart([]); 
    setManualCustomerName(''); 
    setSelectedCustomerId(''); 
    setSaleType('retail');
  };

  const total = cart.reduce((s, i) => s + (i.price * i.quantity), 0);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 no-print">
      <div className="lg:col-span-2 space-y-4">
        <div className="flex items-center justify-between bg-gray-800 p-4 rounded-xl border border-gray-700">
             <h2 className="font-bold text-white flex items-center gap-2"><Settings className="text-[#FA8072]" size={20} /> قائمة المنتجات</h2>
             <button onClick={onOpenProductManager} className="text-xs bg-gray-700 hover:bg-gray-600 text-gray-300 px-3 py-1.5 rounded-lg transition-colors">تعديل</button>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
            {products.map(p => (
                <button key={p.id} onClick={() => addToCart(p)} className="flex flex-col items-center justify-center p-4 bg-gray-800 border border-gray-700 hover:bg-gray-700 hover:border-[#FA8072] text-white rounded-2xl transition-all shadow-sm active:scale-95 h-32 relative group">
                    <div className={`absolute top-2 right-2 px-1.5 py-0.5 rounded text-[10px] font-bold ${p.unitType === 'kg' ? 'bg-yellow-400 text-black' : 'bg-blue-300 text-black'}`}>{p.unitType === 'kg' ? 'كغ' : 'قطعة'}</div>
                    <span className="font-bold text-sm text-center mb-1 group-hover:text-[#FA8072]">{p.name}</span>
                    <span className="text-xs text-gray-400 bg-gray-900/50 px-2 py-1 rounded-md">{p.price.toLocaleString()} ل.س</span>
                </button>
            ))}
            <button onClick={() => setShowCustomInput(true)} className="flex flex-col items-center justify-center p-4 bg-gray-800 border border-dashed border-gray-600 hover:bg-gray-700 text-gray-400 rounded-2xl h-32"><Edit3 size={20} className="mb-2" /><span className="text-xs">مادة حرة</span></button>
        </div>

        {showCustomInput && (
            <div className="bg-gray-800 p-4 rounded-xl border border-[#FA8072] animate-fade-up relative">
                <button onClick={() => setShowCustomInput(false)} className="absolute left-3 top-3 text-gray-500 hover:text-white"><X size={18} /></button>
                <h4 className="text-sm font-bold text-white mb-3">إضافة مادة حرة</h4>
                <div className="grid grid-cols-1 md:grid-cols-12 gap-2">
                    <input type="text" value={customForm.name} onChange={e => setCustomForm({...customForm, name: e.target.value})} placeholder="المادة" className="md:col-span-4 bg-gray-900 border border-gray-600 text-white px-3 py-2 rounded-lg text-sm" autoFocus />
                    <input type="number" value={customForm.cost} onChange={e => setCustomForm({...customForm, cost: e.target.value})} placeholder="التكلفة" className="md:col-span-2 bg-gray-900 border border-gray-600 text-red-400 px-3 py-2 rounded-lg text-sm" />
                    <input type="number" value={customForm.price} onChange={e => setCustomForm({...customForm, price: e.target.value})} placeholder="البيع" className="md:col-span-2 bg-gray-900 border border-gray-600 text-green-400 px-3 py-2 rounded-lg text-sm" />
                    <select value={customForm.unit} onChange={e => setCustomForm({...customForm, unit: e.target.value as UnitType})} className="md:col-span-2 bg-gray-900 border border-gray-600 text-white px-2 py-2 rounded-lg text-sm"><option value="piece">قطعة</option><option value="kg">كغ</option></select>
                    <button onClick={addCustomToCart} className="md:col-span-2 bg-[#FA8072] text-white rounded-lg font-bold">إضافة</button>
                </div>
            </div>
        )}
      </div>

      <div className="lg:col-span-1">
        <div className="bg-gray-800 rounded-2xl border border-gray-700 shadow-xl overflow-hidden flex flex-col h-full min-h-[500px]">
            <div className="bg-gray-900/80 p-4 border-b border-gray-700 space-y-3">
                <div className="flex justify-between items-center">
                    <h3 className="font-bold text-white flex items-center gap-2"><ShoppingCart size={20} className="text-[#FA8072]" /> سلة المبيعات</h3>
                    {cart.length > 0 && <button onClick={() => setCart([])} className="text-xs text-red-400 underline">إلغاء</button>}
                </div>
                <div className="grid grid-cols-2 bg-gray-700 p-1 rounded-lg">
                    <button onClick={() => setSaleType('retail')} className={`py-1.5 text-xs font-bold rounded-md transition-colors ${saleType === 'retail' ? 'bg-white text-black' : 'text-gray-400'}`}>مفرق</button>
                    <button onClick={() => setSaleType('wholesale')} className={`py-1.5 text-xs font-bold rounded-md transition-colors ${saleType === 'wholesale' ? 'bg-[#FA8072] text-white' : 'text-gray-400'}`}>جملة</button>
                </div>
                {saleType === 'retail' ? (
                     <input type="text" value={manualCustomerName} onChange={e => setManualCustomerName(e.target.value)} placeholder="الاسم (اختياري)..." className="w-full bg-gray-800 border border-gray-600 text-white text-sm rounded-lg px-3 py-2" />
                ) : (
                    <div className="flex gap-2">
                         <select value={selectedCustomerId} onChange={e => setSelectedCustomerId(e.target.value)} className={`w-full bg-gray-800 border text-white text-sm rounded-lg px-3 py-2 outline-none ${!selectedCustomerId && cart.length > 0 ? 'border-orange-500/50' : 'border-gray-600'}`}>
                            <option value="">اختر العميل...</option>
                            {customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                         </select>
                        <button onClick={onOpenCustomerManager} className="bg-blue-600 text-white px-3 rounded-lg hover:bg-blue-500 transition-colors"><UserPlus size={18} /></button>
                    </div>
                )}
            </div>

            <div className="flex-grow p-3 overflow-y-auto space-y-2">
                {!cart.length ? (
                    <div className="h-full flex flex-col items-center justify-center text-gray-500 opacity-50"><ShoppingCart size={48} className="mb-2" /><p>سلة المبيعات فارغة</p></div>
                ) : (
                    cart.map(i => (
                        <div key={i.tempId} className="bg-gray-700/50 p-3 rounded-xl flex flex-col gap-2 border border-gray-700 relative">
                            <div className="flex justify-between items-start">
                                <div className="flex flex-col"><span className="text-white font-medium text-sm">{i.name}</span><span className="text-[9px] text-gray-400">سعر الوحدة: {i.price}</span></div>
                                <button onClick={() => setCart(p => p.filter(it => it.tempId !== i.tempId))} className="text-gray-500 hover:text-red-500"><Trash2 size={14} /></button>
                            </div>
                            <div className="flex items-center justify-between">
                                <div className="flex items-center gap-1 bg-gray-900 rounded-lg px-2 py-1">
                                    <button onClick={() => updateQty(i.tempId, -1)} className="text-gray-400"><Minus size={10} /></button>
                                    <span className="text-white text-sm font-bold min-w-[35px] text-center">{i.quantity}</span>
                                    <button onClick={() => updateQty(i.tempId, 1)} className="text-gray-400"><Plus size={10} /></button>
                                </div>

                                <div className="flex items-center gap-1">
                                    {i.unitType === 'kg' ? (
                                        <div className="flex flex-col items-end">
                                            <label className="text-[8px] text-gray-500 font-bold mb-0.5">تغيير بالمبلغ:</label>
                                            <input 
                                                type="number" 
                                                defaultValue={parseFloat((i.price * i.quantity).toFixed(0))}
                                                onBlur={(e) => updateByPrice(i.tempId, e.target.value)}
                                                className="w-20 bg-gray-900 border border-[#FA8072]/40 rounded px-1.5 py-0.5 text-right text-xs text-[#FA8072] font-bold outline-none focus:border-[#FA8072]"
                                            />
                                        </div>
                                    ) : (
                                        <span className="text-[#FA8072] font-bold">{(i.price * i.quantity).toLocaleString()} ل.س</span>
                                    )}
                                </div>
                            </div>
                        </div>
                    ))
                )}
            </div>

            <div className="p-4 bg-gray-900 border-t border-gray-700">
                <div className="flex justify-between items-center mb-4">
                    <span className="text-gray-400 font-bold">المجموع النهائي:</span>
                    <span className="text-2xl font-bold text-white">{total.toLocaleString()} <span className="text-xs text-gray-500">ل.س</span></span>
                </div>

                {saleType === 'wholesale' && !selectedCustomerId && cart.length > 0 && (
                    <p className="text-orange-400 text-[10px] text-center mb-2 font-bold animate-pulse">يجب اختيار عميل لتأكيد البيع بالجملة</p>
                )}

                <button 
                  onClick={handleCheckout} 
                  disabled={isCheckoutDisabled} 
                  className={`w-full py-3.5 rounded-xl font-bold text-lg flex items-center justify-center gap-2 transition-all active:scale-95 ${!isCheckoutDisabled ? 'bg-green-600 text-white hover:bg-green-500 shadow-lg shadow-green-900/20' : 'bg-gray-700 text-gray-500 cursor-not-allowed'}`}
                >
                  <CheckCircle size={24} /> 
                  تأكيد البيع
                </button>
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { X, Calendar, ChevronDown, ChevronUp, Download, Store, User, Search, Receipt, Package, ArrowRight, Folder, CalendarDays, TrendingDown, TrendingUp, Wallet, BadgeDollarSign, Edit3, Save, Trash2 } from 'lucide-react';
import { ArchivedDay, SaleItem } from '../types';

interface HistoryModalProps {
  history: ArchivedDay[];
  onClose: () => void;
  onClearHistory: () => void;
  onPreviewInvoice: (items: SaleItem[]) => void;
  onUpdateOrder: (date: string, orderId: string, updatedItems: SaleItem[]) => void;
}

type NavStep = 'years' | 'months' | 'days';
type ViewMode = 'invoices' | 'items' | 'profit';

export const HistoryModal: React.FC<HistoryModalProps> = ({ history, onClose, onClearHistory, onPreviewInvoice, onUpdateOrder }) => {
  const [step, setStep] = useState<NavStep>('years');
  const [selectedYear, setSelectedYear] = useState<string>('');
  const [selectedMonth, setSelectedMonth] = useState<number>(-1);
  const [searchTerm, setSearchTerm] = useState('');

  const [viewMode, setViewMode] = useState<ViewMode>('invoices');
  const [expandedDayId, setExpandedDayId] = useState<string | null>(null);

  const [editingOrder, setEditingOrder] = useState<{ date: string, orderId: string, items: SaleItem[] } | null>(null);

  const searchResults = useMemo(() => {
      if (!searchTerm) return null;
      const lowerTerm = searchTerm.toLowerCase();
      const allInvoices: { date: string; items: SaleItem[]; total: number; customerName: string; saleType: string; orderId: string }[] = [];

      history.forEach(day => {
          const dayGroups: { [key: string]: SaleItem[] } = {};
          day.items.forEach(item => {
              const key = item.orderId || `legacy-${item.time}`;
              if (!dayGroups[key]) dayGroups[key] = [];
              dayGroups[key].push(item);
          });

          Object.values(dayGroups).forEach(group => {
              const first = group[0];
              const name = (first.customerName || `زبون ${first.customerNumber}`).toLowerCase();
              if (name.includes(lowerTerm) || first.customerNumber.toString().includes(lowerTerm)) {
                  allInvoices.push({
                      date: day.date,
                      items: group,
                      total: group.reduce((sum, i) => sum + i.price * i.quantity, 0),
                      customerName: first.customerName || `زبون ${first.customerNumber}`,
                      saleType: first.saleType,
                      orderId: first.orderId
                  });
              }
          });
      });
      return allInvoices;
  }, [history, searchTerm]);

  const years = useMemo(() => {
    const uniqueYears = new Set<string>(history.map(day => new Date(day.timestamp).getFullYear().toString()));
    return Array.from(uniqueYears).sort((a, b) => b.localeCompare(a));
  }, [history]);

  const months = useMemo(() => {
    if (!selectedYear) return [];
    const uniqueMonths = new Set<number>(
      history
        .filter(day => new Date(day.timestamp).getFullYear().toString() === selectedYear)
        .map(day => new Date(day.timestamp).getMonth())
    );
    return Array.from(uniqueMonths).sort((a, b) => b - a);
  }, [history, selectedYear]);

  const currentDaysData = useMemo(() => {
    if (!selectedYear || selectedMonth === -1) return [];
    return history.filter(day => {
      const d = new Date(day.timestamp);
      return d.getFullYear().toString() === selectedYear && d.getMonth() === selectedMonth;
    });
  }, [history, selectedYear, selectedMonth]);

  const aggregatedItems = useMemo(() => {
      const itemMap = new Map<string, { name: string; quantity: number; revenue: number; cost: number; unitType: string }>();
      currentDaysData.forEach(day => {
          day.items.forEach(item => {
              const key = `${item.name}-${item.unitType}`;
              const existing = itemMap.get(key);
              const cost = (item.costPrice || 0) * item.quantity;
              const revenue = item.price * item.quantity;
              if (existing) {
                  existing.quantity += item.quantity;
                  existing.revenue += revenue;
                  existing.cost += cost;
              } else {
                  itemMap.set(key, { name: item.name, quantity: item.quantity, revenue: revenue, cost: cost, unitType: item.unitType });
              }
          });
      });
      return Array.from(itemMap.values()).sort((a, b) => b.revenue - a.revenue);
  }, [currentDaysData]);

  const totalRevenueForPeriod = currentDaysData.reduce((sum, day) => sum + day.totalRevenue, 0);
  const totalCostForPeriod = aggregatedItems.reduce((sum, item) => sum + item.cost, 0);
  const totalProfitForPeriod = totalRevenueForPeriod - totalCostForPeriod;

  const handleYearSelect = (year: string) => { setSelectedYear(year); setStep('months'); };
  const handleMonthSelect = (monthIndex: number) => { setSelectedMonth(monthIndex); setStep('days'); };
  const handleBack = () => {
    if (step === 'days') { setStep('months'); setSelectedMonth(-1); } 
    else if (step === 'months') { setStep('years'); setSelectedYear(''); }
  };

  const saveEditedOrder = () => {
      if (!editingOrder) return;
      onUpdateOrder(editingOrder.date, editingOrder.orderId, editingOrder.items);
      setEditingOrder(null);
  };

  const getMonthName = (monthIndex: number) => {
    const date = new Date(2000, monthIndex);
    return date.toLocaleString('ar-SY', { month: 'long' });
  };

  const renderContent = () => {
    if (editingOrder) {
        return (
            <div className="bg-gray-800 rounded-2xl p-6 space-y-4 animate-fade-up">
                <div className="flex justify-between items-center border-b border-gray-700 pb-4">
                    <h4 className="text-white font-bold flex items-center gap-2"><Edit3 size={18} /> تعديل الفاتورة - {editingOrder.date}</h4>
                    <button onClick={() => setEditingOrder(null)} className="text-gray-400"><X size={20}/></button>
                </div>
                <div className="space-y-3 overflow-y-auto max-h-[50vh]">
                    {editingOrder.items.map((item, idx) => (
                        <div key={item.id} className="bg-gray-700 p-4 rounded-xl flex flex-col md:flex-row items-center gap-4">
                            <span className="text-white font-bold flex-1">{item.name}</span>
                            <div className="flex items-center gap-2">
                                <label className="text-[10px] text-gray-500 uppercase">الكمية</label>
                                <input type="number" step="0.1" value={item.quantity} onChange={e => {
                                    const next = [...editingOrder.items];
                                    next[idx] = { ...next[idx], quantity: parseFloat(e.target.value) || 0 };
                                    setEditingOrder({ ...editingOrder, items: next });
                                }} className="bg-gray-900 text-white w-20 text-center py-1 rounded" />
                            </div>
                            <div className="flex items-center gap-2">
                                <label className="text-[10px] text-gray-500 uppercase">السعر</label>
                                <input type="number" value={item.price} onChange={e => {
                                    const next = [...editingOrder.items];
                                    next[idx] = { ...next[idx], price: parseFloat(e.target.value) || 0 };
                                    setEditingOrder({ ...editingOrder, items: next });
                                }} className="bg-gray-900 text-[#FA8072] font-bold w-24 text-center py-1 rounded" />
                            </div>
                            <button onClick={() => {
                                const next = editingOrder.items.filter(i => i.id !== item.id);
                                setEditingOrder({ ...editingOrder, items: next });
                            }} className="text-red-400 p-2"><Trash2 size={16}/></button>
                        </div>
                    ))}
                </div>
                <div className="flex gap-3 pt-4 border-t border-gray-700">
                    <button onClick={saveEditedOrder} className="flex-1 bg-green-600 text-white py-3 rounded-xl font-bold flex items-center justify-center gap-2"><Save size={20}/> حفظ التعديلات</button>
                    <button onClick={() => setEditingOrder(null)} className="px-6 bg-gray-700 text-white rounded-xl">إلغاء</button>
                </div>
            </div>
        );
    }

    if (searchTerm) {
        if (!searchResults || searchResults.length === 0) return <div className="flex flex-col items-center justify-center h-full text-gray-500"><Search size={48} className="mb-4 opacity-50" /><p>لا توجد نتائج مطابقة</p></div>;
        return (
            <div className="animate-fade-up space-y-4 overflow-y-auto max-h-[70vh]">
                 <div className="space-y-3">
                    {searchResults.map((inv, idx) => (
                         <div key={idx} className="bg-gray-800 border border-gray-700 rounded-xl p-4">
                             <div className="flex justify-between items-start">
                                 <div><span className="font-bold text-white block">{inv.customerName}</span><span className="text-xs text-gray-500">{inv.date}</span></div>
                                 <div className="flex items-center gap-3">
                                     <span className="font-bold text-[#FA8072]">{inv.total.toLocaleString()}</span>
                                     <button onClick={() => setEditingOrder({ date: inv.date, orderId: inv.orderId, items: inv.items })} className="bg-blue-600/20 text-blue-400 p-2 rounded-lg"><Edit3 size={16} /></button>
                                     <button onClick={() => onPreviewInvoice(inv.items)} className="bg-gray-700 p-2 rounded-lg text-white"><Download size={16} /></button>
                                 </div>
                             </div>
                         </div>
                    ))}
                 </div>
            </div>
        );
    }

    if (step === 'years') return (
        <div className="grid grid-cols-2 md:grid-cols-3 gap-4 animate-fade-up">
            {years.map(year => (
                <button key={year} onClick={() => handleYearSelect(year)} className="bg-gray-700 hover:bg-gray-600 border border-gray-600 p-6 rounded-2xl flex flex-col items-center gap-3 transition-all">
                    <Folder size={40} className="text-[#FA8072]" />
                    <span className="text-xl font-bold text-white">{year}</span>
                </button>
            ))}
        </div>
    );

    if (step === 'months') return (
        <div className="grid grid-cols-2 md:grid-cols-3 gap-4 animate-fade-up">
            {months.map(monthIdx => (
                <button key={monthIdx} onClick={() => handleMonthSelect(monthIdx)} className="bg-gray-700 hover:bg-gray-600 border border-gray-600 p-6 rounded-2xl flex flex-col items-center gap-3 transition-all">
                    <CalendarDays size={40} className="text-blue-400" />
                    <span className="text-xl font-bold text-white">{getMonthName(monthIdx)}</span>
                </button>
            ))}
        </div>
    );

    if (step === 'days') return (
        <div className="flex flex-col gap-4 animate-fade-up h-full">
            <div className="flex bg-gray-700 p-1 rounded-xl shrink-0">
                <button onClick={() => setViewMode('invoices')} className={`flex-1 flex items-center justify-center gap-2 px-4 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'invoices' ? 'bg-white text-black' : 'text-gray-400'}`}><Receipt size={16} /> الفواتير</button>
                <button onClick={() => setViewMode('items')} className={`flex-1 flex items-center justify-center gap-2 px-4 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'items' ? 'bg-[#FA8072] text-white' : 'text-gray-400'}`}><Package size={16} /> المواد</button>
                <button onClick={() => setViewMode('profit')} className={`flex-1 flex items-center justify-center gap-2 px-4 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'profit' ? 'bg-green-600 text-white' : 'text-gray-400'}`}><BadgeDollarSign size={16} /> الأرباح</button>
            </div>
            <div className="flex-1 overflow-y-auto bg-gray-900/30 rounded-xl border border-gray-700/50 p-2">
                {viewMode === 'profit' ? (
                    <div className="animate-fade-up space-y-4">
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                            <div className="bg-gray-800 p-4 rounded-xl border border-gray-700 text-center"><span className="text-[10px] text-gray-500 font-bold block mb-1 uppercase tracking-wider">الإيراد</span><span className="text-xl font-bold text-white">{totalRevenueForPeriod.toLocaleString()}</span></div>
                            <div className="bg-gray-800 p-4 rounded-xl border border-gray-700 text-center"><span className="text-[10px] text-gray-500 font-bold block mb-1 uppercase tracking-wider">التكلفة</span><span className="text-xl font-bold text-red-400">{totalCostForPeriod.toLocaleString()}</span></div>
                            <div className="bg-green-900/20 p-4 rounded-xl border border-green-800 text-center"><span className="text-[10px] text-green-600 font-bold block mb-1 uppercase tracking-wider">الربح الصافي</span><span className="text-2xl font-black text-green-400">{totalProfitForPeriod.toLocaleString()}</span></div>
                        </div>
                        <div className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden"><table className="w-full text-right text-sm"><thead className="bg-gray-900 text-gray-500 text-[10px]"><tr><th className="p-3">المادة</th><th className="p-3 text-center">الكمية</th><th className="p-3">الربح</th></tr></thead><tbody className="divide-y divide-gray-700">{aggregatedItems.map((item, idx) => (<tr key={idx}><td className="p-3 text-white">{item.name}</td><td className="p-3 text-center text-gray-400">{item.quantity} {item.unitType === 'kg' ? 'كغ' : 'قطعة'}</td><td className="p-3 text-green-400 font-bold">{(item.revenue - item.cost).toLocaleString()}</td></tr>))}</tbody></table></div>
                    </div>
                ) : viewMode === 'items' ? (
                    <div className="space-y-3">
                        {aggregatedItems.map((item, idx) => (
                            <div key={idx} className="bg-gray-800 p-3 rounded-xl border border-gray-700 flex justify-between items-center">
                                <div><span className="text-white font-bold block">{item.name}</span><span className="text-xs text-gray-500">{item.quantity} مبيع</span></div>
                                <span className="text-[#FA8072] font-bold">{item.revenue.toLocaleString()}</span>
                            </div>
                        ))}
                    </div>
                ) : (
                    <div className="space-y-3">
                        {currentDaysData.map(day => {
                            const dayOrders = new Map<string, SaleItem[]>();
                            day.items.forEach(i => { const key = i.orderId || i.time; if(!dayOrders.has(key)) dayOrders.set(key, []); dayOrders.get(key)!.push(i); });
                            return (
                                <div key={day.id} className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden">
                                    <div onClick={() => setExpandedDayId(expandedDayId === day.id ? null : day.id)} className="p-4 flex justify-between items-center cursor-pointer bg-gray-900/50">
                                        <div className="flex items-center gap-2">{expandedDayId === day.id ? <ChevronUp size={16} /> : <ChevronDown size={16} />}<span className="text-white font-bold">{day.date}</span></div>
                                        <span className="text-[#FA8072] font-bold">{day.totalRevenue.toLocaleString()}</span>
                                    </div>
                                    {expandedDayId === day.id && (
                                        <div className="p-3 bg-gray-900/20 border-t border-gray-700 space-y-2">
                                            {Array.from(dayOrders.entries()).map(([oid, items]) => (
                                                <div key={oid} className="bg-gray-700/30 p-2 rounded flex justify-between items-center">
                                                    <span className="text-xs text-gray-300 font-medium truncate max-w-[150px]">{items[0].customerName || `زبون ${items[0].customerNumber}`}</span>
                                                    <div className="flex gap-2">
                                                        <button onClick={() => setEditingOrder({ date: day.date, orderId: oid, items })} className="text-blue-400 p-1"><Edit3 size={14} /></button>
                                                        <button onClick={() => onPreviewInvoice(items)} className="text-white p-1"><Download size={14} /></button>
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
    );
  };

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-2xl w-full max-w-4xl shadow-2xl border border-gray-700 animate-fade-up flex flex-col h-[85vh]">
        <div className="p-4 border-b border-gray-700 bg-gray-900/50 rounded-t-2xl flex justify-between items-center">
            <div className="flex items-center gap-3">
                {step !== 'years' && <button onClick={handleBack} className="bg-gray-700 p-2 rounded-full text-white"><ArrowRight size={20} /></button>}
                <h3 className="font-bold text-lg text-white">سجل المبيعات والتحليل</h3>
            </div>
            <div className="flex-grow max-w-xs mx-4"><div className="relative"><Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500" size={14}/><input type="text" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} placeholder="بحث..." className="w-full bg-gray-900 border border-gray-700 text-white py-1.5 pr-8 pl-4 rounded-lg text-xs outline-none focus:border-[#FA8072]"/></div></div>
            <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full text-gray-400"><X size={24} /></button>
        </div>
        <div className="p-4 flex-1 overflow-hidden bg-gray-900/20">{renderContent()}</div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, Suspense } from 'react';
import { Plus, Trash2, X, ShoppingCart, Folder, FileText, CheckCircle, Clock, Download, Printer, UserPlus, ArrowRight, CalendarDays, TrendingDown, Search, Phone, FileSignature, Wallet, Edit3, Save } from 'lucide-react';
import { PurchaseInvoice, PurchaseItem, ArchivedDay, PaymentStatus, Supplier } from '../types';

const PurchasePrintModal = React.lazy(() => import('./PurchasePrintModal').then(module => ({ default: module.PurchasePrintModal })));

interface ExpensesModalProps {
  currentPurchases: PurchaseInvoice[];
  archivedHistory: ArchivedDay[]; 
  onAddInvoice: (invoice: PurchaseInvoice) => void;
  onDeleteInvoice: (id: string) => void;
  isOpen: boolean;
  onClose: () => void;
  suppliers: Supplier[];
  onAddSupplier?: (supplier: Omit<Supplier, 'id'>) => void;
  onDeleteSupplier?: (id: string) => void;
  onUpdatePurchase?: (date: string, purchaseId: string, updatedInvoice: PurchaseInvoice) => void;
}

type Tab = 'new' | 'history' | 'suppliers';
type NavStep = 'years' | 'months' | 'days';

export const ExpensesModal: React.FC<ExpensesModalProps> = ({ 
  currentPurchases, 
  archivedHistory,
  onAddInvoice, 
  onDeleteInvoice,
  isOpen,
  onClose,
  suppliers = [],
  onAddSupplier,
  onDeleteSupplier,
  onUpdatePurchase
}) => {
  const [activeTab, setActiveTab] = useState<Tab>('new');
  const [supplierName, setSupplierName] = useState('');
  const [paymentStatus, setPaymentStatus] = useState<PaymentStatus>('paid'); 
  const [itemInputs, setItemInputs] = useState({ name: '', quantity: '', cost: '' });
  const [currentInvoiceItems, setCurrentInvoiceItems] = useState<PurchaseItem[]>([]);

  const [editingInvoice, setEditingInvoice] = useState<PurchaseInvoice | null>(null);

  const [newSupName, setNewSupName] = useState('');
  const [newSupPhone, setNewSupPhone] = useState('');
  const [newSupNotes, setNewSupNotes] = useState('');

  const [navStep, setNavStep] = useState<NavStep>('years');
  const [selectedYear, setSelectedYear] = useState<string>('');
  const [selectedMonth, setSelectedMonth] = useState<number>(-1);
  const [searchTerm, setSearchTerm] = useState('');

  const [invoiceToPrint, setInvoiceToPrint] = useState<PurchaseInvoice | null>(null);

  // FIX: Collect all unique invoices by ID to prevent duplication between current purchases and history
  const allInvoices = useMemo(() => {
    const invoiceMap = new Map<string, PurchaseInvoice>();

    // First, add archived invoices
    archivedHistory.forEach(day => {
      day.purchaseInvoices?.forEach(inv => {
        invoiceMap.set(inv.id, inv);
      });
    });

    // Then, add/overwrite with current day's purchases to ensure latest data
    currentPurchases.forEach(inv => {
      invoiceMap.set(inv.id, inv);
    });

    return Array.from(invoiceMap.values()).sort((a, b) => b.timestamp - a.timestamp);
  }, [currentPurchases, archivedHistory]);

  const years = useMemo(() => {
    const uniqueYears = new Set<string>(allInvoices.map(inv => new Date(inv.timestamp).getFullYear().toString()));
    return Array.from(uniqueYears).sort((a, b) => b.localeCompare(a));
  }, [allInvoices]);

  const months = useMemo(() => {
    if (!selectedYear) return [];
    const uniqueMonths = new Set<number>(allInvoices.filter(inv => new Date(inv.timestamp).getFullYear().toString() === selectedYear).map(inv => new Date(inv.timestamp).getMonth()));
    return Array.from(uniqueMonths).sort((a, b) => b - a);
  }, [allInvoices, selectedYear]);

  const filteredInvoices = useMemo(() => {
    if (!selectedYear || selectedMonth === -1) return [];
    return allInvoices.filter(inv => { const d = new Date(inv.timestamp); return d.getFullYear().toString() === selectedYear && d.getMonth() === selectedMonth; });
  }, [allInvoices, selectedYear, selectedMonth]);

  const getMonthName = (m: number) => new Date(2000, m).toLocaleString('ar-SY', { month: 'long' });

  const searchResults = useMemo(() => {
    if (!searchTerm) return null;
    const lower = searchTerm.toLowerCase();
    return allInvoices.filter(i => i.supplierName.toLowerCase().includes(lower) || i.items.some(it => it.name.toLowerCase().includes(lower)));
  }, [allInvoices, searchTerm]);

  const handleSaveInvoice = () => {
      if (!supplierName || currentInvoiceItems.length === 0) return alert('بيانات ناقصة');
      const totalAmount = currentInvoiceItems.reduce((sum, item) => sum + item.total, 0);
      onAddInvoice({ id: Date.now().toString(), supplierName, date: new Date().toLocaleDateString('en-GB'), timestamp: Date.now(), items: currentInvoiceItems, totalAmount, paymentStatus });
      setSupplierName(''); setCurrentInvoiceItems([]); alert('تم الحفظ.');
  };

  const handleUpdateArchived = () => {
      if (!editingInvoice || !onUpdatePurchase) return;
      const totalAmount = editingInvoice.items.reduce((sum, item) => sum + item.total, 0);
      onUpdatePurchase(editingInvoice.date, editingInvoice.id, { ...editingInvoice, totalAmount });
      setEditingInvoice(null); alert('تم تعديل الفاتورة.');
  };

  const addItem = (isEdit: boolean) => {
      if (!itemInputs.name || !itemInputs.quantity || !itemInputs.cost) return;
      const q = parseFloat(itemInputs.quantity); const c = parseFloat(itemInputs.cost);
      const newItem = { id: Date.now().toString(), name: itemInputs.name, quantity: q, cost: c, total: q * c };
      if (isEdit && editingInvoice) {
          setEditingInvoice({ ...editingInvoice, items: [...editingInvoice.items, newItem] });
      } else {
          setCurrentInvoiceItems(prev => [...prev, newItem]);
      }
      setItemInputs({ name: '', quantity: '', cost: '' });
  };

  if (!isOpen) return null;

  return (
    <>
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-2xl w-full max-w-2xl shadow-2xl border border-gray-700 animate-fade-up flex flex-col h-[85vh]">

        <div className="p-4 border-b border-gray-700 flex justify-between items-center bg-gray-900/50 rounded-t-2xl shrink-0">
          <div className="flex items-center gap-2 text-white"><ShoppingCart size={20} className="text-[#FA8072]" /><h3 className="font-bold text-lg">المشتريات والموردين</h3></div>
          <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full transition-colors"><X size={20} className="text-gray-400" /></button>
        </div>

        <div className="flex border-b border-gray-700 bg-gray-700/20">
            <button onClick={() => {setActiveTab('new'); setEditingInvoice(null);}} className={`flex-1 py-3 text-sm font-bold ${activeTab === 'new' && !editingInvoice ? 'bg-[#FA8072] text-white' : 'text-gray-400 hover:bg-gray-700'}`}>جديدة</button>
            <button onClick={() => {setActiveTab('history'); setEditingInvoice(null);}} className={`flex-1 py-3 text-sm font-bold ${activeTab === 'history' && !editingInvoice ? 'bg-[#FA8072] text-white' : 'text-gray-400 hover:bg-gray-700'}`}>سجل المشتريات</button>
            <button onClick={() => {setActiveTab('suppliers'); setEditingInvoice(null);}} className={`flex-1 py-3 text-sm font-bold ${activeTab === 'suppliers' && !editingInvoice ? 'bg-[#FA8072] text-white' : 'text-gray-400 hover:bg-gray-700'}`}>الموردين</button>
        </div>

        <div className="p-4 md:p-6 overflow-y-auto flex-1 bg-gray-900/30">

          {editingInvoice ? (
              <div className="space-y-4 animate-fade-up">
                  <div className="flex justify-between items-center bg-blue-900/20 p-4 rounded-xl border border-blue-500/30">
                      <h4 className="text-blue-400 font-bold flex items-center gap-2"><Edit3 size={18}/> تعديل الفاتورة: {editingInvoice.supplierName}</h4>
                      <button onClick={() => setEditingInvoice(null)} className="text-gray-400"><X size={18}/></button>
                  </div>
                  <div className="grid grid-cols-2 gap-3">
                      <select value={editingInvoice.supplierName} onChange={e => setEditingInvoice({...editingInvoice, supplierName: e.target.value})} className="bg-gray-900 border border-gray-600 rounded-lg px-3 py-2 text-white text-sm outline-none">
                        {suppliers.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
                      </select>
                      <div className="flex bg-gray-900 p-1 rounded-lg">
                        <button onClick={() => setEditingInvoice({...editingInvoice, paymentStatus: 'paid'})} className={`flex-1 py-1 text-xs rounded transition-colors ${editingInvoice.paymentStatus === 'paid' ? 'bg-green-600 text-white' : 'text-gray-500'}`}>نقدي</button>
                        <button onClick={() => setEditingInvoice({...editingInvoice, paymentStatus: 'credit'})} className={`flex-1 py-1 text-xs rounded transition-colors ${editingInvoice.paymentStatus === 'credit' ? 'bg-orange-600 text-white' : 'text-gray-500'}`}>آجل</button>
                      </div>
                  </div>
                  <div className="bg-gray-800 p-4 rounded-xl border border-gray-700 flex flex-col md:flex-row gap-2">
                      <input type="text" value={itemInputs.name} onChange={e => setItemInputs({...itemInputs, name: e.target.value})} placeholder="المادة" className="flex-grow bg-gray-900 border border-gray-600 rounded-lg px-3 py-2 text-white text-sm" />
                      <input type="number" value={itemInputs.quantity} onChange={e => setItemInputs({...itemInputs, quantity: e.target.value})} placeholder="الكمية" className="w-20 bg-gray-900 border border-gray-600 rounded-lg text-center text-white text-sm" />
                      <input type="number" value={itemInputs.cost} onChange={e => setItemInputs({...itemInputs, cost: e.target.value})} placeholder="السعر" className="w-24 bg-gray-900 border border-gray-600 rounded-lg text-center text-white text-sm" />
                      <button onClick={() => addItem(true)} className="bg-blue-600 text-white p-2 rounded-lg"><Plus size={18} /></button>
                  </div>
                  <div className="bg-gray-800 rounded-xl overflow-hidden border border-gray-700 max-h-40 overflow-y-auto">
                      <table className="w-full text-sm text-right">
                          <tbody className="divide-y divide-gray-700">
                              {editingInvoice.items.map((item, idx) => (
                                  <tr key={item.id}><td className="p-2 text-white">{item.name}</td><td className="p-2 text-center text-gray-400">{item.quantity}</td><td className="p-2 font-bold text-red-400">{item.total.toLocaleString()}</td><td className="p-2 text-left"><button onClick={() => setEditingInvoice({...editingInvoice, items: editingInvoice.items.filter((_, i) => i !== idx)})} className="text-red-500"><Trash2 size={14} /></button></td></tr>
                              ))}
                          </tbody>
                      </table>
                  </div>
                  <button onClick={handleUpdateArchived} className="w-full bg-blue-600 text-white py-3 rounded-xl font-bold flex items-center justify-center gap-2"><Save size={20}/> حفظ التغييرات</button>
              </div>
          ) : activeTab === 'new' ? (
              <div className="space-y-4 animate-fade-up">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="bg-gray-800 p-4 rounded-xl border border-gray-700"><label className="text-[10px] text-gray-500 font-bold block mb-1">المورد</label><select value={supplierName} onChange={e => setSupplierName(e.target.value)} className="w-full bg-gray-900 border border-gray-600 rounded-lg px-3 py-2 text-white text-sm outline-none"><option value="">اختر مورد</option>{suppliers.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}</select></div>
                    <div className="bg-gray-800 p-4 rounded-xl border border-gray-700"><label className="text-[10px] text-gray-500 font-bold block mb-1">الدفع</label><div className="flex bg-gray-900 p-1 rounded-lg"><button onClick={() => setPaymentStatus('paid')} className={`flex-1 py-1.5 text-xs font-bold rounded-md ${paymentStatus === 'paid' ? 'bg-green-600 text-white' : 'text-gray-400'}`}>نقدي</button><button onClick={() => setPaymentStatus('credit')} className={`flex-1 py-1.5 text-xs font-bold rounded-md ${paymentStatus === 'credit' ? 'bg-orange-600 text-white' : 'text-gray-400'}`}>آجل</button></div></div>
                  </div>
                  <div className="bg-gray-800 p-4 rounded-xl border border-gray-700 flex flex-col md:flex-row gap-2"><input type="text" value={itemInputs.name} onChange={e => setItemInputs({...itemInputs, name: e.target.value})} placeholder="المادة" className="flex-grow bg-gray-900 border border-gray-600 rounded-lg px-3 py-2 text-white text-sm" /><input type="number" value={itemInputs.quantity} onChange={e => setItemInputs({...itemInputs, quantity: e.target.value})} placeholder="الكمية" className="w-20 bg-gray-900 border border-gray-600 rounded-lg text-center text-white text-sm" /><input type="number" value={itemInputs.cost} onChange={e => setItemInputs({...itemInputs, cost: e.target.value})} placeholder="السعر" className="w-24 bg-gray-900 border border-gray-600 rounded-lg text-center text-white text-sm" /><button onClick={() => addItem(false)} className="bg-red-600 text-white p-2 rounded-lg"><Plus size={18} /></button></div>
                  <div className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden min-h-[100px]"><table className="w-full text-sm text-right"><tbody className="divide-y divide-gray-700">{currentInvoiceItems.map(item => (<tr key={item.id}><td className="p-2 text-white">{item.name}</td><td className="p-2 text-center">{item.quantity}</td><td className="p-2 font-bold text-red-400">{item.total.toLocaleString()}</td><td className="p-2 text-left"><button onClick={() => setCurrentInvoiceItems(s => s.filter(i => i.id !== item.id))} className="text-gray-500 hover:text-red-500"><Trash2 size={14} /></button></td></tr>))}</tbody></table></div>
                  <div className="flex items-center justify-between"><div className="text-xl font-bold text-red-400">{currentInvoiceItems.reduce((s,i) => s+i.total, 0).toLocaleString()}</div><button onClick={handleSaveInvoice} className="bg-green-600 text-white px-6 py-2.5 rounded-xl font-bold flex items-center gap-2 shadow-lg"><FileText size={18} /> حفظ</button></div>
              </div>
          ) : activeTab === 'history' ? (
              <div className="space-y-4 animate-fade-up">
                  <div className="relative"><Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500" size={16} /><input type="text" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} placeholder="بحث..." className="w-full bg-gray-800 border border-gray-700 rounded-xl pr-10 pl-4 py-2 text-white text-sm outline-none" /></div>
                  {searchTerm ? (
                      <div className="space-y-2">{searchResults?.map(inv => (<div key={inv.id} className="bg-gray-800 rounded-xl border border-gray-700 p-3 flex items-center justify-between"><div><span className="font-bold text-white block text-sm">{inv.supplierName}</span><span className="text-[10px] text-gray-500">{inv.date}</span></div><div className="flex gap-2"><button onClick={() => setEditingInvoice(inv)} className="bg-blue-600/20 text-blue-400 p-2 rounded-lg"><Edit3 size={16}/></button><button onClick={() => setInvoiceToPrint(inv)} className="bg-gray-700 text-white p-2 rounded-lg"><Printer size={16}/></button></div></div>))}</div>
                  ) : (
                    <>
                        <div className="flex items-center gap-2 mb-2">{navStep !== 'years' && (<button onClick={() => setNavStep(navStep === 'days' ? 'months' : 'years')} className="p-1.5 bg-gray-700 rounded-lg text-white hover:bg-[#FA8072] transition-colors"><ArrowRight size={14} /></button>)}<h4 className="text-white font-bold text-xs">{navStep === 'years' ? 'أرشيف السنوات' : navStep === 'months' ? selectedYear : getMonthName(selectedMonth)}</h4></div>
                        {navStep === 'years' && (<div className="grid grid-cols-2 md:grid-cols-3 gap-3">{years.map(y => (<button key={y} onClick={() => { setSelectedYear(y); setNavStep('months'); }} className="bg-gray-800 p-4 rounded-xl border border-gray-700 hover:border-[#FA8072] flex flex-col items-center gap-2 transition-all"><Folder size={24} className="text-[#FA8072]" /><span className="font-bold text-sm text-white">{y}</span></button>))}</div>)}
                        {navStep === 'months' && (<div className="grid grid-cols-2 md:grid-cols-3 gap-3">{months.map(m => (<button key={m} onClick={() => { setSelectedMonth(m); setNavStep('days'); }} className="bg-gray-800 p-4 rounded-xl border border-gray-700 hover:border-[#FA8072] flex flex-col items-center gap-2 transition-all"><CalendarDays size={24} className="text-blue-400" /><span className="font-bold text-sm text-white">{getMonthName(m)}</span></button>))}</div>)}
                        {navStep === 'days' && (<div className="space-y-2">{filteredInvoices.map(inv => (<div key={inv.id} className="bg-gray-800 rounded-xl border border-gray-700 p-3 flex items-center justify-between group"><div><span className="font-bold text-white block text-sm">{inv.supplierName}</span><span className="text-[9px] text-gray-500">{inv.date}</span></div><div className="flex items-center gap-2"><span className="font-bold text-red-400 text-sm">{inv.totalAmount.toLocaleString()}</span><button onClick={() => setEditingInvoice(inv)} className="bg-blue-600/20 text-blue-400 p-2 rounded-lg"><Edit3 size={14}/></button><button onClick={() => setInvoiceToPrint(inv)} className="bg-gray-700 hover:bg-[#FA8072] text-white p-2 rounded-lg transition-all"><Printer size={14} /></button></div></div>))}</div>)}
                    </>
                  )}
              </div>
          ) : (
              <div className="space-y-6 animate-fade-up">
                  <div className="bg-gray-800 p-5 rounded-xl border border-gray-700 space-y-4">
                      <h4 className="text-[#FA8072] font-bold text-sm">إضافة مورد</h4>
                      <input type="text" value={newSupName} onChange={e => setNewSupName(e.target.value)} placeholder="الاسم" className="w-full bg-gray-900 border border-gray-600 rounded-lg px-3 py-2 text-white text-sm outline-none" />
                      <input type="text" value={newSupPhone} onChange={e => setNewSupPhone(e.target.value)} placeholder="الهاتف" className="w-full bg-gray-900 border border-gray-600 rounded-lg px-3 py-2 text-white text-sm dir-ltr text-right outline-none" />
                      <button onClick={() => { if(!newSupName) return; onAddSupplier?.({ name: newSupName, phone: newSupPhone, notes: newSupNotes }); setNewSupName(''); setNewSupPhone(''); }} className="w-full bg-[#FA8072] text-white py-3 rounded-xl font-bold">حفظ المورد</button>
                  </div>
                  <div className="space-y-2">{suppliers.map(s => (<div key={s.id} className="bg-gray-800 p-3 rounded-xl border border-gray-700 flex justify-between items-center"><span className="text-white font-bold">{s.name}</span><button onClick={() => onDeleteSupplier?.(s.id)} className="text-gray-600 hover:text-red-500 p-1"><Trash2 size={16} /></button></div>))}</div>
              </div>
          )}
        </div>
      </div>
    </div>
    {invoiceToPrint && <Suspense fallback={null}><PurchasePrintModal invoice={invoiceToPrint} onClose={() => setInvoiceToPrint(null)} /></Suspense>}
    </>
  );
};

import React, { useState, useMemo } from 'react';
import { X, Calendar, ChevronDown, ChevronUp, Download, Store, User, Search, Receipt, Package, ArrowRight, Folder, CalendarDays, TrendingDown, TrendingUp, Wallet, BadgeDollarSign, Edit3, Save, Trash2, Filter } from 'lucide-react';
import { ArchivedDay, SaleItem, SaleType } from '../types';

interface HistoryModalProps {
  history: ArchivedDay[];
  onClose: () => void;
  onClearHistory: () => void;
  onPreviewInvoice: (items: SaleItem[]) => void;
  onUpdateOrder: (date: string, orderId: string, updatedItems: SaleItem[]) => void;
}

type NavStep = 'years' | 'months' | 'days';
type ViewMode = 'invoices' | 'items' | 'profit';
type SaleFilter = 'all' | 'retail' | 'wholesale';

export const HistoryModal: React.FC<HistoryModalProps> = ({ history, onClose, onClearHistory, onPreviewInvoice, onUpdateOrder }) => {
  const [step, setStep] = useState<NavStep>('years');
  const [selectedYear, setSelectedYear] = useState<string>('');
  const [selectedMonth, setSelectedMonth] = useState<number>(-1);
  const [searchTerm, setSearchTerm] = useState('');

  const [viewMode, setViewMode] = useState<ViewMode>('invoices');
  const [saleFilter, setSaleFilter] = useState<SaleFilter>('all');
  const [expandedDayId, setExpandedDayId] = useState<string | null>(null);

  const [editingOrder, setEditingOrder] = useState<{ date: string, orderId: string, items: SaleItem[] } | null>(null);

  const searchResults = useMemo(() => {
      if (!searchTerm) return null;
      const lowerTerm = searchTerm.toLowerCase();
      const allInvoices: { date: string; items: SaleItem[]; total: number; customerName: string; saleType: string; orderId: string }[] = [];

      history.forEach(day => {
          const dayGroups: { [key: string]: SaleItem[] } = {};
          day.items.forEach(item => {
              const key = item.orderId || `legacy-${item.time}`;
              if (!dayGroups[key]) dayGroups[key] = [];
              dayGroups[key].push(item);
          });

          Object.values(dayGroups).forEach(group => {
              const first = group[0];
              const name = (first.customerName || `زبون ${first.customerNumber}`).toLowerCase();
              if (name.includes(lowerTerm) || first.customerNumber.toString().includes(lowerTerm)) {
                  allInvoices.push({
                      date: day.date,
                      items: group,
                      total: group.reduce((sum, i) => sum + i.price * i.quantity, 0),
                      customerName: first.customerName || `زبون ${first.customerNumber}`,
                      saleType: first.saleType,
                      orderId: first.orderId
                  });
              }
          });
      });
      return allInvoices;
  }, [history, searchTerm]);

  const years = useMemo(() => {
    const uniqueYears = new Set<string>(history.map(day => new Date(day.timestamp).getFullYear().toString()));
    return Array.from(uniqueYears).sort((a, b) => b.localeCompare(a));
  }, [history]);

  const months = useMemo(() => {
    if (!selectedYear) return [];
    const uniqueMonths = new Set<number>(
      history
        .filter(day => new Date(day.timestamp).getFullYear().toString() === selectedYear)
        .map(day => new Date(day.timestamp).getMonth())
    );
    return Array.from(uniqueMonths).sort((a, b) => b - a);
  }, [history, selectedYear]);

  // Main data filtering logic for day view
  const currentDaysData = useMemo(() => {
    if (!selectedYear || selectedMonth === -1) return [];

    return history.filter(day => {
      const d = new Date(day.timestamp);
      return d.getFullYear().toString() === selectedYear && d.getMonth() === selectedMonth;
    }).map(day => {
        // Apply sale type filter to items within each day
        const filteredItems = day.items.filter(item => 
            saleFilter === 'all' || item.saleType === saleFilter
        );

        return {
            ...day,
            items: filteredItems,
            totalRevenue: filteredItems.reduce((s, i) => s + (i.price * i.quantity), 0),
            totalItems: filteredItems.reduce((s, i) => s + i.quantity, 0)
        };
    }).filter(day => day.items.length > 0); // Only keep days that have items after filtering
  }, [history, selectedYear, selectedMonth, saleFilter]);

  const aggregatedItems = useMemo(() => {
      const itemMap = new Map<string, { name: string; quantity: number; revenue: number; cost: number; unitType: string }>();
      currentDaysData.forEach(day => {
          day.items.forEach(item => {
              const key = `${item.name}-${item.unitType}`;
              const existing = itemMap.get(key);
              const cost = (item.costPrice || 0) * item.quantity;
              const revenue = item.price * item.quantity;
              if (existing) {
                  existing.quantity += item.quantity;
                  existing.revenue += revenue;
                  existing.cost += cost;
              } else {
                  itemMap.set(key, { name: item.name, quantity: item.quantity, revenue: revenue, cost: cost, unitType: item.unitType });
              }
          });
      });
      return Array.from(itemMap.values()).sort((a, b) => b.revenue - a.revenue);
  }, [currentDaysData]);

  const totalRevenueForPeriod = currentDaysData.reduce((sum, day) => sum + day.totalRevenue, 0);
  const totalCostForPeriod = aggregatedItems.reduce((sum, item) => sum + item.cost, 0);
  const totalProfitForPeriod = totalRevenueForPeriod - totalCostForPeriod;

  const handleYearSelect = (year: string) => { setSelectedYear(year); setStep('months'); };
  const handleMonthSelect = (monthIndex: number) => { setSelectedMonth(monthIndex); setStep('days'); };
  const handleBack = () => {
    if (step === 'days') { setStep('months'); setSelectedMonth(-1); } 
    else if (step === 'months') { setStep('years'); setSelectedYear(''); }
  };

  const saveEditedOrder = () => {
      if (!editingOrder) return;
      onUpdateOrder(editingOrder.date, editingOrder.orderId, editingOrder.items);
      setEditingOrder(null);
  };

  const getMonthName = (monthIndex: number) => {
    const date = new Date(2000, monthIndex);
    return date.toLocaleString('ar-SY', { month: 'long' });
  };

  const renderContent = () => {
    if (editingOrder) {
        return (
            <div className="bg-gray-800 rounded-2xl p-6 space-y-4 animate-fade-up">
                <div className="flex justify-between items-center border-b border-gray-700 pb-4">
                    <h4 className="text-white font-bold flex items-center gap-2"><Edit3 size={18} /> تعديل الفاتورة - {editingOrder.date}</h4>
                    <button onClick={() => setEditingOrder(null)} className="text-gray-400"><X size={20}/></button>
                </div>
                <div className="space-y-3 overflow-y-auto max-h-[50vh]">
                    {editingOrder.items.map((item, idx) => (
                        <div key={item.id} className="bg-gray-700 p-4 rounded-xl flex flex-col md:flex-row items-center gap-4">
                            <span className="text-white font-bold flex-1">{item.name}</span>
                            <div className="flex items-center gap-2">
                                <label className="text-[10px] text-gray-500 uppercase">الكمية</label>
                                <input type="number" step="0.1" value={item.quantity} onChange={e => {
                                    const next = [...editingOrder.items];
                                    next[idx] = { ...next[idx], quantity: parseFloat(e.target.value) || 0 };
                                    setEditingOrder({ ...editingOrder, items: next });
                                }} className="bg-gray-900 text-white w-20 text-center py-1 rounded" />
                            </div>
                            <div className="flex items-center gap-2">
                                <label className="text-[10px] text-gray-500 uppercase">السعر</label>
                                <input type="number" value={item.price} onChange={e => {
                                    const next = [...editingOrder.items];
                                    next[idx] = { ...next[idx], price: parseFloat(e.target.value) || 0 };
                                    setEditingOrder({ ...editingOrder, items: next });
                                }} className="bg-gray-900 text-[#FA8072] font-bold w-24 text-center py-1 rounded" />
                            </div>
                            <button onClick={() => {
                                const next = editingOrder.items.filter(i => i.id !== item.id);
                                setEditingOrder({ ...editingOrder, items: next });
                            }} className="text-red-400 p-2"><Trash2 size={16}/></button>
                        </div>
                    ))}
                </div>
                <div className="flex gap-3 pt-4 border-t border-gray-700">
                    <button onClick={saveEditedOrder} className="flex-1 bg-green-600 text-white py-3 rounded-xl font-bold flex items-center justify-center gap-2"><Save size={20}/> حفظ التعديلات</button>
                    <button onClick={() => setEditingOrder(null)} className="px-6 bg-gray-700 text-white rounded-xl">إلغاء</button>
                </div>
            </div>
        );
    }

    if (searchTerm) {
        if (!searchResults || searchResults.length === 0) return <div className="flex flex-col items-center justify-center h-full text-gray-500"><Search size={48} className="mb-4 opacity-50" /><p>لا توجد نتائج مطابقة</p></div>;
        return (
            <div className="animate-fade-up space-y-4 overflow-y-auto max-h-[70vh]">
                 <div className="space-y-3">
                    {searchResults.map((inv, idx) => (
                         <div key={idx} className="bg-gray-800 border border-gray-700 rounded-xl p-4">
                             <div className="flex justify-between items-start">
                                 <div>
                                     <span className="font-bold text-white block">{inv.customerName}</span>
                                     <div className="flex items-center gap-2">
                                        <span className="text-xs text-gray-500">{inv.date}</span>
                                        <span className={`text-[10px] px-1.5 py-0.5 rounded font-bold ${inv.saleType === 'wholesale' ? 'bg-[#FA8072]/20 text-[#FA8072]' : 'bg-blue-400/20 text-blue-400'}`}>
                                            {inv.saleType === 'wholesale' ? 'جملة' : 'مفرق'}
                                        </span>
                                     </div>
                                 </div>
                                 <div className="flex items-center gap-3">
                                     <span className="font-bold text-[#FA8072]">{inv.total.toLocaleString()}</span>
                                     <button onClick={() => setEditingOrder({ date: inv.date, orderId: inv.orderId, items: inv.items })} className="bg-blue-600/20 text-blue-400 p-2 rounded-lg"><Edit3 size={16} /></button>
                                     <button onClick={() => onPreviewInvoice(inv.items)} className="bg-gray-700 p-2 rounded-lg text-white"><Download size={16} /></button>
                                 </div>
                             </div>
                         </div>
                    ))}
                 </div>
            </div>
        );
    }

    if (step === 'years') return (
        <div className="grid grid-cols-2 md:grid-cols-3 gap-4 animate-fade-up">
            {years.map(year => (
                <button key={year} onClick={() => handleYearSelect(year)} className="bg-gray-700 hover:bg-gray-600 border border-gray-600 p-6 rounded-2xl flex flex-col items-center gap-3 transition-all">
                    <Folder size={40} className="text-[#FA8072]" />
                    <span className="text-xl font-bold text-white">{year}</span>
                </button>
            ))}
        </div>
    );

    if (step === 'months') return (
        <div className="grid grid-cols-2 md:grid-cols-3 gap-4 animate-fade-up">
            {months.map(monthIdx => (
                <button key={monthIdx} onClick={() => handleMonthSelect(monthIdx)} className="bg-gray-700 hover:bg-gray-600 border border-gray-600 p-6 rounded-2xl flex flex-col items-center gap-3 transition-all">
                    <CalendarDays size={40} className="text-blue-400" />
                    <span className="text-xl font-bold text-white">{getMonthName(monthIdx)}</span>
                </button>
            ))}
        </div>
    );

    if (step === 'days') return (
        <div className="flex flex-col gap-4 animate-fade-up h-full">

            {/* Main Tabs (Invoices, Items, Profit) */}
            <div className="flex bg-gray-700 p-1 rounded-xl shrink-0">
                <button onClick={() => setViewMode('invoices')} className={`flex-1 flex items-center justify-center gap-2 px-4 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'invoices' ? 'bg-white text-black' : 'text-gray-400'}`}><Receipt size={16} /> الفواتير</button>
                <button onClick={() => setViewMode('items')} className={`flex-1 flex items-center justify-center gap-2 px-4 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'items' ? 'bg-[#FA8072] text-white' : 'text-gray-400'}`}><Package size={16} /> المواد</button>
                <button onClick={() => setViewMode('profit')} className={`flex-1 flex items-center justify-center gap-2 px-4 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'profit' ? 'bg-green-600 text-white' : 'text-gray-400'}`}><BadgeDollarSign size={16} /> الأرباح</button>
            </div>

            {/* Sale Type Sub-filter */}
            <div className="flex items-center gap-2 bg-gray-800/50 p-1 rounded-xl border border-gray-700 shrink-0">
                <span className="text-[10px] font-bold text-gray-500 mr-2 flex items-center gap-1"><Filter size={10} /> نوع البيع:</span>
                <button onClick={() => setSaleFilter('all')} className={`flex-1 py-1 text-[10px] font-bold rounded-lg transition-colors ${saleFilter === 'all' ? 'bg-gray-600 text-white' : 'text-gray-500 hover:bg-gray-700'}`}>الكل</button>
                <button onClick={() => setSaleFilter('retail')} className={`flex-1 py-1 text-[10px] font-bold rounded-lg transition-colors ${saleFilter === 'retail' ? 'bg-blue-600/30 text-blue-400 border border-blue-500/20' : 'text-gray-500 hover:bg-gray-700'}`}>مفرق</button>
                <button onClick={() => setSaleFilter('wholesale')} className={`flex-1 py-1 text-[10px] font-bold rounded-lg transition-colors ${saleFilter === 'wholesale' ? 'bg-[#FA8072]/30 text-[#FA8072] border border-[#FA8072]/20' : 'text-gray-500 hover:bg-gray-700'}`}>جملة</button>
            </div>

            <div className="flex-1 overflow-y-auto bg-gray-900/30 rounded-xl border border-gray-700/50 p-2">
                {viewMode === 'profit' ? (
                    <div className="animate-fade-up space-y-4">
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                            <div className="bg-gray-800 p-4 rounded-xl border border-gray-700 text-center"><span className="text-[10px] text-gray-500 font-bold block mb-1 uppercase tracking-wider">الإيراد ({saleFilter === 'all' ? 'كلي' : saleFilter === 'retail' ? 'مفرق' : 'جملة'})</span><span className="text-xl font-bold text-white">{totalRevenueForPeriod.toLocaleString()}</span></div>
                            <div className="bg-gray-800 p-4 rounded-xl border border-gray-700 text-center"><span className="text-[10px] text-gray-500 font-bold block mb-1 uppercase tracking-wider">التكلفة</span><span className="text-xl font-bold text-red-400">{totalCostForPeriod.toLocaleString()}</span></div>
                            <div className="bg-green-900/20 p-4 rounded-xl border border-green-800 text-center"><span className="text-[10px] text-green-600 font-bold block mb-1 uppercase tracking-wider">الربح الصافي</span><span className="text-2xl font-black text-green-400">{totalProfitForPeriod.toLocaleString()}</span></div>
                        </div>
                        <div className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden"><table className="w-full text-right text-sm"><thead className="bg-gray-900 text-gray-500 text-[10px]"><tr><th className="p-3">المادة</th><th className="p-3 text-center">الكمية</th><th className="p-3">الربح</th></tr></thead><tbody className="divide-y divide-gray-700">{aggregatedItems.map((item, idx) => (<tr key={idx}><td className="p-3 text-white">{item.name}</td><td className="p-3 text-center text-gray-400">{item.quantity} {item.unitType === 'kg' ? 'كغ' : 'قطعة'}</td><td className="p-3 text-green-400 font-bold">{(item.revenue - item.cost).toLocaleString()}</td></tr>))}</tbody></table></div>
                    </div>
                ) : viewMode === 'items' ? (
                    <div className="space-y-3">
                        {aggregatedItems.length === 0 ? (
                            <div className="text-center py-10 text-gray-600 text-sm">لا توجد مبيعات بهذا النوع في الفترة المحددة</div>
                        ) : aggregatedItems.map((item, idx) => (
                            <div key={idx} className="bg-gray-800 p-3 rounded-xl border border-gray-700 flex justify-between items-center">
                                <div><span className="text-white font-bold block">{item.name}</span><span className="text-xs text-gray-500">{item.quantity} مبيع</span></div>
                                <span className="text-[#FA8072] font-bold">{item.revenue.toLocaleString()}</span>
                            </div>
                        ))}
                    </div>
                ) : (
                    <div className="space-y-3">
                        {currentDaysData.length === 0 ? (
                             <div className="text-center py-10 text-gray-600 text-sm">لا توجد فواتير بهذا النوع في الفترة المحددة</div>
                        ) : currentDaysData.map(day => {
                            const dayOrders = new Map<string, SaleItem[]>();
                            day.items.forEach(i => { const key = i.orderId || i.time; if(!dayOrders.has(key)) dayOrders.set(key, []); dayOrders.get(key)!.push(i); });
                            return (
                                <div key={day.id} className="bg-gray-800 rounded-xl border border-gray-700 overflow-hidden">
                                    <div onClick={() => setExpandedDayId(expandedDayId === day.id ? null : day.id)} className="p-4 flex justify-between items-center cursor-pointer bg-gray-900/50">
                                        <div className="flex items-center gap-2">{expandedDayId === day.id ? <ChevronUp size={16} /> : <ChevronDown size={16} />}<span className="text-white font-bold">{day.date}</span></div>
                                        <div className="flex items-center gap-4">
                                            <span className="text-xs text-gray-500">{day.items.length} مادة</span>
                                            <span className="text-[#FA8072] font-bold">{day.totalRevenue.toLocaleString()}</span>
                                        </div>
                                    </div>
                                    {expandedDayId === day.id && (
                                        <div className="p-3 bg-gray-900/20 border-t border-gray-700 space-y-2">
                                            {Array.from(dayOrders.entries()).map(([oid, items]) => (
                                                <div key={oid} className={`p-2 rounded flex justify-between items-center border ${items[0].saleType === 'wholesale' ? 'bg-[#FA8072]/5 border-[#FA8072]/20' : 'bg-blue-400/5 border-blue-400/20'}`}>
                                                    <div className="flex flex-col">
                                                        <span className="text-xs text-gray-300 font-bold truncate max-w-[150px]">{items[0].customerName || `زبون ${items[0].customerNumber}`}</span>
                                                        <span className={`text-[8px] font-bold ${items[0].saleType === 'wholesale' ? 'text-[#FA8072]' : 'text-blue-400'}`}>{items[0].saleType === 'wholesale' ? 'جملة' : 'مفرق'}</span>
                                                    </div>
                                                    <div className="flex gap-2">
                                                        <span className="text-xs font-bold text-white mr-2 self-center">{items.reduce((s, i) => s + (i.price * i.quantity), 0).toLocaleString()}</span>
                                                        <button onClick={() => setEditingOrder({ date: day.date, orderId: oid, items })} className="text-blue-400 p-1"><Edit3 size={14} /></button>
                                                        <button onClick={() => onPreviewInvoice(items)} className="text-white p-1"><Download size={14} /></button>
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
    );
  };

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-2xl w-full max-w-4xl shadow-2xl border border-gray-700 animate-fade-up flex flex-col h-[85vh]">
        <div className="p-4 border-b border-gray-700 bg-gray-900/50 rounded-t-2xl flex justify-between items-center">
            <div className="flex items-center gap-3">
                {step !== 'years' && <button onClick={handleBack} className="bg-gray-700 p-2 rounded-full text-white"><ArrowRight size={20} /></button>}
                <h3 className="font-bold text-lg text-white">سجل المبيعات والتحليل</h3>
            </div>
            <div className="flex-grow max-w-xs mx-4"><div className="relative"><Search className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500" size={14}/><input type="text" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} placeholder="بحث عن زبون..." className="w-full bg-gray-900 border border-gray-700 text-white py-1.5 pr-8 pl-4 rounded-lg text-xs outline-none focus:border-[#FA8072]"/></div></div>
            <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-full text-gray-400"><X size={24} /></button>
        </div>
        <div className="p-4 flex-1 overflow-hidden bg-gray-900/20">{renderContent()}</div>
      </div>
    </div>
  );
};
